function getLazyScriptId(src) {
  return `wpl-lazy-${String(src || "").replace(/[^a-z0-9_-]+/gi, "-")}`;
}

function loadScriptOnce(src, { globalCheck = null } = {}) {
  if (typeof globalCheck === "function") {
    try {
      if (globalCheck()) return Promise.resolve();
    } catch {
      // Fall through and try the script load.
    }
  }
  const safeSrc = String(src || "").trim();
  if (!safeSrc) return Promise.reject(new Error("missing_script_src"));
  const existingLoad = WPL_SCRIPT_LOADS.get(safeSrc);
  if (existingLoad) return existingLoad;

  const promise = new Promise((resolve, reject) => {
    const scriptId = getLazyScriptId(safeSrc);
    const existingScript = document.getElementById(scriptId);
    if (existingScript?.dataset.loaded === "true") {
      resolve();
      return;
    }
    if (existingScript) {
      existingScript.addEventListener("load", () => resolve(), { once: true });
      existingScript.addEventListener("error", () => reject(new Error(`script_load_failed:${safeSrc}`)), { once: true });
      return;
    }
    const script = document.createElement("script");
    script.id = scriptId;
    script.src = safeSrc;
    script.async = true;
    script.dataset.wplLazySrc = safeSrc;
    script.addEventListener("load", () => {
      script.dataset.loaded = "true";
      resolve();
    }, { once: true });
    script.addEventListener("error", () => reject(new Error(`script_load_failed:${safeSrc}`)), { once: true });
    document.body.appendChild(script);
  });
  WPL_SCRIPT_LOADS.set(safeSrc, promise);
  return promise;
}

async function ensurePdfLibLoaded() {
  await loadScriptOnce(PDF_LIB_SRC, {
    globalCheck: () => Boolean(window.PDFLib?.PDFDocument)
  });
  if (!window.PDFLib?.PDFDocument) {
    throw new Error("pdf_lib_unavailable");
  }
  return window.PDFLib;
}

async function ensureCoachPlannerDomainLoaded() {
  await loadScriptOnce(COACH_PLANNER_DOMAIN_SRC);
}

async function ensureMessagesDomainLoaded() {
  await loadScriptOnce(MESSAGES_DOMAIN_SRC, {
    globalCheck: () => Boolean(window.WPLMessagesDomain)
  });
  if (!window.WPLMessagesDomain) {
    throw new Error("messages_domain_unavailable");
  }
  return window.WPLMessagesDomain;
}

function shouldLoadMessagesDomainForRender() {
  const panel = document.getElementById("panel-messages");
  return Boolean(panel && !panel.classList.contains("hidden"));
}

async function renderMessages() {
  if (!shouldLoadMessagesDomainForRender()) return;
  const domain = await ensureMessagesDomainLoaded();
  return domain.renderMessages?.();
}

async function startMessagesRealtimeSync(options = {}) {
  const domain = await ensureMessagesDomainLoaded();
  return domain.startMessagesRealtimeSync?.(options);
}

async function openDirectMessageThreadWithRetry(contactUid, attempts = 5) {
  const domain = await ensureMessagesDomainLoaded();
  return domain.openDirectMessageThreadWithRetry?.(contactUid, attempts);
}

async function appendMessageToThread(payload = {}) {
  const domain = await ensureMessagesDomainLoaded();
  if (typeof domain.appendMessageToThread !== "function") {
    throw new Error("messages_append_unavailable");
  }
  return domain.appendMessageToThread(payload);
}

function normalizeMessageParticipantRole(role, email = "") {
  const normalizedRole = normalizeAuthRole(role);
  if (normalizedRole === "coach" || normalizedRole === "parent" || normalizedRole === "athlete") {
    return normalizedRole;
  }
  if (normalizedRole === "admin" || isForcedAdminEmail(email) || OFFICIAL_COACH_EMAILS.has(normalizeEmail(email))) {
    return "coach";
  }
  return "athlete";
}

function getMessagesCurrentUser() {
  const authUser = getAuthUser();
  if (!authUser?.id) return null;
  const profile = getProfile() || {};
  const email = normalizeEmail(authUser.email || profile.email || "");
  const role = normalizeMessageParticipantRole(profile.role || authUser.role, email);
  return {
    uid: String(authUser.id || "").trim(),
    email,
    role,
    name: String(profile.name || authUser.email || "").trim() || "User",
    linkedCoachUid: String(profile.linkedCoachUid || "").trim(),
    linkedAthleteId: String(profile.linkedAthleteId || "").trim(),
    linkedAthleteUid: String(profile.linkedAthleteUid || "").trim(),
    status: normalizeParentVerificationStatus(profile.status)
  };
}

function isCoachMessagingUser(user) {
  return normalizeMessageParticipantRole(user?.role, user?.email) === "coach";
}

async function ensureDirectMessageThread(contact) {
  const domain = await ensureMessagesDomainLoaded();
  if (typeof domain.ensureDirectMessageThread !== "function") {
    throw new Error("messages_thread_unavailable");
  }
  return domain.ensureDirectMessageThread(contact);
}

function markMessageThreadSeen(threadId = "", timestamp = 0) {
  ensureMessagesDomainLoaded()
    .then((domain) => domain.markMessageThreadSeen?.(threadId, timestamp))
    .catch((err) => console.warn("Message seen sync unavailable", err));
}

function getFirestoreServerTimestamp() {
  if (typeof firebase !== "undefined" && firebase.firestore?.FieldValue?.serverTimestamp) {
    return firebase.firestore.FieldValue.serverTimestamp();
  }
  return new Date().toISOString();
}

function getFirestoreArrayUnion(...values) {
  if (typeof firebase !== "undefined" && firebase.firestore?.FieldValue?.arrayUnion) {
    return firebase.firestore.FieldValue.arrayUnion(...values);
  }
  return values;
}

function messageTimestampToMillis(value) {
  if (!value) return 0;
  if (typeof value.toMillis === "function") return value.toMillis();
  if (typeof value.toDate === "function") return value.toDate().getTime();
  return parseIsoTimestamp(value);
}

function formatMessageTimestamp(value) {
  const ms = messageTimestampToMillis(value);
  if (!ms) return "";
  const locale = currentLang === "es" ? "es-ES" : "en-US";
  return new Date(ms).toLocaleString(locale, {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    timeZone: APP_TIMEZONE
  });
}

async function prepareMessagesDomainForOpen() {
  const domain = await ensureMessagesDomainLoaded();
  return domain.prepareForOpen?.();
}

function reportMessagesDomainOpenFailure() {
  const status = document.getElementById("messagesStatus");
  if (status) {
    status.textContent = currentLang === "es"
      ? "No se pudieron cargar los mensajes. Intenta abrir Mensajes otra vez."
      : "Messages could not load. Try opening Messages again.";
    status.classList.add("error");
  }
}

function runWhenBrowserIsIdle(callback, { timeout = 1500 } = {}) {
  if (typeof callback !== "function") return;
  const runner = () => {
    try {
      callback();
    } catch (error) {
      console.warn("Deferred domain task failed.", error);
    }
  };
  if (typeof window.requestIdleCallback === "function") {
    window.requestIdleCallback(runner, { timeout });
    return;
  }
  window.setTimeout(runner, Math.min(Math.max(timeout, 0), 1500));
}

function startMessagesRealtimeWhenIdle(options = {}) {
  runWhenBrowserIsIdle(() => {
    startMessagesRealtimeSync(options).catch((err) => {
      console.warn("Messages realtime bootstrap failed", err);
    });
  }, { timeout: 2500 });
}

function startMediaDomainSyncWhenIdle() {
  runWhenBrowserIsIdle(() => {
    ensureMediaDomainSyncNow().catch((err) => {
      console.warn("Failed to hydrate shared media in deferred domain sync", err);
    });
  }, { timeout: 2200 });
}

async function ensureMediaDomainSyncNow() {
  await hydrateMediaTreeFromSharedStore();
  startMediaRealtimeSync();
  renderMedia();
}

