function setLanguage(lang, { source = "system", skipConfirm = false, refresh = true } = {}) {
  const nextLang = resolveLang(lang);
  if (nextLang === currentLang && !skipConfirm) {
    setHeaderLang(nextLang);
    return true;
  }

  if (!skipConfirm && source === "header" && nextLang !== "en" && nextLang !== currentLang) {
    const confirmMsg = LANGUAGE_CONFIRM[nextLang] || LANGUAGE_CONFIRM.es;
    if (!window.confirm(confirmMsg)) {
      langChangeLocked = true;
      setHeaderLang(currentLang);
      langChangeLocked = false;
      return false;
    }
  }

  currentLang = nextLang;
  document.documentElement.lang = nextLang;
  localStorage.setItem(LANG_KEY, nextLang);
  setHeaderLang(nextLang);

  const profile = getProfile();
  if (profile) {
    profile.lang = nextLang;
    setProfile(profile);
  }

  if (typeof window !== "undefined" && typeof window.dispatchEvent === "function") {
    try {
      window.dispatchEvent(new CustomEvent("wpl:language-changed", {
        detail: { lang: nextLang, source }
      }));
    } catch {
      // ignore cross-browser custom event issues
    }
  }

  if (refresh) refreshLanguageUI();
  return true;
}

function parseStoredJson(key) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function clearLegacyRegisteredUsersCache() {
  localStorage.removeItem("wpl_registered_users_cache");
}

function getAuthUser() {
  const auth = parseStoredJson(AUTH_USER_KEY);
  if (!auth || typeof auth !== "object") return null;
  const id = auth.id ? String(auth.id).trim() : "";
  if (!id) return null;
  const email = normalizeEmail(auth.email || "");
  const requestedRole = normalizeAuthRole(auth.role);
  const role = (requestedRole === "admin" || isForcedAdminEmail(email))
    ? (hasTrustedAdminSession({ email, userId: id }) ? "admin" : "athlete")
    : requestedRole;
  return {
    id,
    email,
    role
  };
}

function setAuthUser(authUser) {
  if (!authUser) {
    stopUserClientStateSync();
    localStorage.removeItem(AUTH_USER_KEY);
    return;
  }
  const id = String(authUser.id || "");
  const email = normalizeEmail(authUser.email || "");
  const requestedRole = normalizeAuthRole(authUser.role);
  const role = (requestedRole === "admin" || isForcedAdminEmail(email))
    ? (hasTrustedAdminSession({ email, userId: id }) ? "admin" : "athlete")
    : requestedRole;
  const payload = {
    id,
    email,
    role
  };
  localStorage.setItem(AUTH_USER_KEY, JSON.stringify(payload));
}

function profileStorageKey(userId) {
  const id = userId ? String(userId) : "";
  if (!id) return PROFILE_KEY;
  const safeId = id.replace(/[^a-zA-Z0-9_-]/g, "_");
  return `wpl_profile_user_${safeId}`;
}

function normalizeProfileForAuth(profile, authUser) {
  const base = profile && typeof profile === "object" ? { ...profile } : {};
  if (authUser?.id) base.user_id = authUser.id;
  const email = normalizeEmail(base.email || authUser?.email || "");
  if (email) base.email = email;
  const normalizedPhoto = getProfilePhotoValue(base);
  if (normalizedPhoto) {
    base.photo = normalizedPhoto;
  } else {
    delete base.photoUrl;
    delete base.profilePhoto;
  }
  const requestedRole = normalizeAuthRole(authUser?.role || base.role);
  const allowAdmin = hasTrustedAdminSession({ email, userId: authUser?.id || base.user_id });
  const role = (requestedRole === "admin" || isForcedAdminEmail(email))
    ? (allowAdmin ? "admin" : "athlete")
    : requestedRole;
  base.role = role;
  base.view = resolveViewForRole(role, base.view);
  if (role === "parent") {
    base.status = normalizeParentVerificationStatus(base.status);
    base.athleteName = getParentLinkedAthleteName(base);
    base.linkedAthleteId = getParentLinkedAthleteId(base);
    base.linkedAthleteUid = getParentLinkedAthleteUid(base);
    base.linkedCoachUid = getParentLinkedCoachUid(base);
    base.linkedCoachName = getParentLinkedCoachName(base);
  } else if (role === "athlete") {
    base.linkedAthleteId = getAthleteLinkedAthleteId(base);
    base.linkedAthleteUid = getAthleteLinkedAthleteUid(base, authUser);
    base.linkedCoachUid = getAthleteLinkedCoachUid(base);
    base.linkedCoachName = getAthleteLinkedCoachName(base);
  }
  if (!base.lang) {
    const storedLang = localStorage.getItem(LANG_KEY);
    base.lang = storedLang && SUPPORTED_LANGS.has(storedLang) ? storedLang : DEFAULT_LANG;
  }
  return base;
}

function getProfile() {
  const authUser = getAuthUser();
  if (authUser?.id) {
    const userProfile = parseStoredJson(profileStorageKey(authUser.id));
    if (userProfile) {
      return normalizeProfileForAuth(userProfile, authUser);
    }
  }
  const fallback = parseStoredJson(PROFILE_KEY);
  return fallback ? normalizeProfileForAuth(fallback, authUser) : null;
}

function setProfile(profile, { sync = true } = {}) {
  const authUser = getAuthUser();
  if (!profile || typeof profile !== "object") {
    localStorage.removeItem(PROFILE_KEY);
    if (authUser?.id) {
      localStorage.removeItem(profileStorageKey(authUser.id));
    }
    return;
  }
  const normalized = normalizeProfileForAuth(profile, authUser);
  localStorage.setItem(PROFILE_KEY, JSON.stringify(normalized));
  if (authUser?.id) {
    localStorage.setItem(profileStorageKey(authUser.id), JSON.stringify(normalized));
    if (sync) {
      queueFirebaseProfileSync(authUser.id, normalized);
    }
  }
}

async function applyProfile(profile) {
  if (!profile) {
    stopCoachWorkspaceRealtimeSync();
    stopParentPortalRealtimeSync();
    stopAthletePortalRealtimeSync();
    stopAdminUsersRealtimeSync();
    stopProfilePhotoRealtimeSync();
    teardownMessagesSession();
    setLanguage(getPreferredLang(), { skipConfirm: true, refresh: false });
    setView("athlete");
    refreshLanguageUI();
    return;
  }

  const role = normalizeAuthRole(profile.role);
  const view = resolveViewForRole(role, profile.view);
  setLanguage(profile.lang || getPreferredLang(), { skipConfirm: true, refresh: false });
  setView(view);
  if (view === "coach") {
    clearLegacyCoachPlannerArtifacts();
  }
  if (isCoachRole(role)) {
    startCoachWorkspaceRealtimeSync();
  } else {
    stopCoachWorkspaceRealtimeSync();
  }
  if (role === "parent") {
    startParentPortalRealtimeSync();
  } else {
    stopParentPortalRealtimeSync();
  }
  if (role === "athlete") {
    await startAthletePortalRealtimeSync();
  } else {
    stopAthletePortalRealtimeSync();
  }
  if (isAdminRole(role)) {
    startAdminUsersRealtimeSync();
  } else {
    stopAdminUsersRealtimeSync();
  }
  startMessagesRealtimeWhenIdle({
    forceRefreshContacts: true
  });
  refreshLanguageUI();
  startProfilePhotoRealtimeSync();
  syncVisibleProfileAvatars(profile);
}

function stopProfilePhotoRealtimeSync() {
  if (profilePhotoRealtimeUnsub) {
    try {
      profilePhotoRealtimeUnsub();
    } catch {
      // ignore unsubscribe errors
    }
    profilePhotoRealtimeUnsub = null;
  }
}

function startProfilePhotoRealtimeSync() {
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!authUser?.id || !profile || !firebaseFirestoreInstance) {
    stopProfilePhotoRealtimeSync();
    return;
  }
  if (profilePhotoRealtimeUnsub) return;
  profilePhotoRealtimeUnsub = firebaseFirestoreInstance
    .collection(FIREBASE_USERS_COLLECTION)
    .doc(authUser.id)
    .onSnapshot((snapshot) => {
      const exists = typeof snapshot?.exists === "function" ? snapshot.exists() : Boolean(snapshot?.exists);
      if (!exists) return;
      const remoteData = snapshot.data() || {};
      const hasRemotePhotoField = ["photo", "photoUrl", "profilePhoto"].some((key) =>
        Object.prototype.hasOwnProperty.call(remoteData, key)
      );
      if (!hasRemotePhotoField) return;
      const remotePhoto = String(remoteData.photo || remoteData.photoUrl || remoteData.profilePhoto || "").trim();
      const currentProfile = getProfile() || profile || {};
      const currentPhoto = getProfilePhotoValue(currentProfile);
      if (remotePhoto !== currentPhoto) {
        const updatedProfile = { ...currentProfile, photo: remotePhoto };
        setProfile(updatedProfile, { sync: false });
        syncVisibleProfileAvatars(updatedProfile);

        if (aPhoto && isAthleteRole(updatedProfile.role)) {
          aPhoto.value = remotePhoto;
          renderAthleteProfilePhotoPreview({
            photoValue: remotePhoto,
            profileName: updatedProfile.name || "",
            statusMessage: currentLang === "es"
              ? "Foto actualizada desde otro dispositivo."
              : "Photo updated from another device.",
            statusTone: "ok"
          });
        }
      }
    }, (err) => console.warn("Profile photo realtime sync failed", err));
}

