async function ensureOfficialCompetitionRecordsForWorkspace(ownerUid = "", competitionsSnapshot = null) {
  const safeOwnerUid = String(ownerUid || "").trim();
  if (!safeOwnerUid || !firebaseFirestoreInstance) return;
  const competitionsRef = getCoachWorkspaceCollectionRef("competitions", safeOwnerUid);
  if (!competitionsRef) return;
  const snapshot = competitionsSnapshot || await withTimeout(
    competitionsRef.get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_competitions_seed_timeout"
  );
  const existingRows = (snapshot?.docs || []).map((doc) => normalizeCoachCompetitionRecord(doc.id, doc.data() || {}));
  const existingById = new Map(existingRows.map((row) => [row.id, row]));
  const batch = firebaseFirestoreInstance.batch();
  let hasWrites = false;

  getSeedCoachCompetitionRecords().forEach((seed) => {
    const existing = existingById.get(seed.id) || null;
    const mergedAthleteNames = uniqueNames([...(existing?.athleteNames || []), ...(seed.athleteNames || [])]);
    const mergedAthleteIds = uniqueNames([...(existing?.athleteIds || []), ...(seed.athleteIds || [])])
      .map((value) => String(value || "").trim())
      .filter(Boolean);
    const mergedAthleteUids = uniqueNames([...(existing?.athleteUids || []), ...(seed.athleteUids || [])])
      .map((value) => String(value || "").trim())
      .filter(Boolean);
    const baseChanged = !existing
      || String(existing.name || "") !== String(seed.name || "")
      || String(existing.location || "") !== String(seed.location || "")
      || String(existing.style || "") !== String(seed.style || "")
      || String(existing.description || "") !== String(seed.description || "")
      || String(existing.organizer || "") !== String(seed.organizer || "")
      || String(existing.note || "") !== String(seed.note || "")
      || String(existing.startDateKey || "") !== String(seed.startDateKey || "")
      || String(existing.endDateKey || "") !== String(seed.endDateKey || "")
      || Boolean(existing.allowSelfJoin !== false) !== Boolean(seed.allowSelfJoin !== false)
      || Boolean(existing.allowCoachInvite !== false) !== Boolean(seed.allowCoachInvite !== false)
      || existing.system !== true;
    const rosterChanged = !existing
      || !stringListsEqual(existing.athleteNames || [], mergedAthleteNames)
      || !stringListsEqual(existing.athleteIds || [], mergedAthleteIds)
      || !stringListsEqual(existing.athleteUids || [], mergedAthleteUids);
    if (!baseChanged && !rosterChanged) {
      return;
    }
    const payload = stripUndefinedDeep({
      ...seed,
      athleteNames: mergedAthleteNames,
      athleteIds: mergedAthleteIds,
      athleteUids: mergedAthleteUids,
      updatedBy: String(getAuthUser()?.id || safeOwnerUid).trim(),
      updatedAt: getFirestoreServerTimestamp(),
      createdBy: String(existing?.createdBy || getAuthUser()?.id || safeOwnerUid).trim(),
      createdAt: existing ? undefined : getFirestoreServerTimestamp()
    });
    batch.set(competitionsRef.doc(seed.id), payload, { merge: true });
    hasWrites = true;
  });

  if (hasWrites) {
    await withTimeout(
      batch.commit(),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_official_competitions_seed_commit_timeout"
    );
  }
}

function getSeedCopyValue(value) {
  if (value && typeof value === "object") {
    return String(value.en || value.es || Object.values(value)[0] || "").trim();
  }
  return String(value || "").trim();
}

function getCoachAthleteRecords() {
  const profile = getProfile();
  if (isCoachRole(profile?.role)) {
    const authUser = getAuthUser();
    const coachMeta = {
      coachUid: String(authUser?.id || "").trim(),
      coachName: String(profile?.name || authUser?.email || "").trim(),
      coachEmail: normalizeEmail(profile?.email || authUser?.email || "")
    };
    const directoryRecords = coachAthleteDirectoryCache.map((user) => buildCoachAthleteRecordFromUser(user, coachMeta));
    const mergedLiveRecords = mergeCoachAthleteSourceRecords(directoryRecords, coachAthletesCache);
    if (PUBLISH_READY_MODE && directoryRecords.length) {
      const directoryIds = new Set(directoryRecords.map((record) => normalizeAthleteId(record.id, record.name)));
      const directoryUids = new Set(directoryRecords.map((record) => normalizeUid(record.athleteUid)).filter(Boolean));
      const directoryEmails = new Set(
        directoryRecords
          .map((record) => normalizeEmail(record.athleteEmail || record.email || ""))
          .filter(Boolean)
      );
      const filteredRecords = mergedLiveRecords.filter((record) => {
        const recordId = normalizeAthleteId(record.id, record.name);
        const recordUid = normalizeUid(record.athleteUid || record.uid || "");
        const recordEmail = normalizeEmail(record.athleteEmail || record.email || "");
        const recordName = normalizeName(record.name || "");
        return (
          directoryIds.has(recordId)
          || (recordUid && directoryUids.has(recordUid))
          || (recordEmail && directoryEmails.has(recordEmail))
          || directoryRecords.some((entry) => normalizeName(entry.name || "") === recordName)
        );
      });
      if (filteredRecords.length) return filteredRecords;
      return directoryRecords;
    }
    const liveWorkspaceRecords = mergedLiveRecords.filter((record) => !isLegacyCoachAthleteRecord(record));
    if (liveWorkspaceRecords.length) return liveWorkspaceRecords;
  }
  if (coachAthletesCache.length) {
    return coachAthletesCache.filter((record) => !isLegacyCoachAthleteRecord(record));
  }
  if (!athletePortalAthleteCache) return [];
  return [normalizeCoachAthleteRecord(
    normalizeAthleteId(athletePortalAthleteCache.id, athletePortalAthleteCache.name),
    athletePortalAthleteCache
  )];
}

function parseAthleteExperienceYears(value) {
  const numeric = Number(String(value ?? "").trim());
  return Number.isFinite(numeric) ? numeric : null;
}

function getAutomaticGroupMembersForAthletes(groupId = "", athletes = []) {
  const normalizedGroupId = String(groupId || "").trim();
  const preparedAthletes = athletes
    .map((athlete) => normalizeCoachAthleteRecord(normalizeAthleteId(athlete?.id, athlete?.name), athlete))
    .filter((athlete) => athlete?.id && athlete?.name);

  return preparedAthletes.filter((athlete) => {
    const experienceYears = parseAthleteExperienceYears(athlete.experienceYears);
    const textBlob = [
      athlete.notes,
      athlete.strategy,
      athlete.preferred,
      athlete.availability,
      athlete.level,
      ...(athlete.tags || [])
    ].join(" ").toLowerCase();
    switch (normalizedGroupId) {
      case "all-registered-athletes":
        return true;
      case "varsity":
        return String(athlete.level || "").toLowerCase() === "advanced"
          || (experienceYears != null && experienceYears >= 5);
      case "jv":
        return String(athlete.level || "").toLowerCase() === "intermediate"
          || (experienceYears != null && experienceYears >= 2 && experienceYears < 5);
      case "beginners":
        return String(athlete.level || "").toLowerCase() === "beginner"
          || (experienceYears != null && experienceYears >= 0 && experienceYears < 2);
      case "competition-team":
        return String(athlete.level || "").toLowerCase() === "advanced"
          || /competition|tournament|travel squad|varsity/.test(textBlob);
      case "rehab-return-to-play":
        return /rehab|return to play|injury|limited|recover/.test(textBlob);
      case "remote-athletes":
        return /remote|travel|virtual/.test(textBlob);
      case "private-clients":
        return /private|client|1:1|one-on-one/.test(textBlob);
      default:
        return false;
    }
  });
}

