function getSmartTagDef(tagId) {
  return SMART_TAGS.find((tag) => tag.id === tagId) || null;
}

function smartTagLabel(tagId) {
  const def = getSmartTagDef(tagId);
  if (!def) return tagId;
  return pickCopy(def.label);
}

function formatSmartTag(tagId) {
  const def = getSmartTagDef(tagId);
  if (!def) return tagId;
  return `${def.icon} ${pickCopy(def.label)}`;
}

function normalizeSmartTags(tags) {
  if (!Array.isArray(tags)) return [];
  const allowed = new Set(SMART_TAGS.map((tag) => tag.id));
  return tags.filter((tag) => allowed.has(tag));
}

function localizeAthlete(athlete) {
  if (currentLang !== "es") return athlete;
  return {
    ...athlete,
    style: translateValue(athlete.style),
    availability: translateValue(athlete.availability),
    preferred: translateValue(athlete.preferred),
    international: translateValue(athlete.international),
    history: translateValue(athlete.history),
    level: getLevelLabel(athlete.level),
    position: translateOptionValue("pPosition", athlete.position),
    strategy: translateOptionValue("pStrategy", athlete.strategy),
    notes: translateValue(athlete.notes),
    tags: normalizeSmartTags(athlete.tags)
  };
}

function getAthletesData() {
  const profile = getProfile();
  const sourceAthletes = getCoachAthleteRecords().length
    ? getCoachAthleteRecords()
    : [];
  const merged = sourceAthletes.map((athlete) => {
    if (!profile || profile.role !== "athlete" || !profile.name || profile.name !== athlete.name) {
      return { ...athlete, tags: normalizeSmartTags(athlete.tags) };
    }
    const profileTags = normalizeSmartTags(profile.tags);
    return {
      ...athlete,
      ...profile,
      tags: profileTags.length ? profileTags : normalizeSmartTags(athlete.tags),
      favoritePosition: profile.favoritePosition || athlete.favoritePosition,
      psychTendency: profile.psychTendency || athlete.psychTendency,
      offenseTop3: Array.isArray(profile.offenseTop3) && profile.offenseTop3.length
        ? profile.offenseTop3
        : athlete.offenseTop3,
      defenseTop3: Array.isArray(profile.defenseTop3) && profile.defenseTop3.length
        ? profile.defenseTop3
        : athlete.defenseTop3
    };
  });
  const profileName = profile?.role === "athlete" ? profile.name : "";
  const hasProfileMatch = profileName && merged.some((athlete) => athlete.name === profileName);
  if (profile?.role === "athlete" && athletePortalAthleteCache) {
    const linkedAthlete = mergeAthletePortalProfileWithWorkspace(profile, athletePortalAthleteCache);
    const next = merged.filter((athlete) => !athleteIdentityMatches(athlete, linkedAthlete));
    next.unshift(linkedAthlete);
    return currentLang === "es" ? next.map((athlete) => localizeAthlete(athlete)) : next;
  }
  if (profileName && !hasProfileMatch) {
    const profileTags = normalizeSmartTags(profile.tags);
    const styleEnglish = SELECT_COPY.aStyle?.en?.[profile.style] || profile.style || "";
    const preferred = profile.trainingFocus || profile.offenseTop3?.[0] || "";
    const years = profile.years ? String(profile.years) : "";
    merged.push({
      ...profile,
      name: profileName,
      weight: profile.currentWeight || "",
      style: styleEnglish,
      availability: "Available",
      preferred,
      international: profile.internationalEvents || (profile.international === "yes" ? "International" : "None"),
      history: years ? `Training history: ${years} years` : "",
      notes: profile.resultsHistory || "",
      experienceYears: years || profile.experienceYears || "",
      favoritePosition: profile.favoritePosition || profile.position || "neutral",
      psychTendency: profile.psychTendency || strategyToTendency(profile.strategy),
      offenseTop3: Array.isArray(profile.offenseTop3) ? profile.offenseTop3 : [],
      defenseTop3: Array.isArray(profile.defenseTop3) ? profile.defenseTop3 : [],
      tags: profileTags
    });
  }
  return currentLang === "es" ? merged.map((athlete) => localizeAthlete(athlete)) : merged;
}

function getJournalInsightsData() {
  const athletes = getAthletesData();
  if (!athletes.length) {
    return [currentLang === "es" ? "No hay atletas registrados todavia." : "No registered athletes yet."];
  }
  const rows = getJournalAthletesData();
  const rowsWithEntry = rows.filter((row) => row.hasEntry);
  if (!rowsWithEntry.length) {
    return [currentLang === "es" ? "Sin datos de readiness todavia. Guarda la primera entrada." : "No readiness data yet. Save the first entry."];
  }
  const energyValues = rowsWithEntry.map((row) => parseScoreValue(row.energy)).filter((value) => value > 0);
  const sleepValues = rowsWithEntry.map((row) => parseHoursValue(row.sleep)).filter((value) => value > 0);
  const avgEnergy = energyValues.length
    ? `${(energyValues.reduce((sum, value) => sum + value, 0) / energyValues.length).toFixed(1)}/5`
    : (currentLang === "es" ? "Sin datos" : "No data");
  const avgSleep = sleepValues.length
    ? `${(sleepValues.reduce((sum, value) => sum + value, 0) / sleepValues.length).toFixed(1)} hrs`
    : (currentLang === "es" ? "Sin datos" : "No data");
  const staleCount = rowsWithEntry.filter((row) => getCoachJournalState(row.name) === "stale").length;
  if (currentLang === "es") {
    return [
      `Entradas de readiness: ${rowsWithEntry.length}/${athletes.length}`,
      `Energia promedio: ${avgEnergy}`,
      `Sueno promedio: ${avgSleep}`,
      staleCount ? `Journals atrasados: ${staleCount}` : "Todos los journals recientes estan al dia"
    ];
  }
  return [
    `Readiness entries: ${rowsWithEntry.length}/${athletes.length}`,
    `Average energy: ${avgEnergy}`,
    `Average sleep: ${avgSleep}`,
    staleCount ? `Stale journals: ${staleCount}` : "All recent journals are up to date"
  ];
}

function getJournalFlagsData() {
  const athletes = getAthletesData();
  if (!athletes.length) {
    return [currentLang === "es" ? "No hay riesgos porque no hay atletas en el roster." : "No risk flags because there are no athletes in the roster."];
  }
  const rows = getJournalAthletesData();
  const rowsWithEntry = rows.filter((row) => row.hasEntry);
  if (!rowsWithEntry.length) {
    return [currentLang === "es" ? "Sin datos de journal todavia." : "No journal data yet."];
  }
  const highSorenessCount = rowsWithEntry.filter((row) => parseScoreValue(row.soreness) >= 4).length;
  const lowSleepCount = rowsWithEntry.filter((row) => {
    const hours = parseHoursValue(row.sleep);
    return hours > 0 && hours < 6.5;
  }).length;
  const staleCount = rowsWithEntry.filter((row) => getCoachJournalState(row.name) === "stale").length;
  const noDataCount = rows.filter((row) => !row.hasEntry).length;
  const flags = [];
  if (currentLang === "es") {
    if (highSorenessCount) flags.push(`${highSorenessCount} atleta(s) con dolor 4+`);
    if (lowSleepCount) flags.push(`${lowSleepCount} atleta(s) con sueno bajo (< 6.5h)`);
    if (staleCount) flags.push(`${staleCount} atleta(s) con journal atrasado`);
    if (noDataCount) flags.push(`${noDataCount} atleta(s) sin entradas de readiness`);
    return flags.length ? flags : ["Sin banderas de riesgo activas."];
  }
  if (highSorenessCount) flags.push(`${highSorenessCount} athlete(s) at soreness 4+`);
  if (lowSleepCount) flags.push(`${lowSleepCount} athlete(s) with low sleep (< 6.5h)`);
  if (staleCount) flags.push(`${staleCount} athlete(s) with stale journal updates`);
  if (noDataCount) flags.push(`${noDataCount} athlete(s) without readiness entries`);
  return flags.length ? flags : ["No active readiness flags."];
}

function getJournalAthletesData(selectedAthleteName = getSelectedCoachAthleteName()) {
  const athletes = getAthletesData();
  if (!athletes.length) return [];
  const selectedKey = normalizeName(selectedAthleteName);
  return athletes
    .map((athlete) => {
      const latest = getLatestCoachJournalRecord(athlete.name);
      const updatedScore = Date.parse(
        latest?.updatedAt
        || latest?.createdAt
        || (isDateKey(latest?.entryDate) ? `${latest.entryDate}T23:59:59` : "")
      ) || 0;
      return {
        name: athlete.name,
        sleep: latest?.sleep || "",
        energy: latest?.energy || "",
        soreness: latest?.soreness || "",
        mood: latest?.mood || "",
        weight: latest?.weight || "",
        note: latest?.note || "",
        entryDate: latest?.entryDate || "",
        hasEntry: Boolean(latest),
        updatedScore
      };
    })
    .sort((left, right) => {
      const leftSelected = normalizeName(left.name) === selectedKey ? 1 : 0;
      const rightSelected = normalizeName(right.name) === selectedKey ? 1 : 0;
      if (leftSelected !== rightSelected) return rightSelected - leftSelected;
      const leftHasEntry = left.hasEntry ? 1 : 0;
      const rightHasEntry = right.hasEntry ? 1 : 0;
      if (leftHasEntry !== rightHasEntry) return rightHasEntry - leftHasEntry;
      if (left.updatedScore !== right.updatedScore) return right.updatedScore - left.updatedScore;
      return left.name.localeCompare(right.name);
    })
    .map(({ updatedScore, ...row }) => row);
}

