function getCurrentAppRouteName() {
  const path = String(window.location?.pathname || "").replace(/\/+$/, "");
  const last = path.split("/").filter(Boolean).pop() || "";
  return APP_ROUTE_NAMES.includes(last) ? last : "";
}

function resolveRouteTargetForView(target) {
  if (!target || typeof target !== "object") return String(target || "").trim();
  const view = currentView || "athlete";
  return String(target[view] || target[normalizeAuthRole(getProfile()?.role)] || target.athlete || "").trim();
}

function resolveAppTabFromRoutePath() {
  const route = getCurrentAppRouteName();
  if (!route) return "";
  return resolveRouteTargetForView(APP_ROUTE_TO_TAB[route]);
}

function getAppBasePathForRoutes() {
  const path = String(window.location?.pathname || "/");
  const normalizedPath = path.endsWith("/") ? path : path.replace(/[^/]*$/, "");
  const currentRoute = getCurrentAppRouteName();
  if (currentRoute) {
    const marker = `/${currentRoute}/`;
    const markerIndex = `${path}/`.lastIndexOf(marker);
    if (markerIndex >= 0) return `${path.slice(0, markerIndex + 1)}`;
  }
  if (path.endsWith("/index.html")) return path.slice(0, -"index.html".length);
  return normalizedPath || "/";
}

function getRouteUrlForTab(tabKey) {
  const route = APP_ROUTE_BY_TAB[tabKey] || "";
  if (!route) return "";
  const basePath = getAppBasePathForRoutes();
  return `${basePath}${route}/`;
}

function syncBrowserRouteForTab(tabKey, { replace = false } = {}) {
  if (isApplyingBrowserRoute || !appDomainRenderReady || !window.history?.pushState) return;
  const nextUrl = getRouteUrlForTab(tabKey);
  if (!nextUrl || nextUrl === window.location.pathname) return;
  const method = replace ? "replaceState" : "pushState";
  window.history[method]({ tab: tabKey }, "", nextUrl);
}

function buildMessagesWindowUrl(contactUid = "") {
  const base = `${window.location.origin}${window.location.pathname}`;
  const params = new URLSearchParams();
  params.set("openTab", "messages");
  const safeContactUid = normalizeUid(contactUid);
  if (safeContactUid) {
    params.set("contactUid", safeContactUid);
  }
  return `${base}?${params.toString()}`;
}

async function applyLaunchConfig() {
  if (launchConfigApplied) return;
  launchConfigApplied = true;
  if (APP_LAUNCH_CONFIG.competitionShareId) {
    await openPublicCompetitionShare(APP_LAUNCH_CONFIG.competitionShareId);
    return;
  }
  if (!APP_LAUNCH_CONFIG.tab) return;
  await enterPlansCoachGuestIfNeeded();
  await showTab(APP_LAUNCH_CONFIG.tab);
  if (APP_LAUNCH_CONFIG.contactUid) {
    await openDirectMessageThreadWithRetry(APP_LAUNCH_CONFIG.contactUid);
  }
}

function isCoachRouteContext() {
  return currentView === "coach" || currentView === "admin";
}

function resolveRouteTabRequest(name) {
  if (!isCoachRouteContext()) {
    return { tab: name, focusPanel: "" };
  }
  if (COACH_ROUTE_PANELS[name]) {
    return { tab: name, focusPanel: COACH_ROUTE_DEFAULT_PANEL[name] || "" };
  }
  const route = COACH_ROUTE_BY_PANEL[name];
  if (route) {
    return { tab: route, focusPanel: name };
  }
  return { tab: name, focusPanel: "" };
}

function resolveTabPanelForCurrentView(tabKey) {
  const safeTabKey = String(tabKey || "").trim().toLowerCase();
  if (safeTabKey === "plans" && currentView === "athlete") {
    return "training";
  }
  return safeTabKey;
}

function shouldReloadForPrunedRoutePanels(tabKey, visiblePanels = []) {
  if (!window.WPL_ROUTED_PANEL_PRUNING) return false;
  if (!Array.isArray(visiblePanels) || !visiblePanels.length) return false;
  const missingPanel = visiblePanels.some((panelKey) => {
    const el = panels[panelKey];
    return !el || !document.body.contains(el);
  });
  if (!missingPanel) return false;
  const nextUrl = getRouteUrlForTab(tabKey);
  if (!nextUrl) return false;
  try {
    return new URL(nextUrl, window.location.origin).pathname !== window.location.pathname;
  } catch {
    return nextUrl !== window.location.pathname;
  }
}

async function showTab(name) {
  const resolved = resolveRouteTabRequest(name);
  if (athleteCalendarActionModal && resolved.tab !== "calendar") {
    closeAthleteCalendarActionModal();
  }
  if (questionnaireReminderModal && !questionnaireReminderModal.classList.contains("hidden") && resolved.tab !== "athlete-profile") {
    hideQuestionnaireReminderModal();
  }
  const targetBtn = tabBtns.find((btn) => btn.dataset.tab === resolved.tab && !btn.hidden);
  const fallbackTab = tabBtns.find((btn) => !btn.hidden)?.dataset.tab;
  const hasContent = Boolean(COACH_ROUTE_PANELS[resolved.tab] || panels[resolved.tab]);
  const safeTab = targetBtn ? resolved.tab : (hasContent ? resolved.tab : (fallbackTab || resolved.tab));
  if (safeTab !== "tournament-view") {
    lastTournamentReturnTab = safeTab;
  }
  const primaryPanel = resolveTabPanelForCurrentView(safeTab);
  const visiblePanels = COACH_ROUTE_PANELS[safeTab] || [primaryPanel];
  if (shouldReloadForPrunedRoutePanels(safeTab, visiblePanels)) {
    const nextUrl = getRouteUrlForTab(safeTab);
    if (nextUrl) window.location.assign(nextUrl);
    return;
  }
  const focusPanel = visiblePanels.includes(resolved.focusPanel)
    ? resolved.focusPanel
    : (COACH_ROUTE_DEFAULT_PANEL[safeTab] || "");
  currentTopTab = safeTab;
  currentFocusedPanel = focusPanel || safeTab;
  syncBrowserRouteForTab(safeTab);

  tabBtns.forEach((b) => b.classList.toggle("active", b.dataset.tab === safeTab));
  Object.entries(panels).forEach(([k, el]) => {
    if (!el) return;
    const orderIndex = visiblePanels.indexOf(k);
    el.style.order = orderIndex >= 0 ? String(orderIndex + 1) : "999";
    el.classList.toggle("hidden", orderIndex === -1);
  });

  if (appDomainRenderReady && visiblePanels.includes("plans")) {
    try {
      await ensureCoachPlannerDomainLoaded();
    } catch (error) {
      console.warn("Coach planner domain failed to load.", error);
      toast(pickCopy({
        en: "Planner is still loading. Try opening Plans again.",
        es: "El planificador todavia esta cargando. Intenta abrir Planes otra vez."
      }));
    }
    if (!hasModernCoachPlanner() && templatePdfBytes) {
      await generateFilledPdf({ download: false });
    }
  }

  if (visiblePanels.includes("coach-match") && coachMatchSelect?.value) {
    renderCoachMatchView(coachMatchSelect.value);
  }

  if (visiblePanels.includes("competition-preview")) {
    const profile = getProfile();
    const competitionProfile = isCoachRouteContext()
      ? getSelectedCoachAthleteRecord()
      : (isAthleteRole(profile?.role) ? (getAthletePortalLinkedAthlete() || profile) : profile);
    renderCompetitionPreview(competitionProfile);
  }

  if (visiblePanels.includes("tournament-view")) {
    renderTournamentView();
  }

  if (visiblePanels.includes("athlete-profile")) {
    renderAthleteProfileFormMode();
  }

  if (visiblePanels.includes("calendar-manager")) {
    renderCalendarManager();
  }

  if (appDomainRenderReady && visiblePanels.includes("media")) {
    ensureMediaDomainSyncNow().catch((err) => {
      console.warn("Failed to open media domain", err);
      renderMedia();
    });
  }

  if (appDomainRenderReady && visiblePanels.includes("dashboard")) {
    renderDashboard();
    renderCoachProfile();
  }

  if (appDomainRenderReady && visiblePanels.includes("assignments")) {
    renderCoachAssignments();
    renderCompletionTracking();
  }

  if (appDomainRenderReady && visiblePanels.includes("athletes")) {
    renderAthleteManagement();
    renderAthleteNotes();
  }

  if (appDomainRenderReady && visiblePanels.includes("journal-monitor")) {
    renderJournalMonitor();
  }

  if (appDomainRenderReady && visiblePanels.includes("permissions")) {
    maybeRefreshAdminUsers();
  }

  if (appDomainRenderReady && visiblePanels.includes("messages")) {
    prepareMessagesDomainForOpen()
      .then(() => startMessagesRealtimeSync({ forceRefreshContacts: true }))
      .catch((err) => {
        console.warn("Failed to open messages tab", err);
        reportMessagesDomainOpenFailure();
        renderMessages();
      });
  }

  resetViewportToTop();
}

function flashActionTarget(element) {
  if (!element) return;
  element.classList.remove("panel-action-flash");
  void element.offsetWidth;
  element.classList.add("panel-action-flash");
  window.setTimeout(() => {
    element.classList.remove("panel-action-flash");
  }, 1400);
}

