function createDefaultTrainingBuilderState() {
  return {
    templates: [],
    athletes: [],
    library: [],
    blocks: [],
    week: [],
    brandTitle: "",
    dashboardTitle: "",
    practiceTitle: "",
    practiceDescription: "",
    selectedTemplate: 0,
    selectedAthlete: 0,
    selectedLibrary: 0,
    selectedDay: 0
  };
}

function cloneTrainingBuilderState(state = createDefaultTrainingBuilderState()) {
  return {
    ...state,
    templates: (state.templates || []).map((entry) => ({ ...entry })),
    athletes: (state.athletes || []).map((entry) => ({ ...entry })),
    library: (state.library || []).map((entry) => ({ ...entry })),
    blocks: (state.blocks || []).map((entry) => ({ ...entry })),
    week: (state.week || []).map((entry) => ({ ...entry }))
  };
}

function ensureTrainingBuilderTemplateId(template = {}, fallbackIndex = 0) {
  if (!template || typeof template !== "object") {
    return `tb-template-${Date.now().toString(36)}-${fallbackIndex}`;
  }
  const safeExistingId = String(template.id || "").trim();
  if (safeExistingId) return safeExistingId;
  const generated = `tb-template-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}-${fallbackIndex}`;
  template.id = generated;
  return generated;
}

function isTrainingTemplatePendingDelete(template = {}) {
  const templateId = ensureTrainingBuilderTemplateId(template);
  return Boolean(pendingTemplateDeleteById[templateId] || isSwipeDeletePending(`template:${templateId}`));
}

function ensureTrainingBuilderSelectionVisible() {
  if (!Array.isArray(trainingBuilderState.templates) || !trainingBuilderState.templates.length) {
    trainingBuilderState.selectedTemplate = 0;
    return;
  }
  trainingBuilderState.templates.forEach((template, index) => {
    ensureTrainingBuilderTemplateId(template, index);
  });
  const selectedIndex = normalizeTrainingBuilderIndex(trainingBuilderState.selectedTemplate, trainingBuilderState.templates);
  const selectedTemplate = trainingBuilderState.templates[selectedIndex] || null;
  if (selectedTemplate && !isTrainingTemplatePendingDelete(selectedTemplate)) {
    trainingBuilderState.selectedTemplate = selectedIndex;
    return;
  }
  const nextIndex = trainingBuilderState.templates.findIndex((template) => !isTrainingTemplatePendingDelete(template));
  trainingBuilderState.selectedTemplate = nextIndex >= 0 ? nextIndex : selectedIndex;
}

function normalizeTrainingBuilderIndex(index, list = []) {
  const size = Array.isArray(list) ? list.length : 0;
  if (!size) return 0;
  const parsed = Number(index);
  if (!Number.isFinite(parsed)) return 0;
  return Math.max(0, Math.min(size - 1, Math.floor(parsed)));
}

function loadTrainingBuilderState() {
  const fallback = createDefaultTrainingBuilderState();
  if (hasModernCoachPlanner()) return fallback;
  try {
    const raw = localStorage.getItem(TRAINING_BUILDER_STORAGE_KEY);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return fallback;
    const merged = {
      ...fallback,
      ...parsed,
      templates: Array.isArray(parsed.templates) && parsed.templates.length ? parsed.templates : fallback.templates,
      athletes: Array.isArray(parsed.athletes) && parsed.athletes.length ? parsed.athletes : fallback.athletes,
      library: Array.isArray(parsed.library) && parsed.library.length ? parsed.library : fallback.library,
      blocks: Array.isArray(parsed.blocks) && parsed.blocks.length ? parsed.blocks : fallback.blocks,
      week: Array.isArray(parsed.week) && parsed.week.length ? parsed.week : fallback.week
    };
    merged.selectedTemplate = normalizeTrainingBuilderIndex(merged.selectedTemplate, merged.templates);
    merged.selectedAthlete = normalizeTrainingBuilderIndex(merged.selectedAthlete, merged.athletes);
    merged.selectedLibrary = normalizeTrainingBuilderIndex(merged.selectedLibrary, merged.library);
    merged.selectedDay = normalizeTrainingBuilderIndex(merged.selectedDay, merged.week);
    merged.templates.forEach((template, index) => {
      ensureTrainingBuilderTemplateId(template, index);
    });
    return merged;
  } catch {
    return fallback;
  }
}

let trainingBuilderState = loadTrainingBuilderState();

function persistTrainingBuilderState() {
  try {
    localStorage.setItem(TRAINING_BUILDER_STORAGE_KEY, JSON.stringify(trainingBuilderState));
  } catch {
    // ignore persistence errors
  }
}

function getTrainingBuilderTotalMinutes() {
  return (trainingBuilderState.blocks || []).reduce((sum, block) => {
    const parsed = parseInt(String(block?.time || "").replace(/[^0-9]/g, ""), 10);
    return sum + (Number.isFinite(parsed) ? parsed : 0);
  }, 0);
}

function updateTrainingBuilderStatus(message = "", { error = false } = {}) {
  if (!tbStatus) return;
  tbStatus.textContent = message;
  tbStatus.dataset.state = error ? "error" : "";
}

function renderTrainingBuilderTemplateDetails() {
  ensureTrainingBuilderSelectionVisible();
  const current = trainingBuilderState.templates[trainingBuilderState.selectedTemplate] || null;
  if (!tbTemplateNameInput || !tbTemplateBlocksInput || !tbTemplateDurationInput || !tbTemplateLevelInput) return;
  tbTemplateNameInput.value = current?.name || "";
  tbTemplateBlocksInput.value = current?.blocks != null ? String(current.blocks) : "";
  tbTemplateDurationInput.value = current?.duration || "";
  tbTemplateLevelInput.value = current?.level || "";
}

function queueTrainingBuilderTemplateSwipeDelete(template = null) {
  if (!template || typeof template !== "object") return;
  if (trainingBuilderState.templates.length <= 1) {
    toast(pickCopy({
      en: "Keep at least one template in the builder.",
      es: "Mantiene al menos una plantilla en el constructor."
    }));
    return;
  }
  const templateId = ensureTrainingBuilderTemplateId(template);
  const swipeKey = `template:${templateId}`;
  if (isSwipeDeletePending(swipeKey)) return;
  const safeTemplateName = String(template.name || "").trim() || (currentLang === "es" ? "Plantilla" : "Template");
  const scheduled = scheduleSwipeDelete({
    key: swipeKey,
    labelCopy: {
      en: `${safeTemplateName} removed`,
      es: `${safeTemplateName} eliminada`
    },
    onCommit: async () => {
      pendingTemplateDeleteById = { ...pendingTemplateDeleteById };
      delete pendingTemplateDeleteById[templateId];
      trainingBuilderState.templates = trainingBuilderState.templates.filter((entry) => (
        ensureTrainingBuilderTemplateId(entry) !== templateId
      ));
      if (!trainingBuilderState.templates.length) {
        trainingBuilderState.templates = [{ id: "tb-template-default", name: "New Template", blocks: 4, duration: "60 min", level: "All Levels" }];
      }
      ensureTrainingBuilderSelectionVisible();
      persistTrainingBuilderState();
      renderTrainingBuilder();
    },
    onUndo: () => {
      pendingTemplateDeleteById = { ...pendingTemplateDeleteById };
      delete pendingTemplateDeleteById[templateId];
      ensureTrainingBuilderSelectionVisible();
      renderTrainingBuilder();
    },
    onError: () => {
      pendingTemplateDeleteById = { ...pendingTemplateDeleteById };
      delete pendingTemplateDeleteById[templateId];
      renderTrainingBuilder();
      toast(pickCopy({
        en: "Could not delete template.",
        es: "No se pudo eliminar la plantilla."
      }));
    }
  });
  if (!scheduled) return;
  pendingTemplateDeleteById = {
    ...pendingTemplateDeleteById,
    [templateId]: true
  };
  ensureTrainingBuilderSelectionVisible();
  renderTrainingBuilder();
}

function renderTrainingBuilderLists() {
  if (tbTemplateList) {
    ensureTrainingBuilderSelectionVisible();
    tbTemplateList.innerHTML = "";
    trainingBuilderState.templates.forEach((template, index) => {
      const templateId = ensureTrainingBuilderTemplateId(template, index);
      if (isTrainingTemplatePendingDelete(template)) return;
      const item = document.createElement("button");
      item.type = "button";
      item.className = `training-builder-item${index === trainingBuilderState.selectedTemplate ? " active" : ""}`;
      item.dataset.templateId = templateId;
      item.innerHTML = `<strong>${escapeHtml(template.name || "Template")}</strong><small>${escapeHtml(`${template.blocks || 0} blocks • ${template.duration || "0 min"} • ${template.level || "-"}`)}</small>`;
      item.addEventListener("click", () => {
        trainingBuilderState.selectedTemplate = index;
        renderTrainingBuilder();
      });
      bindSwipeDeleteGesture(item, {
        key: `template:${templateId}`,
        onSwipeDelete: () => {
          queueTrainingBuilderTemplateSwipeDelete(template);
        }
      });
      tbTemplateList.appendChild(item);
    });
    if (!tbTemplateList.children.length) {
      const empty = document.createElement("div");
      empty.className = "small muted";
      empty.textContent = currentLang === "es"
        ? "No hay plantillas visibles."
        : "No visible templates.";
      tbTemplateList.appendChild(empty);
    }
  }

  if (tbAthleteList) {
    tbAthleteList.innerHTML = "";
    trainingBuilderState.athletes.forEach((athlete, index) => {
      const item = document.createElement("div");
      item.className = `training-builder-item${index === trainingBuilderState.selectedAthlete ? " active" : ""}`;
      item.innerHTML = `<strong>${escapeHtml(athlete.name || "Athlete")}</strong><small>${escapeHtml(`${athlete.status || "-"} • ${athlete.progress || 0}%`)}</small><div class="training-builder-progress"><span style="width:${Math.max(0, Math.min(100, Number(athlete.progress || 0)))}%"></span></div>`;
      item.addEventListener("click", () => {
        trainingBuilderState.selectedAthlete = index;
        renderTrainingBuilder();
      });
      tbAthleteList.appendChild(item);
    });
  }

  if (tbLibraryList) {
    tbLibraryList.innerHTML = "";
    trainingBuilderState.library.forEach((entry, index) => {
      const item = document.createElement("div");
      item.className = `training-builder-item${index === trainingBuilderState.selectedLibrary ? " active" : ""}`;
      item.innerHTML = `<strong>${escapeHtml(entry.title || "Library item")}</strong><small>${escapeHtml(`${entry.type || "Item"} • ${entry.tag || "-"}`)}</small>`;
      item.addEventListener("click", () => {
        trainingBuilderState.selectedLibrary = index;
        renderTrainingBuilder();
      });
      tbLibraryList.appendChild(item);
    });
  }

  if (tbWeekList) {
    tbWeekList.innerHTML = "";
    trainingBuilderState.week.forEach((entry, index) => {
      const wrap = document.createElement("div");
      wrap.className = `training-builder-item${index === trainingBuilderState.selectedDay ? " active" : ""}`;
      wrap.innerHTML = `
        <strong>${escapeHtml(entry.day || "Day")} • ${escapeHtml(entry.title || "-")}</strong>
        <small>${escapeHtml(entry.note || "")}</small>
      `;
      const row = document.createElement("div");
      row.className = "training-builder-block-grid";
      row.innerHTML = `
        <input type="text" data-field="day" value="${escapeHtml(entry.day || "")}">
        <input type="text" data-field="title" value="${escapeHtml(entry.title || "")}">
        <input type="text" data-field="note" value="${escapeHtml(entry.note || "")}">
      `;
      row.querySelectorAll("input").forEach((input) => {
        input.addEventListener("input", () => {
          trainingBuilderState.week[index][input.dataset.field] = input.value;
          trainingBuilderState.selectedDay = index;
          persistTrainingBuilderState();
          renderTrainingBuilder();
        });
      });
      wrap.appendChild(row);
      wrap.addEventListener("click", () => {
        trainingBuilderState.selectedDay = index;
        renderTrainingBuilder();
      });
      tbWeekList.appendChild(wrap);
    });
  }
}

function renderTrainingBuilderBlocks() {
  if (!tbBlockList) return;
  tbBlockList.innerHTML = "";
  trainingBuilderState.blocks.forEach((block, index) => {
    const card = document.createElement("article");
    card.className = "training-builder-block";
    card.innerHTML = `
      <div class="training-builder-block-top">
        <strong>${currentLang === "es" ? `Bloque ${index + 1}` : `Block ${index + 1}`}</strong>
        <button type="button" class="ghost" data-remove-index="${index}">${currentLang === "es" ? "Eliminar" : "Remove"}</button>
      </div>
      <div class="training-builder-block-grid">
        <input type="text" data-field="phase" value="${escapeHtml(block.phase || "")}">
        <input type="text" data-field="title" value="${escapeHtml(block.title || "")}">
        <input type="text" data-field="time" value="${escapeHtml(block.time || "")}">
      </div>
      <textarea rows="2" data-field="note">${escapeHtml(block.note || "")}</textarea>
    `;
    card.querySelectorAll("input, textarea").forEach((field) => {
      field.addEventListener("input", () => {
        const key = field.dataset.field;
        trainingBuilderState.blocks[index][key] = field.value;
        persistTrainingBuilderState();
        renderTrainingBuilder();
      });
    });
    card.querySelector("[data-remove-index]")?.addEventListener("click", () => {
      trainingBuilderState.blocks = trainingBuilderState.blocks.filter((_, itemIndex) => itemIndex !== index);
      if (!trainingBuilderState.blocks.length) {
        trainingBuilderState.blocks = [{ phase: "Technique", title: "New Block", time: "10 min", note: "Coach note here." }];
      }
      persistTrainingBuilderState();
      renderTrainingBuilder();
    });
    tbBlockList.appendChild(card);
  });
}

function renderTrainingBuilder() {
  if (!tbBrandTitleInput || !tbDashboardTitleInput || !tbPracticeTitleInput || !tbPracticeDescriptionInput) return;
  ensureTrainingBuilderSelectionVisible();
  if (tbSectionTitle) tbSectionTitle.textContent = currentLang === "es" ? "Constructor de entrenamiento" : "Practice Builder";
  if (tbSectionSubtitle) {
    tbSectionSubtitle.textContent = currentLang === "es"
      ? "Arma la practica con bloques reutilizables, plantillas, progreso de atletas y vista semanal."
      : "Build practice with reusable blocks, templates, athlete completion, and week view.";
  }
  if (tbApplyToPlanBtn) {
    tbApplyToPlanBtn.textContent = currentLang === "es" ? "Aplicar a Create Plan" : "Apply to Create Plan";
  }
  tbBrandTitleInput.value = trainingBuilderState.brandTitle || "";
  tbDashboardTitleInput.value = trainingBuilderState.dashboardTitle || "";
  tbPracticeTitleInput.value = trainingBuilderState.practiceTitle || "";
  tbPracticeDescriptionInput.value = trainingBuilderState.practiceDescription || "";
  renderTrainingBuilderTemplateDetails();
  renderTrainingBuilderLists();
  renderTrainingBuilderBlocks();
  if (tbBlockTotalMinutes) {
    const total = getTrainingBuilderTotalMinutes();
    tbBlockTotalMinutes.textContent = currentLang === "es"
      ? `Tiempo total estimado: ${total} min`
      : `Estimated total time: ${total} min`;
  }
}

function getTrainingBuilderPayload() {
  return cloneTrainingBuilderState(trainingBuilderState);
}

function applyTrainingBuilderToPlan() {
  if (planTitleInput) planTitleInput.value = String(trainingBuilderState.practiceTitle || "").trim();
  if (planFocusInput) planFocusInput.value = String(trainingBuilderState.practiceDescription || "").trim();
  const blockSummary = trainingBuilderState.blocks
    .map((block) => `${block.phase || "Block"} - ${block.title || ""} (${block.time || ""})${block.note ? `: ${block.note}` : ""}`.trim())
    .filter(Boolean)
    .join("\n");
  if (planNotesInput) planNotesInput.value = blockSummary;
  if (planMonthlyNotes) {
    planMonthlyNotes.value = trainingBuilderState.week
      .map((entry) => `${entry.day || ""}: ${entry.title || ""}${entry.note ? ` - ${entry.note}` : ""}`.trim())
      .filter(Boolean)
      .join("\n");
  }
  clearPlanSaveStatus();
  updateTrainingBuilderStatus(
    currentLang === "es" ? "Contenido aplicado a Create Plan." : "Builder content applied to Create Plan."
  );
}

function bindTrainingBuilderEvents() {
  if (trainingBuilderBound) return;
  const simpleFields = [
    [tbBrandTitleInput, "brandTitle"],
    [tbDashboardTitleInput, "dashboardTitle"],
    [tbPracticeTitleInput, "practiceTitle"],
    [tbPracticeDescriptionInput, "practiceDescription"]
  ];
  simpleFields.forEach(([input, key]) => {
    if (!input) return;
    input.addEventListener("input", () => {
      trainingBuilderState[key] = input.value;
      persistTrainingBuilderState();
    });
  });

  const templateFields = [
    [tbTemplateNameInput, "name"],
    [tbTemplateBlocksInput, "blocks"],
    [tbTemplateDurationInput, "duration"],
    [tbTemplateLevelInput, "level"]
  ];
  templateFields.forEach(([input, key]) => {
    if (!input) return;
    input.addEventListener("input", () => {
      const index = normalizeTrainingBuilderIndex(trainingBuilderState.selectedTemplate, trainingBuilderState.templates);
      if (!trainingBuilderState.templates[index]) return;
      trainingBuilderState.templates[index][key] = key === "blocks" ? Number(input.value || 0) : input.value;
      persistTrainingBuilderState();
      renderTrainingBuilder();
    });
  });

  tbTemplateAddBtn?.addEventListener("click", () => {
    trainingBuilderState.templates.push({
      id: `tb-template-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
      name: "New Template",
      blocks: 4,
      duration: "60 min",
      level: "All Levels"
    });
    trainingBuilderState.selectedTemplate = trainingBuilderState.templates.length - 1;
    persistTrainingBuilderState();
    renderTrainingBuilder();
  });

  tbTemplateRemoveBtn?.addEventListener("click", () => {
    if (trainingBuilderState.templates.length <= 1) return;
    const selectedTemplate = trainingBuilderState.templates[normalizeTrainingBuilderIndex(trainingBuilderState.selectedTemplate, trainingBuilderState.templates)] || null;
    queueTrainingBuilderTemplateSwipeDelete(selectedTemplate);
  });

  tbBlockAddBtn?.addEventListener("click", () => {
    trainingBuilderState.blocks.push({ phase: "New Phase", title: "New Block", time: "10 min", note: "Coach note here." });
    persistTrainingBuilderState();
    renderTrainingBuilder();
  });

  tbApplyToPlanBtn?.addEventListener("click", () => {
    applyTrainingBuilderToPlan();
  });
  trainingBuilderBound = true;
}

function initializeTrainingBuilder() {
  if (!tbBlockList) return;
  bindTrainingBuilderEvents();
  renderTrainingBuilder();
}

const PLAN_SOURCE_LIBRARY = {
  scratch: {
    label: { en: "From scratch", es: "Desde cero" },
    summary: {
      en: "Starting from scratch. Build the plan structure directly in this screen.",
      es: "Empiezas desde cero. Construye el plan directamente en esta pantalla."
    },
    selectLabel: { en: "", es: "" },
    options: []
  },
  duplicate: {
    label: { en: "Duplicate previous", es: "Duplicar anterior" },
    summary: {
      en: "Start from a recent plan and adjust dates, volume, or targets.",
      es: "Parte de un plan reciente y ajusta fechas, volumen o destinatarios."
    },
    selectLabel: { en: "Previous plan", es: "Plan anterior" },
    options: []
  }
};

function getPlanScopeLabel() {
  const scopeCopy = {
    day: { en: "Daily plan", es: "Plan diario" },
    week: { en: "Weekly plan", es: "Plan semanal" },
    month: { en: "Monthly plan", es: "Plan mensual" },
    season: { en: "Season plan", es: "Plan de temporada" }
  };
  return pickCopy(scopeCopy[planRangeType] || scopeCopy.day);
}

function getPlanTargetSummary() {
  if (planAssignMode === "group") {
    const group = getCoachGroupRecords().find((item) => item.id === planAssignedGroup) || getCoachGroupRecords()[0];
    const groupName = group?.name || (currentLang === "es" ? "grupo" : "group");
    return currentLang === "es"
      ? `Asignado a ${groupName}`
      : `Assigned to ${groupName}`;
  }
  if (!planAssignedAthletes.length) {
    return currentLang === "es" ? "Sin destino seleccionado" : "No target selected yet";
  }
  if (planAssignMode === "single") {
    return currentLang === "es"
      ? `Asignado a ${planAssignedAthletes[0]}`
      : `Assigned to ${planAssignedAthletes[0]}`;
  }
  return currentLang === "es"
    ? `Asignado a ${planAssignedAthletes.length} atletas`
    : `Assigned to ${planAssignedAthletes.length} athletes`;
}

function getPlanSourceConfig(mode = planSourceMode) {
  const source = PLAN_SOURCE_LIBRARY[mode] || PLAN_SOURCE_LIBRARY.scratch;
  if (mode === "duplicate") {
    return { ...source, options: getDuplicatePlanOptionsForType(planRangeType) };
  }
  return { ...source, options: [] };
}

function ensurePlanSourceSelection(mode = planSourceMode) {
  const source = getPlanSourceConfig(mode);
  if (!source.options.length) {
    planSourceSelection = "";
    return;
  }
  if (!source.options.some((option) => option.value === planSourceSelection)) {
    planSourceSelection = source.options[0]?.value || "";
  }
}

function getSelectedPlanSourceRecord() {
  const source = getPlanSourceConfig(planSourceMode);
  return source.options.find((option) => option.value === planSourceSelection)?.record || null;
}

function resolveCoachPlanSaveTargetId() {
  const activeEditingId = String(currentEditingCoachPlanId || "").trim();
  if (activeEditingId) {
    return { planId: activeEditingId, canceled: false, error: "" };
  }
  if (planSourceMode !== "duplicate") {
    return { planId: "", canceled: false, error: "" };
  }
  const sourceRecord = getSelectedPlanSourceRecord();
  const sourcePlanId = String(sourceRecord?.id || "").trim();
  if (!sourcePlanId) {
    return { planId: "", canceled: false, error: "" };
  }

  const loadedPlanName = String(sourceRecord?.title || sourceRecord?.name || "").trim()
    || pickCopy({ en: "loaded plan", es: "plan cargado" });
  const promptMessage = pickCopy({
    en: `You loaded "${loadedPlanName}".\nHow do you want to save?\n\n1) Update loaded plan\n2) Save as new plan (keep original)\n\nType 1 or 2. Press Cancel to stop.`,
    es: `Cargaste "${loadedPlanName}".\nComo quieres guardar?\n\n1) Actualizar plan cargado\n2) Guardar como plan nuevo (mantener original)\n\nEscribe 1 o 2. Pulsa Cancelar para detener.`
  });

  if (typeof window !== "undefined" && typeof window.prompt === "function") {
    const rawChoice = window.prompt(promptMessage, "2");
    if (rawChoice === null) {
      return { planId: "", canceled: true, error: "" };
    }
    const normalizedChoice = String(rawChoice || "").trim().toLowerCase();
    if (["1", "update", "overwrite", "actualizar", "sobrescribir"].includes(normalizedChoice)) {
      return { planId: sourcePlanId, canceled: false, error: "" };
    }
    if (["2", "new", "save new", "nuevo", "guardar nuevo"].includes(normalizedChoice)) {
      return { planId: "", canceled: false, error: "" };
    }
    return {
      planId: "",
      canceled: true,
      error: pickCopy({
        en: "Save canceled. Use 1 to update the loaded plan or 2 to save a new one.",
        es: "Guardado cancelado. Usa 1 para actualizar el plan cargado o 2 para guardar uno nuevo."
      })
    };
  }

  if (typeof window !== "undefined" && typeof window.confirm === "function") {
    const overwriteLoaded = window.confirm(
      `${promptMessage}\n\n${pickCopy({
        en: "OK = Update loaded plan | Cancel = Save as new",
        es: "Aceptar = Actualizar plan cargado | Cancelar = Guardar como nuevo"
      })}`
    );
    return { planId: overwriteLoaded ? sourcePlanId : "", canceled: false, error: "" };
  }

  return { planId: "", canceled: false, error: "" };
}

function getPlanAssignGroupOptions() {
  return [
    ...getCoachGroupRecords().map((group) => ({
      value: group.id,
      label: { en: group.name, es: group.name },
      record: group
    })),
    {
      value: "__create_new_group__",
      label: {
        en: "+ Create New Group",
        es: "+ Crear grupo nuevo"
      }
    }
  ];
}

function setPlanSaveStatusMessage(message, { error = false } = {}) {
  if (!planSaveStatus) return;
  planSaveStatus.textContent = message || "";
  planSaveStatus.classList.toggle("error", error);
}

function clearPlanSaveStatus() {
  setPlanSaveStatusMessage("");
}

function syncPlanSaveButtons() {
  if (hasModernCoachPlanner()) return;
  const savingLabel = pickCopy({ en: "Saving...", es: "Guardando..." });
  if (savePlanBtn) {
    savePlanBtn.disabled = coachPlanSyncState.saving;
    savePlanBtn.textContent = coachPlanSyncState.saving
      ? savingLabel
      : pickCopy({ en: "Save Plan", es: "Guardar plan" });
  }
  if (savePlanAssignBtn) {
    savePlanAssignBtn.disabled = coachPlanSyncState.saving;
    savePlanAssignBtn.textContent = coachPlanSyncState.saving
      ? savingLabel
      : pickCopy({ en: "Save Plan + Assign", es: "Guardar plan + asignar" });
  }
}

function updatePlanQuickSummary() {
  if (!planQuickSummary) return;
  const source = PLAN_SOURCE_LIBRARY[planSourceMode];
  const sourceLabel = pickCopy(source?.label || PLAN_SOURCE_LIBRARY.scratch.label);
  planQuickSummary.textContent = `${getPlanScopeLabel()} • ${sourceLabel} • ${getPlanTargetSummary()}`;
  if (planAssignSummary) {
    planAssignSummary.textContent = getPlanTargetSummary();
  }
}

function renderPlanSourceControls() {
  if (hasModernCoachPlanner()) return;
  if (planBuildTitle) planBuildTitle.textContent = currentLang === "es" ? "Inicia el plan" : "Start the plan";
  if (planBuildSubtitle) {
    planBuildSubtitle.textContent = currentLang === "es"
      ? "Elige el tipo de plan y si empiezas desde cero o duplicando uno anterior."
      : "Choose the plan type, then decide whether to start from zero or duplicate a previous plan.";
  }
  planSourceButtons.forEach((btn) => {
    const copy = {
      scratch: { en: "From scratch", es: "Desde cero" },
      duplicate: { en: "Duplicate previous", es: "Duplicar anterior" }
    };
    btn.textContent = pickCopy(copy[btn.dataset.planSource] || copy.scratch);
    btn.classList.toggle("active", btn.dataset.planSource === planSourceMode);
  });
  const source = getPlanSourceConfig(planSourceMode);
  ensurePlanSourceSelection(planSourceMode);
  if (planSourceSummary) {
    const selection = source.options.find((item) => item.value === planSourceSelection);
    if (selection) {
      planSourceSummary.textContent = `${pickCopy(source.summary)} ${pickCopy(selection.label)}.`;
    } else if (planSourceMode === "duplicate") {
      planSourceSummary.textContent = pickCopy({
        en: "No previous plans of this type yet. Save one first, then duplicate it here.",
        es: "Todavia no hay planes anteriores de este tipo. Guarda uno primero y luego duplicalo aqui."
      });
    } else {
      planSourceSummary.textContent = pickCopy(source.summary);
    }
  }
  if (!planSourceSelectWrapper || !planSourceSelect || !planSourceSelectLabel) {
    updatePlanQuickSummary();
    return;
  }
  const hasOptions = source.options.length > 0;
  planSourceSelectWrapper.classList.toggle("hidden", !hasOptions);
  if (!hasOptions) {
    updatePlanQuickSummary();
    return;
  }
  planSourceSelectLabel.textContent = pickCopy(source.selectLabel);
  planSourceSelect.innerHTML = "";
  source.options.forEach((option) => {
    const el = document.createElement("option");
    el.value = option.value;
    el.textContent = pickCopy(option.label);
    planSourceSelect.appendChild(el);
  });
  planSourceSelect.value = planSourceSelection;
  updatePlanQuickSummary();
}

function renderPlanAssignControls() {
  if (hasModernCoachPlanner()) return;
  if (planAssignMode === "single" && planAssignedAthletes.length > 1) {
    planAssignedAthletes = planAssignedAthletes.slice(0, 1);
  }
  planAssignModeButtons.forEach((btn) => {
    const copy = {
      single: { en: "Single athlete", es: "Un atleta" },
      multi: { en: "Multiple athletes", es: "Varios atletas" },
      group: { en: "Group", es: "Grupo" }
    };
    btn.textContent = pickCopy(copy[btn.dataset.planAssignMode] || copy.single);
    btn.classList.toggle("active", btn.dataset.planAssignMode === planAssignMode);
  });
  if (planAssignTitle) planAssignTitle.textContent = currentLang === "es" ? "Asigna este plan" : "Assign this plan";
  if (planAssignSubtitle) {
    planAssignSubtitle.textContent = currentLang === "es"
      ? "Envialo a un atleta, varios atletas o un grupo completo sin salir de Create Plan."
      : "Send it to one athlete, several athletes, or a full group without leaving Create Plan.";
  }
  if (planAssignGroupLabel) {
    planAssignGroupLabel.textContent = currentLang === "es" ? "Grupo" : "Group";
  }
  if (planAssignSelectAll) {
    planAssignSelectAll.hidden = planAssignMode !== "multi";
    planAssignSelectAll.textContent = currentLang === "es" ? "Seleccionar equipo completo" : "Select full team";
  }
  if (planAssignHint) {
    const hintMap = {
      single: { en: "Pick one athlete.", es: "Elige un atleta." },
      multi: { en: "Pick several athletes.", es: "Elige varios atletas." },
      group: { en: "Pick a full group.", es: "Elige un grupo completo." }
    };
    planAssignHint.textContent = pickCopy(hintMap[planAssignMode] || hintMap.single);
  }
  if (planAssignGroupWrapper && planAssignGroup) {
    planAssignGroupWrapper.classList.toggle("hidden", planAssignMode !== "group");
    planAssignGroup.innerHTML = "";
    const options = getPlanAssignGroupOptions();
    options.forEach((group) => {
      const option = document.createElement("option");
      option.value = group.value;
      option.textContent = pickCopy(group.label);
      planAssignGroup.appendChild(option);
    });
    if (!options.some((group) => group.value === planAssignedGroup)) {
      planAssignedGroup = options[0]?.value || "varsity";
    }
    planAssignGroup.value = planAssignedGroup;
  }
  if (planAssignAthletes) {
    planAssignAthletes.classList.toggle("hidden", planAssignMode === "group");
    planAssignAthletes.innerHTML = "";
    getAthletesData().forEach((athlete) => {
      const btn = document.createElement("button");
      btn.type = "button";
      btn.className = `plan-athlete-option${planAssignedAthletes.includes(athlete.name) ? " active" : ""}`;
      btn.innerHTML = `<strong>${athlete.name}</strong><span>${athlete.weight} - ${athlete.style}</span>`;
      btn.addEventListener("click", () => {
        if (planAssignMode === "single") {
          planAssignedAthletes = [athlete.name];
        } else if (planAssignMode === "multi") {
          if (planAssignedAthletes.includes(athlete.name)) {
            planAssignedAthletes = planAssignedAthletes.filter((name) => name !== athlete.name);
          } else {
            planAssignedAthletes = [...planAssignedAthletes, athlete.name];
          }
        }
        renderPlanAssignControls();
      });
      planAssignAthletes.appendChild(btn);
    });
  }
  updatePlanQuickSummary();
}

function formatPlanDateLabel(dateKey) {
  const key = normalizeDateKey(dateKey);
  const locale = currentLang === "es" ? "es-ES" : "en-US";
  return dateFromKey(key).toLocaleDateString(locale, {
    month: "short",
    day: "numeric",
    year: "numeric"
  });
}

function formatPlanRangeLabel(range) {
  if (!range?.startKey) return "";
  if (!range.endKey || range.endKey === range.startKey) {
    return formatPlanDateLabel(range.startKey);
  }
  return `${formatPlanDateLabel(range.startKey)} - ${formatPlanDateLabel(range.endKey)}`;
}

function populateSeasonYearSelect() {
  if (!seasonYearSelect || seasonYearSelect.options.length) return;
  const currentYear = getCurrentAppDate().getFullYear();
  for (let year = currentYear - 1; year <= currentYear + 3; year += 1) {
    const option = document.createElement("option");
    option.value = String(year);
    option.textContent = String(year);
    seasonYearSelect.appendChild(option);
  }
  seasonYearSelect.value = String(currentYear);
}

function clearDailyPlanSelections() {
  selectionBlocks.forEach((block) => {
    const chosen = block.querySelector(".chosen-list");
    if (chosen) chosen.innerHTML = "";
  });
}

function applyDailyPlanSelections(items = {}) {
  clearDailyPlanSelections();
  selectionBlocks.forEach((block) => {
    const key = block.dataset.block;
    const chosen = block.querySelector(".chosen-list");
    if (!chosen) return;
    (items[key] || []).forEach((value) => addChosenItem(chosen, value));
  });
}

function setPlanEditorRange(range = {}) {
  const startKey = normalizeDateKey(range.startKey || getCurrentAppDateKey());
  const endKey = normalizeDateKey(range.endKey || startKey);
  planRangeSelection.start = dateFromKey(startKey);
  planRangeSelection.end = dateFromKey(planRangeType === "day" ? startKey : endKey);
  updateRangeInputsFromSelection();
}

function resetCoachPlanEditor() {
  if (hasModernCoachPlanner()) return;
  currentEditingCoachPlanId = "";
  if (planTitleInput) planTitleInput.value = defaultPlanTitle(planRangeType);
  if (planFocusInput) planFocusInput.value = "";
  if (planNotesInput) planNotesInput.value = "";
  if (planMonthlyNotes) planMonthlyNotes.value = "";
  populateSeasonYearSelect();
  if (seasonYearSelect) seasonYearSelect.value = String(getCurrentAppDate().getFullYear());
  clearDailyPlanSelections();
  clearPlanSaveStatus();
  updatePlanQuickSummary();
}

function applyCoachPlanRecordToEditor(record, { clearEditingId = true } = {}) {
  if (!record) return;
  if (clearEditingId) currentEditingCoachPlanId = "";
  if (planTitleInput) planTitleInput.value = record.title || defaultPlanTitle(planRangeType);
  if (planFocusInput) planFocusInput.value = record.focus || "";
  if (planNotesInput) planNotesInput.value = record.coachNotes || "";
  if (planMonthlyNotes) planMonthlyNotes.value = record.monthlyNotes || "";
  populateSeasonYearSelect();
  if (seasonYearSelect) {
    seasonYearSelect.value = String(record.seasonYear || seasonYearSelect.value || getCurrentAppDate().getFullYear());
  }
  applyDailyPlanSelections(record.items || {});
  if (record.range?.startKey) {
    setPlanEditorRange(record.range);
  }
  if (record.audience?.mode) {
    planAssignMode = record.audience.mode;
    planAssignedAthletes = [...(record.audience.athleteNames || [])];
    planAssignedGroup = record.audience.groupId || planAssignedGroup;
    renderPlanAssignControls();
  }
  clearPlanSaveStatus();
}

function applySelectedPlanSource() {
  if (hasModernCoachPlanner()) return;
  const record = getSelectedPlanSourceRecord();
  if (!record) {
    if (planSourceMode === "scratch") {
      resetCoachPlanEditor();
    }
    return;
  }
  applyCoachPlanRecordToEditor(record);
}

function buildCurrentPlanRange() {
  const startKey = normalizeDateKey(planRangeStartInput?.value || toDateKey(planRangeSelection.start));
  const rawEndKey = planRangeEndInput?.value || toDateKey(planRangeSelection.end || planRangeSelection.start);
  const endKey = normalizeDateKey(planRangeType === "day" ? startKey : rawEndKey);
  if (planRangeType !== "day" && !planRangeEndInput?.value && (!planRangeSelection.end || endKey === startKey)) {
    return null;
  }
  return { startKey, endKey };
}

function getPlanSourceDescriptor() {
  if (planSourceMode === "scratch") {
    return {
      sourceMode: "scratch",
      sourceRefId: "",
      sourceLabel: pickCopy(PLAN_SOURCE_LIBRARY.scratch.label)
    };
  }
  const source = getPlanSourceConfig(planSourceMode);
  const selection = source.options.find((option) => option.value === planSourceSelection);
  return {
    sourceMode: planSourceMode,
    sourceRefId: selection?.record?.id || planSourceSelection,
    sourceLabel: selection ? pickCopy(selection.label) : pickCopy(source.label)
  };
}

function getCurrentPlanAudience() {
  if (planAssignMode === "group") {
    const group = getCoachGroupRecords().find((item) => item.id === planAssignedGroup) || null;
    return {
      mode: "group",
      athleteNames: [...(group?.memberNames || [])],
      athleteIds: [...(group?.memberIds || [])],
      athleteUids: [...(group?.memberUids || [])],
      groupId: group?.id || "",
      groupName: group?.name || ""
    };
  }
  const resolvedMembers = resolveAssignmentAudienceMembers(planAssignedAthletes);
  return {
    mode: planAssignMode,
    athleteNames: resolvedMembers.memberNames,
    athleteIds: resolvedMembers.memberIds,
    athleteUids: resolvedMembers.memberUids,
    groupId: "",
    groupName: ""
  };
}

function buildCoachPlanDraft() {
  const range = buildCurrentPlanRange();
  if (!range) {
    return {
      error: pickCopy({
        en: "Choose a start and end date for this plan.",
        es: "Elige una fecha de inicio y una fecha final para este plan."
      })
    };
  }

  const sourceDescriptor = getPlanSourceDescriptor();
  const title = String(planTitleInput?.value || "").trim() || defaultPlanTitle(planRangeType);
  const sourceRecord = getSelectedPlanSourceRecord();

  return normalizeCoachPlanRecord(currentEditingCoachPlanId || slugifyKey(`${title}-${range.startKey}`), {
    title,
    type: planRangeType,
    focus: String(planFocusInput?.value || "").trim(),
    coachNotes: String(planNotesInput?.value || "").trim(),
    sourceMode: sourceDescriptor.sourceMode,
    sourceRefId: sourceDescriptor.sourceRefId,
    sourceLabel: sourceDescriptor.sourceLabel,
    range,
    items: normalizePlanItems(collectDailySelections()),
    monthlyNotes: String(planMonthlyNotes?.value || "").trim() || String(sourceRecord?.monthlyNotes || "").trim(),
    seasonYear: String(seasonYearSelect?.value || "").trim(),
    trainingBuilder: getTrainingBuilderPayload(),
    audience: getCurrentPlanAudience(),
    createdBy: String(getProfile()?.name || getAuthUser()?.email || "").trim(),
    updatedBy: String(getProfile()?.name || getAuthUser()?.email || "").trim()
  });
}

function getPlanAssignmentTypeLabel(type) {
  const copy = {
    day: { en: "Daily Plan", es: "Plan diario" },
    week: { en: "Weekly Plan", es: "Plan semanal" },
    month: { en: "Monthly Plan", es: "Plan mensual" },
    season: { en: "Season Plan", es: "Plan de temporada" }
  };
  return pickCopy(copy[normalizePlanType(type)] || copy.day);
}

function resolveAssignmentAudienceMembers(names = []) {
  const uniqueMemberNames = uniqueNames(names);
  const members = uniqueMemberNames
    .map((name) => getCoachAthleteRecordByIdentity(name) || { id: slugifyKey(name), name, athleteUid: "" })
    .filter(Boolean);
  return {
    memberNames: uniqueNames(members.map((member) => member.name)),
    memberIds: uniqueNames(members.map((member) => normalizeAthleteId(member.id, member.name))),
    memberUids: uniqueNames(members.map((member) => normalizeUid(member.athleteUid)).filter(Boolean))
  };
}

function getAssignmentTargetsFromPlan(plan) {
  if (!plan?.audience) return [];
  if (plan.audience.mode === "group") {
    const group = getCoachGroupRecords().find((item) => item.id === plan.audience.groupId) || null;
    if (!group) return [];
    const memberNames = uniqueNames(group.memberNames || []);
    const athleteIds = uniqueNames(group.memberIds || []);
    const athleteUids = uniqueNames(group.memberUids || []);
    if (!memberNames.length && !athleteIds.length && !athleteUids.length) {
      return [];
    }
    return [{
      assigneeType: "group",
      assigneeId: group.id,
      assigneeName: group.name,
      assigneeNames: memberNames,
      athleteIds,
      athleteUids
    }];
  }
  return uniqueNames(plan.audience.athleteNames).map((name) => {
    const athlete = getCoachAthleteRecordByIdentity(name) || null;
    return {
      assigneeType: "athlete",
      assigneeId: normalizeAthleteId(athlete?.id, name),
      assigneeName: athlete?.name || name,
      assigneeNames: [athlete?.name || name],
      athleteIds: [normalizeAthleteId(athlete?.id, name)],
      athleteUids: athlete?.athleteUid ? [normalizeUid(athlete.athleteUid)] : []
    };
  });
}

async function ensureCoachAthleteLinksForTargets(targets = []) {
  if (!isCoachWorkspaceActive() || !firebaseFirestoreInstance) return 0;
  const usersRef = getUsersCollectionRef();
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!usersRef || !authUser?.id) return 0;

  const coachUid = String(authUser.id || "").trim();
  const coachName = String(profile?.name || authUser?.email || "Coach").trim();
  const coachEmail = normalizeEmail(authUser?.email || profile?.email || "");
  if (!coachUid) return 0;

  const uniqueAthleteUids = new Set();
  const uniqueAthleteIds = new Set();
  (Array.isArray(targets) ? targets : []).forEach((target) => {
    (target?.athleteUids || []).forEach((uid) => {
      const safe = normalizeUid(uid);
      if (safe) uniqueAthleteUids.add(safe);
    });
    (target?.athleteIds || []).forEach((athleteId) => {
      const safe = normalizeAthleteId(athleteId);
      if (safe) uniqueAthleteIds.add(safe);
    });
  });

  const resolvedUserIds = new Set(uniqueAthleteUids);
  const unresolvedAthleteIds = Array.from(uniqueAthleteIds).filter((athleteId) => {
    if (!athleteId) return false;
    return !Array.from(resolvedUserIds).some((uid) => uid === athleteId);
  });

  for (const athleteId of unresolvedAthleteIds) {
    try {
      const snap = await withTimeout(
        usersRef.where("linkedAthleteId", "==", athleteId).limit(4).get(),
        FIREBASE_OP_TIMEOUT_MS,
        "firestore_assignment_link_lookup_timeout"
      );
      if (snap.empty) continue;
      const athleteDoc = snap.docs.find((doc) => normalizeAuthRole(doc.data()?.role || "") === "athlete");
      const resolvedDoc = athleteDoc || snap.docs[0];
      const resolvedId = normalizeUid(resolvedDoc?.id);
      if (resolvedId) resolvedUserIds.add(resolvedId);
    } catch (err) {
      console.warn("Assignment recipient link lookup failed", err);
    }
  }

  if (!resolvedUserIds.size) return 0;

  const batch = firebaseFirestoreInstance.batch();
  let updates = 0;
  resolvedUserIds.forEach((uid) => {
    if (!uid) return;
    batch.set(usersRef.doc(uid), stripUndefinedDeep({
      linkedCoachUid: coachUid,
      linkedCoachName: coachName,
      linkedCoachEmail: coachEmail,
      linkedAthleteUid: uid,
      updatedAt: new Date().toISOString()
    }), { merge: true });
    updates += 1;
  });
  if (!updates) return 0;
  await withTimeout(
    batch.commit(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignment_link_commit_timeout"
  );
  return updates;
}

async function replaceAssignmentsForPlan(plan) {
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments");
  if (!assignmentsRef || !plan?.id) return [];
  const targets = getAssignmentTargetsFromPlan(plan);
  if (!targets.length) {
    throw new Error("plan_assignment_target_required");
  }

  await ensureCoachAthleteLinksForTargets(targets);

  const existingSnap = await withTimeout(
    assignmentsRef.where("planId", "==", plan.id).get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignments_fetch_timeout"
  );

  const batch = firebaseFirestoreInstance.batch();
  existingSnap.forEach((doc) => batch.delete(doc.ref));
  const timestamp = getFirestoreServerTimestamp();
  const startDateKey = plan.range?.startKey || plan.range?.endKey || getCurrentAppDateKey();
  const endDateKey = plan.range?.endKey || plan.range?.startKey || getCurrentAppDateKey();
  const dueDateKey = plan.range?.endKey || plan.range?.startKey || getCurrentAppDateKey();
  const dueLabel = formatPlanDateLabel(dueDateKey);
  const createdAssignments = [];

  targets.forEach((target) => {
    const ref = assignmentsRef.doc();
    const assignmentPayload = stripUndefinedDeep({
      title: plan.title,
      assigneeType: target.assigneeType,
      assigneeId: target.assigneeId,
      assigneeName: target.assigneeName,
      assigneeNames: target.assigneeNames,
      athleteIds: target.athleteIds,
      athleteUids: target.athleteUids,
      type: getPlanAssignmentTypeLabel(plan.type),
      startDateKey,
      endDateKey,
      dueDateKey,
      dueLabel,
      status: "not_started",
      note: plan.focus || plan.coachNotes || "",
      source: plan.sourceLabel || getPlanScopeLabel(),
      planId: plan.id,
      planType: plan.type,
      notificationStatus: "assignment_only",
      createdAt: timestamp,
      updatedAt: timestamp
    });
    batch.set(ref, assignmentPayload);
    createdAssignments.push(normalizeCoachAssignmentRecord(ref.id, {
      ...assignmentPayload,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    }));
  });

  await withTimeout(batch.commit(), FIREBASE_OP_TIMEOUT_MS, "firestore_assignments_write_timeout");
  return createdAssignments;
}

async function saveCoachPlan({ createAssignments = false, navigateAfterSave = false } = {}) {
  if (hasModernCoachPlanner()) return;
  if (coachPlanSyncState.saving) return;
  if (!isCoachWorkspaceActive()) {
    setPlanSaveStatusMessage(pickCopy({
      en: "Coach workspace is not available for this account.",
      es: "El espacio del coach no esta disponible para esta cuenta."
    }), { error: true });
    return;
  }

  const draft = buildCoachPlanDraft();
  if (draft.error) {
    setPlanSaveStatusMessage(draft.error, { error: true });
    return;
  }

  if (createAssignments && getAssignmentTargetsFromPlan(draft).length === 0) {
    setPlanSaveStatusMessage(pickCopy({
      en: "Choose an athlete, or a group that already has members, before sending assignments.",
      es: "Elige un atleta, o un grupo que ya tenga miembros, antes de enviar asignaciones."
    }), { error: true });
    return;
  }

  const plansRef = getCoachWorkspaceCollectionRef("plans");
  if (!plansRef) {
    setPlanSaveStatusMessage(pickCopy({
      en: "Plan storage is not configured.",
      es: "El almacenamiento de planes no esta configurado."
    }), { error: true });
    return;
  }

  const saveTarget = resolveCoachPlanSaveTargetId();
  if (saveTarget.error) {
    setPlanSaveStatusMessage(saveTarget.error, { error: true });
    return;
  }
  if (saveTarget.canceled) {
    setPlanSaveStatusMessage(pickCopy({
      en: "Save canceled.",
      es: "Guardado cancelado."
    }));
    return;
  }
  const saveTargetPlanId = String(saveTarget.planId || "").trim();
  const isUpdatingExistingPlan = Boolean(saveTargetPlanId);

  coachPlanSyncState.saving = true;
  syncPlanSaveButtons();
  setPlanSaveStatusMessage(pickCopy({
    en: "Saving plan...",
    es: "Guardando plan..."
  }));

  try {
    const planRef = isUpdatingExistingPlan ? plansRef.doc(saveTargetPlanId) : plansRef.doc();
    const timestamp = getFirestoreServerTimestamp();
    await withTimeout(
      planRef.set(stripUndefinedDeep({
        ...draft,
        id: undefined,
        createdAt: isUpdatingExistingPlan ? undefined : timestamp,
        updatedAt: timestamp
      }), { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_plan_write_timeout"
    );

    currentEditingCoachPlanId = planRef.id;
    coachPlanSyncState.lastSavedId = planRef.id;
    coachPlanSyncState.lastSavedType = draft.type;

    let assignmentCount = 0;
    if (createAssignments) {
      const createdAssignments = await replaceAssignmentsForPlan({ ...draft, id: planRef.id });
      assignmentCount = createdAssignments.length;
    }

    localStorage.setItem("wpl_daily_plan", JSON.stringify(draft.items));

    const successMessage = createAssignments
      ? pickCopy({
          en: `Plan saved and ${assignmentCount} assignment${assignmentCount === 1 ? "" : "s"} sent.`,
          es: `Plan guardado y ${assignmentCount} asignacion${assignmentCount === 1 ? "" : "es"} enviada${assignmentCount === 1 ? "" : "s"}.`
        })
      : pickCopy({
          en: `Plan saved for ${formatPlanRangeLabel(draft.range)}.`,
          es: `Plan guardado para ${formatPlanRangeLabel(draft.range)}.`
        });
    setPlanSaveStatusMessage(successMessage);
    toast(successMessage);
    if (navigateAfterSave) {
      showTab("coach-home");
    }
  } catch (err) {
    console.warn("Failed to save coach plan", err);
    setPlanSaveStatusMessage(pickCopy({
      en: "Could not save the plan. Check Firebase and try again.",
      es: "No se pudo guardar el plan. Revisa Firebase y vuelve a intentarlo."
    }), { error: true });
  } finally {
    coachPlanSyncState.saving = false;
    syncPlanSaveButtons();
  }
}

async function createNewCoachGroup() {
  const namePrompt = pickCopy({
    en: "New group name",
    es: "Nombre del nuevo grupo"
  });
  const name = window.prompt(namePrompt, "");
  if (name == null) return null;
  const cleanName = String(name || "").trim();
  if (!cleanName) return null;

  const membersPrompt = pickCopy({
    en: "Optional athlete names separated by commas",
    es: "Nombres de atletas opcionales separados por comas"
  });
  const membersRaw = window.prompt(membersPrompt, planAssignedAthletes.join(", "));
  const resolvedMembers = resolveAssignmentAudienceMembers(String(membersRaw || "").split(",").map((item) => item.trim()).filter(Boolean));
  const id = slugifyKey(cleanName);
  const payload = {
    name: cleanName,
    memberNames: resolvedMembers.memberNames,
    memberIds: resolvedMembers.memberIds,
    memberUids: resolvedMembers.memberUids,
    system: false,
    updatedAt: getFirestoreServerTimestamp(),
    createdAt: getFirestoreServerTimestamp()
  };

  const groupsRef = getCoachWorkspaceCollectionRef("groups");
  if (groupsRef) {
    await withTimeout(
      groupsRef.doc(id).set(stripUndefinedDeep(payload), { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_group_write_timeout"
    );
  } else {
    coachGroupsCache = coachWorkspaceSortByUpdated([
      normalizeCoachGroupRecord(id, { ...payload, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() }),
      ...coachGroupsCache
    ]);
  }

  return id;
}

function getCalendarContainers() {
    return [planCalendarContainer].filter(Boolean);
}

function formatMonthlySelection(date) {
    if (!date) return "";
    const locale = currentLang === "es" ? "es-ES" : "en-US";
    return new Intl.DateTimeFormat(locale, { weekday: "long", month: "long", day: "numeric" }).format(date);
}

function updateMonthlySelectionLabel() {
    if (!planMonthlySelection) return;
    if (!planRangeSelection.start) {
        planMonthlySelection.textContent = "Selecciona un día para comenzar.";
        return;
    }
    planMonthlySelection.textContent = `Día seleccionado: ${formatMonthlySelection(planRangeSelection.start)}`;
}

function updateCalendarLabels() {
    if (!planCalendarLabel) return;
    const monthNames = getMonthNames();
    const startDate = new Date(planCalendarYear, planCalendarMonth, 1);
    const endDate = new Date(planCalendarYear, planCalendarMonth + PLAN_MONTHS_VISIBLE - 1, 1);
    const startLabel = `${monthNames[startDate.getMonth()]} ${startDate.getFullYear()}`;
    const endLabel = `${monthNames[endDate.getMonth()]} ${endDate.getFullYear()}`;
    planCalendarLabel.textContent = startLabel === endLabel ? startLabel : `${startLabel} – ${endLabel}`;
}

if (planMonthlyClear) {
    planMonthlyClear.addEventListener("click", () => {
        if (planMonthlyNotes) planMonthlyNotes.value = "";
        toast(currentLang === "es" ? "Notas borradas." : "Notes cleared.");
    });
}

if (planMonthlySave) {
    planMonthlySave.addEventListener("click", () => {
        const targetDate = planRangeSelection.start;
        if (!targetDate) {
            toast(currentLang === "es" ? "Selecciona un día primero." : "Select a day first.");
            return;
        }
        const formatted = formatMonthlySelection(targetDate);
        toast(
            currentLang === "es"
                ? `Plan guardado para ${formatted}.`
                : `Plan saved for ${formatted}.`
        );
    });
}

if (planMonthPrevBtn) {
    planMonthPrevBtn.addEventListener("click", () => {
        const newDate = new Date(planCalendarYear, planCalendarMonth - 1, 1);
        renderPlanCalendar(newDate.getFullYear(), newDate.getMonth());
    });
}

if (planMonthNextBtn) {
    planMonthNextBtn.addEventListener("click", () => {
        const newDate = new Date(planCalendarYear, planCalendarMonth + 1, 1);
        renderPlanCalendar(newDate.getFullYear(), newDate.getMonth());
    });
}

function renderPlanCalendar(year, month) {
    const containers = getCalendarContainers();
    if (!containers.length) return;
    planCalendarYear = year;
    planCalendarMonth = month;
    const monthNames = getMonthNames();
    const daysOfWeek = getDayAbbr();
    const todayKey = getCurrentAppDateKey();
    const dayNamesRow = `<div class="calendar-grid-days">${daysOfWeek.map((day) => `<div class="calendar-day-name">${day}</div>`).join("")}</div>`;

    const buildMonthPanel = (panelYear, panelMonth) => {
        const firstDay = new Date(panelYear, panelMonth, 1);
        const numDays = new Date(panelYear, panelMonth + 1, 0).getDate();
        const startDayOfWeek = firstDay.getDay();
        let html = `<div class="plan-month-panel"><div class="plan-month-panel-label">${monthNames[panelMonth]} ${panelYear}</div>`;
        html += dayNamesRow;
        html += '<div class="plan-month-grid">';
        for (let i = 0; i < startDayOfWeek; i += 1) {
            html += '<span class="calendar-day empty"></span>';
        }
        for (let day = 1; day <= numDays; day += 1) {
            const date = new Date(panelYear, panelMonth, day);
            const key = toDateKey(date);
            const todayClass = key === todayKey ? " today" : "";
            html += `<button type="button" class="calendar-day${todayClass}" data-date="${key}">${day}</button>`;
        }
        html += '</div></div>';
        return html;
    };

    const multiMonthHtml = Array.from({ length: PLAN_MONTHS_VISIBLE }, (_, idx) => {
        const panelDate = new Date(year, month + idx, 1);
        return buildMonthPanel(panelDate.getFullYear(), panelDate.getMonth());
    }).join("");

    containers.forEach((container) => {
        container.innerHTML = `<div class="plan-multi-months">${multiMonthHtml}</div>`;
        container.querySelectorAll('.calendar-day').forEach(dayEl => {
            dayEl.addEventListener('click', () => handlePlanDayClick(dayEl));
        });
    });

    updateCalendarLabels();
    highlightPlanRange();
}

function initializePlanSelectors() {
    if (!document.getElementById('panel-plans')) return;
    if (document.getElementById('coachPlannerApp')) {
      clearLegacyCoachPlannerArtifacts();
      return;
    }
    const today = getCurrentAppDate();
    populateSeasonYearSelect();
    renderPlanCalendar(today.getFullYear(), today.getMonth());
    if (planTitleInput && !planTitleInput.value.trim()) {
      planTitleInput.value = defaultPlanTitle(planRangeType);
    }
    updateRangeInputsFromSelection();
    renderPlanSourceControls();
    renderPlanAssignControls();
    initializeTrainingBuilder();
}

function toIsoDate(date) {
    if (!date || Number.isNaN(date.getTime())) return "";
    const offsetMs = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - offsetMs).toISOString().slice(0, 10);
}

function parseDateInput(value) {
    if (!value) return null;
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function updateRangeInputsFromSelection() {
    if (planRangeStartInput) {
        planRangeStartInput.value = toIsoDate(planRangeSelection.start);
    }
    if (planRangeEndInput) {
        planRangeEndInput.value = planRangeType === "day"
            ? toIsoDate(planRangeSelection.start)
            : toIsoDate(planRangeSelection.end);
    }
    highlightPlanRange();
}

function updateSelectionFromInputs() {
    const startValue = parseDateInput(planRangeStartInput?.value);
    const endValue = parseDateInput(planRangeEndInput?.value);
    if (planRangeType === "day") {
        planRangeSelection.start = startValue || planRangeSelection.start;
        planRangeSelection.end = planRangeSelection.start;
    } else {
        planRangeSelection.start = startValue || planRangeSelection.start;
        planRangeSelection.end = endValue;
        if (
            planRangeSelection.start &&
            planRangeSelection.end &&
            planRangeSelection.end < planRangeSelection.start
        ) {
            [planRangeSelection.start, planRangeSelection.end] = [
                planRangeSelection.end,
                planRangeSelection.start
            ];
        }
    }
    highlightPlanRange();
}

function highlightPlanRange() {
    const containers = getCalendarContainers();
    if (!containers.length) return;
    const start = planRangeSelection.start;
    const end = planRangeType === "day"
        ? start
        : planRangeSelection.end;
    containers.forEach((container) => {
        const days = Array.from(container.querySelectorAll(".calendar-day"));
        days.forEach((dayEl) => {
            const isoDate = dayEl.dataset.date;
            if (!isoDate) {
                dayEl.classList.remove("range-start", "range-end", "range-between");
                return;
            }
            const date = dateFromKey(isoDate);
            dayEl.classList.remove("range-start", "range-between", "range-end");
            if (start && date.getTime() === start.getTime()) {
                dayEl.classList.add("range-start");
            }
            if (end && date.getTime() === end.getTime()) {
                dayEl.classList.add("range-end");
            }
            if (start && end && date > start && date < end) {
                dayEl.classList.add("range-between");
            }
        });
    });
    updateMonthlySelectionLabel();
}

function handlePlanDayClick(dayEl) {
    const dateKey = dayEl.dataset.date;
    if (!dateKey) return;
    const clicked = dateFromKey(dateKey);
    if (planRangeType === "day") {
        planRangeSelection.start = clicked;
        planRangeSelection.end = clicked;
    } else if (!planRangeSelection.start || (planRangeSelection.start && planRangeSelection.end)) {
        planRangeSelection.start = clicked;
        planRangeSelection.end = null;
    } else {
        planRangeSelection.end = clicked;
        if (planRangeSelection.end < planRangeSelection.start) {
            [planRangeSelection.start, planRangeSelection.end] = [
                planRangeSelection.end,
                planRangeSelection.start
            ];
        }
    }
    updateRangeInputsFromSelection();
}

function updatePlanRangeType(subtabKey) {
  const nextType = PLAN_RANGE_KEY_MAP[subtabKey] || "day";
  planRangeType = nextType;
  if (planRangeEndWrapper) {
        planRangeEndWrapper.classList.toggle("hidden", planRangeType === "day");
    }
    if (planRangeType === "day") {
        planRangeSelection.end = planRangeSelection.start;
    }
    updateRangeInputsFromSelection();
    highlightPlanRange();
  if (planRangeHint) {
    planRangeHint.textContent = pickCopy(PLAN_RANGE_HINT[planRangeType]);
  }
  if (planSourceMode === "scratch" && planTitleInput && !currentEditingCoachPlanId) {
    planTitleInput.value = defaultPlanTitle(planRangeType);
  }
  renderPlanSourceControls();
  if (planSourceMode !== "scratch") {
    applySelectedPlanSource();
  }
  updatePlanQuickSummary();
}

if (initialPlanSubtab) {
    updatePlanRangeType(initialPlanSubtab);
}

if (planRangeStartInput) {
    planRangeStartInput.addEventListener("change", () => updateSelectionFromInputs());
}
if (planRangeEndInput) {
  planRangeEndInput.addEventListener("change", () => updateSelectionFromInputs());
}

planSourceButtons.forEach((btn) => {
  btn.addEventListener("click", () => {
    const nextMode = btn.dataset.planSource || "scratch";
    planSourceMode = nextMode;
    ensurePlanSourceSelection(nextMode);
    if (nextMode === "scratch") {
      resetCoachPlanEditor();
    } else {
      applySelectedPlanSource();
    }
    renderPlanSourceControls();
  });
});

if (planSourceSelect) {
  planSourceSelect.addEventListener("change", () => {
    planSourceSelection = planSourceSelect.value;
    applySelectedPlanSource();
    renderPlanSourceControls();
  });
}

planAssignModeButtons.forEach((btn) => {
  btn.addEventListener("click", () => {
    planAssignMode = btn.dataset.planAssignMode || "single";
    if (planAssignMode === "single" && planAssignedAthletes.length > 1) {
      planAssignedAthletes = planAssignedAthletes.slice(0, 1);
    }
    renderPlanAssignControls();
  });
});

if (planAssignGroup) {
  planAssignGroup.addEventListener("change", async () => {
    const selectedValue = planAssignGroup.value;
    if (selectedValue === "__create_new_group__") {
      const previous = planAssignedGroup;
      try {
        const newGroupId = await createNewCoachGroup();
        planAssignedGroup = newGroupId || previous;
      } catch (err) {
        console.warn("Failed to create group", err);
        toast(pickCopy({
          en: "Could not create group.",
          es: "No se pudo crear el grupo."
        }));
        planAssignedGroup = previous;
      }
      renderPlanAssignControls();
      return;
    }
    planAssignedGroup = selectedValue;
    clearPlanSaveStatus();
    updatePlanQuickSummary();
  });
}

if (planAssignSelectAll) {
  planAssignSelectAll.addEventListener("click", () => {
    planAssignMode = "multi";
    planAssignedAthletes = getAthletesData().map((athlete) => athlete.name);
    renderPlanAssignControls();
  });
}

[planTitleInput, planFocusInput, planNotesInput, planMonthlyNotes, seasonYearSelect].forEach((input) => {
  if (!input) return;
  input.addEventListener("input", () => clearPlanSaveStatus());
  input.addEventListener("change", () => clearPlanSaveStatus());
});

if (savePlanBtn) {
  savePlanBtn.addEventListener("click", async () => {
    await saveCoachPlan({ createAssignments: false });
  });
}

