const aCompetitionCue = document.getElementById("aCompetitionCue");

function collectTechniques(selector) {
  return Array.from(document.querySelectorAll(selector))
    .filter((el) => el.checked)
    .map((el) => el.value);
}

function fillTechniques(selector, values = []) {
  document.querySelectorAll(selector).forEach((el) => {
    el.checked = values.includes(el.value);
  });
}

function normalizeTopThree(list = []) {
  return list.filter(Boolean).map((item) => String(item).trim()).filter(Boolean).slice(0, 3);
}

function topThreeFromInputs(inputs = []) {
  return normalizeTopThree(inputs.map((input) => input?.value || ""));
}

function showProfileSubtab(name) {
  if (!profileSubtabButtons.length || !profileSubpanels.length) return;
  const next = name || currentProfileSubtab || "training";
  currentProfileSubtab = next;
  profileSubtabButtons.forEach((btn) => {
    btn.classList.toggle("active", btn.dataset.profileTab === next);
  });
  profileSubpanels.forEach((panel) => {
    const isActive = panel.dataset.profilePanel === next;
    panel.classList.toggle("hidden", !isActive);
  });
}

function isCoachAthleteProfileEditActive() {
  return isCoachRouteContext() && !!coachAthleteProfileEditContext;
}

function isCoachSelfProfileEditActive() {
  return isCoachRouteContext() && !coachAthleteProfileEditContext && coachSelfProfileEditMode;
}

function getAthleteProfileFormSourceProfile() {
  if (isCoachAthleteProfileEditActive()) {
    return coachAthleteProfileEditContext?.profile || {};
  }
  if (isCoachSelfProfileEditActive()) {
    return getProfile() || {};
  }
  return getProfile() || {};
}

function getAthleteProfileFormSubmitBtn() {
  if (!athleteProfileForm) return null;
  return athleteProfileForm.querySelector('button[type="submit"]');
}

function ensureCoachAthleteProfileEditNotice() {
  if (!athleteProfileForm) return null;
  let notice = document.getElementById("coachAthleteProfileEditNotice");
  if (!notice) {
    notice = document.createElement("div");
    notice.id = "coachAthleteProfileEditNotice";
    notice.className = "mini-card hidden";
    const firstChild = athleteProfileForm.firstElementChild || null;
    if (firstChild) athleteProfileForm.insertBefore(notice, firstChild);
    else athleteProfileForm.prepend(notice);
  }
  return notice;
}

function renderAthleteProfileFormMode() {
  const isCoachContext = isCoachRouteContext();
  const isCoachEditing = isCoachAthleteProfileEditActive();
  const isCoachSelfEditing = isCoachSelfProfileEditActive();
  const editContext = coachAthleteProfileEditContext || null;
  const notice = ensureCoachAthleteProfileEditNotice();
  const submitBtn = getAthleteProfileFormSubmitBtn();

  if (athleteProfileHeaderTitle) {
    athleteProfileHeaderTitle.textContent = isCoachEditing
      ? (currentLang === "es" ? "Perfil del atleta (editor completo)" : "Athlete Profile (Full Editor)")
      : isCoachSelfEditing
        ? (currentLang === "es" ? "Mi perfil (editor completo)" : "My Profile (Full Editor)")
      : (isCoachContext
          ? (currentLang === "es" ? "Perfil del atleta (selecciona atleta primero)" : "Athlete Profile (select athlete first)")
          : (currentLang === "es" ? "Perfil del atleta" : "Athlete Profile"));
  }
  if (athleteProfileHeaderChip) {
    athleteProfileHeaderChip.textContent = isCoachEditing
      ? (currentLang === "es" ? "Coach editando" : "Coach editing")
      : isCoachSelfEditing
        ? (currentLang === "es" ? "Perfil del coach" : "Coach profile")
      : (isCoachContext
          ? (currentLang === "es" ? "Selecciona en Athletes" : "Select in Athletes")
          : (currentLang === "es" ? "Crear y editar" : "Create & Edit"));
  }
  if (submitBtn) {
    submitBtn.textContent = isCoachEditing
      ? (currentLang === "es" ? "Guardar perfil del atleta" : "Save Athlete Profile")
      : isCoachSelfEditing
        ? (currentLang === "es" ? "Guardar mi perfil" : "Save My Profile")
      : (currentLang === "es" ? "Guardar perfil" : "Save Profile");
    submitBtn.disabled = isCoachContext && !isCoachEditing && !isCoachSelfEditing;
  }
  if (continueQuestionnaireLaterBtn) {
    continueQuestionnaireLaterBtn.textContent = isCoachEditing
      ? (currentLang === "es" ? "Guardar y volver a Athletes" : "Save and return to Athletes")
      : isCoachSelfEditing
        ? (currentLang === "es" ? "Guardar y volver a Home" : "Save and return Home")
      : (isCoachContext
          ? (currentLang === "es" ? "Ir a Athletes" : "Go to Athletes")
          : pickCopy(BUTTON_COPY.continueQuestionnaireLaterBtn));
  }
  if (aRole) {
    if (isCoachEditing || isCoachContext) {
      aRole.value = isCoachSelfEditing ? "coach" : "athlete";
      aRole.disabled = true;
    } else {
      aRole.disabled = false;
    }
  }

  if (!notice) return;
  if (!isCoachContext) {
    notice.classList.add("hidden");
    notice.innerHTML = "";
    return;
  }

  notice.classList.remove("hidden");
  if (isCoachEditing && editContext) {
    const safeName = escapeHtml(editContext.athleteName || (currentLang === "es" ? "Atleta" : "Athlete"));
    notice.innerHTML = `
      <h3>${currentLang === "es" ? "Modo coach: formulario completo del atleta" : "Coach mode: full athlete form"}</h3>
      <p class="small">${currentLang === "es"
        ? `Estas editando el formulario completo de ${safeName}. Los cambios se guardan en el perfil real del atleta.`
        : `You are editing the full form for ${safeName}. Changes are saved to the athlete's real profile.`}</p>
      <div class="row">
        <button type="button" id="coachAthleteEditReturnBtn" class="ghost">${currentLang === "es" ? "Volver a Athletes" : "Back to Athletes"}</button>
      </div>
    `;
  } else if (isCoachSelfEditing) {
    notice.innerHTML = `
      <h3>${currentLang === "es" ? "Modo coach: tu perfil editable" : "Coach mode: your editable profile"}</h3>
      <p class="small">${currentLang === "es"
        ? "Aqui puedes actualizar tu foto, nombre y datos del perfil que se muestran en el coach view."
        : "Update your photo, name, and profile details shown across coach view here."}</p>
      <div class="row">
        <button type="button" id="coachAthleteEditReturnBtn" class="ghost">${currentLang === "es" ? "Volver a Home" : "Back to Home"}</button>
      </div>
    `;
  } else {
    notice.innerHTML = `
      <h3>${currentLang === "es" ? "Selecciona un atleta para editar" : "Select an athlete to edit"}</h3>
      <p class="small">${currentLang === "es"
        ? "Abre Athletes, elige un atleta y presiona 'Editar perfil completo' para usar este formulario."
        : "Open Athletes, choose an athlete, and press 'Edit full profile' to use this form."}</p>
      <div class="row">
        <button type="button" id="coachAthleteEditReturnBtn" class="ghost">${currentLang === "es" ? "Ir a Athletes" : "Go to Athletes"}</button>
      </div>
    `;
  }
  const returnBtn = document.getElementById("coachAthleteEditReturnBtn");
  if (returnBtn) {
    returnBtn.addEventListener("click", () => {
      if (isCoachSelfEditing) {
        coachSelfProfileEditMode = false;
        focusRoutePanel("dashboard");
      } else {
        focusRoutePanel("coach-athletes");
      }
    });
  }
}

function renderProfileTagPicker(tags = profileTagState) {
  if (!aTags) return;
  const selected = new Set(normalizeSmartTags(Array.from(tags)));
  aTags.innerHTML = "";
  SMART_TAGS.forEach((tag) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "tag-chip";
    btn.dataset.tagId = tag.id;
    btn.textContent = `${tag.icon} ${pickCopy(tag.label)}`;
    btn.classList.toggle("active", selected.has(tag.id));
    btn.addEventListener("click", () => {
      if (selected.has(tag.id)) selected.delete(tag.id);
      else selected.add(tag.id);
      profileTagState = selected;
      renderProfileTagPicker(selected);
      renderCoachQuickPreview(readAthleteProfileForm(getAthleteProfileFormSourceProfile()));
    });
    aTags.appendChild(btn);
  });
  profileTagState = selected;
}

function setProfileTags(tags) {
  profileTagState = new Set(normalizeSmartTags(tags));
  renderProfileTagPicker(profileTagState);
}

function getProfileTags() {
  return normalizeSmartTags(Array.from(profileTagState));
}

function tendencyFallback(strategy) {
  return strategyToTendency(strategy);
}

function readAthleteProfileForm(existing = {}) {
  const neutralTech = collectTechniques(".a-tech-neutral");
  const defenseTech = collectTechniques(".a-tech-defense");
  const offenseTop3 = topThreeFromInputs([aOffense1, aOffense2, aOffense3]);
  const defenseTop3 = topThreeFromInputs([aDefense1, aDefense2, aDefense3]);
  const setupsTop3 = topThreeFromInputs([aSetup1, aSetup2, aSetup3]);
  const cornerCoachCues = topThreeFromInputs([aCornerCue1, aCornerCue2, aCornerCue3]);
  const mentalReminders = topThreeFromInputs([aMentalReminder1, aMentalReminder2, aMentalReminder3]);
  const safetyWarnings = [aSafetyWarning1?.value.trim(), aSafetyWarning2?.value.trim()].filter(Boolean);
  const physicalLimitations = [aPhysicalLimitation1?.value.trim(), aPhysicalLimitation2?.value.trim()].filter(Boolean);
  const tendency = aPsychTendency?.value || tendencyFallback(aStrategy?.value);
  return {
    ...existing,
    role: normalizeAuthRole(aRole?.value || existing.role),
    name: aName?.value.trim() || "",
    age: aAge?.value.trim() || "",
    photo: aPhoto?.value.trim() || "",
    country: aCountry?.value.trim() || "",
    city: aCity?.value.trim() || "",
    schoolClub: aSchoolClub?.value || "no",
    schoolName: aSchool?.value.trim() || "",
    clubName: aClub?.value.trim() || "",
    schoolGrade: aSchoolGrade?.value.trim() || "",
    trainingRoutines: aTrainingRoutines?.value.trim() || "",
    trainingVolume: aTrainingVolume?.value.trim() || "",
    trainingFocus: aTrainingFocus?.value.trim() || "",
    preferredMoves: aPreferredMoves?.value.trim() || "",
    preferred_moves: aPreferredMoves?.value.trim() || "",
    stance: aStance?.value || "",
    questionnaireNotes: aQuestionnaireNotes?.value.trim() || "",
    style: aStyle?.value || "freestyle",
    currentWeight: aWeight?.value.trim() || "",
    weightClass: aWeightClass?.value.trim() || "",
    years: aYears?.value.trim() || "",
    level: aLevel?.value || "intermediate",
    position: aPosition?.value || "neutral",
    strategy: aStrategy?.value || "balanced",
    strategyA: aStrategyA?.value.trim() || "",
    strategyB: aStrategyB?.value.trim() || "",
    strategyC: aStrategyC?.value.trim() || "",
    safeMoves: aSafeMoves?.value.trim() || "",
    riskyMoves: aRiskyMoves?.value.trim() || "",
    resultsHistory: aResultsHistory?.value.trim() || "",
    tags: getProfileTags(),
    favoritePosition: aFavoritePosition?.value || aPosition?.value || "neutral",
    psychTendency: tendency || tendencyFallback(aStrategy?.value),
    pressureError: aPressureError?.value.trim() || "",
    coachSignal: aCoachSignal?.value.trim() || "",
    offenseTop3: offenseTop3.length ? offenseTop3 : neutralTech.slice(0, 3),
    defenseTop3: defenseTop3.length ? defenseTop3 : defenseTech.slice(0, 3),
    techniques: {
      neutral: neutralTech,
      top: collectTechniques(".a-tech-top"),
      bottom: collectTechniques(".a-tech-bottom"),
      defense: defenseTech,
      neutralOther: aNeutralOther?.value.trim() || "",
      topOther: aTopOther?.value.trim() || "",
      bottomOther: aBottomOther?.value.trim() || "",
      defenseOther: aDefenseOther?.value.trim() || ""
    },
    international: aInternational?.value || "no",
    internationalEvents: aInternationalEvents?.value.trim() || "",
    internationalYears: aInternationalYears?.value.trim() || "",
    coachCues: aCoachCues?.value || "specific",
    cueNotes: aCueNotes?.value.trim() || "",
    injuryNotes: aInjuryNotes?.value.trim() || "",
    archetype: aArchetype?.value || "",
    bodyType: aBodyType?.value || "",
    cueWords: [aCueWord1?.value.trim(), aCueWord2?.value.trim(), aCueWord3?.value.trim()].filter(Boolean),
    challenges: [
      aChallengeOne?.value.trim() || "",
      aChallengeTwo?.value.trim() || "",
      aChallengeThree?.value.trim() || ""
    ].filter(Boolean),
    challengeOne: aChallengeOne?.value.trim() || "",
    challengeTwo: aChallengeTwo?.value.trim() || "",
    challengeThree: aChallengeThree?.value.trim() || "",
    defaultTechniques: {
      leadLeg: aLeadLeg?.value || "left",
      leftAttack: aLeftAttack?.value.trim() || "",
      rightAttack: aRightAttack?.value.trim() || "",
      preferredTies: aPreferredTies?.value.trim() || "",
      miscNotes: aMiscNotes?.value.trim() || ""
    },
    setupsTop3,
    cornerCoachCues,
    mentalReminders,
    safetyWarnings,
    physicalLimitations,
    competitionCue: aCompetitionCue?.value.trim() || ""
  };
}

