// ---------- FAVORITES ----------
const FAV_KEY = "wpl_favorites";
const favoritesList = document.getElementById("favoritesList");

function normalizeFavoriteEntry(entry) {
  if (typeof entry === "string") {
    return {
      label: String(entry || "").trim(),
      assetPath: "",
      mediaType: "",
      tags: [],
      favoriteType: "",
      targetAthlete: "",
      targetTab: "",
      targetView: ""
    };
  }
  return {
    label: String(entry?.label || entry?.title || "").trim(),
    assetPath: String(entry?.assetPath || entry?.url || "").trim(),
    mediaType: String(entry?.mediaType || "").trim(),
    tags: normalizeLooseTagList(entry?.tags || []),
    favoriteType: String(entry?.favoriteType || entry?.type || "").trim().toLowerCase(),
    targetAthlete: String(entry?.targetAthlete || entry?.athleteName || "").trim(),
    targetTab: String(entry?.targetTab || "").trim(),
    targetView: String(entry?.targetView || "").trim()
  };
}

function favoriteEntryKey(entry) {
  const safe = normalizeFavoriteEntry(entry);
  if (safe.favoriteType === "athlete_profile" && safe.targetAthlete) {
    return `athlete::${normalizeName(safe.targetAthlete)}`;
  }
  const safeAsset = String(safe.assetPath || "").trim().toLowerCase();
  if (safeAsset) return `asset::${safeAsset}`;
  return `label::${String(safe.label || "").trim().toLowerCase()}`;
}

function removeFavoriteEntry(entry) {
  const safeKey = favoriteEntryKey(entry);
  const current = getFavorites();
  const next = current.filter((item) => favoriteEntryKey(item) !== safeKey);
  const removed = next.length !== current.length;
  if (removed) {
    setFavorites(next);
    renderFavorites();
  }
  return { removed };
}

function isAthleteProfileFavoriteEntry(entry) {
  const safe = normalizeFavoriteEntry(entry);
  return safe.favoriteType === "athlete_profile" && Boolean(safe.targetAthlete || safe.label);
}

function buildAthleteProfileFavoriteEntry(athlete = {}) {
  const athleteName = String(athlete?.name || "").trim();
  return {
    label: athleteName,
    assetPath: "",
    mediaType: "",
    tags: ["athlete-profile", "competition"],
    favoriteType: "athlete_profile",
    targetAthlete: athleteName,
    targetTab: "coach-competition",
    targetView: "coach"
  };
}

function getFavoriteAthleteEntries() {
  return getFavorites().filter((entry) => isAthleteProfileFavoriteEntry(entry));
}

function isAthleteProfileFavoriteSaved(athleteName = "") {
  const safeName = normalizeName(athleteName);
  if (!safeName) return false;
  return getFavoriteAthleteEntries().some((entry) => normalizeName(entry.targetAthlete || entry.label) === safeName);
}

function openFavoriteEntry(entry) {
  const safe = normalizeFavoriteEntry(entry);
  if (isAthleteProfileFavoriteEntry(safe)) {
    const athleteName = String(safe.targetAthlete || safe.label || "").trim();
    const athleteRecord = getCoachAthleteRecordByIdentity(athleteName)
      || getAthletesData().find((item) => normalizeName(item.name) === normalizeName(athleteName))
      || null;
    if (!athleteRecord) {
      toast(currentLang === "es" ? "Ese atleta ya no esta disponible." : "That athlete is no longer available.");
      return;
    }
    if (!isCoachRole(getProfile()?.role)) {
      toast(currentLang === "es" ? "Esta vista favorita es para el coach." : "This favorite view is for coach access.");
      return;
    }
    selectCoachMatchAthlete(athleteRecord.name, { allowFallback: false });
    Promise.resolve(showTab(safe.targetTab || "coach-competition")).catch(() => {});
    return;
  }
  if (safe.assetPath) {
    window.open(safe.assetPath, "_blank", "noopener,noreferrer");
  }
}

function toggleAthleteProfileFavorite(athlete = {}) {
  const safeName = String(athlete?.name || "").trim();
  if (!safeName) return false;
  if (isAthleteProfileFavoriteSaved(safeName)) {
    const result = removeFavoriteEntry(buildAthleteProfileFavoriteEntry(athlete));
    if (result.removed) {
      toast(currentLang === "es" ? "Atleta removido de Favoritos." : "Athlete removed from Favorites.");
    }
    return false;
  }
  const result = addFavoriteEntry(buildAthleteProfileFavoriteEntry(athlete));
  if (result.added) {
    toast(currentLang === "es" ? "Atleta guardado en Favoritos." : "Athlete saved to Favorites.");
  }
  return result.added;
}

function getFavorites() {
  if (Array.isArray(userCloudFavoritesCache)) {
    return userCloudFavoritesCache
      .map((entry) => normalizeFavoriteEntry(entry))
      .filter((entry) => entry.label || entry.assetPath);
  }
  try {
    const parsed = JSON.parse(localStorage.getItem(FAV_KEY) || "[]");
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry) => normalizeFavoriteEntry(entry))
      .filter((entry) => entry.label || entry.assetPath);
  } catch {
    return [];
  }
}

function setFavorites(list) {
  const normalized = Array.isArray(list)
    ? list.map((entry) => normalizeFavoriteEntry(entry)).filter((entry) => entry.label || entry.assetPath)
    : [];
  userCloudFavoritesCache = normalized;
  localStorage.setItem(FAV_KEY, JSON.stringify(normalized));
  if (!userClientStateApplying) {
    scheduleUserClientStateWrite(USER_CLIENT_STATE_DOCS.favorites, () => ({ items: normalized }));
  }
}

function addFavoriteEntry(entry) {
  const nextEntry = normalizeFavoriteEntry(entry);
  if (!nextEntry.label && !nextEntry.assetPath) return { added: false };
  const existing = getFavorites();
  const existingKeys = new Set(existing.map((item) => favoriteEntryKey(item)));
  const key = favoriteEntryKey(nextEntry);
  if (existingKeys.has(key)) {
    return { added: false };
  }
  const next = [nextEntry, ...existing];
  setFavorites(next);
  renderFavorites();
  return { added: true };
}

function renderFavorites() {
  const favs = getFavorites();
  favoritesList.innerHTML = "";

  if (favs.length === 0) {
    const li = document.createElement("li");
    li.textContent = pickCopy({ en: "No favorites yet.", es: "Aun no hay favoritos." });
    favoritesList.appendChild(li);
    return;
  }

  favs.forEach((f, idx) => {
    const li = document.createElement("li");
    const tags = Array.isArray(f.tags) && f.tags.length ? ` [${f.tags.join(", ")}]` : "";
    const typeLabel = isAthleteProfileFavoriteEntry(f)
      ? pickCopy({ en: "Athlete profile", es: "Perfil de atleta" })
      : String(f.mediaType || "").trim();
    const type = typeLabel ? ` (${typeLabel})` : "";
    li.textContent = `${f.label}${type}${tags}`;

    const del = document.createElement("button");
    del.textContent = pickCopy({ en: "Remove", es: "Eliminar" });
    del.style.marginLeft = "10px";

    del.addEventListener("click", () => {
      const updated = getFavorites().filter((_, i) => i !== idx);
      setFavorites(updated);
      renderFavorites();
    });

    li.appendChild(del);
    if (isAthleteProfileFavoriteEntry(f)) {
      const openAthlete = document.createElement("button");
      openAthlete.textContent = pickCopy({ en: "Open Competition", es: "Abrir Competition" });
      openAthlete.style.marginLeft = "8px";
      openAthlete.addEventListener("click", () => {
        openFavoriteEntry(f);
      });
      li.appendChild(openAthlete);
    } else if (f.assetPath) {
      const open = document.createElement("button");
      open.textContent = pickCopy({ en: "Open", es: "Abrir" });
      open.style.marginLeft = "8px";
      open.addEventListener("click", () => {
        openFavoriteEntry(f);
      });
      li.appendChild(open);
    }
    favoritesList.appendChild(li);
  });
}
// ---------- TODAY ----------

function toast(msg) {
  dailyStatus.textContent = msg;
  setTimeout(() => (dailyStatus.textContent = ""), 1600);
}

function getAthleteLivePlanRecords() {
  if (athletePortalPlansCache.length) {
    return coachWorkspaceSortByUpdated(athletePortalPlansCache);
  }
  const assignment = getAthletePortalPrimaryAssignment();
  if (!assignment) return [];
  return [{
    id: assignment.id,
    title: assignment.title,
    type: assignment.planType || "day",
    range: {
      startKey: assignment.dueDateKey || getCurrentAppDateKey(),
      endKey: assignment.dueDateKey || getCurrentAppDateKey()
    },
    focus: assignment.note || assignment.type,
    items: {
      intro: [assignment.title],
      drills: assignment.note ? [assignment.note] : [],
      announcements: assignment.mediaTitle ? [assignment.mediaTitle] : []
    }
  }];
}

function buildAthletePlanDetailLines(plan) {
  if (!plan) return [];
  const labels = {
    intro: currentLang === "es" ? "Inicio" : "Intro",
    warmup: currentLang === "es" ? "Warm-up" : "Warm-up",
    drills: currentLang === "es" ? "Drills" : "Drills",
    live: currentLang === "es" ? "Live" : "Live",
    cooldown: currentLang === "es" ? "Cooldown" : "Cooldown",
    announcements: currentLang === "es" ? "Notas" : "Notes"
  };
  return Object.entries(plan.items || {})
    .filter(([, values]) => Array.isArray(values) && values.length)
    .map(([key, values]) => `${labels[key] || key}: ${values.join(" - ")}`);
}

function getAthleteTrainingAssignments({ includeCompleted = true } = {}) {
  if (!isAthleteRole(getProfile()?.role)) return [];
  const list = sortAthleteAssignmentsForDisplay(athletePortalAssignmentsCache).filter((assignment) => {
    const track = getAssignmentTrainingTrack(assignment);
    if (!["wrestling", "lifting", "mental"].includes(track)) return false;
    if (includeCompleted) return true;
    return normalizeAssignmentStatus(assignment.status) !== "completed";
  });
  return list;
}

function getAthleteTrainingAssignmentsForDisplay() {
  const baseAssignments = getAthleteTrainingAssignments({ includeCompleted: false });
  const replayableMentalAssignments = sortAthleteAssignmentsForDisplay(athletePortalAssignmentsCache).filter((assignment) => (
    getAssignmentTrainingTrack(assignment) === "mental"
    && isPlayableAthleteMentalAssignment(assignment)
  ));
  const mergedById = new Map();
  [...baseAssignments, ...replayableMentalAssignments].forEach((assignment) => {
    const safeId = String(assignment?.id || "").trim();
    if (!safeId) return;
    mergedById.set(safeId, assignment);
  });
  return sortAthleteAssignmentsForDisplay(Array.from(mergedById.values()));
}

function getAthleteNoSharedTrainingMessage() {
  return currentLang === "es"
    ? "Tu entrenador aun no ha compartido un plan de entrenamiento contigo."
    : "Your coach has not shared a training plan with you yet.";
}

function normalizeAthleteTrainingTrackSelection(value = "") {
  const safeValue = String(value || "").trim().toLowerCase();
  if (safeValue === "lifting" || safeValue === "mental") return safeValue;
  return "wrestling";
}

function getAthleteTrainingTrackSectionLabel(track = "wrestling") {
  const safeTrack = normalizeAthleteTrainingTrackSelection(track);
  if (safeTrack === "lifting") {
    return currentLang === "es" ? "Lifting y Conditioning" : "Lifting & Conditioning";
  }
  if (safeTrack === "mental") {
    return currentLang === "es" ? "Mind y Focus Training" : "Mind & Focus Training";
  }
  return currentLang === "es" ? "Wrestling Training" : "Wrestling Training";
}

function renderAthleteTrainingTrackSwitch(assignments = []) {
  if (!athleteTrainingTrackSwitch) return;
  const sections = ["wrestling", "lifting", "mental"];
  athleteTrainingTrackSwitch.classList.remove("hidden");
  if (athleteTrainingTrackHint) {
    athleteTrainingTrackHint.classList.remove("hidden");
    athleteTrainingTrackHint.textContent = currentLang === "es"
      ? "Vista solo lectura. El entrenador controla ediciones y asignaciones."
      : "Read-only view. Coach controls edits and assignments.";
  }
  athleteTrainingSelectedTrack = normalizeAthleteTrainingTrackSelection(athleteTrainingSelectedTrack);
  athleteTrainingTrackSwitch.querySelectorAll("[data-athlete-training-track]").forEach((button) => {
    const track = normalizeAthleteTrainingTrackSelection(button.dataset.athleteTrainingTrack || "");
    const count = (Array.isArray(assignments) ? assignments : []).filter((assignment) => getAssignmentTrainingTrack(assignment) === track).length;
    button.textContent = `${getAthleteTrainingTrackSectionLabel(track)} (${count})`;
    const isActive = track === athleteTrainingSelectedTrack;
    button.classList.toggle("active", isActive);
    button.setAttribute("aria-selected", isActive ? "true" : "false");
    button.onclick = () => {
      if (athleteTrainingSelectedTrack === track) return;
      athleteTrainingSelectedTrack = track;
      athleteTrainingSelectedAssignmentId = "";
      renderPlanGrid(0);
    };
  });
}

function getAthletePlanById(planId = "") {
  const safeId = String(planId || "").trim();
  if (!safeId) return null;
  return athletePortalPlansCache.find((plan) => String(plan.id || "").trim() === safeId) || null;
}

function getTrainingTrackLabel(track = "wrestling") {
  const safeTrack = String(track || "wrestling").trim().toLowerCase();
  if (safeTrack === "lifting") return currentLang === "es" ? "Lifting y conditioning" : "Lifting";
  if (safeTrack === "mental") return currentLang === "es" ? "Mind y Focus" : "Mind & Focus";
  return currentLang === "es" ? "Wrestling" : "Wrestling";
}

function buildDefaultGlobalMentalLeaderboard() {
  return Object.keys(GLOBAL_MENTAL_GAME_META).reduce((acc, gameKey) => {
    acc[gameKey] = [];
    return acc;
  }, {});
}

function normalizeGlobalMentalLeaderboardRole(role = "") {
  const safeRole = normalizeAuthRole(role);
  if (safeRole === "administrator" || safeRole === "head_coach") return "coach";
  if (safeRole === "coach" || safeRole === "athlete" || safeRole === "parent" || safeRole === "admin") {
    return safeRole;
  }
  return "athlete";
}

function getGlobalMentalRoleLabel(role = "") {
  const safeRole = normalizeGlobalMentalLeaderboardRole(role);
  if (safeRole === "coach") return currentLang === "es" ? "Entrenador" : "Coach";
  if (safeRole === "parent") return currentLang === "es" ? "Padre" : "Parent";
  if (safeRole === "admin") return currentLang === "es" ? "Admin" : "Admin";
  return currentLang === "es" ? "Atleta" : "Athlete";
}

function getGlobalMentalGameMeta(gameKey = "") {
  const safeKey = String(gameKey || "").trim().toLowerCase();
  const meta = GLOBAL_MENTAL_GAME_META[safeKey] || {};
  return {
    key: safeKey,
    title: currentLang === "es" ? (meta.titleEs || meta.title || safeKey) : (meta.title || safeKey),
    duration: Number.isFinite(Number(meta.duration)) ? Number(meta.duration) : 0
  };
}

function normalizeGlobalMentalLeaderboardEntry(raw = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const uid = normalizeUid(source.uid || source.id || "");
  const bestScore = Math.max(0, parseInt(String(source.bestScore ?? source.mentalScore ?? 0), 10) || 0);
  const plays = Math.max(0, parseInt(String(source.plays || 0), 10) || 0);
  const fallbackName = uid ? `${currentLang === "es" ? "Usuario" : "User"} ${uid.slice(0, 6)}` : (currentLang === "es" ? "Usuario" : "User");
  const name = String(source.name || source.email || fallbackName).trim() || fallbackName;
  const updatedAtIso = String(source.updatedAtIso || "").trim();
  return {
    uid,
    name,
    role: normalizeGlobalMentalLeaderboardRole(source.role),
    bestScore,
    plays,
    updatedAtIso
  };
}

function getGlobalMentalLeaderboardEntriesRef(gameKey = "") {
  const safeGameKey = String(gameKey || "").trim().toLowerCase();
  if (!safeGameKey || !GLOBAL_MENTAL_GAME_META[safeGameKey] || !firebaseFirestoreInstance) return null;
  try {
    return firebaseFirestoreInstance
      .collection(FIREBASE_SHARED_COLLECTION)
      .doc(`mental_game_leaderboard_${safeGameKey}`)
      .collection("entries");
  } catch {
    return null;
  }
}

function getGlobalMentalLeaderboardRows(gameKey = "") {
  const safeGameKey = String(gameKey || "").trim().toLowerCase();
  const rows = Array.isArray(athleteMentalLeaderboardCache?.[safeGameKey])
    ? athleteMentalLeaderboardCache[safeGameKey]
    : [];
  return rows
    .map((row) => normalizeGlobalMentalLeaderboardEntry(row))
    .filter((row) => row.uid)
    .sort((left, right) => {
      if (right.bestScore !== left.bestScore) return right.bestScore - left.bestScore;
      return (Date.parse(right.updatedAtIso || "") || 0) - (Date.parse(left.updatedAtIso || "") || 0);
    })
    .slice(0, GLOBAL_MENTAL_LEADERBOARD_LIMIT);
}

function upsertGlobalMentalLeaderboardEntry(gameKey = "", entry = {}) {
  const safeGameKey = String(gameKey || "").trim().toLowerCase();
  if (!safeGameKey || !GLOBAL_MENTAL_GAME_META[safeGameKey]) return;
  const normalized = normalizeGlobalMentalLeaderboardEntry(entry);
  if (!normalized.uid) return;
  const currentRows = Array.isArray(athleteMentalLeaderboardCache?.[safeGameKey])
    ? athleteMentalLeaderboardCache[safeGameKey]
    : [];
  const nextRows = currentRows
    .map((row) => normalizeGlobalMentalLeaderboardEntry(row))
    .filter((row) => row.uid && row.uid !== normalized.uid);
  nextRows.push(normalized);
  athleteMentalLeaderboardCache[safeGameKey] = nextRows
    .sort((left, right) => {
      if (right.bestScore !== left.bestScore) return right.bestScore - left.bestScore;
      return (Date.parse(right.updatedAtIso || "") || 0) - (Date.parse(left.updatedAtIso || "") || 0);
    })
    .slice(0, GLOBAL_MENTAL_LEADERBOARD_LIMIT);
}

function renderAthleteGlobalMentalLeaderboardSection() {
  if (!athleteGlobalLeaderboardCard || !athleteGlobalLeaderboardGrid || !athleteGlobalLeaderboardStatus) return;
  const isAthlete = isAthleteRole(getProfile()?.role);
  const shouldShow = isAthlete && normalizeAthleteTrainingTrackSelection(athleteTrainingSelectedTrack) === "mental";
  athleteGlobalLeaderboardCard.classList.toggle("hidden", !shouldShow);
  if (!shouldShow) return;

  if (athleteGlobalLeaderboardTitle) {
    athleteGlobalLeaderboardTitle.textContent = currentLang === "es" ? "Leaderboard global de juegos" : "Global game leaderboard";
  }
  if (athleteGlobalLeaderboardChip) {
    athleteGlobalLeaderboardChip.textContent = currentLang === "es" ? "Top 10" : "Top 10";
  }
  athleteGlobalLeaderboardStatus.textContent = String(athleteMentalLeaderboardStatus || "").trim()
    || (currentLang === "es" ? "Cargando leaderboard global..." : "Loading global leaderboard...");

  const cards = Object.keys(GLOBAL_MENTAL_GAME_META).map((gameKey) => {
    const meta = getGlobalMentalGameMeta(gameKey);
    const rows = getGlobalMentalLeaderboardRows(gameKey);
    const rowMarkup = rows.length
      ? rows.map((entry, index) => `
        <li class="athlete-global-leaderboard-row">
          <span class="athlete-global-leaderboard-rank">#${index + 1}</span>
          <span class="athlete-global-leaderboard-name">${escapeHtml(entry.name)}</span>
          <span class="athlete-global-leaderboard-role">${escapeHtml(getGlobalMentalRoleLabel(entry.role))}</span>
          <strong class="athlete-global-leaderboard-score">${escapeHtml(entry.bestScore)}</strong>
        </li>
      `).join("")
      : `<li class="athlete-global-leaderboard-empty">${escapeHtml(currentLang === "es" ? "Sin resultados todavia." : "No scores yet.")}</li>`;
    return `
      <article class="athlete-global-leaderboard-game">
        <header>
          <h4>${escapeHtml(meta.title)}</h4>
          <span>${escapeHtml(`${meta.duration}s`)}</span>
        </header>
        <ol class="athlete-global-leaderboard-list">${rowMarkup}</ol>
      </article>
    `;
  }).join("");

  athleteGlobalLeaderboardGrid.innerHTML = cards;
}

function stopAthleteGlobalMentalLeaderboardSync() {
  athleteMentalLeaderboardUnsubs.forEach((unsubscribe) => {
    if (typeof unsubscribe !== "function") return;
    try {
      unsubscribe();
    } catch {
      // ignore unsubscribe failures
    }
  });
  athleteMentalLeaderboardUnsubs = [];
  athleteMentalLeaderboardLoadedKeys = {};
  athleteMentalLeaderboardCache = buildDefaultGlobalMentalLeaderboard();
  athleteMentalLeaderboardReady = false;
  athleteMentalLeaderboardStatus = currentLang === "es"
    ? "Cargando leaderboard global..."
    : "Loading global leaderboard...";
  renderAthleteGlobalMentalLeaderboardSection();
}

function startAthleteGlobalMentalLeaderboardSync() {
  stopAthleteGlobalMentalLeaderboardSync();
  const authUser = getAuthUser();
  const gameKeys = Object.keys(GLOBAL_MENTAL_GAME_META);
  if (!gameKeys.length) {
    athleteMentalLeaderboardReady = true;
    athleteMentalLeaderboardStatus = currentLang === "es" ? "No hay juegos disponibles." : "No games available.";
    renderAthleteGlobalMentalLeaderboardSection();
    return;
  }
  if (!firebaseFirestoreInstance) {
    athleteMentalLeaderboardReady = true;
    athleteMentalLeaderboardStatus = currentLang === "es"
      ? "Leaderboard no disponible sin Firebase."
      : "Leaderboard unavailable without Firebase.";
    renderAthleteGlobalMentalLeaderboardSection();
    return;
  }
  if (!authUser?.id) {
    athleteMentalLeaderboardReady = true;
    athleteMentalLeaderboardStatus = currentLang === "es"
      ? "Inicia sesion para ver el leaderboard."
      : "Sign in to load leaderboard.";
    renderAthleteGlobalMentalLeaderboardSection();
    return;
  }

  let loadedCount = 0;
  const markLoaded = (gameKey = "") => {
    const safeGameKey = String(gameKey || "").trim().toLowerCase();
    if (!safeGameKey || athleteMentalLeaderboardLoadedKeys[safeGameKey]) return;
    athleteMentalLeaderboardLoadedKeys[safeGameKey] = true;
    loadedCount += 1;
  };

  gameKeys.forEach((gameKey) => {
    const ref = getGlobalMentalLeaderboardEntriesRef(gameKey);
    if (!ref) {
      athleteMentalLeaderboardCache[gameKey] = [];
      markLoaded(gameKey);
      return;
    }
    const unsubscribe = ref
      .orderBy("bestScore", "desc")
      .limit(GLOBAL_MENTAL_LEADERBOARD_LIMIT)
      .onSnapshot((snapshot) => {
        athleteMentalLeaderboardCache[gameKey] = snapshot.docs
          .map((doc) => normalizeGlobalMentalLeaderboardEntry({ id: doc.id, ...(doc.data() || {}) }))
          .filter((row) => row.uid)
          .sort((left, right) => {
            if (right.bestScore !== left.bestScore) return right.bestScore - left.bestScore;
            return (Date.parse(right.updatedAtIso || "") || 0) - (Date.parse(left.updatedAtIso || "") || 0);
          })
          .slice(0, GLOBAL_MENTAL_LEADERBOARD_LIMIT);
        markLoaded(gameKey);
        const totalRows = gameKeys.reduce((sum, key) => sum + getGlobalMentalLeaderboardRows(key).length, 0);
        athleteMentalLeaderboardReady = loadedCount >= gameKeys.length;
        if (athleteMentalLeaderboardReady) {
          athleteMentalLeaderboardStatus = totalRows
            ? (currentLang === "es" ? "Leaderboard en vivo sincronizado para todos los usuarios." : "Live leaderboard synced across all users.")
            : (currentLang === "es" ? "Sin resultados aun. Completa un juego para registrar records." : "No scores yet. Complete a game to set records.");
        } else {
          athleteMentalLeaderboardStatus = currentLang === "es"
            ? `Cargando leaderboard global (${loadedCount}/${gameKeys.length})...`
            : `Loading global leaderboard (${loadedCount}/${gameKeys.length})...`;
        }
        renderAthleteGlobalMentalLeaderboardSection();
      }, (err) => {
        console.warn("Athlete global mental leaderboard sync failed", err);
        athleteMentalLeaderboardCache[gameKey] = [];
        markLoaded(gameKey);
        athleteMentalLeaderboardReady = loadedCount >= gameKeys.length;
        athleteMentalLeaderboardStatus = currentLang === "es"
          ? "No se pudo sincronizar el leaderboard ahora."
          : "Could not sync leaderboard right now.";
        renderAthleteGlobalMentalLeaderboardSection();
      });
    athleteMentalLeaderboardUnsubs.push(unsubscribe);
  });
}

async function publishGlobalMentalLeaderboardResult(gameKey = "", result = {}) {
  const safeGameKey = String(gameKey || "").trim().toLowerCase();
  if (!safeGameKey || !GLOBAL_MENTAL_GAME_META[safeGameKey]) return;
  const ref = getGlobalMentalLeaderboardEntriesRef(safeGameKey);
  const authUser = getAuthUser();
  const profile = getProfile();
  const uid = normalizeUid(authUser?.id || "");
  if (!ref || !uid) return;

  const entryRef = ref.doc(uid);
  const score = Math.max(0, parseInt(String(result?.score ?? result?.mentalScore ?? 0), 10) || 0);
  const accuracy = Math.max(0, parseInt(String(result?.accuracy ?? 0), 10) || 0);
  const speedScore = Math.max(0, parseInt(String(result?.speedScore ?? 0), 10) || 0);
  const controlScore = Math.max(0, parseInt(String(result?.controlScore ?? result?.consistencyScore ?? 0), 10) || 0);
  const name = String(profile?.name || authUser?.email || "").trim() || `${currentLang === "es" ? "Usuario" : "User"} ${uid.slice(0, 6)}`;
  const role = normalizeGlobalMentalLeaderboardRole(profile?.role || authUser?.role);
  const updatedAtIso = new Date().toISOString();

  try {
    const existingSnap = await withTimeout(entryRef.get(), FIREBASE_OP_TIMEOUT_MS, "firestore_global_leaderboard_read_timeout");
    const existing = existingSnap?.exists ? (existingSnap.data() || {}) : {};
    const previousBest = Math.max(0, parseInt(String(existing.bestScore ?? existing.mentalScore ?? 0), 10) || 0);
    const previousPlays = Math.max(0, parseInt(String(existing.plays || 0), 10) || 0);
    const bestScore = Math.max(previousBest, score);
    const isNewBest = score >= previousBest;
    const payload = stripUndefinedDeep({
      uid,
      gameKey: safeGameKey,
      name,
      email: String(profile?.email || authUser?.email || existing.email || "").trim().toLowerCase(),
      role,
      bestScore,
      lastScore: score,
      plays: previousPlays + 1,
      updatedAt: getFirestoreServerTimestamp(),
      updatedAtIso,
      bestAt: isNewBest ? getFirestoreServerTimestamp() : (existing.bestAt || existing.updatedAt || getFirestoreServerTimestamp()),
      bestAccuracy: isNewBest ? accuracy : Math.max(0, parseInt(String(existing.bestAccuracy || 0), 10) || 0),
      bestSpeedScore: isNewBest ? speedScore : Math.max(0, parseInt(String(existing.bestSpeedScore || 0), 10) || 0),
      bestControlScore: isNewBest ? controlScore : Math.max(0, parseInt(String(existing.bestControlScore || 0), 10) || 0),
      createdAt: existingSnap?.exists ? existing.createdAt : getFirestoreServerTimestamp()
    });
    await withTimeout(
      entryRef.set(payload, { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_global_leaderboard_write_timeout"
    );
    upsertGlobalMentalLeaderboardEntry(safeGameKey, {
      uid,
      name,
      role,
      bestScore,
      plays: previousPlays + 1,
      updatedAtIso
    });
    athleteMentalLeaderboardStatus = currentLang === "es"
      ? "Leaderboard en vivo sincronizado para todos los usuarios."
      : "Live leaderboard synced across all users.";
    renderAthleteGlobalMentalLeaderboardSection();
  } catch (err) {
    console.warn("Failed to publish global mental leaderboard result", err);
  }
}

const MENTAL_ASSIGNMENT_GAME_KEYS = {
  GO_NO_GO: "go_no_go",
  MEMORY: "memory_sequence",
  DECISION: "quick_decision",
  SCORE: "score_awareness",
  SWITCH: "rule_switch"
};

const SUPPORTED_MENTAL_ASSIGNMENT_KEYS = new Set(Object.values(MENTAL_ASSIGNMENT_GAME_KEYS));

function shuffleArray(values = []) {
  return [...(Array.isArray(values) ? values : [])]
    .map((value) => ({ value, sort: Math.random() }))
    .sort((left, right) => left.sort - right.sort)
    .map((entry) => entry.value);
}

function getAssignmentMentalGameKey(assignment = null) {
  return String(assignment?.mentalGameKey || "").trim().toLowerCase();
}

function isPlayableAthleteMentalAssignment(assignment = null) {
  return getAssignmentTrainingTrack(assignment) === "mental"
    && SUPPORTED_MENTAL_ASSIGNMENT_KEYS.has(getAssignmentMentalGameKey(assignment));
}

function getAthleteAssignmentPriorityMeta(assignment = null) {
  if (!isPlayableAthleteMentalAssignment(assignment)) return null;
  if (normalizeAssignmentStatus(assignment?.status) === "completed") return null;
  return {
    label: currentLang === "es" ? "Juego prioritario" : "Priority game",
    className: "status-pill-alert",
    note: currentLang === "es"
      ? "Asignado por el coach. Completa este juego una vez para quitar prioridad."
      : "Assigned by coach. Complete this game once to clear priority."
  };
}

function buildAthleteMentalPracticeAssignment(gameKey = "") {
  const safeKey = String(gameKey || "").trim().toLowerCase();
  const meta = getGlobalMentalGameMeta(safeKey);
  return {
    id: `practice_${safeKey || "go_no_go"}`,
    title: meta.title || "Mental Game",
    trainingTrack: "mental",
    mentalGameKey: safeKey || MENTAL_ASSIGNMENT_GAME_KEYS.GO_NO_GO,
    mentalGameTitle: meta.title || "Mental Game",
    mentalGameDuration: meta.duration || 30,
    status: "completed"
  };
}

async function runAthleteMentalPracticeGame(gameKey = "") {
  const safeKey = String(gameKey || "").trim().toLowerCase();
  if (!SUPPORTED_MENTAL_ASSIGNMENT_KEYS.has(safeKey)) return false;
  const practiceAssignment = buildAthleteMentalPracticeAssignment(safeKey);
  const rawResult = safeKey === MENTAL_ASSIGNMENT_GAME_KEYS.GO_NO_GO
    ? await openAthleteGoNoGoAssignmentGame(practiceAssignment)
    : await openAthleteMentalQuizGame(practiceAssignment);
  if (!rawResult) return false;
  try {
    await publishGlobalMentalLeaderboardResult(safeKey, rawResult);
  } catch (err) {
    console.warn("Athlete mental practice leaderboard publish failed", err);
  }
  return true;
}

function appendAthleteMentalPracticeHub(container) {
  if (!container) return;
  const gameKeys = Object.keys(GLOBAL_MENTAL_GAME_META);
  if (!gameKeys.length) return;
  const row = document.createElement("li");
  row.className = "assignment-step-summary athlete-mental-practice-hub";
  row.innerHTML = `
    <strong>${escapeHtml(currentLang === "es" ? "Practice Games" : "Practice Games")}</strong>
    <div class="small muted">${escapeHtml(currentLang === "es"
      ? "Puedes jugar cualquier juego mental cuando quieras. Cada resultado cuenta para el scoreboard global."
      : "You can play any mental game anytime. Every result counts on the global scoreboard.")}</div>
  `;
  const actions = document.createElement("div");
  actions.className = "assignment-card-actions athlete-mental-practice-actions";
  gameKeys.forEach((gameKey) => {
    const meta = getGlobalMentalGameMeta(gameKey);
    const button = document.createElement("button");
    button.type = "button";
    button.className = "ghost";
    button.textContent = `${meta.title} (${meta.duration}s)`;
    button.addEventListener("click", async () => {
      button.disabled = true;
      try {
        const completed = await runAthleteMentalPracticeGame(gameKey);
        if (!completed) {
          toast(currentLang === "es" ? "Juego cancelado." : "Game canceled.");
          return;
        }
        toast(currentLang === "es" ? "Resultado guardado en el scoreboard." : "Result saved to the scoreboard.");
      } catch (err) {
        console.warn("Athlete mental practice run failed", err);
        toast(currentLang === "es" ? "No se pudo completar el juego." : "Could not complete the game.");
      } finally {
        button.disabled = false;
      }
    });
    actions.appendChild(button);
  });
  row.appendChild(actions);
  container.appendChild(row);
}

function formatAssignmentResultReactionSeconds(reactionMs = 0) {
  const safeReaction = Number.isFinite(Number(reactionMs)) ? Number(reactionMs) : 0;
  return `${Math.max(0, safeReaction / 1000).toFixed(2)}s`;
}

function buildAssignmentCompletionResultSummary(assignment = null, result = null) {
  const normalized = normalizeAssignmentCompletionResult(result, assignment);
  if (normalized.summary) return normalized.summary;
  const label = normalized.label || (currentLang === "es" ? "Tarea" : "Task");
  if (normalized.type === "mental_game") {
    const parts = [];
    if (Number.isFinite(normalized.score)) {
      parts.push(`${currentLang === "es" ? "Puntaje" : "Score"} ${normalized.score}`);
    }
    if (Number.isFinite(normalized.reactionMs)) {
      parts.push(`${currentLang === "es" ? "Reaccion" : "Reaction"} ${formatAssignmentResultReactionSeconds(normalized.reactionMs)}`);
    }
    if (Number.isFinite(normalized.accuracy)) {
      parts.push(`${currentLang === "es" ? "Precision" : "Accuracy"} ${normalized.accuracy}%`);
    }
    if (parts.length) {
      return `${label}: ${parts.join(" • ")}`;
    }
  }
  return "";
}

function getAssignmentCompletionResultSummary(assignment = null) {
  return buildAssignmentCompletionResultSummary(assignment, {
    type: assignment?.completionResultType || "",
    label: assignment?.completionResultLabel || assignment?.mentalGameTitle || assignment?.title || "",
    summary: assignment?.completionResultSummary || "",
    score: assignment?.completionResultScore,
    reactionMs: assignment?.completionResultReactionMs,
    accuracy: assignment?.completionResultAccuracy
  });
}

function extractChecklistLinesFromText(rawText = "") {
  const text = String(rawText || "").trim();
  if (!text) return [];
  return text
    .replace(/\s{2,}/g, " ")
    .split(/\n+|\s+-\s+|;\s+/)
    .map((line) => String(line || "").trim())
    .filter(Boolean);
}

function buildAthleteAssignmentChecklistSteps(assignment = null) {
  if (!assignment) return [];
  const steps = [];
  const seen = new Set();
  const pushStep = (value, keyPrefix = "step", idSeed = "") => {
    const label = String(value || "").trim();
    if (!label) return;
    const stableSeed = String(idSeed || label).trim().toLowerCase();
    const dedupeKey = stableSeed || label.toLowerCase();
    if (seen.has(dedupeKey)) return;
    seen.add(dedupeKey);
    steps.push({
      id: `${keyPrefix}-${slugifyKey(stableSeed || label)}-${steps.length + 1}`,
      label
    });
  };

  const linkedPlan = getAthletePlanById(assignment.planId);
  if (linkedPlan?.items && typeof linkedPlan.items === "object") {
    const labels = {
      intro: currentLang === "es" ? "Inicio" : "Intro",
      warmup: currentLang === "es" ? "Warm-up" : "Warm-up",
      drills: currentLang === "es" ? "Drills" : "Drills",
      live: currentLang === "es" ? "Live" : "Live",
      cooldown: currentLang === "es" ? "Cooldown" : "Cooldown",
      announcements: currentLang === "es" ? "Notas" : "Notes"
    };
    ["intro", "warmup", "drills", "live", "cooldown", "announcements"].forEach((key) => {
      const values = Array.isArray(linkedPlan.items[key]) ? linkedPlan.items[key] : [];
      values.forEach((line) => {
        pushStep(`${labels[key]}: ${line}`, key, `${key}-${line}`);
      });
    });
  }

  const trainingTrack = getAssignmentTrainingTrack(assignment);
  if (trainingTrack === "mental") {
    const title = assignment.mentalGameTitle || assignment.title;
    if (title) {
      const durationSuffix = assignment.mentalGameDuration ? ` (${assignment.mentalGameDuration}s)` : "";
      pushStep(`${currentLang === "es" ? "Completa" : "Complete"} ${title}${durationSuffix}`, "mental", `${title}-${assignment.mentalGameDuration || ""}`);
    }
  }

  if (assignment.mediaTitle) {
    pushStep(`${currentLang === "es" ? "Ver film" : "Watch film"}: ${assignment.mediaTitle}`, "media", assignment.mediaTitle);
  }

  const noteLines = extractChecklistLinesFromText(assignment.note).map((line) => line.replace(/^complete[^:]*:\s*/i, "").trim());
  noteLines.forEach((line) => pushStep(line, "note", line));

  if (!steps.length) {
    pushStep(assignment.title || (currentLang === "es" ? "Tarea asignada" : "Assigned task"), "task", assignment.id || assignment.title);
  }
  return steps;
}

function getAssignmentChecklistProgress(assignment = null, steps = null, checklistOverride = null) {
  const safeSteps = Array.isArray(steps) ? steps : buildAthleteAssignmentChecklistSteps(assignment);
  const checklist = checklistOverride && typeof checklistOverride === "object"
    ? normalizeAssignmentChecklist(checklistOverride)
    : normalizeAssignmentChecklist(assignment?.athleteChecklist);
  const total = safeSteps.length;
  const done = safeSteps.reduce((count, step) => count + (checklist[step.id] ? 1 : 0), 0);
  return { total, done, checklist };
}

async function updateAthleteAssignmentChecklistStep(assignment, stepId, checked, { completionResult = null } = {}) {
  const coachUid = getAthleteLinkedCoachUid();
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments", coachUid);
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!assignment?.id || !coachUid || !assignmentsRef || !authUser?.id) {
    throw new Error("athlete_assignment_checklist_unavailable");
  }
  if (isAssignmentLockedUntilScheduledDate(assignment, athletePortalPlansCache, getCurrentAppDateKey())) {
    throw new Error("athlete_assignment_locked_until_due_date");
  }
  const steps = buildAthleteAssignmentChecklistSteps(assignment);
  const nextChecklist = {
    ...normalizeAssignmentChecklist(assignment.athleteChecklist),
    [stepId]: Boolean(checked)
  };
  const progress = getAssignmentChecklistProgress(assignment, steps, nextChecklist);
  let nextStatus = "not_started";
  if (progress.total && progress.done >= progress.total) {
    nextStatus = "completed";
  } else if (progress.done > 0) {
    nextStatus = "in_progress";
  } else if (assignment.dueDateKey && assignment.dueDateKey < getCurrentAppDateKey()) {
    nextStatus = "overdue";
  }
  const completionPayload = nextStatus === "completed"
    ? normalizeAssignmentCompletionResult(completionResult, assignment)
    : null;
  await withTimeout(
    assignmentsRef.doc(assignment.id).set(stripUndefinedDeep({
      athleteChecklist: nextChecklist,
      status: nextStatus,
      updatedAt: getFirestoreServerTimestamp(),
      startedAt: nextStatus === "in_progress" || nextStatus === "completed" ? getFirestoreServerTimestamp() : null,
      completedAt: nextStatus === "completed" ? getFirestoreServerTimestamp() : null,
      completionResultType: completionPayload?.type || undefined,
      completionResultLabel: completionPayload?.label || undefined,
      completionResultSummary: completionPayload?.summary || undefined,
      completionResultScore: completionPayload?.score,
      completionResultReactionMs: completionPayload?.reactionMs,
      completionResultAccuracy: completionPayload?.accuracy,
      completionResultAt: completionPayload ? getFirestoreServerTimestamp() : undefined,
      athleteLogUid: authUser.id,
      athleteLogName: String(profile?.name || authUser.email || "").trim()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_athlete_assignment_checklist_timeout"
  );
  if (
    nextStatus === "completed"
    && normalizeAssignmentStatus(assignment?.status) !== "completed"
    && String(assignment?.assigneeType || "").trim().toLowerCase() !== "coach"
  ) {
    try {
      await notifyCoachAssignmentCompletedViaMessages(assignment, {
        athleteUid: authUser.id,
        athleteName: String(profile?.name || authUser.email || "").trim(),
        completionResultSummary: completionPayload?.summary || ""
      });
    } catch (err) {
      console.warn("Assignment checklist completion notify failed", err);
    }
  }
}

async function updateAthleteAssignmentStatus(assignment, status, { completionResult = null } = {}) {
  const coachUid = getAthleteLinkedCoachUid();
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments", coachUid);
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!assignment?.id || !coachUid || !assignmentsRef || !authUser?.id) {
    throw new Error("athlete_assignment_sync_unavailable");
  }
  if (isAssignmentLockedUntilScheduledDate(assignment, athletePortalPlansCache, getCurrentAppDateKey())) {
    throw new Error("athlete_assignment_locked_until_due_date");
  }
  const normalizedStatus = normalizeAssignmentStatus(status);
  const completionPayload = normalizedStatus === "completed"
    ? normalizeAssignmentCompletionResult(completionResult, assignment)
    : null;
  await withTimeout(
    assignmentsRef.doc(assignment.id).set(stripUndefinedDeep({
      status: normalizedStatus,
      updatedAt: getFirestoreServerTimestamp(),
      startedAt: normalizedStatus === "in_progress" ? getFirestoreServerTimestamp() : undefined,
      completedAt: normalizedStatus === "completed" ? getFirestoreServerTimestamp() : undefined,
      completionResultType: completionPayload?.type || undefined,
      completionResultLabel: completionPayload?.label || undefined,
      completionResultSummary: completionPayload?.summary || undefined,
      completionResultScore: completionPayload?.score,
      completionResultReactionMs: completionPayload?.reactionMs,
      completionResultAccuracy: completionPayload?.accuracy,
      completionResultAt: completionPayload ? getFirestoreServerTimestamp() : undefined,
      athleteLogUid: authUser.id,
      athleteLogName: String(profile?.name || authUser.email || "").trim()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_athlete_assignment_update_timeout"
  );
  if (
    normalizedStatus === "completed"
    && normalizeAssignmentStatus(assignment?.status) !== "completed"
    && String(assignment?.assigneeType || "").trim().toLowerCase() !== "coach"
  ) {
    try {
      await notifyCoachAssignmentCompletedViaMessages(assignment, {
        athleteUid: authUser.id,
        athleteName: String(profile?.name || authUser.email || "").trim(),
        completionResultSummary: completionPayload?.summary || ""
      });
    } catch (err) {
      console.warn("Assignment completion notify failed", err);
    }
  }
}

function getAssignmentOwnerCoachUid(assignment = null) {
  if (isCoachWorkspaceActive()) {
    return normalizeUid(getAuthUser()?.id || "");
  }
  if (isAthleteRole(getProfile()?.role)) {
    return normalizeUid(getAthleteLinkedCoachUid() || "");
  }
  return normalizeUid(getParentLinkedCoachUid() || "");
}

async function findFirebaseUserByUid(uid = "") {
  const safeUid = normalizeUid(uid);
  if (!safeUid || !firebaseFirestoreInstance) return null;
  const snapshot = await withTimeout(
    firebaseFirestoreInstance.collection(FIREBASE_USERS_COLLECTION).doc(safeUid).get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_user_uid_lookup_timeout"
  ).catch(() => null);
  if (!snapshot?.exists) return null;
  return normalizeManagedUserRecord(snapshot.id, snapshot.data() || {});
}

function buildAssignmentDiscussionNoticeText(assignment, comment) {
  const authorName = String(comment?.authorName || "").trim() || "Athlete";
  const assignmentTitle = String(assignment?.title || "").trim() || (currentLang === "es" ? "asignacion" : "assignment");
  const stepLabel = String(comment?.stepLabel || "").trim();
  const body = String(comment?.text || "").trim();
  if (currentLang === "es") {
    const stepPart = stepLabel ? `\nEjercicio: ${stepLabel}` : "";
    return `Nueva pregunta en ${assignmentTitle} por ${authorName}.${stepPart}\n${body}`;
  }
  const stepPart = stepLabel ? `\nExercise: ${stepLabel}` : "";
  return `New question on ${assignmentTitle} from ${authorName}.${stepPart}\n${body}`;
}

async function notifyAssignmentDiscussionViaMessages(assignment, comment) {
  const current = getMessagesCurrentUser();
  if (!current?.uid) return;
  const coachUid = getAssignmentOwnerCoachUid(assignment);
  if (!coachUid || current.uid === coachUid) return;
  const coachUser = await findFirebaseUserByUid(coachUid);
  const coachContact = {
    uid: coachUid,
    name: coachUser?.name || "Coach",
    email: coachUser?.email || "",
    role: "coach",
    linkedCoachUid: coachUid,
    linkedAthleteId: coachUser?.linkedAthleteId || "",
    linkedAthleteUid: coachUser?.linkedAthleteUid || ""
  };
  const threadId = await ensureDirectMessageThread(coachContact);
  await appendMessageToThread({
    threadId,
    participants: [current, coachContact],
    sender: current,
    text: buildAssignmentDiscussionNoticeText(assignment, comment)
  });
}

function buildAssignmentCompletionNoticeText(assignment, athleteName = "", completionResultSummary = "") {
  const safeAthleteName = String(athleteName || "").trim() || "Athlete";
  const assignmentTitle = String(assignment?.title || "").trim() || (currentLang === "es" ? "asignacion" : "assignment");
  const dueLabel = String(assignment?.dueLabel || formatPlanDateLabel(assignment?.dueDateKey || getCurrentAppDateKey()) || "").trim();
  const resultSummary = String(completionResultSummary || assignment?.completionResultSummary || "").trim();
  if (currentLang === "es") {
    return `Tarea completada: ${assignmentTitle}\nAtleta: ${safeAthleteName}${dueLabel ? `\nEntrega: ${dueLabel}` : ""}${resultSummary ? `\nResultado: ${resultSummary}` : ""}`;
  }
  return `Assignment completed: ${assignmentTitle}\nAthlete: ${safeAthleteName}${dueLabel ? `\nDue: ${dueLabel}` : ""}${resultSummary ? `\nResult: ${resultSummary}` : ""}`;
}

async function notifyCoachAssignmentCompletedViaMessages(assignment, {
  athleteUid = "",
  athleteName = "",
  completionResultSummary = ""
} = {}) {
  const coachUid = getAssignmentOwnerCoachUid(assignment);
  const current = getMessagesCurrentUser();
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments", coachUid);
  if (!assignment?.id || !coachUid || !assignmentsRef || !current?.uid || current.uid === coachUid) return false;

  const assignmentRef = assignmentsRef.doc(String(assignment.id || "").trim());
  const existingSnapshot = await withTimeout(
    assignmentRef.get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignment_completion_notify_read_timeout"
  ).catch(() => null);
  const existing = existingSnapshot?.exists
    ? normalizeCoachAssignmentRecord(existingSnapshot.id, existingSnapshot.data() || {})
    : normalizeCoachAssignmentRecord(assignment.id, assignment || {});
  if (String(existing.notificationStatus || "").trim().toLowerCase() === "completed_notified" || existing.completionNotifiedAt) {
    return false;
  }

  const coachUser = await findFirebaseUserByUid(coachUid);
  const coachContact = {
    uid: coachUid,
    name: coachUser?.name || "Coach",
    email: coachUser?.email || "",
    role: "coach",
    linkedCoachUid: coachUid,
    linkedAthleteId: coachUser?.linkedAthleteId || "",
    linkedAthleteUid: coachUser?.linkedAthleteUid || ""
  };
  const threadId = await ensureDirectMessageThread(coachContact);
  await appendMessageToThread({
    threadId,
    participants: [current, coachContact],
    sender: current,
    text: buildAssignmentCompletionNoticeText(
      existing,
      athleteName || current.name || athleteUid,
      String(completionResultSummary || existing.completionResultSummary || "").trim()
    )
  });
  await withTimeout(
    assignmentRef.set(stripUndefinedDeep({
      notificationStatus: "completed_notified",
      completionNotifiedAt: getFirestoreServerTimestamp(),
      completionNotifiedByUid: normalizeUid(athleteUid || current.uid),
      completionNotifiedByName: String(athleteName || current.name || "").trim(),
      updatedAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignment_completion_notify_write_timeout"
  );
  return true;
}

async function postAssignmentDiscussionComment(assignment, {
  text = "",
  stepId = "",
  stepLabel = "",
  notifyCoach = false
} = {}) {
  const safeAssignmentId = String(assignment?.id || "").trim();
  const message = String(text || "").trim();
  const coachUid = getAssignmentOwnerCoachUid(assignment);
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments", coachUid);
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!safeAssignmentId || !message || !coachUid || !assignmentsRef || !authUser?.id) {
    throw new Error("assignment_comment_unavailable");
  }
  const authorName = String(profile?.name || authUser.email || "").trim() || "User";
  const authorRole = normalizeAuthRole(profile?.role || authUser.role || "athlete");
  const comment = {
    id: `c_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    text: message,
    authorUid: normalizeUid(authUser.id),
    authorName,
    authorRole,
    stepId: String(stepId || "").trim(),
    stepLabel: String(stepLabel || "").trim(),
    createdAtIso: new Date().toISOString()
  };

  const assignmentRef = assignmentsRef.doc(safeAssignmentId);
  const existingSnapshot = await withTimeout(
    assignmentRef.get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignment_comment_read_timeout"
  );
  if (!existingSnapshot.exists) {
    throw new Error("assignment_comment_target_missing");
  }
  const existing = normalizeCoachAssignmentRecord(existingSnapshot.id, existingSnapshot.data() || {});
  const nextDiscussion = normalizeAssignmentDiscussion([...(existing.discussion || []), comment]).slice(-120);
  await withTimeout(
    assignmentRef.set(stripUndefinedDeep({
      discussion: nextDiscussion,
      lastCommentText: comment.text,
      lastCommentBy: comment.authorName,
      lastCommentByUid: comment.authorUid,
      lastCommentByRole: comment.authorRole,
      lastCommentAtIso: comment.createdAtIso,
      lastCommentAt: getFirestoreServerTimestamp(),
      updatedAt: getFirestoreServerTimestamp(),
      athleteLogUid: comment.authorUid,
      athleteLogName: comment.authorName
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_assignment_comment_write_timeout"
  );

  if (notifyCoach && isAthleteRole(authorRole)) {
    try {
      await notifyAssignmentDiscussionViaMessages(assignment, comment);
    } catch (err) {
      console.warn("Assignment discussion message notify failed", err);
    }
  }
  return comment;
}

function clampNumber(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function buildGoNoGoMentalAssignmentResult(session = {}) {
  const hits = Number.isFinite(Number(session.hits)) ? Number(session.hits) : 0;
  const misses = Number.isFinite(Number(session.misses)) ? Number(session.misses) : 0;
  const falseTaps = Number.isFinite(Number(session.falseTaps)) ? Number(session.falseTaps) : 0;
  const reactionTimes = Array.isArray(session.reactionTimes) ? session.reactionTimes.map((value) => Number(value)).filter((value) => Number.isFinite(value) && value > 0) : [];
  const attempts = hits + misses + falseTaps;
  const accuracy = attempts ? Math.round((hits / attempts) * 100) : 0;
  const avgReactionMs = reactionTimes.length
    ? Math.round(reactionTimes.reduce((sum, value) => sum + value, 0) / reactionTimes.length)
    : 0;
  const speedScore = clampNumber(Math.round(100 - ((avgReactionMs - 250) / 7)), 10, 100);
  const controlScore = clampNumber(100 - falseTaps * 12, 0, 100);
  const mentalScore = Math.round((accuracy * 0.45) + (speedScore * 0.35) + (controlScore * 0.2));
  return {
    type: "mental_game",
    score: mentalScore,
    reactionMs: avgReactionMs,
    accuracy,
    hits,
    misses,
    falseTaps,
    speedScore,
    controlScore,
    summary: buildAssignmentCompletionResultSummary(null, {
      type: "mental_game",
      label: "Go / No-Go",
      score: mentalScore,
      reactionMs: avgReactionMs,
      accuracy
    })
  };
}

function getMentalSpeedScoreFromReactionMs(reactionMs = 0) {
  const safe = Number.isFinite(Number(reactionMs)) ? Number(reactionMs) : 0;
  return clampNumber(Math.round(100 - ((safe - 700) / 10)), 15, 100);
}

function buildMentalAssignmentResultFromQuiz({
  assignment = null,
  label = "",
  correct = 0,
  total = 0,
  reactionTimes = []
} = {}) {
  const safeTotal = Math.max(1, Number(total) || 1);
  const safeCorrect = Math.max(0, Math.min(safeTotal, Number(correct) || 0));
  const accuracy = Math.round((safeCorrect / safeTotal) * 100);
  const avgReactionMs = reactionTimes.length
    ? Math.round(reactionTimes.reduce((sum, value) => sum + value, 0) / reactionTimes.length)
    : 0;
  const speedScore = getMentalSpeedScoreFromReactionMs(avgReactionMs || 1200);
  const mentalScore = Math.round((accuracy * 0.65) + (speedScore * 0.35));
  return normalizeAssignmentCompletionResult({
    type: "mental_game",
    label: label || assignment?.mentalGameTitle || assignment?.title || "Mental Game",
    score: mentalScore,
    reactionMs: avgReactionMs,
    accuracy,
    summary: buildAssignmentCompletionResultSummary(assignment, {
      type: "mental_game",
      label: label || assignment?.mentalGameTitle || assignment?.title || "Mental Game",
      score: mentalScore,
      reactionMs: avgReactionMs,
      accuracy
    })
  }, assignment);
}

function buildAthleteMemoryRounds(roundCount = 5) {
  const colorPool = ["Red", "Blue", "Green", "Yellow"];
  const rounds = [];
  for (let index = 0; index < roundCount; index += 1) {
    const length = 3 + Math.floor(Math.random() * 2);
    const sequence = Array.from({ length }, () => colorPool[Math.floor(Math.random() * colorPool.length)]);
    const targetIdx = Math.floor(Math.random() * sequence.length);
    const answer = sequence[targetIdx];
    const options = Array.from(new Set([answer, ...colorPool])).slice(0, 4);
    const shuffled = shuffleArray(options);
    rounds.push({
      prompt: currentLang === "es"
        ? `Memoriza: ${sequence.join(" - ")}. ¿Color #${targetIdx + 1}?`
        : `Memorize: ${sequence.join(" - ")}. Color #${targetIdx + 1}?`,
      options: shuffled,
      answerIndex: Math.max(0, shuffled.indexOf(answer))
    });
  }
  return rounds;
}

function buildAthleteDecisionRounds() {
  const scenarios = [
    {
      prompt: currentLang === "es"
        ? "Vas perdiendo por 1 con 15s en neutral."
        : "You are losing by 1 with 15s left in neutral.",
      options: currentLang === "es"
        ? ["Ataca single limpio", "Retrocede", "Espera sin atacar", "Lanza sin setup"]
        : ["Attack a clean single", "Back away", "Hold and wait", "Force a throw"],
      answerIndex: 0
    },
    {
      prompt: currentLang === "es"
        ? "Vas ganando por 2 con 12s y te presionan."
        : "You are up by 2 with 12s left and under pressure.",
      options: currentLang === "es"
        ? ["Tiro arriesgado", "Controla posicion y circula", "Upper body forzado", "Te quedas quieto"]
        : ["Take a risky shot", "Control position and circle", "Force upper body", "Stand still"],
      answerIndex: 1
    },
    {
      prompt: currentLang === "es"
        ? "El rival carga pesado con la cabeza."
        : "Opponent is heavy on your head.",
      options: currentLang === "es"
        ? ["Snap + go behind", "Te enderezas", "Alcance largo", "Esperar"]
        : ["Snap and go behind", "Stand upright", "Reach from far", "Wait"],
      answerIndex: 0
    },
    {
      prompt: currentLang === "es"
        ? "Bottom, empate al final del combate."
        : "Bottom position, tied late in the match.",
      options: currentLang === "es"
        ? ["Stand-up rapido", "Quedarte plano", "Roll lento", "Mirar el reloj"]
        : ["Fast stand-up", "Stay flat", "Slow roll", "Watch the clock"],
      answerIndex: 0
    }
  ];
  return shuffleArray(scenarios).slice(0, 4);
}

function buildAthleteScoreRounds(roundCount = 4) {
  const events = [
    { text: currentLang === "es" ? "Rojo takedown (+3)" : "Red takedown (+3)", red: 3, green: 0 },
    { text: currentLang === "es" ? "Verde escape (+1)" : "Green escape (+1)", red: 0, green: 1 },
    { text: currentLang === "es" ? "Rojo escape (+1)" : "Red escape (+1)", red: 1, green: 0 },
    { text: currentLang === "es" ? "Verde reversal (+2)" : "Green reversal (+2)", red: 0, green: 2 },
    { text: currentLang === "es" ? "Rojo stall (+1)" : "Red stall (+1)", red: 1, green: 0 },
    { text: currentLang === "es" ? "Verde takedown (+3)" : "Green takedown (+3)", red: 0, green: 3 }
  ];
  const rounds = [];
  for (let index = 0; index < roundCount; index += 1) {
    const picks = shuffleArray(events).slice(0, 3);
    let red = 0;
    let green = 0;
    picks.forEach((event) => {
      red += event.red;
      green += event.green;
    });
    const answer = red === green
      ? (currentLang === "es" ? "Empate" : "Tied")
      : red > green
        ? (currentLang === "es" ? `Rojo por ${red - green}` : `Red by ${red - green}`)
        : (currentLang === "es" ? `Verde por ${green - red}` : `Green by ${green - red}`);
    const options = shuffleArray([
      answer,
      currentLang === "es" ? "Empate" : "Tied",
      currentLang === "es" ? "Rojo por 1" : "Red by 1",
      currentLang === "es" ? "Verde por 1" : "Green by 1"
    ]).slice(0, 4);
    if (!options.includes(answer)) options[0] = answer;
    rounds.push({
      prompt: `${currentLang === "es" ? "Secuencia" : "Sequence"}: ${picks.map((event) => event.text).join(" • ")}\n${currentLang === "es" ? "¿Quien va ganando?" : "Who is leading?"}`,
      options,
      answerIndex: Math.max(0, options.indexOf(answer))
    });
  }
  return rounds;
}

function buildAthleteSwitchRounds(roundCount = 5) {
  const rounds = [];
  const rules = [
    {
      label: currentLang === "es" ? "Toca el numero mayor" : "Tap the higher number",
      pick: (left, right) => (left > right ? 0 : 1)
    },
    {
      label: currentLang === "es" ? "Toca el numero menor" : "Tap the lower number",
      pick: (left, right) => (left < right ? 0 : 1)
    },
    {
      label: currentLang === "es" ? "Toca el numero par" : "Tap the even number",
      pick: (left, right) => (left % 2 === 0 ? 0 : 1)
    }
  ];
  for (let index = 0; index < roundCount; index += 1) {
    const left = 1 + Math.floor(Math.random() * 9);
    let right = 1 + Math.floor(Math.random() * 9);
    while (right === left) right = 1 + Math.floor(Math.random() * 9);
    const rule = rules[Math.floor(Math.random() * rules.length)];
    rounds.push({
      prompt: `${rule.label}: ${left} | ${right}`,
      options: [currentLang === "es" ? "Izquierda" : "Left", currentLang === "es" ? "Derecha" : "Right"],
      answerIndex: rule.pick(left, right)
    });
  }
  return rounds;
}

function getMentalAssignmentQuizConfig(assignment = null) {
  const key = getAssignmentMentalGameKey(assignment);
  if (key === MENTAL_ASSIGNMENT_GAME_KEYS.MEMORY) {
    return {
      title: assignment?.mentalGameTitle || "Memory Sequence",
      subtitle: currentLang === "es" ? "Memoriza y responde rapido." : "Memorize and answer fast.",
      rounds: buildAthleteMemoryRounds(5),
      duration: Math.max(20, Number(assignment?.mentalGameDuration) || 45)
    };
  }
  if (key === MENTAL_ASSIGNMENT_GAME_KEYS.DECISION) {
    return {
      title: assignment?.mentalGameTitle || "Quick Decision",
      subtitle: currentLang === "es" ? "Elige la mejor decision tactica." : "Pick the best tactical decision.",
      rounds: buildAthleteDecisionRounds(),
      duration: Math.max(20, Number(assignment?.mentalGameDuration) || 45)
    };
  }
  if (key === MENTAL_ASSIGNMENT_GAME_KEYS.SCORE) {
    return {
      title: assignment?.mentalGameTitle || "Score Awareness",
      subtitle: currentLang === "es" ? "Lee la secuencia y detecta quien lidera." : "Track sequence and identify the leader.",
      rounds: buildAthleteScoreRounds(4),
      duration: Math.max(20, Number(assignment?.mentalGameDuration) || 45)
    };
  }
  if (key === MENTAL_ASSIGNMENT_GAME_KEYS.SWITCH) {
    return {
      title: assignment?.mentalGameTitle || "Rule Switch",
      subtitle: currentLang === "es" ? "Cambia de regla y responde rapido." : "Switch rules and respond quickly.",
      rounds: buildAthleteSwitchRounds(5),
      duration: Math.max(20, Number(assignment?.mentalGameDuration) || 40)
    };
  }
  return null;
}

function openAthleteMentalQuizGame(assignment = null) {
  return new Promise((resolve) => {
    const config = getMentalAssignmentQuizConfig(assignment);
    if (!config || !Array.isArray(config.rounds) || !config.rounds.length) {
      resolve(null);
      return;
    }
    const overlay = document.createElement("div");
    overlay.className = "athlete-game-modal-overlay";
    overlay.innerHTML = `
      <div class="athlete-game-modal-card" role="dialog" aria-modal="true" aria-label="${escapeHtml(config.title)}">
        <div class="athlete-game-modal-head">
          <div>
            <h3>${escapeHtml(config.title)}</h3>
            <p>${escapeHtml(config.subtitle)}</p>
          </div>
          <button type="button" class="athlete-game-close-btn" data-action="close" aria-label="${escapeHtml(currentLang === "es" ? "Cerrar" : "Close")}">×</button>
        </div>
        <div class="athlete-game-modal-body">
          <div class="athlete-game-modal-meta">
            <span class="chip" id="athleteQuizRoundChip">1/${escapeHtml(String(config.rounds.length))}</span>
            <span class="chip" id="athleteQuizTimeChip">${escapeHtml(`${config.duration}s`)}</span>
          </div>
          <div class="athlete-game-quiz-prompt" id="athleteQuizPrompt"></div>
          <div class="athlete-game-quiz-options" id="athleteQuizOptions"></div>
          <div class="athlete-game-result hidden" id="athleteQuizResult"></div>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);
    window.scrollTo({ top: 0, behavior: "auto" });

    const roundChip = overlay.querySelector("#athleteQuizRoundChip");
    const timeChip = overlay.querySelector("#athleteQuizTimeChip");
    const promptEl = overlay.querySelector("#athleteQuizPrompt");
    const optionsEl = overlay.querySelector("#athleteQuizOptions");
    const resultEl = overlay.querySelector("#athleteQuizResult");
    const closeBtn = overlay.querySelector("[data-action='close']");

    let settled = false;
    let roundIndex = 0;
    let correct = 0;
    const reactionTimes = [];
    let roundStartAt = performance.now();
    let timeLeft = config.duration;
    let timerId = null;

    const settle = (value) => {
      if (settled) return;
      settled = true;
      if (timerId) window.clearInterval(timerId);
      overlay.remove();
      resolve(value);
    };

    const finishQuiz = () => {
      const result = buildMentalAssignmentResultFromQuiz({
        assignment,
        label: config.title,
        correct,
        total: config.rounds.length,
        reactionTimes
      });
      if (resultEl) {
        resultEl.classList.remove("hidden");
        resultEl.innerHTML = `
          <h4>${escapeHtml(currentLang === "es" ? "Resultado del juego" : "Game result")}</h4>
          <p>${escapeHtml(currentLang === "es" ? "Puntaje mental" : "Mental score")}: <strong>${escapeHtml(result.score)}</strong></p>
          <p>${escapeHtml(currentLang === "es" ? "Precision" : "Accuracy")}: <strong>${escapeHtml(result.accuracy)}%</strong></p>
          <p>${escapeHtml(currentLang === "es" ? "Reaccion promedio" : "Average reaction")}: <strong>${escapeHtml(result.reactionMs ? formatAssignmentResultReactionSeconds(result.reactionMs) : "-")}</strong></p>
        `;
      }
      if (optionsEl) optionsEl.innerHTML = "";
      window.setTimeout(() => settle(result), 850);
    };

    const renderRound = () => {
      const round = config.rounds[roundIndex];
      if (!round) {
        finishQuiz();
        return;
      }
      if (roundChip) roundChip.textContent = `${roundIndex + 1}/${config.rounds.length}`;
      if (promptEl) promptEl.textContent = String(round.prompt || "");
      if (!optionsEl) return;
      optionsEl.innerHTML = "";
      roundStartAt = performance.now();
      round.options.forEach((option, optionIdx) => {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "ghost";
        btn.textContent = option;
        btn.addEventListener("click", () => {
          const reaction = Math.round(performance.now() - roundStartAt);
          if (Number.isFinite(reaction) && reaction > 0) {
            reactionTimes.push(reaction);
          }
          if (optionIdx === round.answerIndex) {
            correct += 1;
          }
          roundIndex += 1;
          renderRound();
        });
        optionsEl.appendChild(btn);
      });
    };

    timerId = window.setInterval(() => {
      timeLeft -= 1;
      if (timeChip) timeChip.textContent = `${Math.max(0, timeLeft)}s`;
      if (timeLeft <= 0) {
        finishQuiz();
      }
    }, 1000);

    closeBtn?.addEventListener("click", () => settle(null));
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) settle(null);
    });
    renderRound();
  });
}

function openAthleteGoNoGoAssignmentGame(assignment = null) {
  return new Promise((resolve) => {
    const safeDuration = Math.max(12, Number.isFinite(Number(assignment?.mentalGameDuration)) ? Number(assignment.mentalGameDuration) : 30);
    const gameLabel = String(assignment?.mentalGameTitle || "Go / No-Go").trim() || "Go / No-Go";
    const overlay = document.createElement("div");
    overlay.className = "athlete-game-modal-overlay";
    overlay.innerHTML = `
      <div class="athlete-game-modal-card" role="dialog" aria-modal="true" aria-label="${escapeHtml(gameLabel)}">
        <div class="athlete-game-modal-head">
          <div>
            <h3>${escapeHtml(gameLabel)}</h3>
            <p>${escapeHtml(currentLang === "es" ? "Toca VERDE. Ignora ROJO." : "Tap GREEN. Ignore RED.")}</p>
          </div>
          <button type="button" class="athlete-game-close-btn" data-action="close" aria-label="${escapeHtml(currentLang === "es" ? "Cerrar" : "Close")}">×</button>
        </div>
        <div class="athlete-game-modal-body">
          <div class="athlete-game-modal-meta">
            <span class="chip">${escapeHtml(currentLang === "es" ? `Tiempo ${safeDuration}s` : `${safeDuration}s session`)}</span>
            <span class="chip" id="athleteGameTimeChip">${escapeHtml(currentLang === "es" ? "Listo" : "Ready")}</span>
          </div>
          <button type="button" class="athlete-game-zone idle" id="athleteGameZone">
            ${escapeHtml(currentLang === "es" ? "Toca para empezar" : "Tap to start")}
          </button>
          <p class="small muted athlete-game-hint">${escapeHtml(currentLang === "es" ? "Puedes tocar cualquier parte del area de color." : "You can tap anywhere inside the color area.")}</p>
          <div class="athlete-game-stats">
            <div><span>${escapeHtml(currentLang === "es" ? "Correctos" : "Correct")}</span><strong id="athleteGameHits">0</strong></div>
            <div><span>${escapeHtml(currentLang === "es" ? "Fallos" : "Misses")}</span><strong id="athleteGameMisses">0</strong></div>
            <div><span>${escapeHtml(currentLang === "es" ? "Falsos" : "False taps")}</span><strong id="athleteGameFalse">0</strong></div>
            <div><span>${escapeHtml(currentLang === "es" ? "Reaccion prom." : "Avg reaction")}</span><strong id="athleteGameReaction">-</strong></div>
          </div>
          <div class="athlete-game-result hidden" id="athleteGameResult"></div>
        </div>
        <div class="athlete-game-modal-actions">
          <button type="button" class="ghost" data-action="cancel">${escapeHtml(currentLang === "es" ? "Cancelar" : "Cancel")}</button>
          <button type="button" class="primary hidden" id="athleteGameSubmitBtn">${escapeHtml(currentLang === "es" ? "Guardar resultado" : "Submit result")}</button>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);
    window.scrollTo({ top: 0, behavior: "auto" });

    const zoneBtn = overlay.querySelector("#athleteGameZone");
    const timeChip = overlay.querySelector("#athleteGameTimeChip");
    const hitsEl = overlay.querySelector("#athleteGameHits");
    const missesEl = overlay.querySelector("#athleteGameMisses");
    const falseEl = overlay.querySelector("#athleteGameFalse");
    const reactionEl = overlay.querySelector("#athleteGameReaction");
    const resultEl = overlay.querySelector("#athleteGameResult");
    const submitBtn = overlay.querySelector("#athleteGameSubmitBtn");
    const closeBtn = overlay.querySelector("[data-action='close']");
    const cancelBtn = overlay.querySelector("[data-action='cancel']");
    let settled = false;
    let timerId = null;
    let spawnTimerId = null;
    let stimulusTimeoutId = null;

    const session = {
      started: false,
      finished: false,
      timeLeft: safeDuration,
      hits: 0,
      misses: 0,
      falseTaps: 0,
      reactionTimes: [],
      waitingForTap: false,
      stimulus: "",
      stimulusStartAt: 0
    };

    const clearTimers = () => {
      if (timerId) clearInterval(timerId);
      if (spawnTimerId) clearTimeout(spawnTimerId);
      if (stimulusTimeoutId) clearTimeout(stimulusTimeoutId);
      timerId = null;
      spawnTimerId = null;
      stimulusTimeoutId = null;
    };

    const settle = (value) => {
      if (settled) return;
      settled = true;
      clearTimers();
      overlay.remove();
      resolve(value);
    };

    const updateStats = () => {
      if (hitsEl) hitsEl.textContent = String(session.hits);
      if (missesEl) missesEl.textContent = String(session.misses);
      if (falseEl) falseEl.textContent = String(session.falseTaps);
      const avgReaction = session.reactionTimes.length
        ? Math.round(session.reactionTimes.reduce((sum, value) => sum + value, 0) / session.reactionTimes.length)
        : 0;
      if (reactionEl) {
        reactionEl.textContent = avgReaction ? formatAssignmentResultReactionSeconds(avgReaction) : "-";
      }
    };

    const renderStimulus = () => {
      if (!zoneBtn) return;
      zoneBtn.classList.remove("green", "red", "idle");
      if (!session.started) {
        zoneBtn.classList.add("idle");
        zoneBtn.textContent = currentLang === "es" ? "Toca para empezar" : "Tap to start";
        return;
      }
      if (!session.stimulus) {
        zoneBtn.classList.add("idle");
        zoneBtn.textContent = currentLang === "es" ? "Espera..." : "Wait...";
        return;
      }
      if (session.stimulus === "green") {
        zoneBtn.classList.add("green");
        zoneBtn.textContent = currentLang === "es" ? "VERDE" : "GREEN";
        return;
      }
      zoneBtn.classList.add("red");
      zoneBtn.textContent = currentLang === "es" ? "ROJO" : "RED";
    };

    const scheduleStimulus = () => {
      if (session.finished) return;
      spawnTimerId = setTimeout(() => {
        if (session.finished) return;
        const isGo = Math.random() > 0.35;
        session.stimulus = isGo ? "green" : "red";
        session.waitingForTap = true;
        session.stimulusStartAt = performance.now();
        renderStimulus();
        stimulusTimeoutId = setTimeout(() => {
          if (session.finished) return;
          if (session.waitingForTap && session.stimulus === "green") {
            session.misses += 1;
          }
          session.waitingForTap = false;
          session.stimulus = "";
          renderStimulus();
          updateStats();
          scheduleStimulus();
        }, 650);
      }, 320 + Math.random() * 600);
    };

    const finishSession = () => {
      if (session.finished) return;
      session.finished = true;
      clearTimers();
      session.stimulus = "";
      session.waitingForTap = false;
      renderStimulus();
      const result = buildGoNoGoMentalAssignmentResult(session);
      if (resultEl) {
        resultEl.classList.remove("hidden");
        resultEl.innerHTML = `
          <h4>${escapeHtml(currentLang === "es" ? "Resultado del juego" : "Game result")}</h4>
          <p>${escapeHtml(currentLang === "es" ? "Puntaje mental" : "Mental score")}: <strong>${escapeHtml(result.score)}</strong></p>
          <p>${escapeHtml(currentLang === "es" ? "Precision" : "Accuracy")}: <strong>${escapeHtml(result.accuracy)}%</strong></p>
          <p>${escapeHtml(currentLang === "es" ? "Reaccion promedio" : "Average reaction")}: <strong>${escapeHtml(result.reactionMs ? formatAssignmentResultReactionSeconds(result.reactionMs) : "-")}</strong></p>
        `;
      }
      if (timeChip) {
        timeChip.textContent = currentLang === "es" ? "Completado" : "Completed";
      }
      if (submitBtn) submitBtn.classList.add("hidden");
      if (cancelBtn) cancelBtn.textContent = currentLang === "es" ? "Cerrar" : "Close";
      window.setTimeout(() => settle(result), 900);
    };

    const startSession = () => {
      if (session.started || session.finished) return;
      session.started = true;
      if (timeChip) timeChip.textContent = `${session.timeLeft}s`;
      renderStimulus();
      updateStats();
      scheduleStimulus();
      timerId = setInterval(() => {
        if (session.finished) return;
        session.timeLeft -= 1;
        if (timeChip) timeChip.textContent = `${Math.max(0, session.timeLeft)}s`;
        if (session.timeLeft <= 0) {
          finishSession();
        }
      }, 1000);
    };

    zoneBtn?.addEventListener("click", () => {
      if (!session.started) {
        startSession();
        return;
      }
      if (session.finished || !session.waitingForTap || !session.stimulus) return;
      if (session.stimulus === "green") {
        session.hits += 1;
        const reaction = Math.round(performance.now() - session.stimulusStartAt);
        if (Number.isFinite(reaction) && reaction > 0) {
          session.reactionTimes.push(reaction);
        }
      } else {
        session.falseTaps += 1;
      }
      session.waitingForTap = false;
      session.stimulus = "";
      renderStimulus();
      updateStats();
    });

    closeBtn?.addEventListener("click", () => settle(null));
    cancelBtn?.addEventListener("click", () => settle(null));
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) {
        settle(null);
      }
    });
  });
}

async function runAthleteMentalAssignmentTask(assignment = null) {
  if (!assignment) return false;
  const normalizedStatus = normalizeAssignmentStatus(assignment.status);
  if (normalizedStatus === "not_started") {
    await updateAthleteAssignmentStatus(assignment, "in_progress");
  }

  const gameKey = getAssignmentMentalGameKey(assignment);
  if (!SUPPORTED_MENTAL_ASSIGNMENT_KEYS.has(gameKey)) {
    await updateAthleteAssignmentStatus(assignment, "completed");
    return true;
  }

  const rawResult = gameKey === MENTAL_ASSIGNMENT_GAME_KEYS.GO_NO_GO
    ? await openAthleteGoNoGoAssignmentGame(assignment)
    : await openAthleteMentalQuizGame(assignment);
  if (!rawResult) return false;
  const completionResult = normalizeAssignmentCompletionResult({
    ...rawResult,
    type: "mental_game",
    label: assignment.mentalGameTitle || assignment.title || "Go / No-Go",
    summary: buildAssignmentCompletionResultSummary(assignment, rawResult)
  }, assignment);
  try {
    await publishGlobalMentalLeaderboardResult(gameKey, rawResult);
  } catch (err) {
    console.warn("Athlete mental leaderboard publish failed", err);
  }
  await updateAthleteAssignmentStatus(assignment, "completed", { completionResult });
  return true;
}

async function saveAthleteQuickCheckIn(score) {
  const profile = getProfile();
  const authUser = getAuthUser();
  const coachUid = getAthleteLinkedCoachUid(profile);
  const athleteId = getAthleteLinkedAthleteId(profile);
  const journalRef = getCoachWorkspaceCollectionRef("journal_entries", coachUid);
  if (!isAthleteRole(profile?.role) || !authUser?.id || !coachUid || !athleteId || !journalRef) {
    return;
  }
  const entryDate = getCurrentAppDateKey();
  const recordId = `${athleteId}-${entryDate}`;
  const cachedCheckIn = coachWorkspaceSortByUpdated(athletePortalJournalCache).find((entry) => (
    String(entry?.athleteId || "").trim() === athleteId
    && String(entry?.entryDate || "").trim() === entryDate
    && String(entry?.energy || "").trim()
  )) || null;
  if (cachedCheckIn) {
    return { saved: false, alreadyAnswered: true, entry: cachedCheckIn };
  }
  const existingSnapshot = await withTimeout(
    journalRef.doc(recordId).get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_athlete_checkin_lookup_timeout"
  ).catch(() => null);
  if (existingSnapshot?.exists) {
    const existingData = existingSnapshot.data() || {};
    if (String(existingData.energy || "").trim()) {
      return { saved: false, alreadyAnswered: true, entry: existingData };
    }
  }
  const nowIso = new Date().toISOString();
  const mood = score >= 4
    ? (currentLang === "es" ? "Ready" : "Ready")
    : (score === 3 ? (currentLang === "es" ? "Neutral" : "Neutral") : (currentLang === "es" ? "Need reset" : "Need reset"));
  const localRecord = {
    id: recordId,
    athleteId,
    athleteUid: authUser.id,
    athleteName: String(profile?.name || "").trim(),
    entryDate,
    energy: `${score}/5`,
    mood,
    updatedAt: nowIso,
    createdAt: nowIso
  };
  await withTimeout(
    journalRef.doc(recordId).set(stripUndefinedDeep({
      athleteId,
      athleteUid: authUser.id,
      athleteName: String(profile?.name || "").trim(),
      entryDate,
      energy: `${score}/5`,
      mood,
      updatedAt: getFirestoreServerTimestamp(),
      createdAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_athlete_checkin_timeout"
  );
  const currentEntries = Array.isArray(athletePortalJournalCache) ? athletePortalJournalCache : [];
  const nextEntries = currentEntries
    .map((entry) => (String(entry?.id || "").trim() === recordId ? { ...entry, ...localRecord } : entry))
    .filter((entry, index, list) => list.findIndex((item) => String(item?.id || "").trim() === String(entry?.id || "").trim()) === index);
  if (!nextEntries.some((entry) => String(entry?.id || "").trim() === recordId)) {
    nextEntries.unshift(localRecord);
  }
  athletePortalJournalCache = coachWorkspaceSortByUpdated(nextEntries);
  return { saved: true, entryDate, score, mood };
}

function renderAthleteTrackTaskList(container, records = [], { track = "wrestling" } = {}) {
  if (!container) return;
  container.innerHTML = "";
  const list = Array.isArray(records) ? records : [];
  if (!list.length) {
    const empty = document.createElement("div");
    empty.className = "small muted";
    empty.textContent = track === "mental"
      ? (currentLang === "es" ? "No hay tareas de mind & focus pendientes." : "No pending mind & focus tasks.")
      : (currentLang === "es" ? "No hay tareas de lifting pendientes." : "No pending lifting tasks.");
    container.appendChild(empty);
    return;
  }
  list.slice(0, 6).forEach((record) => {
    const card = document.createElement("div");
    const priorityMeta = getAthleteAssignmentPriorityMeta(record);
    card.className = `completion-card${priorityMeta ? " assignment-priority-card" : ""}`;
    const availability = getAssignmentAvailabilityMeta(record, athletePortalPlansCache, getCurrentAppDateKey());
    const isLocked = availability.locked;
    const statusMeta = priorityMeta || getAssignmentDisplayStatusMeta(record, athletePortalPlansCache, getCurrentAppDateKey());
    const dueLabel = record.dueLabel || formatPlanDateLabel(record.dueDateKey || getCurrentAppDateKey());
    const noteText = String(record.note || "").trim();
    const trackLabel = track === "mental"
      ? (record.mentalGameTitle || record.title || (currentLang === "es" ? "Mind & Focus" : "Mind & Focus"))
      : (record.liftingDayName || record.title || (currentLang === "es" ? "Lifting Plan" : "Lifting Plan"));
    const typeLabel = track === "mental"
      ? (currentLang === "es" ? "Tarea mental" : "Mind task")
      : (currentLang === "es" ? "Tarea de lifting" : "Lifting task");
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <h3>${escapeHtml(trackLabel)}</h3>
          <div class="small">${escapeHtml(typeLabel)} - ${escapeHtml(dueLabel)}</div>
        </div>
        <span class="status-pill ${statusMeta.className}">${statusMeta.label}</span>
      </div>
      ${noteText ? `<div class="completion-card-meta">${escapeHtml(noteText)}</div>` : ""}
    `;
    if (priorityMeta?.note) {
      const priorityNote = document.createElement("div");
      priorityNote.className = "completion-card-meta assignment-priority-note";
      priorityNote.textContent = priorityMeta.note;
      card.appendChild(priorityNote);
    }
    const actions = document.createElement("div");
    actions.className = "assignment-card-actions";
    const normalizedStatus = normalizeAssignmentStatus(record.status);
    const isPlayableMental = isPlayableAthleteMentalAssignment(record);
    if (isLocked && availability.startLabel) {
      const lockNote = document.createElement("div");
      lockNote.className = "completion-card-meta completion-card-lock";
      lockNote.textContent = currentLang === "es"
        ? `Visible ahora. Disponible el ${availability.startLabel}.`
        : `Visible now. Available on ${availability.startLabel}.`;
      card.appendChild(lockNote);
    }
    const askCoachBtn = document.createElement("button");
    askCoachBtn.type = "button";
    askCoachBtn.className = "ghost";
    askCoachBtn.textContent = currentLang === "es" ? "Preguntar al coach" : "Ask coach";
    askCoachBtn.addEventListener("click", async () => {
      const promptText = window.prompt(
        currentLang === "es"
          ? "Escribe tu pregunta para el coach:"
          : "Write your question for the coach:"
      );
      const message = String(promptText || "").trim();
      if (!message) return;
      askCoachBtn.disabled = true;
      try {
        await postAssignmentDiscussionComment(record, {
          text: message,
          notifyCoach: true
        });
        toast(currentLang === "es" ? "Pregunta enviada al coach." : "Question sent to coach.");
      } catch (err) {
        console.warn("Assignment question send failed", err);
        toast(currentLang === "es" ? "No se pudo enviar la pregunta." : "Could not send the question.");
      } finally {
        askCoachBtn.disabled = false;
      }
    });
    actions.appendChild(askCoachBtn);
    if (!isLocked && isPlayableMental) {
      const playBtn = document.createElement("button");
      playBtn.type = "button";
      playBtn.className = "primary";
      playBtn.textContent = normalizedStatus === "completed"
        ? (currentLang === "es" ? "Jugar otra vez" : "Play again")
        : (currentLang === "es" ? "Jugar y enviar" : "Play and submit");
      playBtn.addEventListener("click", async () => {
        playBtn.disabled = true;
        try {
          const completed = await runAthleteMentalAssignmentTask(record);
          if (!completed) {
            toast(currentLang === "es" ? "Juego cancelado." : "Game canceled.");
            return;
          }
          toast(currentLang === "es" ? "Juego completado y enviado al coach." : "Game completed and sent to coach.");
          refreshAthleteAssignmentUI();
        } catch (err) {
          console.warn("Athlete mental task play failed", err);
          toast(currentLang === "es" ? "No se pudo completar el juego." : "Could not complete the game.");
        } finally {
          playBtn.disabled = false;
        }
      });
      actions.appendChild(playBtn);
    } else {
      if (!isLocked && normalizedStatus === "not_started") {
        const startBtn = document.createElement("button");
        startBtn.type = "button";
        startBtn.className = "ghost";
        startBtn.textContent = track === "lifting"
          ? (currentLang === "es" ? "Iniciar entrenamiento" : "Start workout")
          : (currentLang === "es" ? "Iniciar tarea" : "Start task");
        startBtn.addEventListener("click", async () => {
          try {
            await updateAthleteAssignmentStatus(record, "in_progress");
            toast(currentLang === "es" ? "Tarea iniciada." : "Task started.");
            refreshAthleteAssignmentUI();
          } catch (err) {
            console.warn("Athlete track task start failed", err);
            toast(currentLang === "es" ? "No se pudo iniciar la tarea." : "Could not start task.");
          }
        });
        actions.appendChild(startBtn);
      }
      if (!isLocked && normalizedStatus !== "completed") {
        const completeBtn = document.createElement("button");
        completeBtn.type = "button";
        completeBtn.className = "primary";
        completeBtn.textContent = track === "lifting"
          ? (currentLang === "es" ? "Marcar entrenamiento completado" : "Mark workout completed")
          : (currentLang === "es" ? "Marcar tarea completada" : "Mark task completed");
        completeBtn.addEventListener("click", async () => {
          try {
            await updateAthleteAssignmentStatus(record, "completed");
            toast(currentLang === "es" ? "Tarea completada." : "Task completed.");
            refreshAthleteAssignmentUI();
          } catch (err) {
            console.warn("Athlete track task complete failed", err);
            toast(currentLang === "es" ? "No se pudo completar la tarea." : "Could not complete task.");
          }
        });
        actions.appendChild(completeBtn);
      }
    }
    if (actions.children.length) card.appendChild(actions);
    container.appendChild(card);
  });
}

function renderAthleteTrackTaskAreas() {
  if (!athleteTrackTaskGrid) return;
  const profile = getProfile();
  const isPortalAthlete = isAthleteRole(profile?.role) && Boolean(getAthleteLinkedCoachUid(profile));
  athleteTrackTaskGrid.classList.toggle("hidden", !isPortalAthlete);
  if (!isPortalAthlete) {
    if (athleteLiftingTasksList) athleteLiftingTasksList.innerHTML = "";
    if (athleteMindTasksList) athleteMindTasksList.innerHTML = "";
    return;
  }
  if (athleteLiftingTasksTitle) athleteLiftingTasksTitle.textContent = currentLang === "es" ? "Tareas de Lifting" : "Lifting Tasks";
  if (athleteMindTasksTitle) athleteMindTasksTitle.textContent = currentLang === "es" ? "Tareas de Mind & Focus" : "Mind & Focus Tasks";
  const liftingTasks = getAthletePortalTrackAssignments("lifting", { onlyOpen: true });
  const mentalTasks = getAthletePortalTrackAssignments("mental", { onlyOpen: true });
  if (athleteLiftingTasksCount) athleteLiftingTasksCount.textContent = String(liftingTasks.length);
  if (athleteMindTasksCount) athleteMindTasksCount.textContent = String(mentalTasks.length);
  renderAthleteTrackTaskList(athleteLiftingTasksList, liftingTasks, { track: "lifting" });
  renderAthleteTrackTaskList(athleteMindTasksList, mentalTasks, { track: "mental" });
}

function getAthleteUnreadThreadsForToday() {
  const current = getMessagesCurrentUser();
  if (!current?.uid || !Array.isArray(messagesThreadRows)) return [];
  return messagesThreadRows
    .filter((thread) => canMessageThread(current, thread))
    .filter((thread) => isMessageThreadUnread(thread, current))
    .sort((left, right) => (
      messageTimestampToMillis(right.lastMessageAt || right.updatedAt)
      - messageTimestampToMillis(left.lastMessageAt || left.updatedAt)
    ));
}

function renderTodayActionQueue() {
  if (!todayActionQueueCard || !todayActionQueueList) return;
  const profile = getProfile();
  const isPortalAthlete = isAthleteRole(profile?.role) && Boolean(getAthleteLinkedCoachUid(profile));
  todayActionQueueCard.classList.toggle("hidden", !isPortalAthlete);
  if (!isPortalAthlete) {
    todayActionQueueList.innerHTML = "";
    if (todayActionQueueCount) todayActionQueueCount.textContent = "0";
    return;
  }

  if (todayActionQueueTitle) {
    todayActionQueueTitle.textContent = currentLang === "es" ? "Pendiente ahora" : "Pending now";
  }
  if (todayActionQueueHint) {
    todayActionQueueHint.textContent = currentLang === "es"
      ? "Resuelve entrenamiento, juegos y mensajes sin salir de Today."
      : "Resolve training, games, and unread messages without leaving Today.";
  }

  const pendingAssignments = getAthleteTrainingAssignments({ includeCompleted: false })
    .filter((assignment) => (
      !isAssignmentLockedUntilScheduledDate(assignment, athletePortalPlansCache, getCurrentAppDateKey())
    ))
    .sort((left, right) => {
      const leftPriority = getAthleteAssignmentPriorityMeta(left) ? 1 : 0;
      const rightPriority = getAthleteAssignmentPriorityMeta(right) ? 1 : 0;
      if (leftPriority !== rightPriority) return rightPriority - leftPriority;
      return 0;
    });
  const unreadThreads = getAthleteUnreadThreadsForToday();
  const authUser = getAuthUser();
  const unreadNotifications = coachWorkspaceSortByUpdated(athletePortalNotificationsCache)
    .filter((record) => !isNotificationReadByUser(record, authUser?.id || ""));
  if (todayActionQueueCount) {
    todayActionQueueCount.textContent = String(pendingAssignments.length + unreadThreads.length + unreadNotifications.length);
  }

  todayActionQueueList.innerHTML = "";
  if (!pendingAssignments.length && !unreadThreads.length && !unreadNotifications.length) {
    const empty = document.createElement("div");
    empty.className = "small muted";
    empty.textContent = currentLang === "es"
      ? "Todo al dia. No hay tareas pendientes ni mensajes sin leer."
      : "All set. No pending tasks or unread messages.";
    todayActionQueueList.appendChild(empty);
    return;
  }

  pendingAssignments.slice(0, 8).forEach((assignment) => {
    const priorityMeta = getAthleteAssignmentPriorityMeta(assignment);
    const statusMeta = priorityMeta || getAssignmentStatusMeta(assignment.status);
    const normalizedStatus = normalizeAssignmentStatus(assignment.status);
    const isPlayableMental = isPlayableAthleteMentalAssignment(assignment);
    const card = document.createElement("article");
    card.className = `completion-card${priorityMeta ? " assignment-priority-card" : ""}`;
    const dueLabel = assignment.dueLabel || formatPlanDateLabel(assignment.dueDateKey || getCurrentAppDateKey());
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <h3>${escapeHtml(assignment.title || defaultPlanTitle(assignment.planType || "day"))}</h3>
          <div class="small">${escapeHtml(getTrainingTrackLabel(getAssignmentTrainingTrack(assignment)))} • ${escapeHtml(dueLabel)}</div>
        </div>
        <span class="status-pill ${statusMeta.className}">${escapeHtml(statusMeta.label)}</span>
      </div>
    `;
    if (priorityMeta?.note) {
      const priorityNote = document.createElement("div");
      priorityNote.className = "completion-card-meta assignment-priority-note";
      priorityNote.textContent = priorityMeta.note;
      card.appendChild(priorityNote);
    }
    const actions = document.createElement("div");
    actions.className = "assignment-card-actions";
    if (isPlayableMental && normalizedStatus !== "completed") {
      const playBtn = document.createElement("button");
      playBtn.type = "button";
      playBtn.className = "primary";
      playBtn.textContent = currentLang === "es" ? "Jugar y enviar" : "Play and submit";
      playBtn.addEventListener("click", async () => {
        playBtn.disabled = true;
        try {
          const completed = await runAthleteMentalAssignmentTask(assignment);
          if (!completed) {
            toast(currentLang === "es" ? "Juego cancelado." : "Game canceled.");
            return;
          }
          toast(currentLang === "es" ? "Juego completado y enviado al coach." : "Game completed and sent to coach.");
          refreshAthleteAssignmentUI();
        } catch (err) {
          console.warn("Today queue mental task failed", err);
          toast(currentLang === "es" ? "No se pudo completar el juego." : "Could not complete the game.");
        } finally {
          playBtn.disabled = false;
        }
      });
      actions.appendChild(playBtn);
    } else {
      if (normalizedStatus === "not_started") {
        const startBtn = document.createElement("button");
        startBtn.type = "button";
        startBtn.className = "ghost";
        startBtn.textContent = getAssignmentTrainingTrack(assignment) === "lifting"
          ? (currentLang === "es" ? "Iniciar entrenamiento" : "Start workout")
          : (currentLang === "es" ? "Iniciar tarea" : "Start task");
        startBtn.addEventListener("click", async () => {
          startBtn.disabled = true;
          try {
            await updateAthleteAssignmentStatus(assignment, "in_progress");
            toast(currentLang === "es" ? "Tarea iniciada." : "Task started.");
            refreshAthleteAssignmentUI();
          } catch (err) {
            console.warn("Today queue start failed", err);
            toast(currentLang === "es" ? "No se pudo iniciar la tarea." : "Could not start task.");
          } finally {
            startBtn.disabled = false;
          }
        });
        actions.appendChild(startBtn);
      }
      if (normalizedStatus !== "completed") {
        const completeBtn = document.createElement("button");
        completeBtn.type = "button";
        completeBtn.className = "primary";
        completeBtn.textContent = currentLang === "es" ? "Done" : "Done";
        completeBtn.dataset.action = "mark-assignment-done";
        completeBtn.dataset.assignmentId = assignment.id;
        completeBtn.dataset.viewerRole = "athlete";
        actions.appendChild(completeBtn);
      }
    }
    if (assignment.mediaAssetPath) {
      const mediaBtn = document.createElement("button");
      mediaBtn.type = "button";
      mediaBtn.className = "ghost";
      mediaBtn.textContent = currentLang === "es" ? "Ver media" : "Open media";
      mediaBtn.addEventListener("click", () => {
        window.open(assignment.mediaAssetPath, "_blank", "noopener,noreferrer");
      });
      actions.appendChild(mediaBtn);
    }
    if (actions.children.length) card.appendChild(actions);
    todayActionQueueList.appendChild(card);
  });

  unreadThreads.slice(0, 6).forEach((thread) => {
    const current = getMessagesCurrentUser();
    const other = getMessageOtherParticipant(thread, current?.uid || "");
    const card = document.createElement("article");
    card.className = "completion-card";
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <h3>${escapeHtml(currentLang === "es" ? "Mensaje sin leer" : "Unread message")}</h3>
          <div class="small">${escapeHtml(other.name || (currentLang === "es" ? "Contacto" : "Contact"))} • ${escapeHtml(formatMessageTimestamp(thread.lastMessageAt || thread.updatedAt) || "-")}</div>
        </div>
        <span class="status-pill status-pill-pending">${escapeHtml(currentLang === "es" ? "Leer" : "Read")}</span>
      </div>
      <div class="completion-card-meta">${escapeHtml(getMessageThreadPreviewText(thread))}</div>
    `;
    const actions = document.createElement("div");
    actions.className = "assignment-card-actions";
    const markReadBtn = document.createElement("button");
    markReadBtn.type = "button";
    markReadBtn.className = "primary";
    markReadBtn.textContent = currentLang === "es" ? "Marcar leido" : "Mark read";
    markReadBtn.addEventListener("click", () => {
      markMessageThreadSeen(thread.id, messageTimestampToMillis(thread.lastMessageAt || thread.updatedAt));
      updateMessagesUnreadIndicators();
      renderToday(getCurrentAppDayIndex());
    });
    actions.appendChild(markReadBtn);
    const openChatBtn = document.createElement("button");
    openChatBtn.type = "button";
    openChatBtn.className = "ghost";
    openChatBtn.textContent = currentLang === "es" ? "Abrir chat" : "Open chat";
    openChatBtn.addEventListener("click", () => {
      showTab("messages");
      selectMessageThread(thread.id, { openInCompact: true });
    });
    actions.appendChild(openChatBtn);
    card.appendChild(actions);
    todayActionQueueList.appendChild(card);
  });

  unreadNotifications.slice(0, 6).forEach((item) => {
    const card = document.createElement("article");
    card.className = "completion-card";
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <h3>${escapeHtml(item.title || (currentLang === "es" ? "Notificacion de tarea" : "Task notification"))}</h3>
          <div class="small">${escapeHtml(formatAdminTimestamp(item.createdAt || item.updatedAt) || "-")}</div>
        </div>
        <span class="status-pill status-pill-pending">${escapeHtml(currentLang === "es" ? "Sin leer" : "Unread")}</span>
      </div>
      <div class="completion-card-meta">${escapeHtml(item.body || "")}</div>
    `;
    const actions = document.createElement("div");
    actions.className = "assignment-card-actions";
    const markReadBtn = document.createElement("button");
    markReadBtn.type = "button";
    markReadBtn.className = "primary";
    markReadBtn.textContent = currentLang === "es" ? "Marcar leida" : "Mark as read";
    markReadBtn.addEventListener("click", async () => {
      try {
        await markWorkspaceNotificationReadById(item.id, item.coachUid || getAthleteLinkedCoachUid());
        renderToday(getCurrentAppDayIndex());
      } catch (err) {
        console.warn("Notification mark read failed", err);
      }
    });
    actions.appendChild(markReadBtn);
    if (item.assignmentId) {
      const openAssignmentBtn = document.createElement("button");
      openAssignmentBtn.type = "button";
      openAssignmentBtn.className = "ghost";
      openAssignmentBtn.textContent = currentLang === "es" ? "Ir a tareas" : "Go to tasks";
      openAssignmentBtn.addEventListener("click", () => {
        showTab("training");
      });
      actions.appendChild(openAssignmentBtn);
    }
    card.appendChild(actions);
    todayActionQueueList.appendChild(card);
  });
}

function renderToday(dayIndex = getCurrentAppDayIndex()) {
  if (isAthleteRole(getProfile()?.role)) {
    const live = buildAthletePortalTodayPlan();
    const primaryAssignment = live.assignment;
    const nextAssignment = live.nextAssignment;
    const primaryPlan = live.plan;
    const mediaContext = live.mediaContext;
    const statusMeta = primaryAssignment
      ? getAssignmentDisplayStatusMeta(primaryAssignment, athletePortalPlansCache, getCurrentAppDateKey())
      : (nextAssignment
        ? getAssignmentDisplayStatusMeta(nextAssignment, athletePortalPlansCache, getCurrentAppDateKey())
        : { label: currentLang === "es" ? "Sin tarea para hoy" : "No task today" });
    todayTitle.textContent = live.focus;
    if (primaryAssignment || nextAssignment) {
      todaySubtitle.textContent = [
        `${currentLang === "es" ? "Entrega" : "Due"}: ${(primaryAssignment?.dueLabel || live.subtitleNote || formatPlanDateLabel(getCurrentAppDateKey()))}`,
        `${currentLang === "es" ? "Estado" : "Status"}: ${statusMeta.label}`
      ].join(" - ");
    } else {
      todaySubtitle.textContent = currentLang === "es"
        ? "No hay tareas desbloqueadas para hoy."
        : "There are no unlocked tasks for today.";
    }
    todayType.textContent = live.typeLabel || statusMeta.label;
    {
      const focusValue = primaryPlan?.focus || primaryAssignment?.type || nextAssignment?.type || live.focus;
      const linkedCoach = String(getAthleteLinkedCoachName() || "").trim()
        || String(getAthletePortalLinkedAthlete()?.coachName || "").trim()
        || (currentLang === "es" ? "Sin coach" : "No coach");
      const linkedParents = getAthleteLinkedParentNames(getAthletePortalIdentity());
      const parentsLabel = linkedParents.length
        ? linkedParents.join(", ")
        : (currentLang === "es" ? "Sin padres vinculados" : "No linked parents");
      roleMeta.textContent = [
        `${currentLang === "es" ? "Training Focus" : "Training Focus"}: ${focusValue}`,
        `${currentLang === "es" ? "Coach" : "Coach"}: ${linkedCoach}`,
        `${currentLang === "es" ? "Padres" : "Parents"}: ${parentsLabel}`
      ].join(" - ");
    }
    sessionBlocks.innerHTML = "";
    if (live.blocks.length) {
      live.blocks.forEach((block) => {
        const row = document.createElement("div");
        row.className = "session-block";
        row.innerHTML = `<strong>${escapeHtml(block.label)}</strong><span>${escapeHtml(block.detail)}</span>`;
        sessionBlocks.appendChild(row);
      });
    } else {
      sessionBlocks.innerHTML = `<div class="session-block"><strong>${currentLang === "es" ? "Hoy" : "Today"}</strong><span>${escapeHtml(getAthleteNoSharedTrainingMessage())}</span></div>`;
    }
    if (startSessionBtn) startSessionBtn.disabled = !primaryAssignment;
    if (watchFilmBtn) watchFilmBtn.disabled = !mediaContext?.assetPath;
    if (logCompletionBtn) logCompletionBtn.disabled = !primaryAssignment;
    renderAthleteTrackTaskAreas();
    renderTodayActionQueue();
    renderFeelingScale();
    return;
  }

  const weekPlan = getWeekPlanData();
  const plan = weekPlan[dayIndex];
  if (!plan) return;

  todayTitle.textContent = plan.focus;
  const totalLabel = currentLang === "es" ? "Tiempo total" : "Total time";
  const intensityLabel = currentLang === "es" ? "Intensidad" : "Intensity";
  const intensity = getIntensityLabel(plan.intensity);
  todaySubtitle.textContent = `${totalLabel}: ${plan.total} - ${intensityLabel}: ${intensity}`;
  todayType.textContent = plan.focus;
  if (!isCoachRole(getProfile()?.role)) {
    const focusLabel = currentLang === "es" ? "Enfoque" : "Training Focus";
    roleMeta.textContent = `${focusLabel}: ${plan.focus}`;
  }

  sessionBlocks.innerHTML = "";
  plan.blocks.forEach((block) => {
    const row = document.createElement("div");
    row.className = "session-block";
    if ((block.blockKey === "live" || block.blockKey === "drills") && Array.isArray(block.items) && block.items.length) {
      const strong = document.createElement("strong");
      strong.textContent = block.label;
      const pillsDiv = document.createElement("div");
      pillsDiv.className = "session-pills";
      block.items.forEach((item) => {
        const pill = document.createElement("span");
        pill.className = `session-pill ${getPositionBadgeClass(item)}`;
        pill.textContent = item;
        pillsDiv.appendChild(pill);
      });
      row.appendChild(strong);
      row.appendChild(pillsDiv);
    } else {
      row.innerHTML = `<strong>${block.label}</strong><span>${block.detail}</span>`;
    }
    sessionBlocks.appendChild(row);
  });
  renderAthleteTrackTaskAreas();
  renderTodayActionQueue();
  renderFeelingScale();
}

function refreshAthleteAssignmentUI() {
  renderToday(getCurrentAppDayIndex());
  if (isAthleteRole(getProfile()?.role)) {
    renderPlanGrid(0);
  }
}

function getAthleteTodayQuickCheckInEntry() {
  if (!isAthleteRole(getProfile()?.role)) return null;
  const profile = getProfile() || {};
  const athleteId = getAthleteLinkedAthleteId(profile);
  const today = getCurrentAppDateKey();
  if (!athleteId || !today) return null;
  return coachWorkspaceSortByUpdated(athletePortalJournalCache).find((entry) => (
    String(entry?.athleteId || "").trim() === athleteId
    && String(entry?.entryDate || "").trim() === today
    && String(entry?.energy || "").trim()
  )) || null;
}

let athleteFeelingCheckInSaving = false;

function renderFeelingScale() {
  if (!feelingScale) return;
  const isAthlete = isAthleteRole(getProfile()?.role);
  if (!isAthlete) {
    if (athleteFeelingCheckin) {
      athleteFeelingCheckin.classList.add("hidden");
    }
    feelingScale.innerHTML = "";
    return;
  }
  const answeredEntry = getAthleteTodayQuickCheckInEntry();
  if (athleteFeelingCheckin) {
    athleteFeelingCheckin.classList.toggle("hidden", Boolean(answeredEntry));
  }
  feelingScale.innerHTML = "";
  if (answeredEntry) {
    return;
  }
  if (athleteFeelingCheckInSaving) {
    const loading = document.createElement("div");
    loading.className = "small muted";
    loading.textContent = currentLang === "es" ? "Guardando..." : "Saving...";
    feelingScale.appendChild(loading);
    return;
  }
  for (let i = 1; i <= 5; i++) {
    const btn = document.createElement("button");
    btn.textContent = i;
    btn.addEventListener("click", async () => {
      if (athleteFeelingCheckInSaving) return;
      athleteFeelingCheckInSaving = true;
      renderFeelingScale();
      try {
        if (isAthleteRole(getProfile()?.role) && getAthleteLinkedCoachUid()) {
          const result = await saveAthleteQuickCheckIn(i);
          if (result?.alreadyAnswered) {
            toast(currentLang === "es" ? "Ya respondiste hoy." : "You already answered today.");
          } else {
            const msg = currentLang === "es" ? `Chequeo guardado: ${i}/5` : `Check-in saved: ${i}/5`;
            toast(msg);
          }
        } else {
          const msg = currentLang === "es" ? `Chequeo guardado: ${i}/5` : `Check-in saved: ${i}/5`;
          toast(msg);
        }
      } catch (err) {
        console.warn("Athlete check-in save failed", err);
        toast(currentLang === "es" ? "No se pudo guardar el check-in." : "Could not save the check-in.");
      } finally {
        athleteFeelingCheckInSaving = false;
        renderFeelingScale();
      }
    });
    feelingScale.appendChild(btn);
  }
}

startSessionBtn.addEventListener("click", async () => {
  if (isAthleteRole(getProfile()?.role)) {
    const live = buildAthletePortalTodayPlan();
    if (!live.assignment) {
      toast(getAthleteNoSharedTrainingMessage());
      return;
    }
    const intro = currentLang === "es"
      ? `Sesion de ${live.focus}. ${live.blocks[0]?.label || ""}.`
      : `${live.focus} session. ${live.blocks[0]?.label || ""}.`;
    speak(intro);
    if (live.assignment && normalizeAssignmentStatus(live.assignment.status) === "not_started") {
      try {
        await updateAthleteAssignmentStatus(live.assignment, "in_progress");
        toast(currentLang === "es" ? "Sesion iniciada y assignment en progreso." : "Session started and assignment moved to in progress.");
      } catch (err) {
        console.warn("Athlete start session failed", err);
        toast(currentLang === "es" ? "La sesion inicio, pero no se pudo actualizar el estado." : "Session started, but the assignment status did not update.");
      }
      return;
    }
    toast(currentLang === "es" ? "Sesion iniciada. Mantente enfocado." : "Session started. Stay focused.");
    return;
  }
  const plan = getWeekPlanData()[getCurrentAppDayIndex()];
  const intro = currentLang === "es"
    ? `Sesion de ${plan.focus}. ${plan.blocks[0]?.label || ""}.`
    : `${plan.focus} session. ${plan.blocks[0]?.label || ""}.`;
  speak(intro);
  toast(currentLang === "es" ? "Sesion iniciada. Mantente enfocado." : "Session started. Stay focused.");
});

watchFilmBtn.addEventListener("click", () => {
  if (isAthleteRole(getProfile()?.role)) {
    const mediaContext = getAthletePortalMediaContext();
    if (!mediaContext?.assetPath) {
      toast(getAthleteNoSharedTrainingMessage());
      return;
    }
    window.open(mediaContext.assetPath, "_blank", "noopener,noreferrer");
    toast(currentLang === "es" ? "Abriendo film asignado." : "Opening assigned film.");
    return;
  }
  toast(currentLang === "es" ? "Video asignado: Final de pierna simple" : "Film assigned: Single Leg Finish");
});

logCompletionBtn.addEventListener("click", async () => {
  if (isAthleteRole(getProfile()?.role)) {
    const assignment = getAthletePortalPrimaryAssignment();
    if (!assignment) {
      toast(getAthleteNoSharedTrainingMessage());
      return;
    }
    try {
      if (isPlayableAthleteMentalAssignment(assignment)) {
        const completed = await runAthleteMentalAssignmentTask(assignment);
        if (!completed) {
          toast(currentLang === "es" ? "Juego cancelado." : "Game canceled.");
          return;
        }
        toast(currentLang === "es" ? "Juego completado y enviado al coach." : "Game completed and sent to coach.");
      } else {
        await updateAthleteAssignmentStatus(assignment, "completed");
        toast(currentLang === "es" ? "Assignment completado." : "Assignment completed.");
      }
    } catch (err) {
      console.warn("Athlete completion update failed", err);
      toast(currentLang === "es" ? "No se pudo registrar la completacion." : "Could not log completion.");
    }
    return;
  }
  toast(currentLang === "es" ? "Sesion registrada. Buen trabajo." : "Session logged. Great work.");
});

function renderPlanGrid(selectedDay = getCurrentAppDayIndex()) {
  if (isAthleteRole(getProfile()?.role)) {
    const allAssignments = getAthleteTrainingAssignments({ includeCompleted: true });
    const assignments = getAthleteTrainingAssignmentsForDisplay();
    renderAthleteTrainingTrackSwitch(assignments);
    athleteTrainingSelectedTrack = normalizeAthleteTrainingTrackSelection(athleteTrainingSelectedTrack);
    const trackLabel = getAthleteTrainingTrackSectionLabel(athleteTrainingSelectedTrack);
    const filteredAssignments = assignments.filter((item) => (
      getAssignmentTrainingTrack(item) === athleteTrainingSelectedTrack
    ));
    const fallbackAssignment = filteredAssignments.find((item) => normalizeAssignmentStatus(item.status) !== "completed") || filteredAssignments[0];
    const selectedId = String(athleteTrainingSelectedAssignmentId || "").trim();
    if (!selectedId || !filteredAssignments.some((item) => item.id === selectedId)) {
      athleteTrainingSelectedAssignmentId = fallbackAssignment?.id || "";
    }
    if (trainingPanelChip) {
      const completed = filteredAssignments.filter((item) => normalizeAssignmentStatus(item.status) === "completed").length;
      const open = Math.max(0, filteredAssignments.length - completed);
      trainingPanelChip.textContent = currentLang === "es"
        ? `${trackLabel} • ${open} pendientes • ${completed} completadas`
        : `${trackLabel} • ${open} pending • ${completed} done`;
    }
    planGrid.innerHTML = "";
    if (!assignments.length || !filteredAssignments.length) {
      const empty = document.createElement("div");
      empty.className = "small muted";
      empty.textContent = assignments.length
        ? (currentLang === "es" ? "No hay tareas pendientes en esta seccion." : "No pending tasks in this section.")
        : (allAssignments.length
          ? (currentLang === "es" ? "Excelente. Ya completaste todas las tareas asignadas." : "Great job. You already completed all assigned tasks.")
          : getAthleteNoSharedTrainingMessage());
      planGrid.appendChild(empty);
      renderPlanDetails("");
      renderAthleteGlobalMentalLeaderboardSection();
      return;
    }
    filteredAssignments.forEach((assignment) => {
      const card = document.createElement("div");
      const isActive = assignment.id === athleteTrainingSelectedAssignmentId;
      const normalizedStatus = normalizeAssignmentStatus(assignment.status);
      const track = getAssignmentTrainingTrack(assignment);
      const availability = getAssignmentAvailabilityMeta(assignment, athletePortalPlansCache, getCurrentAppDateKey());
      const steps = buildAthleteAssignmentChecklistSteps(assignment);
      const progress = getAssignmentChecklistProgress(assignment, steps);
      const progressText = progress.total
        ? `${progress.done}/${progress.total}`
        : (normalizedStatus === "completed" ? "1/1" : "0/1");
      const priorityMeta = getAthleteAssignmentPriorityMeta(assignment);
      const statusMeta = priorityMeta || getAssignmentDisplayStatusMeta(assignment, athletePortalPlansCache, getCurrentAppDateKey());
      card.className = `plan-card${isActive ? " active" : ""} plan-card-${normalizedStatus}${availability.locked ? " plan-card-scheduled" : ""}${priorityMeta ? " plan-card-priority" : ""}`;
      card.innerHTML = `
        <strong>${escapeHtml(assignment.title || defaultPlanTitle(assignment.planType || "day"))}</strong>
        <div class="small">${escapeHtml(getTrainingTrackLabel(track))} • ${escapeHtml(assignment.dueLabel || formatPlanDateLabel(assignment.dueDateKey || getCurrentAppDateKey()))}</div>
        <div class="small">${escapeHtml(statusMeta.label)} • ${escapeHtml(progressText)}</div>
        ${availability.locked && availability.startLabel ? `<div class="small muted">${escapeHtml(currentLang === "es" ? `Disponible el ${availability.startLabel}` : `Available on ${availability.startLabel}`)}</div>` : ""}
      `;
      card.addEventListener("click", () => {
        athleteTrainingSelectedAssignmentId = assignment.id;
        renderPlanGrid(0);
        renderPlanDetails(assignment.id);
      });
      planGrid.appendChild(card);
    });
    renderPlanDetails(athleteTrainingSelectedAssignmentId);
    renderAthleteGlobalMentalLeaderboardSection();
    return;
  }
  if (!isAthleteRole(getProfile()?.role)) {
    if (athleteTrainingTrackSwitch) athleteTrainingTrackSwitch.classList.add("hidden");
    if (athleteTrainingTrackHint) athleteTrainingTrackHint.classList.add("hidden");
  }
  renderAthleteGlobalMentalLeaderboardSection();

  if (trainingPanelChip) {
    trainingPanelChip.textContent = pickCopy(PANEL_COPY["panel-training"].chip);
  }

  if (isAthleteRole(getProfile()?.role) && getAthleteLivePlanRecords().length) {
    const planRecords = getAthleteLivePlanRecords();
    const safeIndex = Math.min(Math.max(Number(selectedDay) || 0, 0), Math.max(planRecords.length - 1, 0));
    planGrid.innerHTML = "";
    planRecords.forEach((plan, idx) => {
      const card = document.createElement("div");
      card.className = "plan-card" + (idx === safeIndex ? " active" : "");
      card.innerHTML = `
        <strong>${escapeHtml(plan.title || defaultPlanTitle(plan.type || "day"))}</strong>
        <div class="small">${escapeHtml(formatPlanRangeLabel(plan.range))}</div>
      `;
      card.addEventListener("click", () => {
        renderPlanGrid(idx);
        renderPlanDetails(idx);
      });
      planGrid.appendChild(card);
    });
    renderPlanDetails(safeIndex);
    return;
  }

  planGrid.innerHTML = "";
  const weekPlan = getWeekPlanData();
  weekPlan.forEach((plan, idx) => {
    const card = document.createElement("div");
    card.className = "plan-card" + (idx === selectedDay ? " active" : "");
    const intensity = getIntensityLabel(plan.intensity);
    card.innerHTML = `
      <strong>${plan.day}</strong>
      <div class="small">${plan.focus} - ${intensity}</div>
    `;
    card.addEventListener("click", () => {
      renderPlanGrid(idx);
      renderPlanDetails(idx);
    });
    planGrid.appendChild(card);
  });
  renderPlanDetails(selectedDay);
}

function renderPlanDetails(dayIndex) {
  if (isAthleteRole(getProfile()?.role)) {
    const allAssignments = getAthleteTrainingAssignments({ includeCompleted: true });
    const assignments = getAthleteTrainingAssignmentsForDisplay();
    const selectedTrack = normalizeAthleteTrainingTrackSelection(athleteTrainingSelectedTrack);
    const trackAssignments = assignments.filter((item) => getAssignmentTrainingTrack(item) === selectedTrack);
    if (!assignments.length || !trackAssignments.length) {
      planDayTitle.textContent = getAthleteTrainingTrackSectionLabel(selectedTrack);
      planDayDetail.innerHTML = "";
      const emptyRow = document.createElement("li");
      emptyRow.className = "small muted";
      emptyRow.textContent = assignments.length
        ? (selectedTrack === "mental"
          ? (currentLang === "es" ? "No hay tareas mentales asignadas ahora." : "No mental tasks are assigned right now.")
          : (currentLang === "es" ? "No hay tareas pendientes en esta seccion." : "No pending tasks in this section."))
        : (allAssignments.length
          ? (currentLang === "es" ? "Excelente. Ya completaste todas las tareas asignadas." : "Great job. You already completed all assigned tasks.")
          : getAthleteNoSharedTrainingMessage());
      planDayDetail.appendChild(emptyRow);
      if (selectedTrack === "mental") {
        appendAthleteMentalPracticeHub(planDayDetail);
      }
      return;
    }
    if (assignments.length) {
      let selectedAssignment = null;
      const requestedId = typeof dayIndex === "string" ? String(dayIndex || "").trim() : "";
      if (requestedId) {
        selectedAssignment = trackAssignments.find((item) => item.id === requestedId) || null;
      }
      if (!selectedAssignment && athleteTrainingSelectedAssignmentId) {
        selectedAssignment = trackAssignments.find((item) => item.id === athleteTrainingSelectedAssignmentId) || null;
      }
      if (!selectedAssignment && Number.isFinite(Number(dayIndex))) {
        selectedAssignment = trackAssignments[Math.max(0, Math.min(trackAssignments.length - 1, Number(dayIndex)))] || null;
      }
      if (!selectedAssignment) selectedAssignment = trackAssignments[0];
      athleteTrainingSelectedAssignmentId = selectedAssignment?.id || "";
      if (!selectedAssignment) return;

      const trackLabel = getAthleteTrainingTrackSectionLabel(getAssignmentTrainingTrack(selectedAssignment));
      const dueLabel = selectedAssignment.dueLabel || formatPlanDateLabel(selectedAssignment.dueDateKey || getCurrentAppDateKey());
      const availability = getAssignmentAvailabilityMeta(selectedAssignment, athletePortalPlansCache, getCurrentAppDateKey());
      const priorityMeta = getAthleteAssignmentPriorityMeta(selectedAssignment);
      const statusMeta = priorityMeta || getAssignmentDisplayStatusMeta(selectedAssignment, athletePortalPlansCache, getCurrentAppDateKey());
      planDayTitle.textContent = `${selectedAssignment.title || defaultPlanTitle(selectedAssignment.planType || "day")} (${trackLabel})`;
      planDayDetail.innerHTML = "";

      const steps = buildAthleteAssignmentChecklistSteps(selectedAssignment);
      const progress = getAssignmentChecklistProgress(selectedAssignment, steps);
      const summary = document.createElement("li");
      summary.className = "assignment-step-summary";
      const completionSummary = normalizeAssignmentStatus(selectedAssignment.status) === "completed"
        ? getAssignmentCompletionResultSummary(selectedAssignment)
        : "";
      summary.textContent = currentLang === "es"
        ? `${statusMeta.label} • Entrega: ${dueLabel} • Completado: ${progress.done}/${progress.total || 1}${completionSummary ? ` • Resultado: ${completionSummary}` : ""}`
        : `${statusMeta.label} • Due: ${dueLabel} • Completed: ${progress.done}/${progress.total || 1}${completionSummary ? ` • Result: ${completionSummary}` : ""}`;
      planDayDetail.appendChild(summary);

      if (priorityMeta?.note) {
        const priorityNotice = document.createElement("li");
        priorityNotice.className = "assignment-step-summary assignment-priority-note";
        priorityNotice.textContent = priorityMeta.note;
        planDayDetail.appendChild(priorityNotice);
      }

      if (availability.locked && availability.startLabel) {
        const lockNotice = document.createElement("li");
        lockNotice.className = "assignment-step-summary";
        lockNotice.textContent = currentLang === "es"
          ? `Esta tarea ya esta asignada, pero no se puede iniciar hasta el ${availability.startLabel}.`
          : `This task is already assigned, but it cannot be started until ${availability.startLabel}.`;
        planDayDetail.appendChild(lockNotice);
      }

      const selectedStatus = normalizeAssignmentStatus(selectedAssignment.status);
      const canPlayMental = !availability.locked && isPlayableAthleteMentalAssignment(selectedAssignment);
      if (canPlayMental || (!availability.locked && selectedStatus !== "completed")) {
        const actionRow = document.createElement("li");
        actionRow.className = "assignment-step-summary";
        const actions = document.createElement("div");
        actions.className = "assignment-card-actions";
        if (canPlayMental) {
          const playBtn = document.createElement("button");
          playBtn.type = "button";
          playBtn.className = "primary";
          playBtn.textContent = selectedStatus === "completed"
            ? (currentLang === "es" ? "Jugar otra vez" : "Play again")
            : (currentLang === "es" ? "Jugar y enviar" : "Play and submit");
          playBtn.addEventListener("click", async () => {
            playBtn.disabled = true;
            try {
              const completed = await runAthleteMentalAssignmentTask(selectedAssignment);
              if (!completed) {
                toast(currentLang === "es" ? "Juego cancelado." : "Game canceled.");
                return;
              }
              toast(currentLang === "es" ? "Juego completado y enviado al coach." : "Game completed and sent to coach.");
              refreshAthleteAssignmentUI();
            } catch (err) {
              console.warn("Plan details mental task failed", err);
              toast(currentLang === "es" ? "No se pudo completar el juego." : "Could not complete the game.");
            } finally {
              playBtn.disabled = false;
            }
          });
          actions.appendChild(playBtn);
        } else {
          if (normalizeAssignmentStatus(selectedAssignment.status) === "not_started") {
            const startBtn = document.createElement("button");
            startBtn.type = "button";
            startBtn.className = "ghost";
            startBtn.textContent = getAssignmentTrainingTrack(selectedAssignment) === "lifting"
              ? (currentLang === "es" ? "Iniciar entrenamiento" : "Start workout")
              : (currentLang === "es" ? "Iniciar tarea" : "Start task");
            startBtn.addEventListener("click", async () => {
              startBtn.disabled = true;
              try {
                await updateAthleteAssignmentStatus(selectedAssignment, "in_progress");
                toast(currentLang === "es" ? "Tarea iniciada." : "Task started.");
                refreshAthleteAssignmentUI();
              } catch (err) {
                console.warn("Plan details assignment start failed", err);
                toast(currentLang === "es" ? "No se pudo iniciar la tarea." : "Could not start task.");
              } finally {
                startBtn.disabled = false;
              }
            });
            actions.appendChild(startBtn);
          }
          const completeBtn = document.createElement("button");
          completeBtn.type = "button";
          completeBtn.className = "primary";
          completeBtn.textContent = currentLang === "es" ? "Done" : "Done";
          completeBtn.dataset.action = "mark-assignment-done";
          completeBtn.dataset.assignmentId = selectedAssignment.id;
          completeBtn.dataset.viewerRole = "athlete";
          actions.appendChild(completeBtn);
        }
        actionRow.appendChild(actions);
        planDayDetail.appendChild(actionRow);
      }

      if (selectedTrack === "mental") {
        appendAthleteMentalPracticeHub(planDayDetail);
      }

      steps.forEach((step) => {
        const li = document.createElement("li");
        const checked = Boolean(progress.checklist[step.id]) || normalizeAssignmentStatus(selectedAssignment.status) === "completed";
        li.className = `assignment-step${checked ? " is-done" : ""}`;
        const label = document.createElement("div");
        label.className = "assignment-step-row assignment-step-row-readonly";
        const marker = document.createElement("span");
        marker.className = "assignment-step-readonly-indicator";
        marker.textContent = checked ? "✓" : "○";
        const text = document.createElement("span");
        text.className = "assignment-step-label";
        text.textContent = step.label;
        label.appendChild(marker);
        label.appendChild(text);
        li.appendChild(label);
        planDayDetail.appendChild(li);
      });

      const discussionShell = document.createElement("li");
      discussionShell.className = "assignment-discussion-shell";
      const discussionRows = normalizeAssignmentDiscussion(selectedAssignment.discussion || []);
      const discussionTitle = document.createElement("h4");
      discussionTitle.className = "assignment-discussion-title";
      discussionTitle.textContent = currentLang === "es"
        ? `Comentarios de la tarea (${discussionRows.length})`
        : `Task comments (${discussionRows.length})`;
      discussionShell.appendChild(discussionTitle);

      const discussionList = document.createElement("div");
      discussionList.className = "assignment-discussion-list";
      if (!discussionRows.length) {
        const emptyRow = document.createElement("p");
        emptyRow.className = "small muted";
        emptyRow.textContent = currentLang === "es"
          ? "No hay comentarios todavia."
          : "No comments yet.";
        discussionList.appendChild(emptyRow);
      } else {
        discussionRows.slice(-6).forEach((entry) => {
          const row = document.createElement("article");
          row.className = `assignment-discussion-entry${normalizeUid(entry.authorUid) === normalizeUid(getAuthUser()?.id) ? " mine" : ""}`;
          const roleLabel = getRoleLabelEnglish(entry.authorRole || "athlete");
          row.innerHTML = `
            <div class="assignment-discussion-entry-head">
              <strong>${escapeHtml(entry.authorName || "User")}</strong>
              <span>${escapeHtml(roleLabel)} • ${escapeHtml(formatAssignmentDiscussionTime(entry.createdAtIso) || "-")}</span>
            </div>
            ${entry.stepLabel ? `<div class="assignment-discussion-step">${escapeHtml(entry.stepLabel)}</div>` : ""}
            <p>${escapeHtml(entry.text || "")}</p>
          `;
          discussionList.appendChild(row);
        });
      }
      discussionShell.appendChild(discussionList);
      planDayDetail.appendChild(discussionShell);
      return;
    }
  }

  if (isAthleteRole(getProfile()?.role) && getAthleteLivePlanRecords().length) {
    const plan = getAthleteLivePlanRecords()[dayIndex];
    if (!plan) return;
    planDayTitle.textContent = plan.title || defaultPlanTitle(plan.type || "day");
    planDayDetail.innerHTML = "";
    buildAthletePlanDetailLines(plan).forEach((line) => {
      const li = document.createElement("li");
      li.textContent = line;
      planDayDetail.appendChild(li);
    });
    if (!planDayDetail.children.length && plan.focus) {
      const li = document.createElement("li");
      li.textContent = plan.focus;
      planDayDetail.appendChild(li);
    }
    return;
  }
  const plan = getWeekPlanData()[dayIndex];
  if (!plan) return;
  planDayTitle.textContent = currentLang === "es" ? `Plan de ${plan.day}` : `${plan.day} Plan`;
  planDayDetail.innerHTML = "";
  plan.details.forEach((line) => {
    const li = document.createElement("li");
    li.textContent = line;
    planDayDetail.appendChild(li);
  });
}

