let mediaActiveSectionId = null;
let mediaToolsBound = false;
let selectedMediaItemId = "";
let mediaTreeCache = null;
let mediaSyncTimeout = null;
let mediaRealtimeUnsub = null;
let mediaRealtimeUserId = "";

function mediaCopy(key) {
  return pickCopy(MEDIA_COPY[key] || { en: key, es: key });
}

function isAbsoluteUrl(value) {
  return /^https?:\/\//i.test(String(value || "").trim());
}

function normalizeMediaAssetPath(value) {
  return String(value || "").trim();
}

function joinMediaUrl(base, path) {
  const normalizedBase = String(base || "").trim().replace(/\/+$/, "");
  const normalizedPath = String(path || "").trim().replace(/^\/+/, "");
  if (!normalizedBase || !normalizedPath) return "";
  return `${normalizedBase}/${normalizedPath}`;
}

function resolveMediaLocation(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  if (isAbsoluteUrl(raw)) return raw;
  return joinMediaUrl(MEDIA_BASE_URL, raw);
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function makeMediaId(prefix) {
  const seed = Math.random().toString(36).slice(2, 8);
  return `${prefix}_${Date.now().toString(36)}_${seed}`;
}

function buildDefaultMediaTree() {
  const items = getMediaItemsData();
  const nodes = [];
  const sectionIds = new Map();

  items.forEach((item) => {
    const sectionName = item.tag || mediaCopy("root");
    let sectionId = sectionIds.get(sectionName);
    if (!sectionId) {
      sectionId = makeMediaId("sec");
      sectionIds.set(sectionName, sectionId);
      nodes.push({
        id: sectionId,
        type: "section",
        name: sectionName,
        parentId: null
      });
    }

    nodes.push({
      id: makeMediaId("item"),
      type: "item",
      title: item.title,
      mediaType: item.type,
      assetPath: normalizeMediaAssetPath(item.assetPath || item.assetUrl || item.url || ""),
      thumbnailPath: normalizeMediaAssetPath(item.thumbnailPath || item.thumbnailUrl || ""),
      duration: String(item.duration || ""),
      assigned: item.assigned,
      note: String(item.note || ""),
      parentId: sectionId
    });
  });

  return { nodes };
}

function ensureYoutubeMediaNode(nodes) {
  if (PUBLISH_READY_MODE) return Array.isArray(nodes) ? nodes.slice() : [];
  const working = Array.isArray(nodes) ? nodes.slice() : [];
  const targetUrl = "https://www.flowrestling.org/training?playing=7965907";
  const normalizedTarget = normalizeMediaAssetPath(targetUrl);
  const exists = working.some(
    (node) =>
      node.type === "item" &&
      normalizeMediaAssetPath(node.assetPath || node.assetUrl || node.url || "") === normalizedTarget
  );
  if (exists) return working;

  const normalizeText = (value) => String(value || "").trim().toLowerCase();
  const sectionNames = new Set(["featured", "destacado"]);
  let section = working.find(
    (node) => node.type === "section" && node.parentId === null && sectionNames.has(normalizeText(node.name))
  );

  if (!section) {
    section = {
      id: makeMediaId("sec"),
      type: "section",
      name: currentLang === "es" ? "Destacado" : "Featured",
      parentId: null
    };
    working.push(section);
  }

  working.push({
    id: makeMediaId("item"),
    type: "item",
    title: currentLang === "es" ? "Final de pierna simple - Coach Chewy" : "Single Leg Finish - Coach Chewy",
    mediaType: currentLang === "es" ? "Video" : "Video",
    assetPath: targetUrl,
    thumbnailPath: "",
    duration: "",
    assigned: currentLang === "es" ? "Esta semana" : "This week",
    note: currentLang === "es"
      ? "Recurso destacado para finalizacion de single leg."
      : "Featured resource for single-leg finishes.",
    parentId: section.id
  });

  return working;
}

function ensureDemoMediaNodes(nodes) {
  if (PUBLISH_READY_MODE) return Array.isArray(nodes) ? nodes.slice() : [];
  const legacyTarget = normalizeMediaAssetPath("https://www.youtube.com/watch?v=FHHOgZ3QTSY");
  const working = (Array.isArray(nodes) ? nodes : []).filter((node) => {
    if (node?.type !== "item") return true;
    const asset = normalizeMediaAssetPath(node.assetPath || node.assetUrl || node.url || "");
    const title = String(node.title || "").toLowerCase();
    return asset !== legacyTarget && !title.includes("trailer oficial");
  });

  const sectionIds = new Map();
  working.forEach((node) => {
    if (node?.type === "section") {
      sectionIds.set(String(node.name || "").trim().toLowerCase(), node.id);
    }
  });

  getMediaItemsData().forEach((item) => {
    const normalizedAsset = normalizeMediaAssetPath(item.assetPath || item.assetUrl || item.url || "");
    const exists = working.some((node) => {
      if (node?.type !== "item") return false;
      const nodeAsset = normalizeMediaAssetPath(node.assetPath || node.assetUrl || node.url || "");
      return String(node.title || "").trim() === String(item.title || "").trim()
        || (normalizedAsset && nodeAsset === normalizedAsset);
    });
    if (exists) return;

    const sectionName = String(item.tag || mediaCopy("root")).trim();
    const sectionKey = sectionName.toLowerCase();
    let sectionId = sectionIds.get(sectionKey);
    if (!sectionId) {
      sectionId = makeMediaId("sec");
      sectionIds.set(sectionKey, sectionId);
      working.push({
        id: sectionId,
        type: "section",
        name: sectionName,
        parentId: null
      });
    }

    working.push({
      id: makeMediaId("item"),
      type: "item",
      title: item.title,
      mediaType: item.type,
      assetPath: normalizedAsset,
      thumbnailPath: normalizeMediaAssetPath(item.thumbnailPath || item.thumbnailUrl || ""),
      duration: String(item.duration || ""),
      assigned: item.assigned,
      note: String(item.note || ""),
      parentId: sectionId
    });
  });

  return working;
}

function normalizeMediaNode(node) {
  if (!node || typeof node !== "object") return null;
  const type = node.type === "item" ? "item" : "section";
  const id = String(node.id || makeMediaId(type === "item" ? "item" : "sec"));
  const parentId = node.parentId ? String(node.parentId) : null;

  if (type === "section") {
    const name = String(node.name || "").trim();
    if (!name) return null;
    return { id, type, name, parentId };
  }

  const title = String(node.title || "").trim();
  if (!title) return null;
  const rawAssetPath = node.assetPath || node.assetUrl || node.url || "";
  const rawThumbnailPath = node.thumbnailPath || node.thumbnailUrl || "";
  return {
    id,
    type,
    title,
    mediaAssetId: String(node.mediaAssetId || "").trim(),
    mediaType: String(node.mediaType || node.typeLabel || "Video"),
    assetPath: normalizeMediaAssetPath(rawAssetPath),
    assetStoragePath: String(node.assetStoragePath || "").trim(),
    thumbnailPath: normalizeMediaAssetPath(rawThumbnailPath),
    thumbnailStoragePath: String(node.thumbnailStoragePath || "").trim(),
    duration: String(node.duration || ""),
    assigned: String(node.assigned || ""),
    note: String(node.note || ""),
    tags: normalizeLooseTagList(node.tags || []),
    parentId
  };
}

function normalizeMediaTree(tree) {
  if (!tree || typeof tree !== "object") return { nodes: [] };
  const rawNodes = Array.isArray(tree.nodes) ? tree.nodes : [];
  const nodes = rawNodes.map((node) => normalizeMediaNode(node)).filter(Boolean);
  return { nodes };
}

function sanitizeMediaFileName(name) {
  const raw = String(name || "").trim().toLowerCase();
  const replaced = raw.replace(/[^a-z0-9._-]+/g, "-").replace(/-+/g, "-");
  return replaced.replace(/^-+|-+$/g, "") || `media-${Date.now()}`;
}

function inferMediaTitleFromFile(file) {
  if (!file?.name) return "";
  return file.name.replace(/\.[^/.]+$/, "").replace(/[_-]+/g, " ").trim();
}

function inferMediaTypeFromFile(file) {
  const fileType = String(file?.type || "").toLowerCase();
  if (fileType.startsWith("image/")) return "Photo";
  if (fileType.startsWith("video/")) return "Video";
  if (fileType.startsWith("audio/")) return "Audio";
  return "Link";
}

function readFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(new Error("file_read_failed"));
    reader.readAsDataURL(file);
  });
}

function getMediaUploadOwnerId() {
  const firebaseUid = String(firebaseAuthInstance?.currentUser?.uid || "").trim();
  if (firebaseUid) return firebaseUid;
  const authUser = getAuthUser();
  if (!authUser?.id) {
    throw new Error("auth_required");
  }
  return String(authUser.id);
}

function getMediaUploadPath(fileName, kind = "assets") {
  const root = WPL_MEDIA_UPLOADS_ROOT || "media_uploads";
  const ownerId = getMediaUploadOwnerId();
  const safeKind = String(kind || "assets").trim().replace(/[^a-z0-9_-]+/gi, "-") || "assets";
  const safeName = sanitizeMediaFileName(fileName);
  return `${root}/${ownerId}/${safeKind}/${Date.now()}-${safeName}`;
}

function getActiveCoachWorkspaceUidForMedia() {
  const profile = getProfile();
  const authUser = getAuthUser();
  if (isCoachRole(profile?.role) && authUser?.id) return String(authUser.id || "").trim();
  if (isAthleteRole(profile?.role)) return String(getAthleteLinkedCoachUid(profile) || "").trim();
  if (isParentRole(profile?.role)) return String(getParentLinkedCoachUid(profile) || "").trim();
  return "";
}

function buildMediaAssetId(assetStoragePath = "", assetPath = "") {
  const seed = String(assetStoragePath || assetPath || "").trim();
  if (!seed) return makeMediaId("asset");
  return `asset-${slugifyKey(seed).slice(0, 72)}`;
}

function findKnownMediaAssetByStoragePath(assetStoragePath = "") {
  const safePath = String(assetStoragePath || "").trim();
  if (!safePath) return null;
  return coachMediaAssetsCache.find((record) => String(record.assetStoragePath || "").trim() === safePath) || null;
}

async function registerMediaAssetInWorkspace({
  file = null,
  assetPath = "",
  assetStoragePath = "",
  thumbnailPath = "",
  thumbnailStoragePath = "",
  source = "media",
  mediaType = "",
  existingMediaAssetId = "",
  tags = []
} = {}) {
  const coachUid = getActiveCoachWorkspaceUidForMedia();
  const collectionRef = getCoachWorkspaceCollectionRef(COACH_WORKSPACE_MEDIA_ASSETS_COLLECTION, coachUid);
  if (!coachUid || !collectionRef) return "";
  const known = findKnownMediaAssetByStoragePath(assetStoragePath);
  const mediaAssetId = String(existingMediaAssetId || known?.id || buildMediaAssetId(assetStoragePath, assetPath)).trim();
  if (!mediaAssetId) return "";
  const authUser = getAuthUser();
  const payload = stripUndefinedDeep({
    mediaAssetId,
    coachUid,
    ownerUid: String(authUser?.id || "").trim(),
    title: inferMediaTitleFromFile(file) || String(file?.name || "").trim() || String(known?.title || "").trim(),
    mediaType: String(mediaType || inferMediaTypeFromFile(file) || known?.mediaType || "").trim() || "Video",
    source: String(source || "media").trim(),
    assetPath: String(assetPath || "").trim(),
    assetStoragePath: String(assetStoragePath || "").trim(),
    thumbnailPath: String(thumbnailPath || "").trim(),
    thumbnailStoragePath: String(thumbnailStoragePath || "").trim(),
    tags: normalizeLooseTagList([...(known?.tags || []), ...normalizeLooseTagList(tags || [])]),
    usedBy: uniqueNames([...(known?.usedBy || []), String(source || "media").trim()]),
    createdAt: known?.createdAt ? undefined : getFirestoreServerTimestamp(),
    updatedAt: getFirestoreServerTimestamp()
  });
  await withTimeout(
    collectionRef.doc(mediaAssetId).set(payload, { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_media_asset_write_timeout"
  ).catch((err) => {
    console.warn("Media asset registration failed", err);
  });
  if (!known) {
    coachMediaAssetsCache = coachWorkspaceSortByUpdated([
      normalizeMediaAssetRecord(mediaAssetId, {
        ...payload,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      }),
      ...coachMediaAssetsCache
    ]);
  }
  return mediaAssetId;
}

function getScaledMediaDimensions(width, height, maxEdge = MEDIA_THUMBNAIL_MAX_EDGE) {
  const safeWidth = Math.max(1, Number(width) || maxEdge);
  const safeHeight = Math.max(1, Number(height) || maxEdge);
  const scale = Math.min(1, maxEdge / Math.max(safeWidth, safeHeight));
  return {
    width: Math.max(1, Math.round(safeWidth * scale)),
    height: Math.max(1, Math.round(safeHeight * scale))
  };
}

function canvasToBlob(canvas, type = "image/jpeg", quality = MEDIA_THUMBNAIL_QUALITY) {
  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) {
        resolve(blob);
      } else {
        reject(new Error("thumbnail_blob_failed"));
      }
    }, type, quality);
  });
}

function waitForDomEvent(target, successEvent, errorEvent = "error", timeoutMs = FIREBASE_OP_TIMEOUT_MS) {
  return new Promise((resolve, reject) => {
    let settled = false;
    const timeoutId = setTimeout(() => {
      cleanup();
      reject(new Error("media_event_timeout"));
    }, timeoutMs);
    const cleanup = () => {
      clearTimeout(timeoutId);
      if (successEvent) target.removeEventListener(successEvent, onSuccess);
      if (errorEvent) target.removeEventListener(errorEvent, onError);
    };
    const onSuccess = () => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };
    const onError = () => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("media_event_failed"));
    };
    if (successEvent) target.addEventListener(successEvent, onSuccess, { once: true });
    if (errorEvent) target.addEventListener(errorEvent, onError, { once: true });
  });
}

async function createImageThumbnailBlob(file) {
  const objectUrl = URL.createObjectURL(file);
  try {
    const image = await new Promise((resolve, reject) => {
      const nextImage = new Image();
      nextImage.onload = () => resolve(nextImage);
      nextImage.onerror = () => reject(new Error("image_thumbnail_load_failed"));
      nextImage.src = objectUrl;
    });
    const { width, height } = getScaledMediaDimensions(image.naturalWidth || image.width, image.naturalHeight || image.height);
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) {
      throw new Error("thumbnail_context_missing");
    }
    context.drawImage(image, 0, 0, width, height);
    return canvasToBlob(canvas);
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

async function createVideoThumbnailBlob(file) {
  const objectUrl = URL.createObjectURL(file);
  const video = document.createElement("video");
  video.preload = "metadata";
  video.muted = true;
  video.playsInline = true;
  video.src = objectUrl;
  try {
    await waitForDomEvent(video, "loadeddata");
    const captureTime = Number.isFinite(video.duration) && video.duration > 0.6
      ? Math.min(video.duration / 3, 1)
      : 0;
    if (captureTime > 0.05) {
      video.currentTime = captureTime;
      await waitForDomEvent(video, "seeked");
    }
    const { width, height } = getScaledMediaDimensions(video.videoWidth || 640, video.videoHeight || 360);
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) {
      throw new Error("thumbnail_context_missing");
    }
    context.drawImage(video, 0, 0, width, height);
    return canvasToBlob(canvas);
  } finally {
    video.pause();
    video.removeAttribute("src");
    video.load();
    URL.revokeObjectURL(objectUrl);
  }
}

async function createMediaThumbnailBlob(file) {
  const fileType = String(file?.type || "").toLowerCase();
  if (fileType.startsWith("image/")) {
    return createImageThumbnailBlob(file);
  }
  if (fileType.startsWith("video/")) {
    return createVideoThumbnailBlob(file);
  }
  return null;
}

function getMediaBaseName(fileName) {
  return String(fileName || "").replace(/\.[^/.]+$/, "") || `media-${Date.now()}`;
}

async function uploadBlobToFirebase(blob, fileName, { kind = "assets", contentType = "", customMetadata = {} } = {}) {
  if (!firebaseStorageInstance) {
    throw new Error("storage_not_configured");
  }
  if (!blob) {
    throw new Error("missing_file");
  }
  const uploadPath = getMediaUploadPath(fileName, kind);
  const ref = firebaseStorageInstance.ref().child(uploadPath);
  const metadata = stripUndefinedDeep({
    contentType: contentType || blob.type || "application/octet-stream",
    customMetadata
  });
  const taskSnapshot = await withTimeout(
    ref.put(blob, metadata),
    STORAGE_UPLOAD_TIMEOUT_MS,
    "storage_upload_timeout"
  );
  const downloadURL = await withTimeout(
    taskSnapshot.ref.getDownloadURL(),
    FIREBASE_OP_TIMEOUT_MS,
    "storage_download_url_timeout"
  );
  return {
    downloadURL,
    fullPath: uploadPath,
    contentType: metadata.contentType || "",
    size: Number(blob.size || 0)
  };
}

async function uploadMediaAssetBundleToFirebase(file, { generateThumbnail = true } = {}) {
  const assetUpload = await uploadBlobToFirebase(file, file.name, {
    kind: "assets",
    contentType: file.type || "application/octet-stream",
    customMetadata: {
      uploaderUid: getAuthUser()?.id || "",
      source: "wpl-web-app"
    }
  });
  let thumbnailPath = "";
  let thumbnailStoragePath = "";
  if (generateThumbnail) {
    try {
      const thumbnailBlob = await createMediaThumbnailBlob(file);
      if (thumbnailBlob) {
        const thumbnailUpload = await uploadBlobToFirebase(
          thumbnailBlob,
          `${getMediaBaseName(file.name)}-thumb.jpg`,
          {
            kind: "thumbnails",
            contentType: "image/jpeg",
            customMetadata: {
              uploaderUid: getAuthUser()?.id || "",
              sourceAssetPath: assetUpload.fullPath
            }
          }
        );
        thumbnailPath = thumbnailUpload.downloadURL;
        thumbnailStoragePath = thumbnailUpload.fullPath;
      }
    } catch (err) {
      console.warn("Thumbnail upload skipped", err);
    }
  }
  const mediaAssetId = await registerMediaAssetInWorkspace({
    file,
    assetPath: assetUpload.downloadURL,
    assetStoragePath: assetUpload.fullPath,
    thumbnailPath,
    thumbnailStoragePath,
    source: "upload",
    mediaType: inferMediaTypeFromFile(file)
  });
  return {
    mediaAssetId,
    assetPath: assetUpload.downloadURL,
    assetStoragePath: assetUpload.fullPath,
    thumbnailPath,
    thumbnailStoragePath
  };
}

function getMediaTreeFromLocalStorage() {
  try {
    const raw = localStorage.getItem(MEDIA_TREE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return normalizeMediaTree(parsed);
  } catch {
    return null;
  }
}

function cacheAndPersistMediaTreeLocally(tree) {
  const normalized = normalizeMediaTree(tree);
  const mergedNodes = ensureDemoMediaNodes(ensureYoutubeMediaNode(normalized.nodes));
  const ready = mergedNodes.length ? { nodes: mergedNodes } : buildDefaultMediaTree();
  mediaTreeCache = ready;
  localStorage.setItem(MEDIA_TREE_KEY, JSON.stringify(ready));
  return ready;
}

function stopMediaRealtimeSync() {
  if (mediaRealtimeUnsub) {
    mediaRealtimeUnsub();
    mediaRealtimeUnsub = null;
  }
  mediaRealtimeUserId = "";
}

async function hydrateMediaTreeFromSharedStore() {
  const authUser = getAuthUser();
  if (!firebaseFirestoreInstance || !authUser?.id) {
    if (mediaTreeCache) return mediaTreeCache;
    const local = getMediaTreeFromLocalStorage();
    if (local) return cacheAndPersistMediaTreeLocally(local);
    return cacheAndPersistMediaTreeLocally(buildDefaultMediaTree());
  }

  const remote = await fetchSharedMediaTreeDoc();
  if (remote && Array.isArray(remote.nodes) && remote.nodes.length) {
    return cacheAndPersistMediaTreeLocally({ nodes: remote.nodes });
  }

  const local = getMediaTreeFromLocalStorage();
  const seeded = cacheAndPersistMediaTreeLocally(local || buildDefaultMediaTree());
  await persistSharedMediaTreeDoc(
    {
      nodes: seeded.nodes,
      updatedAt: new Date().toISOString(),
      updatedBy: authUser.id
    },
    { required: false }
  );
  return seeded;
}

function queueSharedMediaTreeSync(tree) {
  const authUser = getAuthUser();
  if (!firebaseFirestoreInstance || !authUser?.id) return;
  if (mediaSyncTimeout) clearTimeout(mediaSyncTimeout);
  mediaSyncTimeout = setTimeout(() => {
    persistSharedMediaTreeDoc(
      {
        nodes: tree.nodes,
        updatedAt: new Date().toISOString(),
        updatedBy: authUser.id
      },
      { required: false }
    ).catch((err) => {
      console.warn("Background media tree sync failed", err);
    });
  }, 350);
}

function startMediaRealtimeSync() {
  const authUser = getAuthUser();
  if (!firebaseFirestoreInstance || !authUser?.id) {
    stopMediaRealtimeSync();
    return;
  }

  if (mediaRealtimeUnsub && mediaRealtimeUserId === authUser.id) return;
  stopMediaRealtimeSync();
  mediaRealtimeUserId = authUser.id;

  const ref = getSharedMediaTreeDocRef();
  if (!ref) return;
  mediaRealtimeUnsub = ref.onSnapshot(
    (doc) => {
      if (!doc.exists) return;
      const data = doc.data();
      if (!data || !Array.isArray(data.nodes)) return;
      cacheAndPersistMediaTreeLocally({ nodes: data.nodes });
      if (!appRoot?.classList.contains("hidden")) {
        renderMedia();
      }
    },
    (err) => {
      console.warn("Media realtime sync listener failed", err);
    }
  );
}

async function uploadMediaFileToFirebase(file) {
  const upload = await uploadMediaAssetBundleToFirebase(file, { generateThumbnail: false });
  return upload.assetPath;
}

function getStoredMediaTree() {
  if (mediaTreeCache) return mediaTreeCache;
  const local = getMediaTreeFromLocalStorage();
  if (local) return cacheAndPersistMediaTreeLocally(local);
  return cacheAndPersistMediaTreeLocally(buildDefaultMediaTree());
}

function setStoredMediaTree(tree) {
  const normalized = cacheAndPersistMediaTreeLocally(tree);
  queueSharedMediaTreeSync(normalized);
  return normalized;
}

function getMediaNodes() {
  return getStoredMediaTree().nodes;
}

function setMediaNodes(nodes) {
  return setStoredMediaTree({ nodes }).nodes;
}

function findMediaNode(nodes, id) {
  return nodes.find((node) => node.id === id) || null;
}

function getMediaChildren(nodes, parentId, type) {
  return nodes.filter((node) => node.parentId === parentId && (!type || node.type === type));
}

function ensureMediaActiveSection(nodes) {
  if (!mediaActiveSectionId) return;
  const active = findMediaNode(nodes, mediaActiveSectionId);
  if (!active || active.type !== "section") {
    mediaActiveSectionId = null;
  }
}

function getMediaPath(nodes, sectionId) {
  const path = [];
  let current = sectionId ? findMediaNode(nodes, sectionId) : null;
  while (current && current.type === "section") {
    path.unshift(current);
    current = current.parentId ? findMediaNode(nodes, current.parentId) : null;
  }
  return path;
}

function countSectionChildren(nodes, sectionId) {
  const sections = getMediaChildren(nodes, sectionId, "section").length;
  const items = getMediaChildren(nodes, sectionId, "item").length;
  return { sections, items };
}

function sectionMetaText(counts) {
  const sectionsWord = mediaCopy("sectionsCount");
  const itemsWord = mediaCopy("itemsCount");
  return `${counts.sections} ${sectionsWord} - ${counts.items} ${itemsWord}`;
}

function syncSelectedMediaNode(nodes = getMediaNodes()) {
  const selected = findMediaNode(nodes, selectedMediaItemId);
  if (selected?.type === "item") return selected;
  const sectionItems = getMediaChildren(nodes, mediaActiveSectionId, "item");
  const fallback = sectionItems[0] || nodes.find((node) => node.type === "item") || null;
  selectedMediaItemId = fallback?.id || "";
  return fallback;
}

function getMediaAssignmentTargetOptions(mode = mediaAssignmentMode?.value || "athlete") {
  if (mode === "group") {
    return getCoachGroupRecords().map((group) => ({
      value: group.id,
      label: group.name
    }));
  }
  return getAthletesData().map((athlete) => ({
    value: athlete.name,
    label: athlete.name
  }));
}

function populateMediaTargetSelect(selectEl, mode, selectedValue = "") {
  if (!selectEl) return;
  const options = getMediaAssignmentTargetOptions(mode);
  selectEl.innerHTML = options.map((option) => `<option value="${escapeHtml(option.value)}">${escapeHtml(option.label)}</option>`).join("");
  if (!options.length) return;
  selectEl.value = options.some((option) => option.value === selectedValue) ? selectedValue : options[0].value;
}

function buildMediaAnalysisRecordId(mediaNode, mode, targetValue) {
  const suffix = mode === "group" ? targetValue : slugifyKey(targetValue);
  return `${mediaNode.id}-${suffix}`;
}

function getMediaAnalysisTargetLabel(mode, targetValue) {
  if (mode === "group") {
    return getCoachGroupRecords().find((group) => group.id === targetValue)?.name || targetValue;
  }
  return targetValue;
}

function buildReusableMediaReference(mediaNode) {
  if (!mediaNode) {
    return {
      mediaId: "",
      mediaAssetId: "",
      mediaTitle: "",
      mediaAssetPath: "",
      mediaAssetStoragePath: "",
      mediaThumbnailPath: "",
      mediaThumbnailStoragePath: "",
      mediaType: ""
    };
  }
  return {
    mediaId: String(mediaNode.id || "").trim(),
    mediaAssetId: String(mediaNode.mediaAssetId || "").trim(),
    mediaTitle: String(mediaNode.title || "").trim(),
    mediaAssetPath: String(mediaNode.assetPath || "").trim(),
    mediaAssetStoragePath: String(mediaNode.assetStoragePath || "").trim(),
    mediaThumbnailPath: String(mediaNode.thumbnailPath || "").trim(),
    mediaThumbnailStoragePath: String(mediaNode.thumbnailStoragePath || "").trim(),
    mediaType: String(mediaNode.mediaType || "").trim()
  };
}

function renderMediaAnalysisEntries(mediaNode) {
  if (!mediaAnalysisEntries) return;
  const mode = mediaAnalysisMode?.value || "athlete";
  const targetValue = mediaAnalysisTarget?.value || "";
  const targetLabel = getMediaAnalysisTargetLabel(mode, targetValue);
  const athleteRecord = mode === "athlete" ? getCoachAthleteRecordByIdentity(targetValue) : null;
  const record = getCoachMatchAnalysisRecordForMediaTarget({
    mediaId: mediaNode?.id || "",
    mediaAssetPath: mediaNode?.assetPath || "",
    athleteId: athleteRecord?.id || "",
    athleteUid: athleteRecord?.athleteUid || "",
    athleteName: mode === "athlete" ? targetValue : "",
    groupId: mode === "group" ? targetValue : ""
  });
  const entries = record?.entries || [];
  mediaAnalysisEntries.innerHTML = "";
  if (!mediaNode || !entries.length) {
    mediaAnalysisEntries.innerHTML = `<div class="mini-card"><p class="small muted">${currentLang === "es" ? "Todavia no hay analisis guardado para este video." : "No match analysis saved for this media yet."}</p></div>`;
    return;
  }
  const summaryCard = document.createElement("div");
  summaryCard.className = "mini-card";
  summaryCard.innerHTML = `
    <h4>${record.mediaTitle || mediaNode.title}</h4>
    <div class="small">${targetLabel}</div>
    <p class="small">${record.summary || (currentLang === "es" ? "Sin resumen todavia." : "No summary yet.")}</p>
  `;
  mediaAnalysisEntries.appendChild(summaryCard);
  entries.forEach((entry) => {
    const card = document.createElement("div");
    card.className = "mini-card";
    card.innerHTML = `<strong>${entry.timestamp || "--:--"}</strong><p class="small">${entry.note || ""}</p>`;
    mediaAnalysisEntries.appendChild(card);
  });
}

function renderMediaCoachActions(nodes = getMediaNodes()) {
  const selectedMedia = syncSelectedMediaNode(nodes);
  const selectedLabel = selectedMedia
    ? `${currentLang === "es" ? "Seleccionado" : "Selected"}: ${selectedMedia.title}`
    : (currentLang === "es" ? "Selecciona un media para crear la tarea." : "Select a media item to create the assignment.");
  if (mediaSelectedItemLabel) mediaSelectedItemLabel.textContent = selectedLabel;
  if (mediaAnalysisSelectedLabel) mediaAnalysisSelectedLabel.textContent = selectedLabel;
  if (mediaAssignmentDueDate && !mediaAssignmentDueDate.value) mediaAssignmentDueDate.value = getCurrentAppDateKey();
  if (mediaAssignmentTitleInput && selectedMedia && !mediaAssignmentTitleInput.value.trim()) {
    mediaAssignmentTitleInput.value = selectedMedia.title;
  }
  populateMediaTargetSelect(mediaAssignmentTarget, mediaAssignmentMode?.value || "athlete", mediaAssignmentTarget?.value || getSelectedCoachAthleteName());
  populateMediaTargetSelect(mediaAnalysisTarget, mediaAnalysisMode?.value || "athlete", mediaAnalysisTarget?.value || getSelectedCoachAthleteName());
  const selectedAnalysisAthlete = (mediaAnalysisMode?.value || "athlete") === "athlete"
    ? getCoachAthleteRecordByIdentity(mediaAnalysisTarget?.value || "")
    : null;
  const existingAnalysis = getCoachMatchAnalysisRecordForMediaTarget({
    mediaId: selectedMedia?.id || "",
    mediaAssetPath: selectedMedia?.assetPath || "",
    athleteId: selectedAnalysisAthlete?.id || "",
    athleteUid: selectedAnalysisAthlete?.athleteUid || "",
    athleteName: (mediaAnalysisMode?.value || "athlete") === "athlete" ? (mediaAnalysisTarget?.value || "") : "",
    groupId: (mediaAnalysisMode?.value || "athlete") === "group" ? (mediaAnalysisTarget?.value || "") : ""
  });
  if (mediaAnalysisSummary && existingAnalysis && !mediaAnalysisSummary.value.trim()) {
    mediaAnalysisSummary.value = existingAnalysis.summary || "";
  }
  renderMediaAnalysisEntries(selectedMedia);
}

async function createAssignmentFromSelectedMedia() {
  const mediaNode = syncSelectedMediaNode(getMediaNodes());
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments");
  if (!mediaNode || !assignmentsRef) {
    throw new Error("media_assignment_requires_selection");
  }
  const mode = mediaAssignmentMode?.value || "athlete";
  const targetValue = mediaAssignmentTarget?.value || "";
  const dueDateKey = normalizeDateKey(mediaAssignmentDueDate?.value || getCurrentAppDateKey());
  const type = String(mediaAssignmentType?.value || "Video review").trim();
  const title = String(mediaAssignmentTitleInput?.value || mediaNode.title || "").trim();
  const note = String(mediaAssignmentNote?.value || mediaNode.note || "").trim();
  if (!targetValue || !title) {
    throw new Error("media_assignment_target_required");
  }
  const mediaRef = buildReusableMediaReference(mediaNode);
  const mediaAssetId = await registerMediaAssetInWorkspace({
    assetPath: mediaRef.mediaAssetPath,
    assetStoragePath: mediaRef.mediaAssetStoragePath,
    thumbnailPath: mediaRef.mediaThumbnailPath,
    thumbnailStoragePath: mediaRef.mediaThumbnailStoragePath,
    source: "assignment",
    mediaType: mediaRef.mediaType,
    existingMediaAssetId: mediaRef.mediaAssetId
  });
  if (mediaAssetId && !mediaRef.mediaAssetId) {
    const nodes = getMediaNodes();
    const target = nodes.find((node) => node.type === "item" && node.id === mediaNode.id);
    if (target) {
      target.mediaAssetId = mediaAssetId;
      setMediaNodes(nodes);
    }
  }
  const athleteAudience = mode === "group"
    ? (() => {
        const group = getCoachGroupRecords().find((entry) => entry.id === targetValue);
        return {
          athleteIds: [...(group?.memberIds || [])],
          athleteUids: [...(group?.memberUids || [])]
        };
      })()
    : (() => {
        const athlete = getCoachAthleteRecordByIdentity(targetValue);
        return {
          athleteIds: [normalizeAthleteId(athlete?.id, targetValue)],
          athleteUids: athlete?.athleteUid ? [normalizeUid(athlete.athleteUid)] : []
        };
      })();
  const payload = {
    title,
    assigneeType: mode,
    assigneeId: mode === "group" ? targetValue : slugifyKey(targetValue),
    assigneeName: getMediaAnalysisTargetLabel(mode, targetValue),
    assigneeNames: mode === "group"
      ? (getCoachGroupRecords().find((group) => group.id === targetValue)?.memberNames || [])
      : [targetValue],
    athleteIds: athleteAudience.athleteIds,
    athleteUids: athleteAudience.athleteUids,
    type,
    startDateKey: dueDateKey,
    endDateKey: dueDateKey,
    dueDateKey,
    dueLabel: formatPlanDateLabel(dueDateKey),
    status: "not_started",
    note,
    source: `Media - ${mediaRef.mediaType || "Video"}`,
    ...mediaRef,
    mediaAssetId: mediaAssetId || mediaRef.mediaAssetId || "",
    notificationStatus: "assignment_only"
  };
  const ref = assignmentsRef.doc();
  await withTimeout(
    ref.set(stripUndefinedDeep({
      ...payload,
      createdAt: getFirestoreServerTimestamp(),
      updatedAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_media_assignment_timeout"
  );
}

function getMediaActionErrorMessage(err, mode = "assignment") {
  const code = String(err?.code || err?.message || "");
  if (/selection/i.test(code)) {
    return mode === "analysis"
      ? pickCopy({
          en: "Select a media item first.",
          es: "Selecciona un media primero."
        })
      : pickCopy({
          en: "Select a media item before creating the assignment.",
          es: "Selecciona un media antes de crear la asignacion."
        });
  }
  if (/target_required/i.test(code)) {
    return mode === "analysis"
      ? pickCopy({
          en: "Choose an athlete or group and add analysis details.",
          es: "Elige un atleta o grupo y agrega detalles del analisis."
        })
      : pickCopy({
          en: "Choose who should receive this assignment and confirm the title.",
          es: "Elige a quien va esta asignacion y confirma el titulo."
        });
  }
  return mode === "analysis"
    ? pickCopy({
        en: "Could not save the match analysis.",
        es: "No se pudo guardar el analisis."
      })
    : pickCopy({
        en: "Could not create the assignment from media.",
        es: "No se pudo crear la asignacion desde media."
      });
}

async function saveSelectedMediaAnalysis() {
  const mediaNode = syncSelectedMediaNode(getMediaNodes());
  const analysisRef = getCoachWorkspaceCollectionRef("match_analysis");
  if (!mediaNode || !analysisRef) {
    throw new Error("media_analysis_requires_selection");
  }
  const mode = mediaAnalysisMode?.value || "athlete";
  const targetValue = mediaAnalysisTarget?.value || "";
  const targetLabel = getMediaAnalysisTargetLabel(mode, targetValue);
  const summary = String(mediaAnalysisSummary?.value || "").trim();
  const timestamp = String(mediaAnalysisTimestamp?.value || "").trim();
  const note = String(mediaAnalysisNote?.value || "").trim();
  if (!targetValue || (!summary && !timestamp && !note)) {
    throw new Error("media_analysis_target_required");
  }
  const mediaRef = buildReusableMediaReference(mediaNode);
  const mediaAssetId = await registerMediaAssetInWorkspace({
    assetPath: mediaRef.mediaAssetPath,
    assetStoragePath: mediaRef.mediaAssetStoragePath,
    thumbnailPath: mediaRef.mediaThumbnailPath,
    thumbnailStoragePath: mediaRef.mediaThumbnailStoragePath,
    source: "match_analysis",
    mediaType: mediaRef.mediaType,
    existingMediaAssetId: mediaRef.mediaAssetId
  });
  if (mediaAssetId && !mediaRef.mediaAssetId) {
    const nodes = getMediaNodes();
    const target = nodes.find((node) => node.type === "item" && node.id === mediaNode.id);
    if (target) {
      target.mediaAssetId = mediaAssetId;
      setMediaNodes(nodes);
    }
  }
  const athleteRecord = mode === "athlete" ? getCoachAthleteRecordByIdentity(targetValue) : null;
  const existing = getCoachMatchAnalysisRecordForMediaTarget({
    mediaId: mediaRef.mediaId,
    mediaAssetPath: mediaRef.mediaAssetPath,
    athleteId: athleteRecord?.id || "",
    athleteUid: athleteRecord?.athleteUid || "",
    athleteName: mode === "athlete" ? targetValue : "",
    groupId: mode === "group" ? targetValue : ""
  });
  const recordId = existing?.id || buildMediaAnalysisRecordId(mediaNode, mode, targetValue);
  const nextEntries = [...(existing?.entries || [])];
  if (timestamp || note) {
    nextEntries.push({
      timestamp,
      note
    });
  }
  await withTimeout(
    analysisRef.doc(recordId).set(stripUndefinedDeep({
      ...mediaRef,
      mediaAssetId: mediaAssetId || mediaRef.mediaAssetId || "",
      athleteId: mode === "athlete" ? normalizeAthleteId(athleteRecord?.id, targetLabel) : "",
      athleteUid: mode === "athlete" ? normalizeUid(athleteRecord?.athleteUid) : "",
      athleteName: mode === "athlete" ? targetLabel : "",
      groupId: mode === "group" ? targetValue : "",
      summary: summary || existing?.summary || "",
      entries: nextEntries,
      createdAt: existing ? undefined : getFirestoreServerTimestamp(),
      updatedAt: getFirestoreServerTimestamp()
    }), { merge: true }),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_match_analysis_write_timeout"
  );
}

function renderMediaBreadcrumb(nodes) {
  if (!mediaBreadcrumb) return;
  mediaBreadcrumb.innerHTML = "";

  const rootBtn = document.createElement("button");
  rootBtn.type = "button";
  rootBtn.className = "media-crumb" + (!mediaActiveSectionId ? " active" : "");
  rootBtn.textContent = mediaCopy("root");
  rootBtn.addEventListener("click", () => {
    mediaActiveSectionId = null;
    renderMedia();
  });
  mediaBreadcrumb.appendChild(rootBtn);

  const path = getMediaPath(nodes, mediaActiveSectionId);
  path.forEach((section) => {
    const btn = document.createElement("button");
    btn.type = "button";
    const isActive = section.id === mediaActiveSectionId;
    btn.className = "media-crumb" + (isActive ? " active" : "");
    btn.textContent = section.name;
    btn.disabled = isActive;
    btn.addEventListener("click", () => {
      mediaActiveSectionId = section.id;
      renderMedia();
    });
    mediaBreadcrumb.appendChild(btn);
  });
}

function renderMediaSections(nodes) {
  if (!mediaSectionList) return;
  const sections = getMediaChildren(nodes, mediaActiveSectionId, "section");
  mediaSectionList.innerHTML = "";

  if (!sections.length) {
    const empty = document.createElement("div");
    empty.className = "media-empty";
    empty.textContent = mediaCopy("emptySections");
    mediaSectionList.appendChild(empty);
    return;
  }

  sections.forEach((section) => {
    const counts = countSectionChildren(nodes, section.id);
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "media-section-card";
    btn.innerHTML = `
      <strong>${section.name}</strong>
      <div class="small">${sectionMetaText(counts)}</div>
    `;
    btn.addEventListener("click", () => {
      mediaActiveSectionId = section.id;
      renderMedia();
    });
    mediaSectionList.appendChild(btn);
  });
}

function mediaFavoriteLabel(item) {
  const parent = item.parentName ? ` - ${item.parentName}` : "";
  return `${item.title}${parent}`;
}

function renderMediaItems(nodes) {
  if (!mediaItemList) return;
  const items = getMediaChildren(nodes, mediaActiveSectionId, "item");
  const assignedLabel = mediaCopy("assigned");
  const durationLabel = mediaCopy("duration");
  const saveFavLabel = mediaCopy("saveFav");
  const openMediaLabel = mediaCopy("openMedia");
  const selectMediaLabel = currentLang === "es" ? "Seleccionar" : "Select";
  const missingAssetLabel = mediaCopy("missingAsset");
  const parent = mediaActiveSectionId ? findMediaNode(nodes, mediaActiveSectionId) : null;
  const parentName = parent?.type === "section" ? parent.name : "";
  const selectedNode = syncSelectedMediaNode(nodes);

  mediaItemList.innerHTML = "";
  items.forEach((item) => {
    const card = document.createElement("div");
    card.className = `media-item-card${selectedNode?.id === item.id ? " active" : ""}`;
    const assetPath = normalizeMediaAssetPath(item.assetPath || item.assetUrl || item.url || "");
    const thumbnailPath = normalizeMediaAssetPath(item.thumbnailPath || item.thumbnailUrl || "");
    const assetUrl = resolveMediaLocation(assetPath);
    const thumbnailUrl = resolveMediaLocation(thumbnailPath);
    const safeTitle = escapeHtml(item.title);
    const safeType = escapeHtml(item.mediaType);
    const safeAssigned = escapeHtml(item.assigned);
    const safeDuration = escapeHtml(item.duration);
    const safeNote = escapeHtml(item.note);
    const safePath = escapeHtml(assetPath);
    const missingClass = assetUrl ? "" : " media-item-missing";
    card.innerHTML = `
      ${thumbnailUrl ? `<img class="media-item-thumb" src="${escapeHtml(thumbnailUrl)}" alt="${safeTitle}" loading="lazy">` : ""}
      <h4>${safeTitle}</h4>
      <div class="small">${safeType}</div>
      ${assetPath ? `<div class="small media-item-path">${safePath}</div>` : `<div class="small${missingClass}">${missingAssetLabel}</div>`}
      ${item.assigned ? `<div class="small">${assignedLabel}: ${safeAssigned}</div>` : ""}
      ${item.duration ? `<div class="small">${durationLabel}: ${safeDuration}</div>` : ""}
      ${item.note ? `<div class="small">${safeNote}</div>` : ""}
    `;

    const actions = document.createElement("div");
    actions.className = "media-item-actions";
    const selectBtn = document.createElement("button");
    selectBtn.type = "button";
    selectBtn.className = selectedNode?.id === item.id ? "ghost" : "";
    selectBtn.textContent = selectMediaLabel;
    selectBtn.addEventListener("click", () => {
      selectedMediaItemId = item.id;
      if (mediaAssignmentTitleInput) mediaAssignmentTitleInput.value = item.title || "";
      if (mediaAssignmentNote && !mediaAssignmentNote.value.trim()) mediaAssignmentNote.value = item.note || "";
      renderMedia();
    });
    actions.appendChild(selectBtn);
    if (assetUrl) {
      const openBtn = document.createElement("button");
      openBtn.type = "button";
      openBtn.className = "ghost";
      openBtn.textContent = openMediaLabel;
      openBtn.addEventListener("click", () => {
        window.open(assetUrl, "_blank", "noopener,noreferrer");
      });
      actions.appendChild(openBtn);
    }

    const btn = document.createElement("button");
    btn.type = "button";
    btn.textContent = saveFavLabel;
    btn.addEventListener("click", () => {
      const label = mediaFavoriteLabel({ ...item, parentName });
      addFavoriteEntry({
        label,
        assetPath: resolveMediaLocation(item.assetPath || ""),
        mediaType: item.mediaType || "",
        tags: Array.isArray(item.tags) ? item.tags : []
      });
    });
    actions.appendChild(btn);

    card.appendChild(actions);
    mediaItemList.appendChild(card);
  });

  return items.length;
}

function renderMediaEmptyState(sectionCount, itemCount) {
  if (!mediaEmpty) return;
  const isEmpty = sectionCount === 0 && itemCount === 0;
  mediaEmpty.hidden = !isEmpty;
  mediaEmpty.textContent = isEmpty ? mediaCopy("empty") : "";
}

function bindMediaTools() {
  if (mediaToolsBound) return;

  if (mediaAddSectionBtn) {
    mediaAddSectionBtn.addEventListener("click", () => {
      const name = mediaNewSectionName?.value.trim();
      if (!name) {
        toast(mediaCopy("needSectionName"));
        return;
      }
      const nodes = getMediaNodes();
      nodes.push({
        id: makeMediaId("sec"),
        type: "section",
        name,
        parentId: mediaActiveSectionId
      });
      setMediaNodes(nodes);
      if (mediaNewSectionName) mediaNewSectionName.value = "";
      toast(mediaCopy("addSectionToast"));
      renderMedia();
    });
  }

  if (mediaAddItemBtn) {
    mediaAddItemBtn.addEventListener("click", async () => {
      const file = mediaNewItemFile?.files?.[0] || null;
      const inferredTitle = inferMediaTitleFromFile(file);
      const title = mediaNewItemTitle?.value.trim() || inferredTitle;
      let uploadedMedia = null;
      let assetPath = normalizeMediaAssetPath(mediaNewItemAssetPath?.value || "");
      let assetStoragePath = "";
      let thumbnailPath = normalizeMediaAssetPath(mediaNewItemThumbPath?.value || "");
      let thumbnailStoragePath = "";
      if (!title) {
        toast(mediaCopy("needItemTitle"));
        return;
      }
      if (file) {
        try {
          toast(mediaCopy("uploadingMedia"));
          uploadedMedia = await uploadMediaAssetBundleToFirebase(file, {
            generateThumbnail: !thumbnailPath
          });
          assetPath = uploadedMedia.assetPath;
          assetStoragePath = uploadedMedia.assetStoragePath || "";
          if (!thumbnailPath && uploadedMedia.thumbnailPath) {
            thumbnailPath = uploadedMedia.thumbnailPath;
          }
          if (uploadedMedia.thumbnailStoragePath) {
            thumbnailStoragePath = uploadedMedia.thumbnailStoragePath;
          }
          if (mediaNewItemAssetPath) mediaNewItemAssetPath.value = assetPath;
          if (mediaNewItemThumbPath && thumbnailPath) mediaNewItemThumbPath.value = thumbnailPath;
        } catch (err) {
          console.warn("Media upload failed", err);
          toast(mediaCopy("uploadFailed"));
          return;
        }
      }
      if (!assetPath) {
        toast(mediaCopy("needItemAssetPath"));
        return;
      }
      const nodes = getMediaNodes();
      nodes.push({
        id: makeMediaId("item"),
        type: "item",
        title,
        mediaAssetId: uploadedMedia?.mediaAssetId || "",
        mediaType: mediaNewItemType?.value || inferMediaTypeFromFile(file) || "Video",
        assetPath,
        assetStoragePath,
        thumbnailPath,
        thumbnailStoragePath,
        duration: mediaNewItemDuration?.value.trim() || "",
        assigned: mediaNewItemAssigned?.value.trim() || "",
        note: mediaNewItemNote?.value.trim() || "",
        parentId: mediaActiveSectionId
      });
      setMediaNodes(nodes);
      if (mediaNewItemTitle) mediaNewItemTitle.value = "";
      if (mediaNewItemAssetPath) mediaNewItemAssetPath.value = "";
      if (mediaNewItemThumbPath) mediaNewItemThumbPath.value = "";
      if (mediaNewItemDuration) mediaNewItemDuration.value = "";
      if (mediaNewItemAssigned) mediaNewItemAssigned.value = "";
      if (mediaNewItemNote) mediaNewItemNote.value = "";
      if (mediaNewItemFile) mediaNewItemFile.value = "";
      toast(mediaCopy("addItemToast"));
      renderMedia();
    });
  }

  if (mediaNewItemFile) {
    mediaNewItemFile.addEventListener("change", () => {
      const file = mediaNewItemFile.files?.[0];
      if (!file || !mediaNewItemTitle) return;
      if (!mediaNewItemTitle.value.trim()) {
        mediaNewItemTitle.value = inferMediaTitleFromFile(file);
      }
      if (mediaNewItemType) {
        const inferredType = inferMediaTypeFromFile(file);
        if (Array.from(mediaNewItemType.options).some((option) => option.value === inferredType)) {
          mediaNewItemType.value = inferredType;
        }
      }
    });
  }

  if (mediaAssignmentMode) {
    mediaAssignmentMode.addEventListener("change", () => {
      populateMediaTargetSelect(mediaAssignmentTarget, mediaAssignmentMode.value, "");
      renderMediaCoachActions();
    });
  }

  if (mediaAnalysisMode) {
    mediaAnalysisMode.addEventListener("change", () => {
      populateMediaTargetSelect(mediaAnalysisTarget, mediaAnalysisMode.value, "");
      renderMediaCoachActions();
    });
  }

  if (mediaAnalysisTarget) {
    mediaAnalysisTarget.addEventListener("change", () => {
      renderMediaCoachActions();
    });
  }

  if (mediaAssignBtn) {
    mediaAssignBtn.addEventListener("click", async () => {
      if (mediaAssignmentStatus) mediaAssignmentStatus.textContent = "";
      mediaAssignBtn.disabled = true;
      try {
        await createAssignmentFromSelectedMedia();
        if (mediaAssignmentStatus) {
          mediaAssignmentStatus.textContent = currentLang === "es"
            ? "Asignacion creada desde Media."
            : "Assignment created from Media.";
        }
        toast(currentLang === "es" ? "Asignacion creada." : "Assignment created.");
        renderCoachAssignments();
      } catch (err) {
        console.warn("Media assignment create failed", err);
        const message = getMediaActionErrorMessage(err, "assignment");
        if (mediaAssignmentStatus) {
          mediaAssignmentStatus.textContent = message;
        }
        toast(message);
      } finally {
        mediaAssignBtn.disabled = false;
      }
    });
  }

  if (mediaAnalysisAddBtn) {
    mediaAnalysisAddBtn.addEventListener("click", async () => {
      if (mediaAnalysisStatus) mediaAnalysisStatus.textContent = "";
      mediaAnalysisAddBtn.disabled = true;
      try {
        await saveSelectedMediaAnalysis();
        if (mediaAnalysisTimestamp) mediaAnalysisTimestamp.value = "";
        if (mediaAnalysisNote) mediaAnalysisNote.value = "";
        if (mediaAnalysisStatus) {
          mediaAnalysisStatus.textContent = currentLang === "es"
            ? "Analisis guardado."
            : "Analysis saved.";
        }
        renderMediaCoachActions();
      } catch (err) {
        console.warn("Media analysis save failed", err);
        const message = getMediaActionErrorMessage(err, "analysis");
        if (mediaAnalysisStatus) {
          mediaAnalysisStatus.textContent = message;
        }
        toast(message);
      } finally {
        mediaAnalysisAddBtn.disabled = false;
      }
    });
  }

  mediaToolsBound = true;
}

function renderMediaCoachTools(isCoach) {
  if (!mediaCoachTools) return;
  mediaCoachTools.classList.toggle("hidden", !isCoach);
  if (!isCoach) return;

  bindMediaTools();

  if (mediaAddSectionTitle) mediaAddSectionTitle.textContent = mediaCopy("addSectionTitle");
  if (mediaNewSectionLabel) mediaNewSectionLabel.textContent = mediaCopy("addSectionLabel");
  if (mediaAddSectionBtn) mediaAddSectionBtn.textContent = mediaCopy("addSectionBtn");
  if (mediaAddItemTitle) mediaAddItemTitle.textContent = mediaCopy("addItemTitle");
  if (mediaNewItemLabel) mediaNewItemLabel.textContent = mediaCopy("addItemLabel");
  if (mediaNewItemAssetPathLabel) mediaNewItemAssetPathLabel.textContent = mediaCopy("addItemAssetPathLabel");
  if (mediaNewItemFileLabel) mediaNewItemFileLabel.textContent = mediaCopy("addItemFileLabel");
  if (mediaNewItemThumbPathLabel) mediaNewItemThumbPathLabel.textContent = mediaCopy("addItemThumbLabel");
  if (mediaNewItemDurationLabel) mediaNewItemDurationLabel.textContent = mediaCopy("addItemDurationLabel");
  if (mediaNewItemTypeLabel) mediaNewItemTypeLabel.textContent = mediaCopy("addItemTypeLabel");
  if (mediaNewItemAssignedLabel) mediaNewItemAssignedLabel.textContent = mediaCopy("addItemAssignedLabel");
  if (mediaNewItemNoteLabel) mediaNewItemNoteLabel.textContent = mediaCopy("addItemNoteLabel");
  if (mediaAddItemBtn) mediaAddItemBtn.textContent = mediaCopy("addItemBtn");

  if (mediaNewSectionName) mediaNewSectionName.placeholder = pickCopy(MEDIA_PLACEHOLDERS.section);
  if (mediaNewItemTitle) mediaNewItemTitle.placeholder = pickCopy(MEDIA_PLACEHOLDERS.item);
  if (mediaNewItemAssetPath) mediaNewItemAssetPath.placeholder = pickCopy(MEDIA_PLACEHOLDERS.assetPath);
  if (mediaNewItemThumbPath) mediaNewItemThumbPath.placeholder = pickCopy(MEDIA_PLACEHOLDERS.thumbPath);
  if (mediaNewItemDuration) mediaNewItemDuration.placeholder = pickCopy(MEDIA_PLACEHOLDERS.duration);
  if (mediaNewItemAssigned) mediaNewItemAssigned.placeholder = pickCopy(MEDIA_PLACEHOLDERS.assigned);
  if (mediaNewItemNote) mediaNewItemNote.placeholder = pickCopy(MEDIA_PLACEHOLDERS.note);
  if (mediaAssignmentTitle) mediaAssignmentTitle.textContent = currentLang === "es" ? "Asignar tarea desde media" : "Assign Media Task";
  if (mediaAnalysisTitle) mediaAnalysisTitle.textContent = currentLang === "es" ? "Analisis de combate" : "Match Analysis";
  if (mediaAssignBtn) mediaAssignBtn.textContent = currentLang === "es" ? "Crear asignacion" : "Create assignment";
  if (mediaAnalysisAddBtn) mediaAnalysisAddBtn.textContent = currentLang === "es" ? "Guardar analisis" : "Save analysis";
  renderMediaCoachActions();
}

function renderMedia() {
  const nodes = getMediaNodes();
  ensureMediaActiveSection(nodes);
  const profile = getProfile();
  const isCoach = isCoachRole(profile?.role);

  renderMediaBreadcrumb(nodes);
  renderMediaSections(nodes);
  const itemCount = renderMediaItems(nodes) || 0;
  const sectionCount = getMediaChildren(nodes, mediaActiveSectionId, "section").length;
  renderMediaEmptyState(sectionCount, itemCount);
  renderMediaCoachTools(isCoach);
}

// ---------- ANNOUNCEMENTS ----------
const announcementList = document.getElementById("announcementList");
let coachAnnouncementComposerBound = false;

function getCoachAnnouncementCollectionRef(coachUid = "") {
  return getCoachWorkspaceCollectionRef("announcements", coachUid || getAuthUser()?.id || "");
}

function getCoachVerifiedParentRecipients() {
  const coachUid = String(getAuthUser()?.id || "").trim();
  if (!coachUid) return [];
  return coachParentApprovalsCache
    .filter((record) => normalizeAuthRole(record.role) === "parent")
    .filter((record) => normalizeParentVerificationStatus(record.status) === "verified")
    .filter((record) => String(record.linkedCoachUid || "").trim() === coachUid);
}

function setCoachAnnouncementStatus(message = "", type = "") {
  if (!coachAnnouncementStatus) return;
  coachAnnouncementStatus.textContent = message;
  coachAnnouncementStatus.dataset.state = type;
}

function renderCoachAnnouncementRecipientOptions() {
  if (!coachAnnouncementRecipients) return;
  const athletes = getCoachAthleteRecords();
  const groups = getCoachGroupRecords();
  const parents = getCoachVerifiedParentRecipients();
  const options = [];
  athletes.forEach((athlete) => {
    options.push({
      value: `athlete:${normalizeAthleteId(athlete.id, athlete.name)}`,
      label: `${currentLang === "es" ? "Atleta" : "Athlete"} • ${athlete.name}`
    });
  });
  groups.forEach((group) => {
    options.push({
      value: `group:${group.id}`,
      label: `${currentLang === "es" ? "Grupo" : "Group"} • ${group.name}`
    });
  });
  parents.forEach((parent) => {
    options.push({
      value: `parent:${parent.uid}`,
      label: `${currentLang === "es" ? "Padre/Madre" : "Parent"} • ${parent.name || parent.email}`
    });
  });
  const previousValues = new Set(
    Array.from(coachAnnouncementRecipients.selectedOptions || [])
      .map((option) => String(option?.value || "").trim())
      .filter(Boolean)
  );
  coachAnnouncementRecipients.innerHTML = options.length
    ? options.map((option) => `<option value="${escapeHtml(option.value)}"${previousValues.has(option.value) ? " selected" : ""}>${escapeHtml(option.label)}</option>`).join("")
    : `<option value="">${escapeHtml(currentLang === "es" ? "No hay destinatarios disponibles" : "No recipients available")}</option>`;
  coachAnnouncementRecipients.disabled = !options.length;
}

function resolveCoachAnnouncementRecipients() {
  const athletesById = new Map(
    getCoachAthleteRecords().map((athlete) => [normalizeAthleteId(athlete.id, athlete.name), athlete])
  );
  const groupsById = new Map(getCoachGroupRecords().map((group) => [String(group.id || "").trim(), group]));
  const parentsByUid = new Map(getCoachVerifiedParentRecipients().map((parent) => [String(parent.uid || "").trim(), parent]));
  const selectedValues = Array.from(coachAnnouncementRecipients?.selectedOptions || [])
    .map((option) => String(option?.value || "").trim())
    .filter(Boolean);
  const includeAllAthletes = Boolean(coachAnnouncementAllAthletes?.checked);
  const includeAllParents = Boolean(coachAnnouncementAllParents?.checked);
  const athleteIds = new Set();
  const athleteUids = new Set();
  const athleteNames = new Set();
  const parentUids = new Set();
  const groupIds = new Set();
  const groupNames = new Set();

  const addAthlete = (athlete = null) => {
    if (!athlete) return;
    const athleteId = normalizeAthleteId(athlete.id, athlete.name);
    if (athleteId) athleteIds.add(athleteId);
    if (athlete.athleteUid) athleteUids.add(String(athlete.athleteUid || "").trim());
    if (athlete.name) athleteNames.add(String(athlete.name || "").trim());
  };

  if (includeAllAthletes) {
    athletesById.forEach((athlete) => addAthlete(athlete));
  }
  if (includeAllParents) {
    parentsByUid.forEach((parent) => parentUids.add(String(parent.uid || "").trim()));
  }

  selectedValues.forEach((value) => {
    const [kind, rawId] = value.split(":");
    const id = String(rawId || "").trim();
    if (!kind || !id) return;
    if (kind === "athlete") {
      addAthlete(athletesById.get(id));
      return;
    }
    if (kind === "group") {
      const group = groupsById.get(id);
      if (!group) return;
      groupIds.add(id);
      if (group.name) groupNames.add(group.name);
      (group.memberIds || []).forEach((athleteId) => {
        const record = athletesById.get(String(athleteId || "").trim());
        if (record) addAthlete(record);
      });
      (group.memberNames || []).forEach((name) => {
        const record = getCoachAthleteRecords().find((athlete) => normalizeName(athlete.name) === normalizeName(name));
        if (record) addAthlete(record);
      });
      return;
    }
    if (kind === "parent") {
      if (parentsByUid.has(id)) parentUids.add(id);
    }
  });

  return {
    includeAllAthletes,
    includeAllParents,
    athleteIds: Array.from(athleteIds).sort(),
    athleteUids: Array.from(athleteUids).sort(),
    athleteNames: Array.from(athleteNames).sort((a, b) => a.localeCompare(b, undefined, { sensitivity: "base" })),
    parentUids: Array.from(parentUids).sort(),
    groupIds: Array.from(groupIds).sort(),
    groupNames: Array.from(groupNames).sort((a, b) => a.localeCompare(b, undefined, { sensitivity: "base" }))
  };
}

function getAnnouncementRecipientSummary(payload = {}) {
  const athleteCount = Array.isArray(payload.athleteIds) ? payload.athleteIds.length : 0;
  const parentCount = Array.isArray(payload.parentUids) ? payload.parentUids.length : 0;
  const groupCount = Array.isArray(payload.groupIds) ? payload.groupIds.length : 0;
  const bits = [];
  if (payload.includeAllAthletes) {
    bits.push(currentLang === "es" ? "Todos los atletas" : "All athletes");
  } else if (athleteCount) {
    bits.push(`${athleteCount} ${currentLang === "es" ? "atleta(s)" : "athlete(s)"}`);
  }
  if (payload.includeAllParents) {
    bits.push(currentLang === "es" ? "Todos los padres verificados" : "All verified parents");
  } else if (parentCount) {
    bits.push(`${parentCount} ${currentLang === "es" ? "padre(s)" : "parent(s)"}`);
  }
  if (groupCount) {
    bits.push(`${groupCount} ${currentLang === "es" ? "grupo(s)" : "group(s)"}`);
  }
  return bits.join(" • ");
}

function renderCoachAnnouncementList() {
  if (!coachAnnouncementList) return;
  coachAnnouncementList.innerHTML = "";
  const rows = coachWorkspaceSortByUpdated(coachAnnouncementsCache).slice(0, 8);
  if (!rows.length) {
    coachAnnouncementList.innerHTML = `<div class="mini-card"><p class="small muted">${currentLang === "es" ? "Todavia no hay broadcasts guardados." : "No broadcasts saved yet."}</p></div>`;
    return;
  }
  rows.forEach((row) => {
    const card = document.createElement("article");
    card.className = "completion-card";
    const recipientSummary = row.recipientSummary || getAnnouncementRecipientSummary({
      includeAllAthletes: row.allAthletes,
      includeAllParents: row.allParents,
      athleteIds: row.athleteIds,
      parentUids: row.parentUids,
      groupIds: row.groupIds
    });
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <strong>${escapeHtml(row.title || (currentLang === "es" ? "Actualizacion del coach" : "Coach update"))}</strong>
          <div class="small">${escapeHtml(getAnnouncementTimeLabel(row))}</div>
        </div>
        <span class="status-pill status-pill-active">${escapeHtml(currentLang === "es" ? "Enviado" : "Sent")}</span>
      </div>
      <p class="small">${escapeHtml(row.detail || "")}</p>
      ${recipientSummary ? `<div class="completion-card-meta"><span>${escapeHtml(recipientSummary)}</span></div>` : ""}
    `;
    coachAnnouncementList.appendChild(card);
  });
}

async function saveCoachAnnouncement(event) {
  event?.preventDefault?.();
  const profile = getProfile();
  const authUser = getAuthUser();
  if (!isCoachRole(profile?.role) || !authUser?.id) return;
  const announcementsRef = getCoachAnnouncementCollectionRef(authUser.id);
  if (!announcementsRef) {
    setCoachAnnouncementStatus(currentLang === "es" ? "No se pudo conectar announcements." : "Could not connect announcements.", "error");
    return;
  }
  const title = String(coachAnnouncementTitleInput?.value || "").trim();
  const detail = String(coachAnnouncementDetailInput?.value || "").trim();
  if (!title || !detail) {
    setCoachAnnouncementStatus(currentLang === "es" ? "Agrega titulo y mensaje." : "Add a title and message.", "error");
    return;
  }
  const audience = resolveCoachAnnouncementRecipients();
  if (!audience.includeAllAthletes && !audience.includeAllParents && !audience.athleteIds.length && !audience.parentUids.length && !audience.groupIds.length) {
    setCoachAnnouncementStatus(currentLang === "es" ? "Selecciona al menos un destinatario." : "Select at least one recipient.", "error");
    return;
  }
  const recipientSummary = getAnnouncementRecipientSummary(audience);
  if (coachAnnouncementSendBtn) coachAnnouncementSendBtn.disabled = true;
  setCoachAnnouncementStatus(currentLang === "es" ? "Enviando broadcast..." : "Sending broadcast...", "");
  try {
    const docRef = announcementsRef.doc();
    const nowIso = new Date().toISOString();
    await withTimeout(
      docRef.set(stripUndefinedDeep({
        coachUid: authUser.id,
        title,
        detail,
        recipientSummary,
        allAthletes: audience.includeAllAthletes,
        allParents: audience.includeAllParents,
        athleteIds: audience.athleteIds,
        athleteUids: audience.athleteUids,
        athleteNames: audience.athleteNames,
        parentUids: audience.parentUids,
        groupIds: audience.groupIds,
        groupNames: audience.groupNames,
        authorUid: authUser.id,
        authorName: String(profile.name || authUser.email || "Coach").trim(),
        authorRole: normalizeAuthRole(profile.role || authUser.role || "coach"),
        readByUids: [authUser.id],
        createdAtIso: nowIso,
        createdAt: getFirestoreServerTimestamp(),
        updatedAt: getFirestoreServerTimestamp()
      }), { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_announcement_write_timeout"
    );
    if (coachAnnouncementTitleInput) coachAnnouncementTitleInput.value = "";
    if (coachAnnouncementDetailInput) coachAnnouncementDetailInput.value = "";
    if (coachAnnouncementAllAthletes) coachAnnouncementAllAthletes.checked = false;
    if (coachAnnouncementAllParents) coachAnnouncementAllParents.checked = false;
    if (coachAnnouncementRecipients) {
      Array.from(coachAnnouncementRecipients.options || []).forEach((option) => {
        option.selected = false;
      });
    }
    setCoachAnnouncementStatus(currentLang === "es" ? "Broadcast enviado." : "Broadcast sent.", "ok");
    toast(currentLang === "es" ? "Broadcast enviado." : "Broadcast sent.");
  } catch (err) {
    console.warn("Coach announcement send failed", err);
    setCoachAnnouncementStatus(currentLang === "es" ? "No se pudo enviar el broadcast." : "Could not send the broadcast.", "error");
  } finally {
    if (coachAnnouncementSendBtn) coachAnnouncementSendBtn.disabled = false;
  }
}

function bindCoachAnnouncementComposer() {
  if (coachAnnouncementComposerBound) return;
  coachAnnouncementForm?.addEventListener("submit", (event) => {
    saveCoachAnnouncement(event).catch((err) => {
      console.warn("Coach announcement submit failed", err);
      setCoachAnnouncementStatus(currentLang === "es" ? "No se pudo enviar el broadcast." : "Could not send the broadcast.", "error");
    });
  });
  coachAnnouncementComposerBound = true;
}

function applyAnnouncementReadLocally(announcementId = "", coachUid = "", viewerUid = "") {
  const safeAnnouncementId = String(announcementId || "").trim();
  const safeCoachUid = String(coachUid || "").trim();
  const safeViewerUid = String(viewerUid || "").trim();
  if (!safeAnnouncementId || !safeCoachUid || !safeViewerUid) return;
  const applyRead = (rows = []) => rows.map((row) => (
    row.id !== safeAnnouncementId || String(row.coachUid || "").trim() !== safeCoachUid
      ? row
      : {
          ...row,
          readByUids: uniqueNames([...(row.readByUids || []), safeViewerUid])
        }
  ));
  coachAnnouncementsCache = applyRead(coachAnnouncementsCache);
  athletePortalAnnouncementsCache = applyRead(athletePortalAnnouncementsCache);
  parentPortalAnnouncementsCache = applyRead(parentPortalAnnouncementsCache);
}

async function markAnnouncementReadById(announcementId = "", coachUid = "") {
  const current = getMessagesCurrentUser();
  const safeAnnouncementId = String(announcementId || "").trim();
  const safeCoachUid = String(coachUid || "").trim();
  if (!current?.uid || !safeAnnouncementId || !safeCoachUid) return;
  const key = `${safeCoachUid}:${safeAnnouncementId}:${current.uid}`;
  if (announcementReadSyncInFlight[key]) return;
  announcementReadSyncInFlight = {
    ...announcementReadSyncInFlight,
    [key]: true
  };
  try {
    const ref = getCoachAnnouncementCollectionRef(safeCoachUid)?.doc(safeAnnouncementId);
    if (!ref) return;
    await withTimeout(
      ref.set({
        readByUids: getFirestoreArrayUnion(current.uid),
        updatedAt: getFirestoreServerTimestamp()
      }, { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_announcement_read_timeout"
    );
    applyAnnouncementReadLocally(safeAnnouncementId, safeCoachUid, current.uid);
  } catch (err) {
    console.warn("Announcement read sync failed", err);
  } finally {
    const next = { ...announcementReadSyncInFlight };
    delete next[key];
    announcementReadSyncInFlight = next;
  }
}

async function markWorkspaceNotificationReadById(notificationId = "", coachUid = "") {
  const current = getMessagesCurrentUser();
  const safeNotificationId = String(notificationId || "").trim();
  const safeCoachUid = String(coachUid || "").trim();
  if (!current?.uid || !safeNotificationId || !safeCoachUid) return;
  const key = `${safeCoachUid}:${safeNotificationId}:${current.uid}:workspace_notification`;
  if (announcementReadSyncInFlight[key]) return;
  announcementReadSyncInFlight = {
    ...announcementReadSyncInFlight,
    [key]: true
  };
  try {
    const ref = getCoachWorkspaceCollectionRef(COACH_WORKSPACE_NOTIFICATIONS_COLLECTION, safeCoachUid)?.doc(safeNotificationId);
    if (!ref) return;
    await withTimeout(
      ref.set({
        readByUids: getFirestoreArrayUnion(current.uid),
        updatedAt: getFirestoreServerTimestamp()
      }, { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_workspace_notification_read_timeout"
    );
    const applyRead = (rows = []) => rows.map((row) => (
      row.id !== safeNotificationId || String(row.coachUid || "").trim() !== safeCoachUid
        ? row
        : { ...row, readByUids: uniqueNames([...(row.readByUids || []), current.uid]) }
    ));
    coachNotificationsCache = applyRead(coachNotificationsCache);
    athletePortalNotificationsCache = applyRead(athletePortalNotificationsCache);
    parentPortalNotificationsCache = applyRead(parentPortalNotificationsCache);
  } catch (err) {
    console.warn("Workspace notification read sync failed", err);
  } finally {
    const next = { ...announcementReadSyncInFlight };
    delete next[key];
    announcementReadSyncInFlight = next;
  }
}

function renderCoachAnnouncementsComposer() {
  if (coachAnnouncementComposeTitle) coachAnnouncementComposeTitle.textContent = currentLang === "es" ? "Broadcast del coach" : "Coach Broadcast";
  if (coachAnnouncementTitleLabel) coachAnnouncementTitleLabel.textContent = currentLang === "es" ? "Titulo" : "Title";
  if (coachAnnouncementDetailLabel) coachAnnouncementDetailLabel.textContent = currentLang === "es" ? "Anuncio" : "Announcement";
  if (coachAnnouncementAllAthletesLabel) coachAnnouncementAllAthletesLabel.textContent = currentLang === "es" ? "Todos los atletas" : "All athletes";
  if (coachAnnouncementAllParentsLabel) coachAnnouncementAllParentsLabel.textContent = currentLang === "es" ? "Todos los padres verificados" : "All verified parents";
  if (coachAnnouncementRecipientsLabel) coachAnnouncementRecipientsLabel.textContent = currentLang === "es" ? "Destinatarios especificos" : "Specific recipients";
  if (coachAnnouncementRecipientsHint) coachAnnouncementRecipientsHint.textContent = currentLang === "es"
    ? "Elige un atleta, varios atletas, grupos, padres o combina atletas y padres."
    : "Choose one athlete, many athletes, groups, parents, or combine athletes and parents.";
  if (coachAnnouncementRecentTitle) coachAnnouncementRecentTitle.textContent = currentLang === "es" ? "Broadcasts recientes" : "Recent Broadcasts";
  if (coachAnnouncementSendBtn) coachAnnouncementSendBtn.textContent = currentLang === "es" ? "Enviar broadcast" : "Send broadcast";
  if (coachAnnouncementTitleInput) coachAnnouncementTitleInput.placeholder = currentLang === "es" ? "Actualizacion del equipo" : "Team update";
  if (coachAnnouncementDetailInput) coachAnnouncementDetailInput.placeholder = currentLang === "es"
    ? "Comparte recordatorios, cambios de horario o alertas."
    : "Share reminders, schedule changes, or critical alerts.";
  renderCoachAnnouncementRecipientOptions();
  renderCoachAnnouncementList();
  bindCoachAnnouncementComposer();
}

function renderAnnouncements() {
  if (!announcementList) return;
  announcementList.innerHTML = "";
  const rows = getAnnouncementsData();
  if (!rows.length) {
    const li = document.createElement("li");
    li.innerHTML = `<strong>${currentLang === "es" ? "Sin anuncios por ahora" : "No announcements yet"}</strong><div class="small">${currentLang === "es" ? "Los anuncios del staff apareceran aqui." : "Staff announcements will appear here."}</div>`;
    announcementList.appendChild(li);
    return;
  }
  rows.forEach((note) => {
    const li = document.createElement("li");
    const readPill = isAthleteRole(getProfile()?.role) || isParentRole(getProfile()?.role)
      ? `<span class="status-pill ${note.read ? "status-pill-active" : "status-pill-pending"}">${note.read ? (currentLang === "es" ? "Leido" : "Read") : (currentLang === "es" ? "Sin leer" : "Unread")}</span>`
      : "";
    li.innerHTML = `
      <div class="completion-card-top">
        <strong>${escapeHtml(note.title || (currentLang === "es" ? "Actualizacion del coach" : "Coach update"))}</strong>
        ${readPill}
      </div>
      <div class="small">${escapeHtml(note.detail || "")} - ${escapeHtml(note.time || "")}</div>
    `;
    announcementList.appendChild(li);
  });
}

