function renderDashboard() {
  if (homeTasksTitle) homeTasksTitle.textContent = currentLang === "es" ? "Tareas pendientes" : "Pending Tasks";
  if (homeActionsTitle) homeActionsTitle.textContent = currentLang === "es" ? "Accesos rapidos" : "Quick Actions";
  if (homeCompetitionsTitle) homeCompetitionsTitle.textContent = currentLang === "es" ? "Competencias proximas" : "Upcoming Competitions";
  if (homeRecentTrainingTitle) homeRecentTrainingTitle.textContent = currentLang === "es" ? "Entrenamientos recientes" : "Recent Trainings";
  if (homeAlertsTitle) homeAlertsTitle.textContent = currentLang === "es" ? "Alertas importantes" : "Important Alerts";
  if (homeParentApprovalsTitle) homeParentApprovalsTitle.textContent = currentLang === "es" ? "Solicitudes de acceso de padres" : "Parent Access Requests";
  if (homeParentScoutingTitle) homeParentScoutingTitle.textContent = currentLang === "es" ? "Scouting de padres" : "Parent Scouting Feed";

  const athletes = getAthletesData();
  const assignmentRecords = getCoachAssignmentRecords();
  const activeAthletes = athletes.filter((athlete) => normalizeAvailabilityKey(athlete.availability) !== "other").length || athletes.length;
  const openAssignments = assignmentRecords
    .filter((item) => normalizeAssignmentStatus(item.status) !== "completed")
    .sort((left, right) => {
      const leftStatus = normalizeAssignmentStatus(left.status);
      const rightStatus = normalizeAssignmentStatus(right.status);
      const priorityOrder = { overdue: 0, not_started: 1, in_progress: 2, shared: 3 };
      const leftPriority = priorityOrder[leftStatus] ?? 9;
      const rightPriority = priorityOrder[rightStatus] ?? 9;
      if (leftPriority !== rightPriority) return leftPriority - rightPriority;
      const leftDue = String(left.dueDateKey || "").trim();
      const rightDue = String(right.dueDateKey || "").trim();
      if (leftDue && rightDue && leftDue !== rightDue) return leftDue.localeCompare(rightDue);
      return String(left.updatedAt || left.createdAt || "").localeCompare(String(right.updatedAt || right.createdAt || ""));
    });
  const athleteTaskBoards = new Map(
    athletes.map((athlete) => [athlete.name, getAthleteTaskBoard(athlete.name)])
  );
  const journalTaskAthletes = athletes.filter((athlete) => (
    athleteTaskBoards.get(athlete.name)?.taskDetails.some((task) => task.type === "journal")
  ));
  const pendingTaskCount = openAssignments.length + journalTaskAthletes.length;
  const competitionRows = getCoachUpcomingCompetitionRows(3);
  const recentTrainingRows = getCoachRecentTrainingRows(3);
  const dashboardStats = isCoachWorkspaceActive()
    ? [
        {
          title: currentLang === "es" ? "Atletas activos" : "Active athletes",
          value: String(activeAthletes),
          note: currentLang === "es" ? "Roster visible para el coach" : "Roster currently visible to the coach"
        },
        {
          title: currentLang === "es" ? "Tareas pendientes" : "Pending tasks",
          value: String(pendingTaskCount),
          note: currentLang === "es" ? "Asignaciones abiertas + journals pendientes" : "Open assignments plus stale journals"
        },
        {
          title: currentLang === "es" ? "Competencias proximas" : "Upcoming competitions",
          value: String(competitionRows.length),
          note: currentLang === "es" ? "Eventos futuros en calendario" : "Future events on the calendar"
        },
        {
          title: currentLang === "es" ? "Entrenamientos recientes" : "Recent trainings",
          value: String(getCoachPlanRecords().length),
          note: currentLang === "es" ? "Planes guardados en el workspace" : "Plans saved in the workspace"
        }
      ]
    : getTeamStatsData();

  teamStats.innerHTML = "";
  dashboardStats.forEach((stat) => {
    const card = document.createElement("div");
    card.className = "stat-card";
    card.innerHTML = `<p class="small">${stat.title}</p><h3>${stat.value}</h3><p>${stat.note}</p>`;
    teamStats.appendChild(card);
  });

  teamOverview.innerHTML = "";
  const pendingAssignments = openAssignments.slice(0, 6);
  const pendingJournalRows = journalTaskAthletes.slice(0, 3);
  if (isCoachWorkspaceActive()) {
    if (!pendingAssignments.length && !pendingJournalRows.length) {
      teamOverview.innerHTML = `<div class="small muted">${currentLang === "es" ? "No hay tareas pendientes reales ahora mismo." : "No real pending tasks right now."}</div>`;
    } else {
      pendingAssignments.forEach((item) => {
        const statusMeta = getAssignmentStatusMeta(item.status);
        const card = document.createElement("article");
        card.className = "completion-card";
        const assigneeLabel = getCoachAssignmentAssigneeLabel(item);
        const dueLabel = item.dueLabel || formatPlanDateLabel(item.dueDateKey || getCurrentAppDateKey());
        card.innerHTML = `
          <div class="completion-card-top">
            <div>
              <strong>${escapeHtml(item.title || defaultPlanTitle(item.planType || "day"))}</strong>
              <div class="small">${escapeHtml(assigneeLabel || (currentLang === "es" ? "Sin asignar" : "Unassigned"))} • ${escapeHtml(dueLabel)}</div>
            </div>
            <span class="status-pill ${statusMeta.className}">${escapeHtml(statusMeta.label)}</span>
          </div>
          <div class="completion-card-meta"><strong>${currentLang === "es" ? "Causa" : "Cause"}:</strong> ${escapeHtml(getCoachAssignmentCauseLabel(item))}</div>
          <div class="completion-card-meta">${escapeHtml(item.source || getPlanAssignmentTypeLabel(item.planType))}</div>
        `;
        const actions = document.createElement("div");
        actions.className = "completion-task-actions";

        const openBtn = document.createElement("button");
        openBtn.type = "button";
        openBtn.className = "ghost";
        openBtn.textContent = currentLang === "es" ? "Abrir tarea" : "Open task";
        openBtn.addEventListener("click", () => {
          openCoachTaskWorkspace({
            type: "assignment",
            athleteName: getCoachAssignmentPrimaryAthleteName(item) || assigneeLabel,
            assignment: item
          });
        });
        actions.appendChild(openBtn);

        if (normalizeAssignmentStatus(item.status) !== "completed") {
          const completeBtn = document.createElement("button");
          completeBtn.type = "button";
          completeBtn.className = "primary";
          completeBtn.textContent = currentLang === "es" ? "Done" : "Done";
          completeBtn.dataset.action = "mark-assignment-done";
          completeBtn.dataset.assignmentId = item.id;
          completeBtn.dataset.viewerRole = "coach";
          actions.appendChild(completeBtn);
        }

        const deleteBtn = document.createElement("button");
        deleteBtn.type = "button";
        deleteBtn.className = "ghost destructive";
        deleteBtn.textContent = currentLang === "es" ? "Eliminar" : "Delete";
        deleteBtn.dataset.action = "delete-assignment";
        deleteBtn.dataset.assignmentId = item.id;
        deleteBtn.dataset.assignmentTitle = item.title || "";
        actions.appendChild(deleteBtn);

        card.appendChild(actions);
        teamOverview.appendChild(card);
      });

      pendingJournalRows.forEach((athlete) => {
        const board = athleteTaskBoards.get(athlete.name) || getAthleteTaskBoard(athlete.name);
        const journalTask = board.taskDetails.find((task) => task.type === "journal") || null;
        const card = document.createElement("article");
        card.className = "completion-card";
        const row = getCoachCompletionRow(athlete);
        const status = getCompletionStatusMeta(row.status);
        const latestJournalLabel = escapeHtml(journalTask?.dueLabel || board.journalLabel || (currentLang === "es" ? "Journal enviado" : "Journal submitted"));
        const journalNote = escapeHtml(journalTask?.note || journalTask?.cause || pickCopy({ en: "Athlete journal entry", es: "Entrada del journal del atleta" }));
        card.innerHTML = `
          <div class="completion-card-top">
            <div>
              <strong>${escapeHtml(athlete.name)}</strong>
              <div class="small">${escapeHtml(athlete.weight || "")}</div>
            </div>
            <span class="status-pill ${status.className}">${status.label}</span>
          </div>
          <div class="completion-card-meta">${latestJournalLabel}</div>
          <div class="completion-card-meta">${journalNote}</div>
        `;
        const actions = document.createElement("div");
        actions.className = "completion-task-actions";
        const openJournalBtn = document.createElement("button");
        openJournalBtn.type = "button";
        openJournalBtn.className = "ghost";
        openJournalBtn.textContent = currentLang === "es" ? "Abrir journal" : "Open journal";
        openJournalBtn.addEventListener("click", () => {
          openCoachTaskWorkspace({ type: "journal", athleteName: athlete.name });
        });
        actions.appendChild(openJournalBtn);
        card.appendChild(actions);
        teamOverview.appendChild(card);
      });

      if (openAssignments.length > pendingAssignments.length || journalTaskAthletes.length > pendingJournalRows.length) {
        const more = document.createElement("div");
        more.className = "small muted";
        more.textContent = currentLang === "es"
          ? "Abre Plans & Assignments para ver y gestionar la lista completa."
          : "Open Plans & Assignments to manage the full list.";
        teamOverview.appendChild(more);
      }
    }
  } else {
    getTeamOverviewData().forEach((line) => {
      const row = document.createElement("div");
      row.className = "small muted";
      row.textContent = line;
      teamOverview.appendChild(row);
    });
  }

  quickActions.innerHTML = "";
  const quickActionHandlers = [
    () => focusRoutePanel("athletes", { selector: "#athleteSearchInput", selectText: true }),
    () => focusRoutePanel("plans", { selector: "#wtpPlanDate", selectText: true }),
    () => focusRoutePanel("plans", { selector: "#plannerOpenLibraryBtn" }),
    () => focusRoutePanel("competition-preview"),
    () => {
      openEditableCurrentProfile().catch((err) => {
        console.warn("Could not open current profile from home", err);
      });
    }
  ];
  getQuickActionsData().forEach((action, index) => {
    const btn = document.createElement("button");
    btn.className = "action-btn";
    btn.textContent = action;
    btn.addEventListener("click", () => {
      const handler = quickActionHandlers[index];
      if (handler) {
        handler();
        return;
      }
      showTab("coach-home");
    });
    quickActions.appendChild(btn);
  });

  if (homeCompetitions) {
    homeCompetitions.innerHTML = "";
    const items = isCoachWorkspaceActive() ? competitionRows : getHomeCompetitionsData();
    if (!items.length) {
      const li = document.createElement("li");
      li.innerHTML = `<strong>${currentLang === "es" ? "Sin competencias programadas" : "No upcoming competitions"}</strong><div class="small">${currentLang === "es" ? "Agrega eventos en Calendar para verlos aqui." : "Add events in Calendar to see them here."}</div>`;
      homeCompetitions.appendChild(li);
    }
    items.forEach((item) => {
      const li = document.createElement("li");
      li.innerHTML = `<strong>${item.title}</strong><div class="small">${item.detail}</div>`;
      homeCompetitions.appendChild(li);
    });
  }

  if (homeRecentTrainings) {
    homeRecentTrainings.innerHTML = "";
    const items = isCoachWorkspaceActive() ? recentTrainingRows : getHomeRecentTrainingsData();
    if (!items.length) {
      const li = document.createElement("li");
      li.innerHTML = `<strong>${currentLang === "es" ? "Sin entrenamientos recientes" : "No recent trainings"}</strong><div class="small">${currentLang === "es" ? "Crea un plan para que aparezca aqui." : "Create a plan and it will appear here."}</div>`;
      homeRecentTrainings.appendChild(li);
    }
    items.forEach((item) => {
      const li = document.createElement("li");
      li.innerHTML = `<strong>${item.title}</strong><div class="small">${item.detail}</div>`;
      homeRecentTrainings.appendChild(li);
    });
  }

  alertList.innerHTML = "";
  const alerts = getCoachHomeAlerts();
  if (isCoachWorkspaceActive()) {
    const coachUid = String(getAuthUser()?.id || "").trim();
    const unreadNotificationRows = coachWorkspaceSortByUpdated(coachNotificationsCache)
      .filter((record) => (record.recipientUids || []).includes(coachUid) && !isNotificationReadByUser(record, coachUid))
      .slice(0, 4)
      .map((record) => currentLang === "es"
        ? `Pendiente: ${record.title || "Notificacion"}`
        : `Pending: ${record.title || "Notification"}`);
    unreadNotificationRows.forEach((item) => {
      if (!alerts.includes(item)) alerts.push(item);
    });
  }
  alerts.forEach((alert) => {
    const div = document.createElement("div");
    div.className = "alert";
    div.textContent = alert;
    alertList.appendChild(div);
  });

  renderCoachAnnouncementsComposer();
  renderParentApprovalList();
  renderParentScoutingFeed();
}

