function clearParentPortalDataListeners() {
  parentPortalDataUnsubs.forEach((unsubscribe) => {
    try {
      unsubscribe();
    } catch {
      // ignore unsubscribe errors
    }
  });
  parentPortalDataUnsubs = [];
}

function resetParentPortalCaches() {
  parentPortalAthleteCache = null;
  parentPortalTeamCache = [];
  parentPortalAssignmentsCache = [];
  parentPortalPlansCache = [];
  parentPortalJournalCache = [];
  parentPortalScoutingCache = [];
  parentPortalAnnouncementsCache = [];
  parentPortalNotificationsCache = [];
  parentPortalPlanFetchKey = "";
}

function stopParentAudioTracks() {
  if (!parentScoutingStream) return;
  parentScoutingStream.getTracks().forEach((track) => track.stop());
  parentScoutingStream = null;
}

function clearParentAudioDraft() {
  if (parentScoutingAudioUrl) {
    URL.revokeObjectURL(parentScoutingAudioUrl);
  }
  parentScoutingAudioUrl = "";
  parentScoutingAudioBlob = null;
  parentScoutingAudioChunks = [];
  if (parentAudioPreview) {
    parentAudioPreview.pause();
    parentAudioPreview.removeAttribute("src");
    parentAudioPreview.classList.add("hidden");
  }
  if (parentAudioStatus) {
    parentAudioStatus.textContent = currentLang === "es" ? "Todavia no hay nota de audio grabada." : "No audio note recorded yet.";
  }
}

function stopParentPortalRealtimeSync() {
  if (parentPortalUserUnsub) {
    try {
      parentPortalUserUnsub();
    } catch {
      // ignore unsubscribe errors
    }
    parentPortalUserUnsub = null;
  }
  clearParentPortalDataListeners();
  resetParentPortalCaches();
  if (parentScoutingRecorder && parentScoutingRecorder.state !== "inactive") {
    parentScoutingRecorder.stop();
  }
  parentScoutingRecorder = null;
  stopParentAudioTracks();
  clearParentAudioDraft();
  renderParentHome();
  renderParentScouting();
  updateParentFab();
}

function getParentPortalLinkedAthlete() {
  if (parentPortalAthleteCache) return parentPortalAthleteCache;
  const linkedIdentity = resolveAthleteIdentity({
    athleteId: getParentLinkedAthleteId(),
    athleteUid: getParentLinkedAthleteUid(),
    athleteName: getParentLinkedAthleteName()
  });
  if (!linkedIdentity.athleteId && !linkedIdentity.athleteUid && !linkedIdentity.athleteName) return null;
  return getAthletesData().find((entry) => athleteIdentityMatches(entry, linkedIdentity)) || null;
}

function getParentPortalCoachRecord() {
  const linkedCoachUid = getParentLinkedCoachUid();
  return getCoachDirectoryOptions().find((item) => item.uid === linkedCoachUid) || {
    uid: linkedCoachUid,
    name: getParentLinkedCoachName() || "Coach",
    email: getProfile()?.linkedCoachEmail || ""
  };
}

function getParentPortalLatestJournal() {
  return coachWorkspaceSortByUpdated(parentPortalJournalCache)[0] || null;
}

function getParentPortalActiveAssignments() {
  return coachWorkspaceSortByUpdated(parentPortalAssignmentsCache).filter((item) => item.status !== "completed");
}

function isDateKeyWithinScheduleRange(dateKey = "", startKey = "", endKey = "") {
  const safeDateKey = normalizeDateKey(dateKey);
  const safeStartKey = normalizeDateKey(startKey);
  const safeEndKey = normalizeDateKey(endKey || safeStartKey);
  if (!safeDateKey) return false;
  if (safeStartKey && safeEndKey) {
    return safeDateKey >= safeStartKey && safeDateKey <= safeEndKey;
  }
  if (safeStartKey) return safeDateKey === safeStartKey;
  return false;
}

function getAssignmentScheduleMatchLevel(record = null, plansCache = [], dateKey = getCurrentAppDateKey()) {
  if (!record || typeof record !== "object") return 0;
  const safeDateKey = normalizeDateKey(dateKey || getCurrentAppDateKey());
  if (!safeDateKey) return 0;
  const dueDateKey = normalizeDateKey(record.dueDateKey || "");
  const startDateKey = getAssignmentScheduleStartKey(record, plansCache);
  const endDateKey = getAssignmentScheduleEndKey(record, plansCache);
  if (dueDateKey && dueDateKey === safeDateKey) return 3;
  if (startDateKey && endDateKey && isDateKeyWithinScheduleRange(safeDateKey, startDateKey, endDateKey)) {
    return 2;
  }

  const planId = String(record.planId || "").trim();
  if (planId && Array.isArray(plansCache) && plansCache.length) {
    const linkedPlan = plansCache.find((plan) => String(plan?.id || "").trim() === planId) || null;
    if (linkedPlan?.range && isDateKeyWithinScheduleRange(safeDateKey, linkedPlan.range.startKey, linkedPlan.range.endKey)) {
      return 2;
    }
    const scheduledDay = normalizeName(linkedPlan?.day || linkedPlan?.dayName || linkedPlan?.weekday || "");
    if (scheduledDay) {
      const targetDate = dateFromKey(safeDateKey);
      if (targetDate) {
        const dayEn = normalizeName(new Intl.DateTimeFormat("en-US", { weekday: "long", timeZone: APP_TIMEZONE }).format(targetDate));
        const dayEs = normalizeName(new Intl.DateTimeFormat("es-ES", { weekday: "long", timeZone: APP_TIMEZONE }).format(targetDate));
        if (scheduledDay === dayEn || scheduledDay === dayEs) {
          return 2;
        }
      }
    }
  }

  if (!dueDateKey) return 1;
  if (dueDateKey <= safeDateKey) return 1;
  return 0;
}

function getAssignmentScheduleStartKey(record = null, plansCache = []) {
  if (!record || typeof record !== "object") return "";
  const directStartKey = normalizeDateKey(
    record.startDateKey
    || record.weekStartKey
    || record.range?.startKey
    || ""
  );
  if (directStartKey) return directStartKey;
  const planId = String(record.planId || "").trim();
  if (planId && Array.isArray(plansCache) && plansCache.length) {
    const linkedPlan = plansCache.find((plan) => String(plan?.id || "").trim() === planId) || null;
    const linkedStartKey = normalizeDateKey(linkedPlan?.range?.startKey || "");
    if (linkedStartKey) return linkedStartKey;
  }
  return normalizeDateKey(record.dueDateKey || "");
}

function getAssignmentScheduleEndKey(record = null, plansCache = []) {
  if (!record || typeof record !== "object") return "";
  const directEndKey = normalizeDateKey(
    record.endDateKey
    || record.weekEndKey
    || record.range?.endKey
    || ""
  );
  if (directEndKey) return directEndKey;
  const planId = String(record.planId || "").trim();
  if (planId && Array.isArray(plansCache) && plansCache.length) {
    const linkedPlan = plansCache.find((plan) => String(plan?.id || "").trim() === planId) || null;
    const linkedEndKey = normalizeDateKey(linkedPlan?.range?.endKey || linkedPlan?.range?.startKey || "");
    if (linkedEndKey) return linkedEndKey;
  }
  return normalizeDateKey(record.dueDateKey || "");
}

function isAssignmentLockedUntilScheduledDate(record = null, plansCache = [], dateKey = getCurrentAppDateKey()) {
  const safeDateKey = normalizeDateKey(dateKey || getCurrentAppDateKey());
  const normalizedStatus = normalizeAssignmentStatus(record?.status);
  if (!safeDateKey || normalizedStatus === "completed" || normalizedStatus === "shared") return false;
  const startKey = getAssignmentScheduleStartKey(record, plansCache);
  return Boolean(startKey && startKey > safeDateKey);
}

function getAssignmentAvailabilityMeta(record = null, plansCache = [], dateKey = getCurrentAppDateKey()) {
  const startKey = getAssignmentScheduleStartKey(record, plansCache);
  const endKey = getAssignmentScheduleEndKey(record, plansCache);
  const locked = isAssignmentLockedUntilScheduledDate(record, plansCache, dateKey);
  return {
    startKey,
    endKey,
    locked,
    startLabel: startKey ? formatPlanDateLabel(startKey) : "",
    endLabel: endKey ? formatPlanDateLabel(endKey) : ""
  };
}

function getAssignmentDisplayStatusMeta(record = null, plansCache = [], dateKey = getCurrentAppDateKey()) {
  if (isAssignmentLockedUntilScheduledDate(record, plansCache, dateKey)) {
    return {
      label: currentLang === "es" ? "Programado" : "Scheduled",
      className: "status-pill-limited"
    };
  }
  return getAssignmentStatusMeta(record?.status);
}

function getAssignmentByIdForViewer(assignmentId = "", viewerRole = "athlete", assignmentRecord = null) {
  const safeId = String(assignmentId || "").trim();
  if (!safeId) return null;
  if (assignmentRecord && String(assignmentRecord.id || "").trim() === safeId) return assignmentRecord;
  if (normalizeAuthRole(viewerRole) === "coach") {
    return getCoachAssignmentRecords().find((item) => String(item.id || "").trim() === safeId) || null;
  }
  return getAthleteTrainingAssignments({ includeCompleted: true }).find((item) => String(item.id || "").trim() === safeId)
    || getCoachAssignmentRecords().find((item) => String(item.id || "").trim() === safeId)
    || null;
}

async function markAssignmentDone(assignmentId, viewerRole = "athlete", assignmentRecord = null) {
  const role = normalizeAuthRole(viewerRole);
  const safeId = String(assignmentId || "").trim();
  if (!safeId) return;
  if (role === "coach") {
    await updateCoachAssignmentStatus(safeId, "completed");
    return;
  }
  const assignment = getAssignmentByIdForViewer(safeId, role, assignmentRecord);
  if (!assignment) throw new Error("assignment_not_found");
  await updateAthleteAssignmentStatus(assignment, "completed");
}

function refreshAssignmentAfterDone(viewerRole = "athlete") {
  if (normalizeAuthRole(viewerRole) === "coach") {
    renderCoachAssignments();
    renderCompletionTracking();
    renderAthleteManagement();
    renderDashboard();
    return;
  }
  refreshAthleteAssignmentUI();
}

function pickPrimaryAssignmentForDate(assignments = [], plansCache = [], dateKey = getCurrentAppDateKey()) {
  const pool = Array.isArray(assignments) ? assignments : [];
  if (!pool.length) return null;
  const statusIsInProgress = (record) => normalizeAssignmentStatus(record?.status) === "in_progress";
  const atLevel = (level) => pool.filter((record) => getAssignmentScheduleMatchLevel(record, plansCache, dateKey) >= level);
  const todayOrRange = atLevel(2);
  if (todayOrRange.length) {
    return todayOrRange.find(statusIsInProgress)
      || todayOrRange.find((record) => String(record.planId || "").trim())
      || todayOrRange[0];
  }
  const dueNow = atLevel(1);
  return dueNow.find(statusIsInProgress)
    || dueNow.find((record) => String(record.planId || "").trim())
    || dueNow[0]
    || pool.find(statusIsInProgress)
    || pool.find((record) => String(record.planId || "").trim())
    || pool[0]
    || null;
}

function getParentPortalPrimaryAssignment() {
  const assignments = getParentPortalActiveAssignments();
  return pickPrimaryAssignmentForDate(assignments, parentPortalPlansCache, getCurrentAppDateKey())
    || coachWorkspaceSortByUpdated(parentPortalAssignmentsCache)[0]
    || null;
}

function renderParentAssignmentSummary(record) {
  if (!record) {
    return `<p class="small muted">${currentLang === "es" ? "Todavia no hay trabajo asignado para este atleta." : "No assigned work is available for this athlete yet."}</p>`;
  }
  const status = getAssignmentStatusMeta(record.status);
  const linkedPlan = parentPortalPlansCache.find((plan) => plan.id === record.planId) || null;
  const planLists = linkedPlan
    ? Object.entries(linkedPlan.items || {})
        .filter(([, values]) => Array.isArray(values) && values.length)
        .slice(0, 4)
        .map(([key, values]) => `<li><strong>${escapeHtml(key)}:</strong> ${escapeHtml(values.join(", "))}</li>`)
        .join("")
    : "";
  return `
    <div class="parent-summary-stack">
      <div class="completion-card-top">
        <div>
          <strong>${escapeHtml(record.title)}</strong>
          <div class="small">${escapeHtml(record.type)} - ${escapeHtml(record.dueLabel || formatPlanDateLabel(record.dueDateKey || getCurrentAppDateKey()))}</div>
        </div>
        <span class="status-pill ${status.className}">${escapeHtml(status.label)}</span>
      </div>
      <p class="small">${escapeHtml(record.note || (currentLang === "es" ? "Sin nota adicional." : "No extra note attached."))}</p>
      ${linkedPlan ? `<div class="small muted">${escapeHtml(linkedPlan.focus || linkedPlan.coachNotes || "")}</div>` : ""}
      ${planLists ? `<ul class="list tight">${planLists}</ul>` : ""}
    </div>
  `;
}

function renderParentReadinessSummary(entry) {
  if (!entry) {
    return `<p class="small muted">${currentLang === "es" ? "Todavia no hay check-in reciente del atleta." : "No recent athlete check-in is available yet."}</p>`;
  }
  const metrics = [
    { label: currentLang === "es" ? "Sueno" : "Sleep", value: entry.sleep || "-" },
    { label: currentLang === "es" ? "Energia" : "Energy", value: entry.energy || "-" },
    { label: currentLang === "es" ? "Fatiga / dolor" : "Fatigue / soreness", value: entry.soreness || "-" },
    { label: currentLang === "es" ? "Animo" : "Mood", value: entry.mood || "-" }
  ];
  return `
    <div class="parent-readiness-grid">
      ${metrics.map((metric) => `
        <div class="parent-readiness-metric">
          <span>${escapeHtml(metric.label)}</span>
          <strong>${escapeHtml(metric.value)}</strong>
        </div>
      `).join("")}
    </div>
    <p class="small">${escapeHtml(entry.note || (currentLang === "es" ? "Sin observacion adicional del coach." : "No extra coach observation added."))}</p>
  `;
}

function renderParentHome() {
  if (!parentStatusCard || !parentTrainingCard || !parentReadinessCard || !parentCoachCard || !parentAssignmentsCard) return;
  const profile = getProfile() || {};
  const authUser = getAuthUser();
  const verified = isParentVerified(profile);
  const statusMeta = getParentVerificationMeta(profile.status);
  const athleteName = getParentLinkedAthleteName(profile);
  const linkedAthlete = getParentPortalLinkedAthlete();
  const rawLinkedAthlete = linkedAthlete ? (getRawAthleteRecord(linkedAthlete.name) || linkedAthlete) : null;
  const questionnaireMeta = rawLinkedAthlete ? getAthleteQuestionnaireMeta(rawLinkedAthlete, { useDom: false }) : null;
  const coachRecord = getParentPortalCoachRecord();
  const primaryAssignment = getParentPortalPrimaryAssignment();
  const latestJournal = getParentPortalLatestJournal();

  if (parentStatusChip) parentStatusChip.textContent = statusMeta.label;
  if (parentStatusChip) parentStatusChip.className = statusMeta.className;

  if (!verified) {
    const normalizedStatus = normalizeParentVerificationStatus(profile.status);
    const statusTitle = normalizedStatus === "rejected"
      ? (currentLang === "es" ? "Conexion rechazada por el coach" : "Connection rejected by coach")
      : (currentLang === "es" ? "Acceso pendiente de verificacion" : "Access pending verification");
    const statusCopy = normalizedStatus === "rejected"
      ? (currentLang === "es"
        ? "El coach rechazo esta conexion de padre-atleta. Verifica el nombre del atleta y solicita una nueva aprobacion."
        : "The coach rejected this parent-athlete connection. Verify the athlete name and request approval again.")
      : (currentLang === "es"
        ? "La cuenta del padre esta vinculada al atleta indicado, pero el coach debe verificarla antes de desbloquear los datos."
        : "This parent account is linked to the athlete you entered, but a coach must verify the relationship before athlete data unlocks.");
    parentStatusCard.innerHTML = `
      <h3>${statusTitle}</h3>
      <p class="small">${statusCopy}</p>
      <ul class="list tight">
        <li>${currentLang === "es" ? "Atleta solicitado" : "Requested athlete"}: ${escapeHtml(athleteName || "-")}</li>
        <li>${currentLang === "es" ? "Estado" : "Status"}: ${escapeHtml(statusMeta.label)}</li>
        ${questionnaireMeta ? `<li>${currentLang === "es" ? "Cuestionario del atleta" : "Athlete questionnaire"}: ${escapeHtml(`${questionnaireMeta.progress.completed}/${questionnaireMeta.progress.total} (${questionnaireMeta.detail})`)}</li>` : ""}
      </ul>
    `;
    parentTrainingCard.innerHTML = `<p class="small muted">${currentLang === "es" ? "El plan de hoy aparecera aqui en cuanto el coach verifique el acceso." : "Today's training will appear here as soon as the coach verifies access."}</p>`;
    parentReadinessCard.innerHTML = `<p class="small muted">${currentLang === "es" ? "El readiness snapshot se mostrara aqui despues de la verificacion." : "The readiness snapshot will show here after verification."}</p>`;
    parentCoachCard.innerHTML = `<p class="small muted">${currentLang === "es" ? "Usa Messaging para avisarle al coach que ya solicitaste acceso." : "Use Messaging to let the coach know the parent account is waiting for approval."}</p>`;
    parentAssignmentsCard.innerHTML = `<p class="small muted">${currentLang === "es" ? "Las tareas abiertas del atleta se desbloquean cuando la cuenta este verificada." : "Open athlete work unlocks once the account is verified."}</p>`;
    updateParentFab();
    return;
  }

  parentStatusCard.innerHTML = `
    <h3>${escapeHtml(athleteName || (currentLang === "es" ? "Atleta vinculado" : "Linked athlete"))}</h3>
    <p class="small">${currentLang === "es" ? "Solo lectura del entrenamiento y readiness del atleta, mas un canal rapido para scouting y mensajes." : "Read-only training and readiness access for the athlete, plus a quick scouting and messaging channel."}</p>
    <ul class="list tight">
      <li>${currentLang === "es" ? "Coach vinculado" : "Linked coach"}: ${escapeHtml(coachRecord.name || "-")}</li>
      <li>${currentLang === "es" ? "Estado" : "Status"}: ${escapeHtml(statusMeta.label)}</li>
      ${questionnaireMeta ? `<li>${currentLang === "es" ? "Cuestionario del atleta" : "Athlete questionnaire"}: ${escapeHtml(`${questionnaireMeta.progress.completed}/${questionnaireMeta.progress.total} (${questionnaireMeta.detail})`)}</li>` : ""}
    </ul>
  `;
  parentTrainingCard.innerHTML = renderParentAssignmentSummary(primaryAssignment);
  parentReadinessCard.innerHTML = renderParentReadinessSummary(latestJournal);
  parentCoachCard.innerHTML = `
    <div class="parent-summary-stack">
      <strong>${escapeHtml(coachRecord.name || "Coach")}</strong>
      <p class="small">${currentLang === "es" ? "Este es el coach conectado a la cuenta del padre. Usa Messaging para enviar fotos, video y preguntas del torneo." : "This is the coach linked to the parent account. Use Messaging to send tournament photos, video, and questions."}</p>
      <div class="row">
        <button type="button" id="parentCoachMessageBtn">${currentLang === "es" ? "Abrir Messaging" : "Open Messaging"}</button>
      </div>
    </div>
  `;
  const openAssignments = getParentPortalActiveAssignments().slice(0, 4);
  const parentAnnouncements = buildAnnouncementTimelineRows(parentPortalAnnouncementsCache, {
    markRead: currentFocusedPanel === "parent-home"
  }).slice(0, 3);
  const parentNotificationRows = coachWorkspaceSortByUpdated(parentPortalNotificationsCache).slice(0, 4);
  if (currentFocusedPanel === "parent-home") {
    parentNotificationRows.forEach((item) => {
      if (!isNotificationReadByUser(item, authUser?.id || "")) {
        markWorkspaceNotificationReadById(item.id, item.coachUid).catch(() => {});
      }
    });
  }
  parentAssignmentsCard.innerHTML = openAssignments.length
    ? `<ul class="list tight">${openAssignments.map((item) => `<li><strong>${escapeHtml(item.title)}</strong> - ${escapeHtml(getAssignmentStatusMeta(item.status).label)}</li>`).join("")}</ul>`
    : `<p class="small muted">${currentLang === "es" ? "No hay tareas abiertas para este atleta." : "No open tasks for this athlete right now."}</p>`;
  parentAssignmentsCard.innerHTML += parentAnnouncements.length
    ? `
      <h4>${currentLang === "es" ? "Coach updates" : "Coach updates"}</h4>
      <ul class="list tight">
        ${parentAnnouncements.map((item) => `<li><strong>${escapeHtml(item.title)}</strong> - ${escapeHtml(item.detail)} (${escapeHtml(item.time)})</li>`).join("")}
      </ul>
    `
    : `<p class="small muted">${currentLang === "es" ? "No hay updates del coach por ahora." : "No coach updates yet."}</p>`;
  parentAssignmentsCard.innerHTML += parentNotificationRows.length
    ? `
      <h4>${currentLang === "es" ? "Notificaciones de tareas" : "Task notifications"}</h4>
      <ul class="list tight">
        ${parentNotificationRows.map((item) => {
          const unread = !isNotificationReadByUser(item, authUser?.id || "");
          const label = unread ? (currentLang === "es" ? "Sin leer" : "Unread") : (currentLang === "es" ? "Leido" : "Read");
          return `<li><strong>${escapeHtml(item.title || (currentLang === "es" ? "Notificacion" : "Notification"))}</strong> - ${escapeHtml(item.body || "")} (${escapeHtml(label)})</li>`;
        }).join("")}
      </ul>
    `
    : "";
  if (questionnaireMeta && !questionnaireMeta.complete) {
    parentAssignmentsCard.innerHTML += `<p class="small muted">${currentLang === "es" ? "El cuestionario del atleta aun tiene respuestas pendientes. Recomienda completarlo para mejorar el seguimiento del coach." : "The athlete questionnaire still has missing answers. Encourage completion so the coach can track progress accurately."}</p>`;
  }
  document.getElementById("parentCoachMessageBtn")?.addEventListener("click", async () => {
    showTab("messages");
    if (coachRecord.uid) {
      await openDirectMessageThreadWithRetry(coachRecord.uid);
    }
  });
  updateParentFab();
}

function getParentPortalTeammates() {
  const linkedAthleteId = getParentLinkedAthleteId();
  return parentPortalTeamCache.filter((athlete) => athlete.id !== linkedAthleteId && normalizeName(athlete.name) !== normalizeName(getParentLinkedAthleteName()));
}

function renderParentScouting() {
  if (!parentScoutingList || !parentScoutingTarget || !parentScoutingTargetWrap) return;
  const verified = isParentVerified();
  const teammates = getParentPortalTeammates();
  [
    parentScoutingSubjectType,
    parentScoutingTarget,
    parentScoutingFiles,
    parentScoutingText,
    parentScoutingSaveBtn,
    parentAudioStartBtn,
    parentAudioStopBtn,
    parentAudioClearBtn
  ].filter(Boolean).forEach((control) => {
    control.disabled = !verified;
  });
  if (parentScoutingTargetWrap) {
    parentScoutingTargetWrap.classList.toggle("hidden", (parentScoutingSubjectType?.value || "athlete") !== "teammate");
  }
  parentScoutingTarget.innerHTML = teammates.length
    ? teammates.map((athlete) => `<option value="${escapeHtml(athlete.name)}">${escapeHtml(athlete.name)}</option>`).join("")
    : `<option value="">${currentLang === "es" ? "No hay companeros disponibles" : "No teammates available"}</option>`;
  if (!verified) {
    if (parentScoutingStatus) {
      parentScoutingStatus.textContent = currentLang === "es" ? "Scouting se desbloquea cuando el coach verifique la cuenta." : "Scouting unlocks after the coach verifies the parent account.";
    }
    parentScoutingList.innerHTML = `<div class="mini-card"><p class="small muted">${currentLang === "es" ? "La subida de fotos, videos y audio estara disponible una vez la cuenta quede verificada." : "Photo, video, and audio uploads become available once the parent account is verified."}</p></div>`;
    return;
  }

  if (parentScoutingStatus && !parentScoutingStatus.textContent) {
    parentScoutingStatus.textContent = "";
  }
  parentScoutingList.innerHTML = "";
  if (!parentPortalScoutingCache.length) {
    parentScoutingList.innerHTML = `<div class="mini-card"><p class="small muted">${currentLang === "es" ? "Todavia no hay scouting notes subidas desde esta cuenta." : "No scouting notes have been uploaded from this account yet."}</p></div>`;
    return;
  }

  coachWorkspaceSortByUpdated(parentPortalScoutingCache).forEach((item) => {
    const card = document.createElement("article");
    card.className = "completion-card";
    const attachments = Array.isArray(item.attachments) ? item.attachments : [];
    const targetLabel = item.subjectType === "teammate"
      ? `${currentLang === "es" ? "Companero" : "Teammate"}: ${item.targetAthleteName || "-"}`
      : `${currentLang === "es" ? "Mi atleta" : "My athlete"}: ${item.targetAthleteName || getParentLinkedAthleteName()}`;
    card.innerHTML = `
      <div class="completion-card-top">
        <div>
          <strong>${escapeHtml(targetLabel)}</strong>
          <div class="small">${escapeHtml(formatAdminTimestamp(item.updatedAt || item.createdAt))}</div>
        </div>
        <span class="status-pill status-pill-active">${currentLang === "es" ? "Enviado" : "Sent"}</span>
      </div>
      <p class="small">${escapeHtml(item.text || (currentLang === "es" ? "Sin texto adicional." : "No extra text added."))}</p>
      <div class="completion-card-meta">
        <span>${currentLang === "es" ? "Adjuntos" : "Attachments"}: ${attachments.length}</span>
        <span>${currentLang === "es" ? "Audio" : "Audio"}: ${item.audioAttachment?.url ? "1" : "0"}</span>
      </div>
    `;
    if (attachments.length || item.audioAttachment?.url) {
      const links = document.createElement("div");
      links.className = "assignment-card-actions";
      attachments.forEach((file) => {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "ghost";
        btn.textContent = file.type?.startsWith("video") ? (currentLang === "es" ? "Abrir video" : "Open video") : (currentLang === "es" ? "Abrir foto" : "Open photo");
        btn.addEventListener("click", () => window.open(file.url, "_blank", "noopener,noreferrer"));
        links.appendChild(btn);
      });
      if (item.audioAttachment?.url) {
        const audioBtn = document.createElement("button");
        audioBtn.type = "button";
        audioBtn.className = "ghost";
        audioBtn.textContent = currentLang === "es" ? "Escuchar audio" : "Play audio";
        audioBtn.addEventListener("click", () => window.open(item.audioAttachment.url, "_blank", "noopener,noreferrer"));
        links.appendChild(audioBtn);
      }
      card.appendChild(links);
    }
    parentScoutingList.appendChild(card);
  });
}

function mergeCoachRecordsById(...lists) {
  const merged = new Map();
  lists.flat().forEach((item) => {
    if (!item?.id) return;
    merged.set(item.id, item);
  });
  return coachWorkspaceSortByUpdated(Array.from(merged.values()));
}

async function refreshParentPortalPlansFromAssignments() {
  const coachUid = getParentLinkedCoachUid();
  const planIds = Array.from(new Set(parentPortalAssignmentsCache.map((item) => item.planId).filter(Boolean))).sort();
  const nextKey = `${coachUid}:${planIds.join("|")}`;
  if (nextKey === parentPortalPlanFetchKey) return;
  parentPortalPlanFetchKey = nextKey;
  if (!coachUid || !planIds.length) {
    parentPortalPlansCache = [];
    renderParentHome();
    return;
  }
  const plansRef = getCoachWorkspaceCollectionRef("plans", coachUid);
  if (!plansRef) {
    parentPortalPlansCache = [];
    renderParentHome();
    return;
  }
  const snapshots = await Promise.all(planIds.map((planId) => withTimeout(
    plansRef.doc(planId).get(),
    FIREBASE_OP_TIMEOUT_MS,
    "firestore_parent_plan_read_timeout"
  ).catch(() => null)));
  parentPortalPlansCache = snapshots
    .filter((snapshot) => snapshot?.exists)
    .map((snapshot) => normalizeCoachPlanRecord(snapshot.id, snapshot.data() || {}));
  renderParentHome();
}

function refreshParentPortalDataSync() {
  clearParentPortalDataListeners();
  resetParentPortalCaches();
  const profile = getProfile();
  const authUser = getAuthUser();
  if (!isParentRole(profile?.role) || !authUser?.id || !firebaseFirestoreInstance) {
    renderParentHome();
    renderParentScouting();
    updateParentFab();
    return;
  }
  if (!isParentVerified(profile) || !getParentLinkedCoachUid(profile) || !getParentLinkedAthleteName(profile)) {
    renderParentHome();
    renderParentScouting();
    updateParentFab();
    return;
  }
  const coachUid = getParentLinkedCoachUid(profile);
  const athleteId = getParentLinkedAthleteId(profile);
  const athleteName = getParentLinkedAthleteName(profile);
  const athleteUid = getParentLinkedAthleteUid(profile);
  const workspaceAthletesRef = getCoachWorkspaceCollectionRef("athletes", coachUid);
  const assignmentsRef = getCoachWorkspaceCollectionRef("assignments", coachUid);
  const journalRef = getCoachWorkspaceCollectionRef("journal_entries", coachUid);
  const scoutingRef = getCoachWorkspaceCollectionRef("parent_scouting", coachUid);
  const announcementsRef = getCoachWorkspaceCollectionRef("announcements", coachUid);
  const notificationsRef = getCoachWorkspaceCollectionRef(COACH_WORKSPACE_NOTIFICATIONS_COLLECTION, coachUid);
  if (!workspaceAthletesRef || !assignmentsRef || !journalRef || !scoutingRef || !announcementsRef || !notificationsRef) return;
  let parentAssignmentsById = [];
  let parentAssignmentsByName = [];
  let parentAssignmentsByUid = [];
  let parentJournalById = [];
  let parentJournalByName = [];
  const applyParentAssignments = () => {
    parentPortalAssignmentsCache = mergeCoachRecordsById(parentAssignmentsById, parentAssignmentsByName, parentAssignmentsByUid);
    refreshParentPortalPlansFromAssignments().catch((err) => console.warn("Parent plan refresh failed", err));
    renderParentHome();
  };
  const applyParentJournal = () => {
    parentPortalJournalCache = mergeCoachRecordsById(parentJournalById, parentJournalByName);
    renderParentHome();
  };

  parentPortalDataUnsubs.push(
    workspaceAthletesRef.doc(athleteId).onSnapshot((snapshot) => {
      parentPortalAthleteCache = snapshot.exists
        ? normalizeCoachAthleteRecord(snapshot.id, snapshot.data() || {})
        : null;
      renderParentHome();
      renderParentScouting();
    }, (err) => console.warn("Parent athlete sync failed", err)),
    workspaceAthletesRef.onSnapshot((snapshot) => {
      parentPortalTeamCache = snapshot.docs.map((doc) => normalizeCoachAthleteRecord(doc.id, doc.data() || {}));
      renderParentScouting();
    }, (err) => console.warn("Parent teammate sync failed", err)),
    assignmentsRef.where("athleteIds", "array-contains", athleteId).onSnapshot((snapshot) => {
      parentAssignmentsById = snapshot.docs.map((doc) => normalizeCoachAssignmentRecord(doc.id, doc.data() || {}));
      applyParentAssignments();
    }, (err) => console.warn("Parent assignment sync failed", err)),
    assignmentsRef.where("assigneeNames", "array-contains", athleteName).onSnapshot((snapshot) => {
      parentAssignmentsByName = filterLegacyAthleteNameRecords(
        snapshot.docs.map((doc) => normalizeCoachAssignmentRecord(doc.id, doc.data() || {}))
      );
      applyParentAssignments();
    }, (err) => console.warn("Parent assignment name fallback sync failed", err)),
    journalRef.where("athleteId", "==", athleteId).onSnapshot((snapshot) => {
      parentJournalById = snapshot.docs.map((doc) => normalizeCoachJournalRecord(doc.id, doc.data() || {}));
      applyParentJournal();
    }, (err) => console.warn("Parent journal sync failed", err)),
    journalRef.where("athleteName", "==", athleteName).onSnapshot((snapshot) => {
      parentJournalByName = filterLegacyAthleteNameRecords(
        snapshot.docs.map((doc) => normalizeCoachJournalRecord(doc.id, doc.data() || {}))
      );
      applyParentJournal();
    }, (err) => console.warn("Parent journal name fallback sync failed", err)),
    scoutingRef.where("parentUid", "==", authUser.id).onSnapshot((snapshot) => {
      parentPortalScoutingCache = coachWorkspaceSortByUpdated(
        snapshot.docs.map((doc) => normalizeParentScoutingRecord(doc.id, doc.data() || {}))
      );
      renderParentScouting();
    }, (err) => console.warn("Parent scouting sync failed", err)),
    announcementsRef.onSnapshot((snapshot) => {
      parentPortalAnnouncementsCache = coachWorkspaceSortByUpdated(
        snapshot.docs
          .map((doc) => normalizeCoachAnnouncementRecord(doc.id, doc.data() || {}, { coachUid }))
          .filter((record) => announcementTargetsParentRecord(record, getProfile()))
      );
      renderAnnouncements();
      renderParentHome();
    }, (err) => console.warn("Parent announcement sync failed", err)),
    notificationsRef.where("recipientUids", "array-contains", authUser.id).onSnapshot((snapshot) => {
      parentPortalNotificationsCache = coachWorkspaceSortByUpdated(
        snapshot.docs.map((doc) => normalizeCoachNotificationRecord(doc.id, doc.data() || {}, { coachUid }))
      );
      renderParentHome();
    }, (err) => console.warn("Parent notifications sync failed", err))
  );

  if (athleteUid) {
    parentPortalDataUnsubs.push(
      assignmentsRef.where("athleteUids", "array-contains", athleteUid).onSnapshot((snapshot) => {
        parentAssignmentsByUid = snapshot.docs.map((doc) => normalizeCoachAssignmentRecord(doc.id, doc.data() || {}));
        applyParentAssignments();
      }, (err) => console.warn("Parent assignment uid sync failed", err))
    );
  }

  renderParentHome();
  renderParentScouting();
  updateParentFab();
}

function startParentPortalRealtimeSync() {
  const authUser = getAuthUser();
  const profile = getProfile();
  if (!isParentRole(profile?.role) || !authUser?.id || !firebaseFirestoreInstance) {
    stopParentPortalRealtimeSync();
    return;
  }
  if (parentPortalUserUnsub) return;
  parentPortalUserUnsub = firebaseFirestoreInstance.collection(FIREBASE_USERS_COLLECTION).doc(authUser.id).onSnapshot((snapshot) => {
    if (!snapshot.exists) return;
    const currentProfile = getProfile() || {};
    const nextProfile = normalizeProfileForAuth({ ...currentProfile, ...snapshot.data() }, authUser);
    const shouldRefresh = normalizeParentVerificationStatus(currentProfile.status) !== normalizeParentVerificationStatus(nextProfile.status)
      || getParentLinkedCoachUid(currentProfile) !== getParentLinkedCoachUid(nextProfile)
      || getParentLinkedAthleteId(currentProfile) !== getParentLinkedAthleteId(nextProfile)
      || getParentLinkedAthleteUid(currentProfile) !== getParentLinkedAthleteUid(nextProfile)
      || getParentLinkedAthleteName(currentProfile) !== getParentLinkedAthleteName(nextProfile);
    setProfile(nextProfile, { sync: false });
    if (shouldRefresh) {
      refreshParentPortalDataSync();
      startMessagesRealtimeSync({ forceRefreshContacts: true }).catch((err) => {
        console.warn("Parent messages refresh failed", err);
      });
    }
    renderParentHome();
    renderParentScouting();
    updateParentFab();
  }, (err) => console.warn("Parent profile sync failed", err));
  refreshParentPortalDataSync();
}

async function discoverAthleteCoachLink(profile = getProfile(), authUser = getAuthUser()) {
  if (!isAthleteRole(profile?.role) || !authUser?.id || !firebaseFirestoreInstance) return null;
  const athleteId = getAthleteLinkedAthleteId(profile);
  if (!athleteId) return null;

  const [coachSnapshot, adminCoachSnapshot] = await withTimeout(
    Promise.all([
      firebaseFirestoreInstance.collection(FIREBASE_USERS_COLLECTION).where("role", "==", "coach").get(),
      firebaseFirestoreInstance.collection(FIREBASE_USERS_COLLECTION).where("email", "==", "gmunch@united-wc.com").get()
    ]),
    FIREBASE_OP_TIMEOUT_MS * 2,
    "firestore_athlete_coach_lookup_timeout"
  );

  const coachRows = [];
  [...coachSnapshot.docs, ...adminCoachSnapshot.docs].forEach((doc) => {
    const coach = normalizeManagedUserRecord(doc.id, doc.data() || {});
    if (coach.uid && !coachRows.some((item) => item.uid === coach.uid)) {
      coachRows.push(coach);
    }
  });

  const candidates = [];
  for (const coach of coachRows) {
    const athleteRef = getCoachWorkspaceCollectionRef("athletes", coach.uid)?.doc(athleteId);
    if (!athleteRef) continue;
    try {
      const snapshot = await withTimeout(
        athleteRef.get(),
        FIREBASE_OP_TIMEOUT_MS,
        "firestore_athlete_workspace_lookup_timeout"
      );
      if (snapshot.exists) {
        candidates.push({
          coach,
          athlete: normalizeCoachAthleteRecord(snapshot.id, snapshot.data() || {})
        });
      }
    } catch (err) {
      console.warn("Athlete coach lookup skipped", err);
    }
  }

  if (!candidates.length) return null;
  return candidates
    .slice()
    .sort((left, right) => rankCoachLinkCandidate(right, authUser) - rankCoachLinkCandidate(left, authUser))[0] || null;
}

async function syncAthleteProfileLinkIfNeeded(profile = getProfile(), authUser = getAuthUser()) {
  if (!isAthleteRole(profile?.role) || !authUser?.id || !firebaseFirestoreInstance) {
    return profile;
  }
  const hasStableLink = Boolean(
    getAthleteLinkedCoachUid(profile)
    && getAthleteLinkedAthleteId(profile)
    && getAthleteLinkedAthleteUid(profile, authUser) === authUser.id
    && isOfficialCoachEmail(profile?.linkedCoachEmail || "")
  );
  if (hasStableLink) {
    return profile;
  }
  const discovered = await discoverAthleteCoachLink(profile, authUser);
  if (!discovered?.coach?.uid || !discovered?.athlete?.id) {
    return profile;
  }
  const nextProfile = normalizeProfileForAuth({
    ...profile,
    linkedAthleteId: discovered.athlete.id,
    linkedAthleteUid: authUser.id,
    linkedCoachUid: discovered.coach.uid,
    linkedCoachName: discovered.coach.name || "",
    linkedCoachEmail: discovered.coach.email || "",
    name: profile?.name || discovered.athlete.name || profile?.name || ""
  }, authUser);
  setProfile(nextProfile, { sync: false });
  await persistFirebaseProfile(authUser.id, {
    linkedAthleteId: nextProfile.linkedAthleteId,
    linkedAthleteUid: authUser.id,
    linkedCoachUid: nextProfile.linkedCoachUid,
    linkedCoachName: nextProfile.linkedCoachName,
    linkedCoachEmail: nextProfile.linkedCoachEmail || "",
    updatedAt: new Date().toISOString()
  }, { required: false });
  return nextProfile;
}

