function renderAthleteManagement() {
  if (!athleteFilters || !athleteList) return;
  if (coachAthleteRosterIntro) {
    coachAthleteRosterIntro.textContent = currentLang === "es"
      ? "All Athletes. Selecciona un atleta para actualizar Profile, Summary, Competition, Notes, Messages y Corner View."
      : "All Athletes. Select an athlete to update Profile, Summary, Competition, Notes, Messages, and Corner View.";
  }
  renderAthleteFilters();
  if (athleteSearchInput && athleteSearchInput.value !== athleteSearchQuery) {
    athleteSearchInput.value = athleteSearchQuery;
  }
  if (athleteSearchInput) {
    athleteSearchInput.placeholder = currentLang === "es" ? "Search by athlete name" : "Search by athlete name";
  }

  athleteList.innerHTML = "";
  const emptyLabel = currentLang === "es"
    ? "No hay atletas con esos filtros."
    : "No athletes match those filters.";
  const athletes = getAthletesData();
  const filtered = athletes.filter((athlete) => (
    athleteMatchesTagFilter(athlete.tags)
    && athleteMatchesSearch(athlete)
    && athleteMatchesCoachFilters(athlete)
  ));

  let selectedName = String(selectedCoachAthleteRosterName || "").trim();
  if (selectedName && !filtered.some((athlete) => athlete.name === selectedName)) {
    selectedName = "";
    selectedCoachAthleteRosterName = "";
    if (coachMatchSelect) coachMatchSelect.value = "";
  }

  if (!filtered.length) {
    const empty = document.createElement("div");
    empty.className = "mini-card";
    empty.innerHTML = `<h3>${emptyLabel}</h3>`;
    athleteList.appendChild(empty);
    renderCoachAthleteQuickActions("");
    renderCoachAthleteProfile("");
    return;
  }

  filtered.forEach((athlete) => {
    const overview = buildCoachAthleteOverview(athlete);
    const card = document.createElement("button");
    card.type = "button";
    card.className = "athlete-roster-item coach-athlete-name-option";
    const isActive = athlete.name === selectedName;
    card.classList.toggle("active", isActive);
    const rawAthlete = overview.rawAthlete || athlete;
    const questionnaireMeta = overview.questionnaireMeta;
    const board = getAthleteTaskBoard(athlete.name);
    const alerts = getAthleteAlerts(athlete);
    const recentActivity = getCoachAthleteRecentActivity(athlete);
    const pendingCount = board.tasks.length;
    const alertCount = alerts.length;
    const nameParts = splitAthleteName(athlete.name);
    const meta = [
      athlete.weightClass ? `${currentLang === "es" ? "Class" : "Class"} ${athlete.weightClass}` : "",
      overview.teamLabel
    ].filter(Boolean).join(" • ");
    const parentLinks = getParentLinksForAthlete(athlete);
    const pendingParentCount = parentLinks.pending.length;
    const missingProfile = questionnaireMeta.missing;
    card.innerHTML = `
      <div class="coach-athlete-name-option-main">
        <div class="coach-athlete-name-line">
          <span class="wpl-avatar wpl-avatar-sm coach-athlete-option-avatar" data-athlete-avatar></span>
          <div class="coach-athlete-name-option-copy">
            <h4>${escapeHtml(nameParts.firstName || athlete.name)}${nameParts.lastName ? ` <span>${escapeHtml(nameParts.lastName)}</span>` : ""}${isActive ? ` <span class="small">(${currentLang === "es" ? "active" : "active"})</span>` : ""}</h4>
            <div class="small athlete-card-meta">${meta}</div>
            <div class="small muted">${escapeHtml(overview.groupLabels.join(" • ") || (currentLang === "es" ? "No groups yet" : "No groups yet"))}</div>
          </div>
        </div>
        <div class="coach-athlete-name-option-stats">
          ${recentActivity.isRecent ? `<span class="status-pill status-pill-active">${currentLang === "es" ? "Recent activity" : "Recent activity"}</span>` : ""}
          ${pendingCount ? `<span class="status-pill status-pill-pending">${currentLang === "es" ? "Pending" : "Pending"}: ${pendingCount}</span>` : ""}
          ${alertCount ? `<span class="status-pill status-pill-alert">${currentLang === "es" ? "Alerts" : "Alerts"}: ${alertCount}</span>` : ""}
          ${pendingParentCount ? `<span class="status-pill status-pill-journal">${currentLang === "es" ? "Pending parents" : "Pending parents"}: ${pendingParentCount}</span>` : ""}
          ${missingProfile ? `<span class="status-pill ${questionnaireMeta.pillClass}">${currentLang === "es" ? "Missing profile" : "Missing profile"}: ${missingProfile}</span>` : `<span class="status-pill status-pill-active">${currentLang === "es" ? "Profile ready" : "Profile ready"}</span>`}
        </div>
      </div>
      <div class="small muted">${currentLang === "es" ? "Tap to make this the active athlete across coach workflow." : "Tap to make this the active athlete across coach workflow."}</div>
    `;
    renderAvatarElement(card.querySelector("[data-athlete-avatar]"), {
      photo: getProfilePhotoValue(rawAthlete || athlete),
      name: athlete.name,
      fallback: "AT"
    });
    card.addEventListener("click", () => {
      selectedCoachAthleteRosterName = athlete.name;
      selectCoachMatchAthlete(athlete.name, { allowFallback: false });
    });
    athleteList.appendChild(card);
  });

  renderCoachAthleteQuickActions(selectedName);
  renderCoachAthleteProfile(selectedName);
  const selectedAthlete = athletes.find((athlete) => athlete.name === selectedName);
  if (selectedAthlete) {
    renderCoachMatchView(selectedName);
    renderCompetitionPreview(selectedAthlete);
  } else {
    renderCoachMatchView("");
    renderCompetitionPreview(null);
  }
}

if (athleteSearchInput) {
  athleteSearchInput.addEventListener("input", () => {
    athleteSearchQuery = athleteSearchInput.value.trim().toLowerCase();
    renderAthleteManagement();
  });
}

const athleteNotesFocus = document.getElementById("athleteNotesFocus");
const athleteNotesRecent = document.getElementById("athleteNotesRecent");
const athleteNotesSelectedAthlete = document.getElementById("athleteNotesSelectedAthlete");
const coachAthleteNotesForm = document.getElementById("coachAthleteNotesForm");
const coachAthleteFocus1 = document.getElementById("coachAthleteFocus1");
const coachAthleteFocus2 = document.getElementById("coachAthleteFocus2");
const coachAthleteFocus3 = document.getElementById("coachAthleteFocus3");
const coachAthleteRecentNote = document.getElementById("coachAthleteRecentNote");
const coachAthleteNotesStatus = document.getElementById("coachAthleteNotesStatus");
const coachAthleteNotesClearBtn = document.getElementById("coachAthleteNotesClearBtn");

function renderAthleteNotes() {
  if (!athleteNotesFocus || !athleteNotesRecent) return;
  const athleteName = getSelectedCoachAthleteName();
  const athlete = getAthletesData().find((item) => item.name === athleteName) || null;
  const noteBoard = athlete ? getCoachNoteRecord(athlete.name) : null;
  if (!athlete) {
    const selectHint = currentLang === "es"
      ? "Selecciona un atleta en Athletes para ver y editar notas."
      : "Select an athlete in Athletes to view and edit notes.";
    athleteNotesFocus.innerHTML = `<li>${selectHint}</li>`;
    athleteNotesRecent.innerHTML = `<li>${selectHint}</li>`;
    if (athleteNotesSelectedAthlete) {
      athleteNotesSelectedAthlete.textContent = currentLang === "es" ? "Selecciona un atleta." : "Select an athlete.";
    }
    if (coachAthleteFocus1) coachAthleteFocus1.value = "";
    if (coachAthleteFocus2) coachAthleteFocus2.value = "";
    if (coachAthleteFocus3) coachAthleteFocus3.value = "";
    if (coachAthleteRecentNote) coachAthleteRecentNote.value = "";
    return;
  }
  const latestPlan = athlete ? getLatestCoachPlanForAthlete(athlete.name) : null;
  const openAssignments = athlete ? getPlanAssignmentsForAthlete(athlete.name).filter((item) => item.status !== "completed") : [];

  const focusItems = [
    ...(noteBoard?.nextFocus || []).map((item) => getSeedCopyValue(item)),
    latestPlan
      ? `${currentLang === "es" ? "Plan activo" : "Active plan"}: ${latestPlan.title}`
      : "",
    openAssignments[0]
      ? `${currentLang === "es" ? "Siguiente tarea" : "Next task"}: ${openAssignments[0].title}`
      : ""
  ].filter(Boolean).slice(0, 4);

  const recentItems = (noteBoard?.recentNotes || []).map((item) => getSeedCopyValue(item)).slice(0, 3);

  athleteNotesFocus.innerHTML = focusItems
    .map((line) => `<li>${line}</li>`)
    .join("");
  athleteNotesRecent.innerHTML = recentItems
    .map((line) => `<li>${line}</li>`)
    .join("");
  if (athleteNotesSelectedAthlete) {
    athleteNotesSelectedAthlete.textContent = athlete?.name
      ? `${currentLang === "es" ? "Atleta seleccionado" : "Selected athlete"}: ${athlete.name}`
      : (currentLang === "es" ? "Selecciona un atleta." : "Select an athlete.");
  }
  const editableFocus = (noteBoard?.nextFocus || []).map((item) => getSeedCopyValue(item));
  if (coachAthleteFocus1) coachAthleteFocus1.value = editableFocus[0] || "";
  if (coachAthleteFocus2) coachAthleteFocus2.value = editableFocus[1] || "";
  if (coachAthleteFocus3) coachAthleteFocus3.value = editableFocus[2] || "";
}

