const journalInsights = document.getElementById("journalInsights");
const journalFlags = document.getElementById("journalFlags");
const journalAthletes = document.getElementById("journalAthletes");
const coachJournalSelectedAthlete = document.getElementById("coachJournalSelectedAthlete");
const coachJournalForm = document.getElementById("coachJournalForm");
const coachJournalSleep = document.getElementById("coachJournalSleep");
const coachJournalEnergy = document.getElementById("coachJournalEnergy");
const coachJournalSoreness = document.getElementById("coachJournalSoreness");
const coachJournalMood = document.getElementById("coachJournalMood");
const coachJournalWeight = document.getElementById("coachJournalWeight");
const coachJournalNote = document.getElementById("coachJournalNote");
const coachJournalStatus = document.getElementById("coachJournalStatus");
const coachJournalClearBtn = document.getElementById("coachJournalClearBtn");
const coachJournalRecentList = document.getElementById("coachJournalRecentList");

function renderJournalMonitor() {
  if (!journalInsights || !journalFlags || !journalAthletes) return;
  const selectedAthleteName = getSelectedCoachAthleteName();
  journalInsights.innerHTML = "";
  getJournalInsightsData().forEach((line) => {
    const li = document.createElement("li");
    li.textContent = line;
    journalInsights.appendChild(li);
  });

  journalFlags.innerHTML = "";
  getJournalFlagsData().forEach((line) => {
    const li = document.createElement("li");
    li.textContent = line;
    journalFlags.appendChild(li);
  });

  journalAthletes.innerHTML = "";
  const sleepLabel = currentLang === "es" ? "Sueno" : "Sleep";
  const energyLabel = currentLang === "es" ? "Energia" : "Energy";
  const sorenessLabel = currentLang === "es" ? "Dolor" : "Soreness";
  const moodLabel = currentLang === "es" ? "Animo" : "Mood";
  const weightLabel = currentLang === "es" ? "Tendencia de peso" : "Weight trend";
  const noDataLabel = currentLang === "es" ? "Sin datos" : "No data";
  const rows = getJournalAthletesData(selectedAthleteName);
  if (!rows.length) {
    const card = document.createElement("div");
    card.className = "athlete-card";
    card.innerHTML = `<h4>${currentLang === "es" ? "Sin atletas disponibles" : "No athletes available"}</h4>`;
    journalAthletes.appendChild(card);
  } else {
    rows.forEach((athlete) => {
      const isActive = athlete.name === selectedAthleteName;
      const journalState = athlete.hasEntry ? getCoachJournalState(athlete.name) : "no_data";
      const statusClass = journalState === "fresh"
        ? "status-pill-active"
        : journalState === "stale"
          ? "status-pill-journal"
          : "status-pill-pending";
      const statusLabel = journalState === "fresh"
        ? (currentLang === "es" ? "Al dia" : "Fresh")
        : journalState === "stale"
          ? (currentLang === "es" ? "Atrasado" : "Stale")
          : (currentLang === "es" ? "Sin datos" : "No data");
      const lastUpdateLabel = athlete.entryDate
        ? formatPlanDateLabel(athlete.entryDate)
        : (currentLang === "es" ? "Sin entrada guardada" : "No saved entry");
      const card = document.createElement("div");
      card.className = `athlete-card${isActive ? " active" : ""}`;
      card.setAttribute("role", "button");
      card.tabIndex = 0;
      card.innerHTML = `
        <div class="athlete-card-header">
          <div>
            <h4>${escapeHtml(athlete.name)}</h4>
            <div class="small muted">${escapeHtml(lastUpdateLabel)}</div>
          </div>
          <div class="athlete-card-status">
            <span class="status-pill ${statusClass}">${statusLabel}</span>
          </div>
        </div>
        <div class="small">${sleepLabel}: ${escapeHtml(athlete.sleep || noDataLabel)} - ${energyLabel}: ${escapeHtml(athlete.energy || noDataLabel)}</div>
        <div class="small">${sorenessLabel}: ${escapeHtml(athlete.soreness || noDataLabel)} - ${moodLabel}: ${escapeHtml(athlete.mood || noDataLabel)}</div>
        <div class="small">${weightLabel}: ${escapeHtml(athlete.weight || noDataLabel)}</div>
      `;
      const openAthlete = () => {
        selectCoachMatchAthlete(athlete.name, { allowFallback: false });
      };
      card.addEventListener("click", openAthlete);
      card.addEventListener("keydown", (event) => {
        if (event.key !== "Enter" && event.key !== " ") return;
        event.preventDefault();
        openAthlete();
      });
      journalAthletes.appendChild(card);
    });
  }

  const selectedJournal = getLatestCoachJournalRecord(selectedAthleteName);
  if (coachJournalSelectedAthlete) {
    coachJournalSelectedAthlete.textContent = selectedAthleteName
      ? `${currentLang === "es" ? "Atleta seleccionado" : "Selected athlete"}: ${selectedAthleteName}`
      : (currentLang === "es" ? "Selecciona un atleta." : "Select an athlete.");
  }
  if (coachJournalSleep) coachJournalSleep.value = selectedJournal?.sleep || "";
  if (coachJournalEnergy) coachJournalEnergy.value = selectedJournal?.energy || "";
  if (coachJournalSoreness) coachJournalSoreness.value = selectedJournal?.soreness || "";
  if (coachJournalMood) coachJournalMood.value = selectedJournal?.mood || "";
  if (coachJournalWeight) coachJournalWeight.value = selectedJournal?.weight || "";
  if (coachJournalNote) coachJournalNote.value = selectedJournal?.note || "";

  if (coachJournalRecentList) {
    coachJournalRecentList.innerHTML = "";
    const recentEntries = selectedAthleteName ? getCoachJournalRecordSetForAthlete(selectedAthleteName).slice(0, 4) : [];
    if (!recentEntries.length) {
      coachJournalRecentList.innerHTML = `<div class="mini-card"><p class="small muted">${currentLang === "es" ? "Todavia no hay entradas guardadas." : "No readiness entries saved yet."}</p></div>`;
    } else {
      recentEntries.forEach((entry) => {
        const card = document.createElement("article");
        card.className = "completion-card";
        card.innerHTML = `
          <div class="completion-card-top">
            <div>
              <strong>${formatPlanDateLabel(entry.entryDate)}</strong>
              <div class="small">${sleepLabel}: ${entry.sleep || "-"} • ${energyLabel}: ${entry.energy || "-"}</div>
            </div>
            <span class="status-pill ${getCoachJournalState(selectedAthleteName) === "stale" ? "status-pill-journal" : "status-pill-active"}">${getCoachJournalState(selectedAthleteName) === "stale" ? (currentLang === "es" ? "Atrasado" : "Stale") : (currentLang === "es" ? "Al dia" : "Fresh")}</span>
          </div>
          <div class="completion-card-meta">
            <span>${sorenessLabel}: ${entry.soreness || "-"}</span>
            <span>${moodLabel}: ${entry.mood || "-"}</span>
            <span>${weightLabel}: ${entry.weight || "-"}</span>
          </div>
          <p class="small">${entry.note || (currentLang === "es" ? "Sin nota adicional." : "No additional note.")}</p>
        `;
        coachJournalRecentList.appendChild(card);
      });
    }
  }
}

function normalizeCoachQuestionnaireStance(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  return ["left", "right", "switch"].includes(normalized) ? normalized : "";
}

async function resolveAthleteUserUidFromRecord(athleteRecord) {
  const directUid = normalizeUid(athleteRecord?.athleteUid);
  if (directUid) return directUid;
  const athleteEmail = normalizeEmail(athleteRecord?.athleteEmail || "");
  if (!firebaseFirestoreInstance || !athleteEmail) return "";
  try {
    const usersRef = firebaseFirestoreInstance.collection(FIREBASE_USERS_COLLECTION);
    const snapshot = await withTimeout(
      usersRef.where("email", "==", athleteEmail).where("role", "==", "athlete").limit(1).get(),
      FIREBASE_OP_TIMEOUT_MS * 2,
      "firestore_athlete_user_lookup_timeout"
    );
    if (!snapshot.empty) return String(snapshot.docs[0].id || "").trim();
  } catch (err) {
    console.warn("Athlete user lookup by email failed", err);
  }
  return "";
}

async function saveCoachAthleteQuestionnaire(event, athleteName = getSelectedCoachAthleteName()) {
  event?.preventDefault?.();
  const statusEl = document.getElementById("coachAthleteQuestionnaireStatus");
  const athletesRef = getCoachWorkspaceCollectionRef("athletes");
  const athleteRecord = getCoachAthleteRecordByIdentity(athleteName) || getAthletesData().find((entry) => entry.name === athleteName) || null;
  if (!athleteName || !athleteRecord) {
    const message = currentLang === "es" ? "Selecciona un atleta antes de guardar." : "Select an athlete before saving.";
    if (statusEl) statusEl.textContent = message;
    toast(message);
    return;
  }
  if (!athletesRef) {
    const message = currentLang === "es" ? "No hay acceso al registro de atletas." : "Athlete store is not available.";
    if (statusEl) statusEl.textContent = message;
    toast(message);
    return;
  }

  const preferredMoves = String(document.getElementById("coachQuestionPreferredMoves")?.value || "").trim();
  const stance = normalizeCoachQuestionnaireStance(document.getElementById("coachQuestionStance")?.value || "");
  const years = String(document.getElementById("coachQuestionYears")?.value || "").trim();
  const weightClass = String(document.getElementById("coachQuestionWeightClass")?.value || "").trim();
  const questionnaireNotes = String(document.getElementById("coachQuestionAthleteNotes")?.value || "").trim();
  const coachQuestionnaireNotes = String(document.getElementById("coachQuestionCoachNotes")?.value || "").trim();
  const coachName = String(getProfile()?.name || getAuthUser()?.email || "").trim();
  const athleteId = normalizeAthleteId(athleteRecord.id, athleteRecord.name || athleteName);
  const athleteUid = normalizeUid(athleteRecord.athleteUid);
  const athleteEmail = normalizeEmail(athleteRecord.athleteEmail || athleteRecord.email || "");
  const nowIso = new Date().toISOString();

  const payload = stripUndefinedDeep({
    name: athleteRecord.name || athleteName,
    athleteUid,
    athleteEmail,
    preferredMoves,
    preferred_moves: preferredMoves,
    preferred: preferredMoves,
    stance,
    years,
    experienceYears: years,
    experience_years: years,
    weightClass,
    weight_class: weightClass,
    questionnaireNotes,
    notes: questionnaireNotes,
    coachQuestionnaireNotes,
    questionnaireUpdatedBy: coachName,
    questionnaireUpdatedAt: getFirestoreServerTimestamp(),
    updatedAt: getFirestoreServerTimestamp()
  });

  try {
    await withTimeout(
      athletesRef.doc(athleteId).set(payload, { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_coach_questionnaire_update_timeout"
    );

    const nextRecord = normalizeCoachAthleteRecord(athleteId, {
      ...athleteRecord,
      preferredMoves,
      preferred_moves: preferredMoves,
      preferred: preferredMoves,
      stance,
      years,
      experienceYears: years,
      experience_years: years,
      weightClass,
      weight_class: weightClass,
      questionnaireNotes,
      notes: questionnaireNotes,
      coachQuestionnaireNotes,
      questionnaireUpdatedBy: coachName,
      questionnaireUpdatedAt: nowIso,
      updatedAt: nowIso
    });
    coachAthletesCache = coachWorkspaceSortByUpdated([
      nextRecord,
      ...coachAthletesCache.filter((record) => record.id !== athleteId)
    ]);

    const athleteUserUid = athleteUid || await resolveAthleteUserUidFromRecord(athleteRecord);
    if (athleteUserUid) {
      await persistFirebaseProfile(athleteUserUid, {
        preferredMoves,
        preferred_moves: preferredMoves,
        stance,
        years,
        experienceYears: years,
        experience_years: years,
        weightClass,
        weight_class: weightClass,
        questionnaireNotes,
        coachQuestionnaireNotes,
        questionnaireUpdatedBy: coachName,
        questionnaireUpdatedAt: nowIso,
        updatedAt: nowIso
      }, { required: false });
    }

    if (statusEl) {
      statusEl.textContent = currentLang === "es"
        ? "Formulario actualizado. El atleta ya puede ver estos cambios."
        : "Questionnaire updated. The athlete can now see these changes.";
    }
    toast(currentLang === "es" ? "Cuestionario guardado." : "Questionnaire saved.");
    renderAthleteManagement();
    renderCoachAthleteProfile(athleteName);
    renderCoachMatchView(athleteName);
    renderCompetitionPreview(getCoachAthleteRecordByIdentity(athleteName) || athleteRecord);
  } catch (err) {
    console.warn("Coach questionnaire save failed", err);
    const message = currentLang === "es"
      ? "No se pudo guardar el cuestionario del atleta."
      : "Could not save athlete questionnaire.";
    if (statusEl) statusEl.textContent = message;
    toast(message);
  }
}

async function saveCoachAthleteNotes(event) {
  event?.preventDefault?.();
  const athleteName = getSelectedCoachAthleteName();
  const athleteRecord = getCoachAthleteRecordByIdentity(athleteName);
  const notesRef = getCoachWorkspaceCollectionRef("coach_notes");
  if (!athleteName) {
    const message = currentLang === "es" ? "Selecciona un atleta antes de guardar notas." : "Select an athlete before saving notes.";
    if (coachAthleteNotesStatus) coachAthleteNotesStatus.textContent = message;
    toast(message);
    return;
  }
  if (!notesRef) {
    const message = currentLang === "es" ? "Las notas del coach no estan disponibles para esta cuenta." : "Coach notes are not available for this account.";
    if (coachAthleteNotesStatus) coachAthleteNotesStatus.textContent = message;
    toast(message);
    return;
  }
  const nextFocus = [coachAthleteFocus1?.value, coachAthleteFocus2?.value, coachAthleteFocus3?.value]
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  const newNote = String(coachAthleteRecentNote?.value || "").trim();
  const existing = getCoachNoteRecord(athleteName);
  const recentNotes = uniqueNames([
    newNote,
    ...(existing?.recentNotes || [])
  ]).slice(0, 6);
  try {
    await withTimeout(
      notesRef.doc(normalizeAthleteId(athleteRecord?.id, athleteName)).set(stripUndefinedDeep({
        athleteId: normalizeAthleteId(athleteRecord?.id, athleteName),
        athleteUid: normalizeUid(athleteRecord?.athleteUid),
        athleteName,
        nextFocus,
        recentNotes,
        updatedAt: getFirestoreServerTimestamp(),
        createdAt: existing ? undefined : getFirestoreServerTimestamp()
      }), { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_note_write_timeout"
    );
    if (coachAthleteRecentNote) coachAthleteRecentNote.value = "";
    const recordId = normalizeAthleteId(athleteRecord?.id, athleteName);
    coachNotesCache = coachWorkspaceSortByUpdated([
      normalizeCoachNoteRecord(recordId, {
        athleteId: recordId,
        athleteUid: normalizeUid(athleteRecord?.athleteUid),
        athleteName,
        nextFocus,
        recentNotes,
        updatedAt: new Date().toISOString()
      }),
      ...coachNotesCache.filter((record) => record.id !== recordId)
    ]);
    if (coachAthleteNotesStatus) {
      coachAthleteNotesStatus.textContent = currentLang === "es" ? "Notas guardadas." : "Notes saved.";
    }
    renderAthleteNotes();
    renderAthleteManagement();
    renderCoachAthleteProfile(athleteName);
    renderCoachMatchView(athleteName);
  } catch (err) {
    console.warn("Coach notes save failed", err);
    if (coachAthleteNotesStatus) {
      coachAthleteNotesStatus.textContent = currentLang === "es" ? "No se pudieron guardar las notas." : "Could not save notes.";
    }
  }
}

async function saveCoachJournalEntry(event) {
  event?.preventDefault?.();
  const athleteName = getSelectedCoachAthleteName();
  const athleteRecord = getCoachAthleteRecordByIdentity(athleteName);
  const journalRef = getCoachWorkspaceCollectionRef("journal_entries");
  if (!athleteName) {
    const message = currentLang === "es" ? "Selecciona un atleta antes de guardar el journal." : "Select an athlete before saving the journal.";
    if (coachJournalStatus) coachJournalStatus.textContent = message;
    toast(message);
    return;
  }
  if (!journalRef) {
    const message = currentLang === "es" ? "El journal del coach no esta disponible para esta cuenta." : "Coach journal is not available for this account.";
    if (coachJournalStatus) coachJournalStatus.textContent = message;
    toast(message);
    return;
  }
  const entryDate = getCurrentAppDateKey();
  const payload = {
    athleteId: normalizeAthleteId(athleteRecord?.id, athleteName),
    athleteUid: normalizeUid(athleteRecord?.athleteUid),
    athleteName,
    entryDate,
    sleep: String(coachJournalSleep?.value || "").trim(),
    energy: String(coachJournalEnergy?.value || "").trim(),
    soreness: String(coachJournalSoreness?.value || "").trim(),
    mood: String(coachJournalMood?.value || "").trim(),
    weight: String(coachJournalWeight?.value || "").trim(),
    coachNote: String(coachJournalNote?.value || "").trim()
  };
  try {
    await withTimeout(
      journalRef.doc(`${normalizeAthleteId(athleteRecord?.id, athleteName)}-${entryDate}`).set({
        ...payload,
        updatedAt: getFirestoreServerTimestamp(),
        createdAt: getFirestoreServerTimestamp()
      }, { merge: true }),
      FIREBASE_OP_TIMEOUT_MS,
      "firestore_journal_write_timeout"
    );
    const recordId = `${normalizeAthleteId(athleteRecord?.id, athleteName)}-${entryDate}`;
    coachJournalEntriesCache = coachWorkspaceSortByUpdated([
      normalizeCoachJournalRecord(recordId, {
        ...payload,
        updatedAt: new Date().toISOString(),
        createdAt: new Date().toISOString()
      }),
      ...coachJournalEntriesCache.filter((record) => record.id !== recordId)
    ]);
    if (coachJournalStatus) {
      coachJournalStatus.textContent = currentLang === "es" ? "Journal guardado." : "Journal entry saved.";
    }
    renderJournalMonitor();
    renderAthleteManagement();
    renderCoachMatchView(athleteName);
    renderCompetitionPreview(getCoachAthleteRecordByIdentity(athleteName) || getAthletesData().find((item) => item.name === athleteName) || null);
  } catch (err) {
    console.warn("Coach journal save failed", err);
    if (coachJournalStatus) {
      coachJournalStatus.textContent = currentLang === "es" ? "No se pudo guardar el journal." : "Could not save the journal entry.";
    }
  }
}

if (coachAthleteNotesForm) {
  coachAthleteNotesForm.addEventListener("submit", saveCoachAthleteNotes);
}

if (coachAthleteNotesClearBtn) {
  coachAthleteNotesClearBtn.addEventListener("click", () => {
    [coachAthleteFocus1, coachAthleteFocus2, coachAthleteFocus3, coachAthleteRecentNote].forEach((field) => {
      if (field) field.value = "";
    });
    if (coachAthleteNotesStatus) coachAthleteNotesStatus.textContent = "";
  });
}

if (coachJournalForm) {
  coachJournalForm.addEventListener("submit", saveCoachJournalEntry);
}

if (coachJournalClearBtn) {
  coachJournalClearBtn.addEventListener("click", () => {
    [coachJournalSleep, coachJournalEnergy, coachJournalSoreness, coachJournalMood, coachJournalWeight, coachJournalNote].forEach((field) => {
      if (field) field.value = "";
    });
    if (coachJournalStatus) coachJournalStatus.textContent = "";
  });
}

