function selectCoachMatchAthlete(name, { allowFallback = false } = {}) {
  const athletes = getAthletesData();
  const requestedName = String(name || "").trim();
  const selectedAthlete = athletes.find((athlete) => athlete.name === requestedName)
    || (allowFallback ? athletes[0] : null);
  if (!selectedAthlete) {
    if (coachMatchSelect) coachMatchSelect.value = "";
    if (!allowFallback) {
      selectedCoachAthleteRosterName = "";
      renderCoachAthleteProfile("");
      renderAthleteManagement();
    }
    return;
  }
  selectedCoachAthleteRosterName = selectedAthlete.name;
  if (coachMatchSelect) coachMatchSelect.value = selectedAthlete.name;
  renderCoachAthleteProfile(selectedAthlete.name);
  renderCoachMatchView(selectedAthlete.name);
  renderCompetitionPreview(selectedAthlete);
  renderAthleteManagement();
  renderAthleteNotes();
  renderJournalMonitor();
  renderMedia();
}

function openAthleteSummaryView(name = "") {
  if (name) {
    selectCoachMatchAthlete(name);
  } else if (coachMatchSelect?.value) {
    selectCoachMatchAthlete(coachMatchSelect.value);
  }
  Promise.resolve(showTab("coach-match")).finally(() => {
    athleteSummaryCard?.scrollIntoView({ behavior: "smooth", block: "start" });
    flashActionTarget(athleteSummaryCard);
  });
}

if (coachMatchSelect) {
  syncCoachMatchAthleteSelect();
  coachMatchSelect.addEventListener("change", () => selectCoachMatchAthlete(coachMatchSelect.value, { allowFallback: false }));
  selectCoachMatchAthlete("", { allowFallback: false });
}

// ---------- MESSAGES ----------
// Messages domain is loaded lazily from messages-domain.js.

// ---------- SKILLS ----------
const skillsGrid = document.getElementById("skillsGrid");

function renderSkills() {
  if (!skillsGrid) return;
  skillsGrid.innerHTML = "";
  const bestClipLabel = currentLang === "es" ? "Mejor clip" : "Best clip";
  const notesLabel = currentLang === "es" ? "Notas" : "Notes";
  const updatedLabel = currentLang === "es" ? "Actualizado" : "Updated";
  const rows = getSkillsData();
  if (!rows.length) {
    const card = document.createElement("div");
    card.className = "skill-card";
    card.innerHTML = `
      <h3>${currentLang === "es" ? "Sin habilidades registradas" : "No skills logged yet"}</h3>
      <div class="small">${currentLang === "es" ? "El coach puede agregar y actualizar habilidades desde el perfil del atleta." : "Coaches can add and update skills from the athlete profile."}</div>
    `;
    skillsGrid.appendChild(card);
    return;
  }
  rows.forEach((skill) => {
    const card = document.createElement("div");
    card.className = "skill-card";
    card.innerHTML = `
      <h3>${skill.name}</h3>
      <div class="rating">${skill.rating}</div>
      <div class="small">${bestClipLabel}: ${skill.clip}</div>
      <div class="small">${notesLabel}: ${skill.notes}</div>
      <div class="small">${updatedLabel}: ${skill.updated}</div>
    `;
    skillsGrid.appendChild(card);
  });
}

// ---------- JOURNAL ----------
const journalInput = document.getElementById("journalInput");
const saveJournalBtn = document.getElementById("saveJournalBtn");
const journalStatus = document.getElementById("journalStatus");
const journalEntries = document.getElementById("journalEntries");
const JOURNAL_ENTRIES_KEY = "wpl_journal_entries";

function getJournalEntries() {
  if (Array.isArray(userCloudPersonalJournalCache)) {
    return userCloudPersonalJournalCache;
  }
  const saved = localStorage.getItem(JOURNAL_ENTRIES_KEY);
  if (!saved) return [];
  try {
    const parsed = JSON.parse(saved);
    return normalizePersonalJournalEntries(parsed);
  } catch {
    return [];
  }
}

function ensureSeedJournalEntries() {
  if (isAthleteRole(getProfile()?.role) && athletePortalJournalCache.length) {
    return athletePortalJournalCache;
  }
  const existing = getJournalEntries();
  if (existing.length) return existing;
  if (PUBLISH_READY_MODE) return existing;
  const seeded = [
    {
      date: new Date(Date.now() - 1000 * 60 * 60 * 18).toISOString(),
      note: "Sleep was solid. Best feel today was on single-leg finishes after the re-shot. Need to stay patient when the first attack gets blocked."
    }
  ];
  localStorage.setItem(JOURNAL_ENTRIES_KEY, JSON.stringify(seeded));
  return seeded;
}

function formatJournalDate(timestamp) {
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return "";
  const locale = currentLang === "es" ? "es-PR" : "en-US";
  return date.toLocaleString(locale, { dateStyle: "medium", timeStyle: "short" });
}

function renderJournalEntries() {
  if (!journalEntries) return;
  const entries = isAthleteRole(getProfile()?.role) && athletePortalJournalCache.length
    ? coachWorkspaceSortByUpdated(athletePortalJournalCache).map((entry) => ({
        date: entry.updatedAt || entry.createdAt || `${entry.entryDate}T12:00:00`,
        note: entry.athleteReflection || entry.note || entry.coachNote || "",
        meta: entry.entryDate
      }))
    : getJournalEntries();
  if (!entries.length) {
    journalEntries.innerHTML = `<p class="small muted">${pickCopy({ en: "No journal entries yet.", es: "Todavia no hay entradas de diario." })}</p>`;
    return;
  }
  journalEntries.innerHTML = entries
    .slice()
    .reverse()
    .map((entry) => {
      const date = formatJournalDate(entry.date);
      return `
        <div class="journal-entry-card">
          <div class="journal-entry-date">${date || pickCopy({ en: "Unknown time", es: "Hora desconocida" })}</div>
          <p>${String(entry.note || "").replace(/</g, "&lt;").replace(/>/g, "&gt;")}</p>
        </div>
      `;
    })
    .join("");
}

async function saveJournalEntry({
  noteOverride = "",
  entryDateOverride = "",
  silentStatus = false
} = {}) {
  const hasNoteOverride = String(noteOverride || "").trim().length > 0;
  const note = hasNoteOverride
    ? String(noteOverride || "").trim()
    : String(journalInput?.value || "").trim();
  if (!note) {
    if (!silentStatus && journalStatus) {
      journalStatus.textContent = pickCopy({ en: "Write something before saving.", es: "Escribe algo antes de guardar." });
      setTimeout(() => (journalStatus.textContent = ""), 1600);
    }
    return false;
  }
  const entryDate = normalizeDateKey(entryDateOverride || getCurrentAppDateKey());

  if (isAthleteRole(getProfile()?.role) && getAthleteLinkedCoachUid()) {
    const profile = getProfile();
    const authUser = getAuthUser();
    const coachUid = getAthleteLinkedCoachUid(profile);
    const athleteId = getAthleteLinkedAthleteId(profile);
    const journalRef = getCoachWorkspaceCollectionRef("journal_entries", coachUid);
    if (!authUser?.id || !coachUid || !athleteId || !journalRef) {
      if (!silentStatus && journalStatus) {
        journalStatus.textContent = currentLang === "es" ? "No se pudo conectar el journal." : "Could not connect the journal.";
        setTimeout(() => (journalStatus.textContent = ""), 1800);
      }
      return false;
    }
    try {
      await withTimeout(
        journalRef.doc(`${athleteId}-${entryDate}`).set(stripUndefinedDeep({
          athleteId,
          athleteUid: authUser.id,
          athleteName: String(profile?.name || "").trim(),
          entryDate,
          athleteReflection: note,
          updatedAt: getFirestoreServerTimestamp(),
          createdAt: getFirestoreServerTimestamp()
        }), { merge: true }),
        FIREBASE_OP_TIMEOUT_MS,
        "firestore_athlete_journal_write_timeout"
      );
      if (!hasNoteOverride && journalInput) journalInput.value = "";
      if (!silentStatus && journalStatus) {
        journalStatus.textContent = pickCopy({ en: "Entry saved.", es: "Entrada guardada." });
        setTimeout(() => (journalStatus.textContent = ""), 1600);
      }
      renderJournalEntries();
      return true;
    } catch (err) {
      console.warn("Athlete journal save failed", err);
      if (!silentStatus && journalStatus) {
        journalStatus.textContent = currentLang === "es" ? "No se pudo guardar la entrada." : "Could not save the entry.";
        setTimeout(() => (journalStatus.textContent = ""), 1800);
      }
      return false;
    }
  }

  const entries = getJournalEntries();
  entries.push({
    date: `${entryDate}T12:00:00`,
    note,
    entryDate
  });
  const normalizedEntries = normalizePersonalJournalEntries(entries);
  userCloudPersonalJournalCache = normalizedEntries;
  localStorage.setItem(JOURNAL_ENTRIES_KEY, JSON.stringify(normalizedEntries));
  if (!userClientStateApplying) {
    scheduleUserClientStateWrite(USER_CLIENT_STATE_DOCS.personalJournal, () => ({
      entries: normalizedEntries
    }));
  }
  if (!hasNoteOverride && journalInput) journalInput.value = "";
  if (!silentStatus && journalStatus) {
    journalStatus.textContent = pickCopy({ en: "Entry saved.", es: "Entrada guardada." });
    setTimeout(() => (journalStatus.textContent = ""), 1600);
  }
  renderJournalEntries();
  return true;
}

if (saveJournalBtn) {
  saveJournalBtn.addEventListener("click", () => {
    saveJournalEntry().catch((err) => {
      console.warn("Journal entry save failed", err);
    });
  });
}

async function startApp() {
  ensureUserNameDecorationObserver();
  bindResponsiveViewportEvents();
  updateResponsiveViewportState();
  clearLegacyRegisteredUsersCache();
  ensureSeedJournalEntries();
  renderJournalEntries();
  await bootProfile();
  appDomainRenderReady = true;
  await applyLaunchConfig().catch((err) => {
    console.warn("Could not apply launch config", err);
  });
  queueUserNameDecoration(document.body);
  startClock();
  const currentDayIndex = getCurrentAppDayIndex();
  const currentDayKey = getCurrentAppDateKey();
  renderToday(currentDayIndex);
  renderFeelingScale();
  renderPlanGrid(currentDayIndex);
  renderCalendar(currentDayKey);
  renderAnnouncements();
  renderDashboard();
  renderCoachProfile();
  renderPermissions();
  runWhenBrowserIsIdle(() => {
    renderCalendarManager();
    renderMedia();
    renderCoachAssignments();
    renderCompletionTracking();
    renderAthleteManagement();
    renderJournalMonitor();
    renderMessages();
    renderSkills();
    initializePlanSelectors();
  }, { timeout: 1800 });
}

startApp();
